const SAM_RICH={"vwo_gs_C":"<div class=\"sam-intro\">Bij het domein <strong>Thema's</strong> bestudeer je één onderwerp <strong>diepgaand en over een lange periode</strong>. Het examenthema <strong>wisselt per jaar</strong>, maar de aanpak blijft gelijk: je volgt een ontwikkeling door de tijd en verklaart <strong>continuïteit en verandering</strong>.</div><div class=\"sam-head\">Wat is thematische geschiedenis?</div><p>Waar de tijdvakken de hele geschiedenis in stukken verdelen, snijdt een <strong>thema</strong> er juist dwars doorheen: je volgt één onderwerp (bijvoorbeeld 'steden en burgers' of 'verhouding kerk–staat') door meerdere tijdvakken heen, van begin tot heden.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 110\" role=\"img\" aria-label=\"Een historisch thema dat zich door verschillende tijdvakken heen ontwikkelt\"><defs><marker id=\"gsCa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"20\" y1=\"55\" x2=\"300\" y2=\"55\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#gsCa)\"/><g fill=\"var(--or)\"><circle cx=\"55\" cy=\"55\" r=\"4\"/><circle cx=\"130\" cy=\"55\" r=\"4\"/><circle cx=\"205\" cy=\"55\" r=\"4\"/><circle cx=\"275\" cy=\"55\" r=\"4\"/></g><g font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"55\" y=\"72\">ontstaan</text><text x=\"130\" y=\"72\">groei</text><text x=\"205\" y=\"72\">verandering</text><text x=\"275\" y=\"72\">heden</text></g><text x=\"160\" y=\"30\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">één thema door de tijd →</text></svg><div class=\"sam-figcap\"><strong>Thema door de tijd:</strong> je volgt de ontwikkeling van één onderwerp van zijn ontstaan, via groei en verandering, tot het heden — en let daarbij op oorzaken, gevolgen en keerpunten.</div></div><div class=\"sam-head\">Hoe je een thema analyseert</div><table class=\"sam-table\"><thead><tr><th>Vraag</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Ontwikkeling</td><td>hoe verandert het thema door de tijdvakken heen?</td></tr><tr><td>Oorzaak &amp; gevolg</td><td>waardoor treedt verandering op, en wat volgt eruit?</td></tr><tr><td>Continuïteit</td><td>wat blijft juist lange tijd hetzelfde?</td></tr><tr><td>Keerpunten</td><td>welke gebeurtenissen vormen een breuk?</td></tr></tbody></table><div class=\"sam-head\">Continuïteit en verandering</div><p>De kern van een thema is de wisselwerking tussen <strong>continuïteit</strong> (wat blijft) en <strong>verandering</strong> (wat verschuift). Zo zie je dat geschiedenis geen losse feiten is, maar een samenhangend proces met lange lijnen.</p><div class=\"sam-warn\"><strong>Let op:</strong> het exacte examenthema wordt jaarlijks door het CvTE vastgesteld (bijvoorbeeld 'Steden en burgers in de Lage Landen 1050–1700'). De <em>manier</em> van analyseren — ontwikkeling, oorzaak-gevolg, continuïteit en verandering — geldt voor elk thema.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom bekijk je bij een thema zowel continuïteit als verandering?</div><ol class=\"sam-worked-steps\"><li>Een thema ontwikkelt zich over een lange periode.</li><li>Sommige zaken veranderen (bijv. door revoluties of uitvindingen), andere blijven juist lang hetzelfde.</li><li>Door beide te bekijken snap je het proces als geheel, niet alleen de losse momenten.</li></ol><div class=\"sam-worked-ans\">✅ Continuïteit en verandering samen laten de lange lijnen én de keerpunten van het thema zien.</div></div></div>","vwo_sk_G":"<div class=\"sam-intro\">Chemie staat midden in de samenleving: van kunststoffen en medicijnen tot brandstoffen en meststoffen. Dit domein gaat over de <strong>wisselwerking</strong> tussen chemie, <strong>technologie</strong> en <strong>maatschappij</strong> — met de nadruk op <strong>milieu</strong> en <strong>duurzaamheid</strong>.</div><div class=\"sam-head\">Chemie in het dagelijks leven</div><p>Vrijwel alles om je heen is het product van chemische kennis: <strong>materialen</strong> (kunststoffen, metalen, glas), <strong>medicijnen</strong>, <strong>voeding</strong>, <strong>brandstoffen</strong> en <strong>meststoffen</strong>. Technologische vooruitgang en scheikunde gaan hand in hand.</p><div class=\"sam-head\">Van lineair naar circulair</div><p>Lang werkte de economie <strong>lineair</strong>: grondstof → product → afval. Duurzamer is een <strong>circulaire economie</strong>, waarin materialen na gebruik worden hergebruikt of gerecycled, zodat er weinig afval en grondstofverbruik overblijft.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 160\" role=\"img\" aria-label=\"Circulaire economie: grondstof, product, gebruik en recycling in een kringloop\"><defs><marker id=\"skGa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><circle cx=\"150\" cy=\"80\" r=\"55\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" stroke-dasharray=\"4 4\" opacity=\".5\"/><g font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"150\" y=\"22\">grondstof</text><text x=\"222\" y=\"84\">product</text><text x=\"150\" y=\"146\">gebruik</text><text x=\"78\" y=\"84\">recycling</text></g><g stroke=\"var(--or)\" stroke-width=\"1.8\" fill=\"none\"><path d=\"M178,33 A55,55 0 0,1 197,58\" marker-end=\"url(#skGa)\"/><path d=\"M203,102 A55,55 0 0,1 178,127\" marker-end=\"url(#skGa)\"/><path d=\"M122,127 A55,55 0 0,1 97,102\" marker-end=\"url(#skGa)\"/><path d=\"M103,58 A55,55 0 0,1 122,33\" marker-end=\"url(#skGa)\"/></g></svg><div class=\"sam-figcap\"><strong>Circulaire economie:</strong> grondstof → product → gebruik → recycling en weer terug. Materialen blijven in de kringloop, zodat afval en nieuw grondstofverbruik minimaal zijn.</div></div><div class=\"sam-head\">Chemie en milieu</div><table class=\"sam-table\"><thead><tr><th>Uitdaging</th><th>Chemische bijdrage</th></tr></thead><tbody><tr><td>Klimaat</td><td>CO₂-uitstoot beperken, groene brandstoffen</td></tr><tr><td>Afval</td><td>recycling, afbreekbare kunststoffen</td></tr><tr><td>Water &amp; lucht</td><td>zuivering, katalysatoren tegen uitstoot</td></tr></tbody></table><div class=\"sam-head\">Kansen en risico's afwegen</div><p>Nieuwe stoffen en technologieën brengen <strong>kansen</strong> (betere materialen, medicijnen, energie) maar ook <strong>risico's</strong> (giftigheid, milieuschade, uitputting). De maatschappij weegt die tegen elkaar af — een chemicus levert de feiten voor die keuze.</p><div class=\"sam-tip\">Een <strong>levenscyclusanalyse</strong> (LCA) bekijkt de milieubelasting van een product van grondstof tot afval ('van wieg tot graf'), zodat je eerlijk kunt vergelijken welke optie echt duurzamer is.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom is het recyclen van aluminium veel duurzamer dan het opnieuw winnen ervan?</div><ol class=\"sam-worked-steps\"><li>Aluminium winnen uit erts kost enorm veel energie (elektrolyse).</li><li>Omsmelten van bestaand aluminium kost daar maar een fractie van.</li><li>Recycling bespaart dus grondstoffen én veel energie en uitstoot.</li></ol><div class=\"sam-worked-ans\">✅ Recycling houdt het materiaal in de kringloop en scheelt een groot deel van de energie en milieubelasting.</div></div></div>","vwo_sk_F":"<div class=\"sam-intro\">In de industrie worden chemische reacties op grote schaal uitgevoerd. Dit domein gaat over <strong>industriële processen</strong>: hoe je uit grondstoffen efficiënt een product maakt, met aandacht voor <strong>rendement</strong>, <strong>duurzaamheid</strong> en <strong>groene chemie</strong>.</div><div class=\"sam-head\">Het blokschema van een proces</div><p>Een industrieel proces beschrijf je met een <strong>blokschema</strong>: grondstoffen gaan de reactor in, het mengsel wordt gescheiden, en niet-omgezette stoffen worden vaak <strong>gerecycled</strong>. Zo wordt zo min mogelijk verspild.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 130\" role=\"img\" aria-label=\"Blokschema van een industrieel proces met reactor, scheiding, product en recycling van reststoffen\"><defs><marker id=\"skFa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"14\" y=\"40\" width=\"60\" height=\"34\" rx=\"5\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"44\" y=\"55\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">grond-</text><text x=\"44\" y=\"65\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">stoffen</text><rect x=\"112\" y=\"40\" width=\"60\" height=\"34\" rx=\"5\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"142\" y=\"61\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">reactor</text><rect x=\"210\" y=\"40\" width=\"60\" height=\"34\" rx=\"5\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"240\" y=\"61\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">scheiding</text><rect x=\"284\" y=\"40\" width=\"30\" height=\"34\" rx=\"5\" fill=\"var(--or)\" opacity=\".22\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"299\" y=\"61\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">P</text><line x1=\"74\" y1=\"57\" x2=\"110\" y2=\"57\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#skFa)\"/><line x1=\"172\" y1=\"57\" x2=\"208\" y2=\"57\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#skFa)\"/><line x1=\"270\" y1=\"57\" x2=\"282\" y2=\"57\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#skFa)\"/><path d=\"M240,74 L240,100 L142,100 L142,76\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" stroke-dasharray=\"4 3\" marker-end=\"url(#skFa)\"/><text x=\"191\" y=\"112\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">recycling niet-omgezette stof</text></svg><div class=\"sam-figcap\"><strong>Blokschema:</strong> grondstoffen → reactor → scheiding → product (P). Niet-omgezette stoffen gaan via een recyclingstroom terug de reactor in, wat het rendement verhoogt en afval beperkt.</div></div><div class=\"sam-head\">Rendement</div><p>Het <strong>rendement</strong> geeft aan hoeveel product je werkelijk krijgt ten opzichte van de theoretisch maximale opbrengst.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Rendement</div><div class=\"sam-formula-eq\">rendement = (werkelijke opbrengst / maximale opbrengst) × 100%</div><div class=\"sam-formula-note\">Een hoog rendement betekent weinig verlies. Recycling van niet-omgezette grondstoffen en het verschuiven van een evenwicht (Le Chatelier) verhogen het rendement.</div></div><div class=\"sam-head\">Duurzaamheid en groene chemie</div><p><strong>Groene chemie</strong> streeft naar processen die zuinig omgaan met grondstoffen en energie en zo min mogelijk afval maken. Kernbegrippen:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Duurzaam proces</div><ul><li>hoge atoomeconomie</li><li>weinig afval, veel recycling</li><li>hernieuwbare grondstoffen</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Aandachtspunten</div><ul><li>energieverbruik</li><li>gevaarlijke bijproducten</li><li>uitstoot en milieu</li></ul></div></div><div class=\"sam-tip\"><strong>Atoomeconomie:</strong> het deel van alle reagerende atomen dat in het gewenste product terechtkomt. Hoe hoger, hoe minder afval — een maat voor de duurzaamheid van een reactie.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een proces levert 80 g product, terwijl maximaal 100 g mogelijk is. Bereken het rendement.</div><ol class=\"sam-worked-steps\"><li>rendement = (werkelijke opbrengst / maximale opbrengst) × 100%.</li><li>= (80 / 100) × 100%.</li><li>= 80%.</li></ol><div class=\"sam-worked-ans\">✅ Het rendement is 80% — 20% van de mogelijke opbrengst gaat verloren.</div></div></div>","vwo_wb_B":"<div class=\"sam-intro\">Domein B is de basis van wiskunde B: je herkent en gebruikt <strong>standaardfuncties</strong>, past <strong>transformaties</strong> toe, en lost <strong>vergelijkingen</strong> en <strong>ongelijkheden</strong> op — algebraïsch én met de grafiek.</div><div class=\"sam-head\">Standaardfuncties</div><table class=\"sam-table\"><thead><tr><th>Functie</th><th>Vorm</th><th>Grafiek</th></tr></thead><tbody><tr><td>Lineair</td><td>y = ax + b</td><td>rechte lijn</td></tr><tr><td>Kwadratisch</td><td>y = ax² + bx + c</td><td>parabool</td></tr><tr><td>Machtsfunctie</td><td>y = a·xⁿ</td><td>hangt van n af</td></tr><tr><td>Exponentieel</td><td>y = b·gˣ</td><td>groei/afname</td></tr></tbody></table><div class=\"sam-head\">Nulpunten en top van een parabool</div><p>De <strong>nulpunten</strong> zijn de x-waarden waar de grafiek de x-as snijdt (y = 0). De <strong>top</strong> ligt precies tussen de nulpunten in en is het maximum of minimum.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 172\" role=\"img\" aria-label=\"Parabool met twee nulpunten op de x-as en een top ertussen\"><defs><marker id=\"wbBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"20\" y1=\"140\" x2=\"312\" y2=\"140\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#wbBa)\"/><line x1=\"40\" y1=\"160\" x2=\"40\" y2=\"20\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#wbBa)\"/><path d=\"M70.0,140.0 L86.0,112.0 L102.0,88.9 L118.0,70.7 L134.0,57.3 L150.0,48.8 L166.0,45.2 L170.0,45.0 L178.0,45.6 L194.0,50.5 L210.0,60.2 L226.0,74.8 L242.0,94.2 L258.0,118.6 L270.0,140.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><circle cx=\"70\" cy=\"140\" r=\"4\" fill=\"var(--dk)\"/><circle cx=\"270\" cy=\"140\" r=\"4\" fill=\"var(--dk)\"/><circle cx=\"170\" cy=\"45\" r=\"4\" fill=\"var(--or)\"/><text x=\"66\" y=\"156\" font-size=\"9\" fill=\"var(--dk)\">nulpunt</text><text x=\"248\" y=\"156\" font-size=\"9\" fill=\"var(--dk)\">nulpunt</text><text x=\"176\" y=\"42\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">top</text></svg><div class=\"sam-figcap\"><strong>Parabool:</strong> de twee nulpunten liggen op de x-as (y = 0); de top ligt er symmetrisch tussenin. Bij een neerwaartse parabool is de top een maximum.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Nulpunten (abc-formule)</div><div class=\"sam-formula-eq\">x = (−b ± √(b² − 4ac)) / (2a)</div><div class=\"sam-formula-note\">De discriminant D = b² − 4ac bepaalt het aantal nulpunten: D &gt; 0 twee, D = 0 één, D &lt; 0 geen (reële) nulpunten.</div></div><div class=\"sam-head\">Vergelijkingen en ongelijkheden</div><p>Een <strong>vergelijking</strong> los je op door beide kanten gelijk te stellen (algebraïsch of via snijpunten). Bij een <strong>ongelijkheid</strong> (bijv. f(x) &gt; 0) zoek je waar de grafiek boven of onder een grens ligt — let op: bij delen door een negatief getal draait het teken om.</p><div class=\"sam-warn\"><strong>Let op:</strong> vermenigvuldig of deel je een ongelijkheid met een <em>negatief</em> getal, dan klapt het ongelijkheidsteken om (van &lt; naar &gt;).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bepaal de nulpunten van f(x) = x² − 5x + 6.</div><ol class=\"sam-worked-steps\"><li>Ontbinden: x² − 5x + 6 = (x − 2)(x − 3).</li><li>Elk product-deel gelijk aan 0: x − 2 = 0 of x − 3 = 0.</li><li>x = 2 of x = 3.</li></ol><div class=\"sam-worked-ans\">✅ De nulpunten zijn x = 2 en x = 3; de top ligt er middenin, bij x = 2,5.</div></div></div>","vwo_wa_D":"<div class=\"sam-intro\">Domein D draait om <strong>verandering</strong>: hoe snel iets toe- of afneemt. Met <strong>differentiaalrekening</strong> bereken je de <strong>helling</strong> van een grafiek in elk punt — de <strong>afgeleide</strong> — en daarmee groei, snelheid en toppen.</div><div class=\"sam-head\">Gemiddelde en momentane verandering</div><p>De <strong>gemiddelde verandering</strong> tussen twee punten is de helling van de <em>koorde</em> (Δy/Δx). De <strong>momentane verandering</strong> in één punt is de helling van de <em>raaklijn</em>: precies wat de afgeleide f′(x) geeft.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Grafiek met een raaklijn waarvan de helling de afgeleide (momentane verandering) is\"><defs><marker id=\"waDa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"30\" y1=\"156\" x2=\"332\" y2=\"156\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#waDa)\"/><line x1=\"40\" y1=\"164\" x2=\"40\" y2=\"20\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#waDa)\"/><path d=\"M40.0,141.4 L66.0,104.9 L92.0,76.5 L118.0,56.2 L144.0,44.1 L167.1,40.1 L190.2,42.5 L216.2,52.8 L242.2,71.3 L268.2,97.9 L294.2,132.6 L300,141\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"210\" y1=\"40\" x2=\"290\" y2=\"117\" stroke=\"var(--dk)\" stroke-width=\"2\" stroke-dasharray=\"5 3\"/><circle cx=\"250\" cy=\"78.4\" r=\"4\" fill=\"var(--dk)\"/><text x=\"150\" y=\"34\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">y = f(x)</text><text x=\"228\" y=\"132\" font-size=\"9\" fill=\"var(--mu)\">helling = f′(x)</text></svg><div class=\"sam-figcap\"><strong>De afgeleide als helling:</strong> de raaklijn in een punt heeft als richtingscoëfficiënt de waarde van f′(x). Een positieve afgeleide betekent stijgen, een negatieve dalen, nul een top of dal.</div></div><div class=\"sam-head\">Differentiëren</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Standaardregels</div><div class=\"sam-formula-eq\">(xⁿ)′ = n·xⁿ⁻¹  ·  (eˣ)′ = eˣ  ·  (ln x)′ = 1/x</div><div class=\"sam-formula-note\">Met de ketting-, product- en quotiëntregel differentieer je ook samengestelde functies. De afgeleide vertelt hoe snel de functie verandert.</div></div><div class=\"sam-head\">Toppen en dalen</div><p>Waar <strong>f′(x) = 0</strong> is de helling nul: daar ligt een <strong>maximum</strong> of <strong>minimum</strong>. Door het teken van f′(x) links en rechts te bekijken, weet je of het een top (stijgen → dalen) of een dal (dalen → stijgen) is.</p><div class=\"sam-tip\">Toepassing: de afgeleide van de plaats is de snelheid, en de afgeleide van de snelheid is de versnelling. Zo verbindt verandering wiskunde met de echte wereld.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bepaal de helling van f(x) = x² in het punt x = 3.</div><ol class=\"sam-worked-steps\"><li>Differentiëren: f′(x) = 2x.</li><li>Invullen: f′(3) = 2 · 3.</li><li>= 6.</li></ol><div class=\"sam-worked-ans\">✅ De helling (momentane verandering) in x = 3 is 6.</div></div></div>","vwo_na_G":"<div class=\"sam-intro\">Van de kleinste kern tot het grootste sterrenstelsel: dit domein verbindt <strong>straling</strong> met <strong>astrofysica</strong> (sterren en het heelal) en met <strong>medische beeldvorming</strong>. Overal gebruik je hetzelfde <strong>elektromagnetisch spectrum</strong>.</div><div class=\"sam-head\">Het elektromagnetisch spectrum</div><p>Alle <strong>elektromagnetische straling</strong> reist met de lichtsnelheid, maar verschilt in <strong>golflengte</strong> en <strong>frequentie</strong>. Hoe korter de golflengte, hoe hoger de frequentie en de energie per foton (E = h·f).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 130\" role=\"img\" aria-label=\"Het elektromagnetisch spectrum van radiogolven tot gammastraling\"><defs><marker id=\"naGa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><g stroke=\"none\"><rect x=\"20\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\" opacity=\".18\"/><rect x=\"63\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\" opacity=\".30\"/><rect x=\"106\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\" opacity=\".42\"/><rect x=\"149\" y=\"45\" width=\"26\" height=\"26\" fill=\"var(--or)\" opacity=\".60\"/><rect x=\"175\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\" opacity=\".72\"/><rect x=\"218\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\" opacity=\".85\"/><rect x=\"261\" y=\"45\" width=\"43\" height=\"26\" fill=\"var(--or)\"/></g><g font-size=\"6.5\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"41\" y=\"61\">radio</text><text x=\"84\" y=\"61\">micro</text><text x=\"127\" y=\"61\">infrar.</text><text x=\"162\" y=\"61\">zicht</text><text x=\"196\" y=\"61\">UV</text><text x=\"239\" y=\"61\">röntgen</text><text x=\"282\" y=\"61\">gamma</text></g><line x1=\"20\" y1=\"82\" x2=\"304\" y2=\"82\" stroke=\"var(--mu)\" stroke-width=\"1\" marker-start=\"url(#naGa)\" marker-end=\"url(#naGa)\"/><text x=\"40\" y=\"95\" font-size=\"7.5\" fill=\"var(--mu)\">grote golflengte</text><text x=\"300\" y=\"95\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"end\">hoge frequentie/energie</text></svg><div class=\"sam-figcap\"><strong>EM-spectrum:</strong> van links (radiogolven, lange golflengte, lage energie) naar rechts (gammastraling, korte golflengte, hoge energie). Zichtbaar licht is maar een smalle strook in het midden.</div></div><div class=\"sam-head\">Astrofysica: sterren en het heelal</div><p>Sterren zenden een <strong>spectrum</strong> uit waaruit je hun temperatuur en samenstelling afleidt. Uit de <strong>roodverschuiving</strong> van ver weg gelegen sterrenstelsels (het Doppler-effect voor licht) blijkt dat het heelal <strong>uitdijt</strong>: hoe verder weg, hoe sneller ze zich van ons af bewegen.</p><div class=\"sam-tip\"><strong>Roodverschuiving:</strong> licht van een wegbewegende bron verschuift naar langere golflengten (roder). Bijna alle sterrenstelsels vertonen roodverschuiving — het bewijs dat het heelal uitdijt.</div><div class=\"sam-head\">Medische beeldvorming</div><table class=\"sam-table\"><thead><tr><th>Techniek</th><th>Gebruikt</th><th>Toepassing</th></tr></thead><tbody><tr><td>Röntgen</td><td>röntgenstraling</td><td>botten, longen</td></tr><tr><td>Echografie</td><td>ultrageluid</td><td>zwangerschap, organen</td></tr><tr><td>MRI</td><td>magneetvelden + radiogolven</td><td>weke delen, hersenen</td></tr></tbody></table><div class=\"sam-warn\"><strong>Let op:</strong> röntgen- en gammastraling zijn <em>ioniserend</em> (schadelijk in hoge dosis), terwijl echografie (geluid) en MRI (magneetvelden) dat niet zijn. Daarom kies je per situatie de veiligste techniek.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom kun je uit de roodverschuiving van een sterrenstelsel afleiden dat het zich van ons af beweegt?</div><ol class=\"sam-worked-steps\"><li>Bij een wegbewegende bron worden de lichtgolven 'uitgerekt' (Doppler-effect).</li><li>Langere golflengte betekent een verschuiving naar het rode deel van het spectrum.</li><li>Roodverschuiving hoort dus bij een bron die zich verwijdert.</li></ol><div class=\"sam-worked-ans\">✅ Roodverschuiving = wegbeweging; de mate ervan verraadt hoe snel het stelsel zich verwijdert.</div></div></div>","vwo_ak_D":"<div class=\"sam-intro\">Bij het domein <strong>Gebied</strong> analyseer je één <strong>ontwikkelingsregio</strong> diepgaand (de examenregio <strong>wisselt per jaar</strong>; recent Zuid-Amerika). Je verbindt de <strong>fysische</strong> en de <strong>sociale</strong> geografie tot één samenhangend beeld van het gebied.</div><div class=\"sam-head\">Een gebied analyseren</div><p>Een geograaf kijkt naar een gebied via twee 'lagen', en vooral naar hun <strong>samenhang</strong>: hoe de natuur de mens beïnvloedt en andersom.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 140\" role=\"img\" aria-label=\"Gebiedsanalyse: de fysische en sociale laag komen samen tot een beeld van het gebied\"><rect x=\"20\" y=\"20\" width=\"120\" height=\"44\" rx=\"8\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"80\" y=\"38\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Fysische geografie</text><text x=\"80\" y=\"53\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">klimaat · reliëf · bodem</text><rect x=\"160\" y=\"20\" width=\"120\" height=\"44\" rx=\"8\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"220\" y=\"38\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Sociale geografie</text><text x=\"220\" y=\"53\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">bevolking · economie</text><rect x=\"90\" y=\"98\" width=\"120\" height=\"34\" rx=\"8\" fill=\"var(--or)\" opacity=\".2\" stroke=\"var(--or)\" stroke-width=\"1.4\"/><text x=\"150\" y=\"119\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">beeld van het gebied</text><defs><marker id=\"akDa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"80\" y1=\"64\" x2=\"130\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#akDa)\"/><line x1=\"220\" y1=\"64\" x2=\"170\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#akDa)\"/></svg><div class=\"sam-figcap\"><strong>Gebiedsanalyse:</strong> de fysische laag (klimaat, reliëf, bodem) en de sociale laag (bevolking, economie) komen samen tot een verklarend beeld van het gebied.</div></div><div class=\"sam-head\">Fysische geografie</div><table class=\"sam-table\"><thead><tr><th>Aspect</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Klimaat</td><td>temperatuur, neerslag, seizoenen</td></tr><tr><td>Reliëf</td><td>gebergten, laagvlaktes, rivieren</td></tr><tr><td>Bodem &amp; natuur</td><td>vruchtbaarheid, vegetatie, grondstoffen</td></tr></tbody></table><div class=\"sam-head\">Sociale geografie</div><table class=\"sam-table\"><thead><tr><th>Aspect</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Bevolking</td><td>spreiding, groei, migratie, verstedelijking</td></tr><tr><td>Economie</td><td>landbouw, industrie, diensten, handel</td></tr><tr><td>Ontwikkeling</td><td>welvaart, HDI, ongelijkheid tussen regio's</td></tr></tbody></table><div class=\"sam-tip\">De kern van dit domein is de <strong>samenhang</strong>: verklaar bijvoorbeeld hoe het klimaat en reliëf de landbouw, bevolkingsspreiding en economie van de regio bepalen — en hoe de mens het landschap terugverandert.</div><div class=\"sam-warn\"><strong>Let op:</strong> de exacte examenregio wordt jaarlijks vastgesteld in de syllabus. De <em>manier</em> van analyseren (fysisch + sociaal + samenhang) blijft hetzelfde; de feitelijke regio kan wisselen.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Hoe kan het reliëf van een regio de bevolkingsspreiding verklaren?</div><ol class=\"sam-worked-steps\"><li>Hooggebergte en droge of natte gebieden zijn moeilijk bewoonbaar.</li><li>Vlakke, vruchtbare gebieden met water trekken juist landbouw en steden aan.</li><li>Daardoor woont de bevolking geconcentreerd in de gunstige gebieden.</li></ol><div class=\"sam-worked-ans\">✅ De fysische geografie (reliëf, klimaat) stuurt waar mensen zich vestigen — een klassiek voorbeeld van samenhang.</div></div></div>","vwo_ak_E":"<div class=\"sam-intro\">Nederland is een <strong>deltaland</strong>: een groot deel ligt onder zeeniveau. Dit domein gaat over de eigen <strong>leefomgeving</strong> — het <strong>waterbeheer</strong> en overstromingsrisico, de <strong>stedelijke gebieden</strong> en de <strong>ruimtelijke inrichting</strong> van Nederland.</div><div class=\"sam-head\">Leven onder de zeespiegel</div><p>Ongeveer een kwart van Nederland ligt onder <strong>NAP</strong> (Normaal Amsterdams Peil). Zonder <strong>dijken</strong>, <strong>duinen</strong> en <strong>gemalen</strong> zou een groot deel van het land onder water staan. Waterbeheer is daarom van levensbelang.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 150\" role=\"img\" aria-label=\"Dwarsdoorsnede van een polder: de zee met dijk, het lager gelegen land en het grondwaterpeil\"><rect x=\"0\" y=\"55\" width=\"90\" height=\"70\" fill=\"var(--or)\" opacity=\".18\"/><path d=\"M0,55 Q45,50 90,55\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\"/><text x=\"40\" y=\"90\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\">zee</text><path d=\"M90,55 L120,40 L150,55 Z\" fill=\"var(--mu)\" opacity=\".35\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"120\" y=\"34\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">dijk</text><rect x=\"150\" y=\"95\" width=\"170\" height=\"30\" fill=\"var(--mu)\" opacity=\".2\"/><line x1=\"150\" y1=\"95\" x2=\"320\" y2=\"95\" stroke=\"var(--dk)\" stroke-width=\"1.5\"/><text x=\"235\" y=\"115\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">polder (onder NAP)</text><line x1=\"0\" y1=\"55\" x2=\"90\" y2=\"55\" stroke=\"var(--dk)\" stroke-width=\"1\" stroke-dasharray=\"4 2\"/><text x=\"300\" y=\"52\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"end\">zeeniveau (NAP)</text><line x1=\"150\" y1=\"55\" x2=\"320\" y2=\"55\" stroke=\"var(--mu)\" stroke-width=\"0.8\" stroke-dasharray=\"3 3\"/><path d=\"M150,55 L150,95\" stroke=\"var(--mu)\" stroke-width=\"1\" marker-end=\"url(#akEa)\"/><defs><marker id=\"akEa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><text x=\"158\" y=\"78\" font-size=\"7\" fill=\"var(--mu)\">↕ onder NAP</text></svg><div class=\"sam-figcap\"><strong>Polder in dwarsdoorsnede:</strong> de dijk houdt de zee tegen; het land erachter (de polder) ligt lager dan het zeeniveau (NAP). Gemalen pompen overtollig water weg.</div></div><div class=\"sam-head\">Overstromingsrisico</div><p>Het <strong>risico</strong> is een combinatie van <strong>kans</strong> (hoe waarschijnlijk is een overstroming?) en <strong>gevolg</strong> (hoeveel schade en slachtoffers?). In dichtbevolkte, laaggelegen gebieden zijn de gevolgen groot, dus daar zijn de dijken het sterkst.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Overstromingsrisico</div><div class=\"sam-formula-eq\">risico = kans × gevolg</div><div class=\"sam-formula-note\">Je verkleint het risico door de kans te verlagen (hogere dijken, 'Ruimte voor de Rivier') óf de gevolgen te beperken (evacuatieplannen, aangepast bouwen).</div></div><div class=\"sam-head\">Stedelijke gebieden en ruimte</div><p>Nederland is dichtbevolkt, met de <strong>Randstad</strong> als economisch kerngebied. Ruimte is schaars, dus er zijn voortdurend keuzes en conflicten over de <strong>ruimtelijke inrichting</strong>: wonen, werken, natuur, landbouw en infrastructuur strijden om dezelfde grond.</p><div class=\"sam-tip\"><strong>Ruimte voor de Rivier:</strong> in plaats van alleen hogere dijken geeft Nederland rivieren op sommige plekken juist méér ruimte (uiterwaarden), zodat hoogwater veilig weg kan.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom zijn de dijken rond de Randstad extra sterk?</div><ol class=\"sam-worked-steps\"><li>Risico = kans × gevolg.</li><li>De Randstad is dichtbevolkt en economisch cruciaal, dus de gevolgen van een overstroming zijn enorm.</li><li>Om het risico beheersbaar te houden moet de kans daar extra klein zijn.</li></ol><div class=\"sam-worked-ans\">✅ Door de grote gevolgen moeten de dijken hier aan de hoogste veiligheidsnormen voldoen.</div></div></div>","vwo_mw_E":"<div class=\"sam-intro\">Samenlevingen staan niet stil. Het hoofdconcept <strong>verandering</strong> gaat over de grote processen die de moderne samenleving vormden: <strong>modernisering</strong>, <strong>individualisering</strong> en <strong>globalisering</strong>.</div><div class=\"sam-head\">Modernisering</div><p><strong>Modernisering</strong> is de langdurige overgang van een traditionele naar een moderne samenleving. Kenmerken: industrialisatie, verstedelijking, rationalisering, en een groeiende rol van wetenschap en de staat.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 120\" role=\"img\" aria-label=\"Overgang van een traditionele naar een moderne samenleving\"><rect x=\"12\" y=\"35\" width=\"120\" height=\"60\" rx=\"8\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"72\" y=\"55\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">traditioneel</text><text x=\"72\" y=\"72\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">gemeenschap, geloof,</text><text x=\"72\" y=\"83\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">landbouw, vaste rollen</text><rect x=\"188\" y=\"35\" width=\"120\" height=\"60\" rx=\"8\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"248\" y=\"55\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">modern</text><text x=\"248\" y=\"72\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">individu, wetenschap,</text><text x=\"248\" y=\"83\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">industrie, vrije keuze</text><defs><marker id=\"mwEa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"136\" y1=\"65\" x2=\"184\" y2=\"65\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#mwEa)\"/><text x=\"160\" y=\"58\" font-size=\"8\" fill=\"var(--or)\" text-anchor=\"middle\">modernisering</text></svg><div class=\"sam-figcap\"><strong>Modernisering:</strong> de samenleving verschuift van gemeenschap, geloof en vaste rollen naar individu, wetenschap, industrie en vrije keuze.</div></div><div class=\"sam-head\">Individualisering</div><p><strong>Individualisering</strong> is het proces waarbij mensen losser komen te staan van vaste verbanden (kerk, klasse, buurt) en meer hun eigen keuzes maken. Dat geeft <strong>vrijheid</strong>, maar ook minder vanzelfsprekende <strong>binding</strong> en zekerheid.</p><div class=\"sam-head\">Globalisering</div><p><strong>Globalisering</strong> is de toenemende wereldwijde verwevenheid — economisch, cultureel en politiek. Ze brengt kansen (handel, uitwisseling) maar ook spanningen (concurrentie, verlies van eigen identiteit, ongelijkheid).</p><table class=\"sam-table\"><thead><tr><th>Proces</th><th>Kern</th></tr></thead><tbody><tr><td>Modernisering</td><td>traditioneel → modern (industrie, wetenschap)</td></tr><tr><td>Individualisering</td><td>minder vaste verbanden, meer eigen keuze</td></tr><tr><td>Globalisering</td><td>toenemende wereldwijde verwevenheid</td></tr></tbody></table><div class=\"sam-warn\"><strong>Let op de samenhang:</strong> deze processen versterken elkaar. Globalisering en modernisering voeden de individualisering, en individualisering zet de traditionele binding en de verzorgingsstaat verder onder druk.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Hoe kan individualisering de sociale cohesie onder druk zetten?</div><ol class=\"sam-worked-steps\"><li>Mensen komen losser te staan van vaste verbanden (kerk, vereniging, buurt).</li><li>Daardoor nemen vanzelfsprekende contacten en gedeelde normen af.</li><li>Minder gedeelde binding kan de onderlinge verbondenheid verzwakken.</li></ol><div class=\"sam-worked-ans\">✅ Meer individuele vrijheid gaat samen met minder vanzelfsprekende sociale binding.</div></div></div>","vwo_mw_D":"<div class=\"sam-intro\">Wat houdt een samenleving bij elkaar? Het hoofdconcept <strong>binding</strong> gaat over <strong>sociale cohesie</strong>: de mate waarin mensen zich met elkaar en met de samenleving verbonden voelen, en de rol die <strong>instituties</strong> en de <strong>verzorgingsstaat</strong> daarin spelen.</div><div class=\"sam-head\">Sociale cohesie</div><p><strong>Sociale cohesie</strong> is de onderlinge verbondenheid in een groep of samenleving. Ze ontstaat door gedeelde <strong>normen en waarden</strong>, contacten en vertrouwen. Te weinig cohesie leidt tot <strong>anomie</strong>: normverwarring en het gevoel er niet bij te horen.</p><div class=\"sam-head\">Vormen van binding</div><table class=\"sam-table\"><thead><tr><th>Vorm</th><th>Betekenis</th></tr></thead><tbody><tr><td>Sociale binding</td><td>relaties met anderen (gezin, vrienden, verenigingen)</td></tr><tr><td>Institutionele binding</td><td>via instituties zoals school, kerk, staat</td></tr><tr><td>Culturele binding</td><td>gedeelde taal, symbolen, normen en waarden</td></tr></tbody></table><div class=\"sam-head\">Instituties</div><p><strong>Instituties</strong> zijn vaste patronen van regels en organisaties die het samenleven ordenen: het gezin, het onderwijs, de rechtspraak, de kerk, de media. Ze brengen mensen samen (binding) én geven de samenleving stabiliteit.</p><div class=\"sam-head\">De verzorgingsstaat</div><p>De <strong>verzorgingsstaat</strong> versterkt de binding door burgers bestaanszekerheid te bieden (uitkeringen, zorg, onderwijs). Dat vergroot de gelijkheid en solidariteit, maar kost veel en kan afhankelijkheid in de hand werken.</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Versterkt binding</div><ul><li>bestaanszekerheid voor iedereen</li><li>minder ongelijkheid</li><li>solidariteit tussen groepen</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Onder druk door</div><ul><li>hoge kosten en vergrijzing</li><li>individualisering</li><li>afnemend onderling vertrouwen</li></ul></div></div><div class=\"sam-tip\">Instituties hebben een <strong>bindende</strong> functie (mensen verbinden) én een <strong>socialiserende</strong> functie (normen en waarden overdragen) — daarom horen ze bij zowel binding als vorming.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom kan een sterke verzorgingsstaat de sociale cohesie vergroten?</div><ol class=\"sam-worked-steps\"><li>Hij biedt iedereen bestaanszekerheid, ook de zwaksten.</li><li>Dat vermindert grote ongelijkheid en wij-zij-gevoelens.</li><li>Meer gelijkheid en solidariteit versterken de onderlinge verbondenheid.</li></ol><div class=\"sam-worked-ans\">✅ Door bestaanszekerheid en solidariteit voelen meer mensen zich onderdeel van de samenleving.</div></div></div>","vwo_gs_D":"<div class=\"sam-intro\">Dit domein volgt hoe Nederland een <strong>rechtsstaat</strong> en een <strong>parlementaire democratie</strong> werd: van een land waar de koning regeerde naar een staat met <strong>grondrechten</strong>, <strong>machtenscheiding</strong> en <strong>algemeen kiesrecht</strong>.</div><div class=\"sam-head\">Wat is een rechtsstaat?</div><p>In een <strong>rechtsstaat</strong> is de macht van de overheid aan wetten gebonden en worden burgers beschermd tegen willekeur. De kernprincipes:</p><table class=\"sam-table\"><thead><tr><th>Principe</th><th>Betekenis</th></tr></thead><tbody><tr><td>Legaliteitsbeginsel</td><td>de overheid mag alleen handelen op basis van de wet</td></tr><tr><td>Machtenscheiding</td><td>trias politica: wetgevend, uitvoerend, rechterlijk gescheiden</td></tr><tr><td>Grondrechten</td><td>vrijheden van burgers (meningsuiting, godsdienst, gelijkheid)</td></tr><tr><td>Onafhankelijke rechtspraak</td><td>rechters oordelen zonder inmenging</td></tr></tbody></table><div class=\"sam-head\">De weg naar democratie in Nederland</div><p>De parlementaire democratie ontstond stap voor stap. Enkele ijkpunten:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 130\" role=\"img\" aria-label=\"Tijdbalk van de democratisering van Nederland met de grondwet van 1848, evenredige vertegenwoordiging in 1917 en vrouwenkiesrecht in 1919\"><line x1=\"30\" y1=\"72\" x2=\"330\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"2\"/><g font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"40\" y=\"92\">1800</text><text x=\"130\" y=\"92\">1850</text><text x=\"220\" y=\"92\">1900</text><text x=\"310\" y=\"92\">1950</text></g><g stroke=\"var(--mu)\" stroke-width=\"1\"><line x1=\"40\" y1=\"67\" x2=\"40\" y2=\"77\"/><line x1=\"130\" y1=\"67\" x2=\"130\" y2=\"77\"/><line x1=\"220\" y1=\"67\" x2=\"220\" y2=\"77\"/><line x1=\"310\" y1=\"67\" x2=\"310\" y2=\"77\"/></g><g fill=\"var(--or)\"><circle cx=\"126\" cy=\"72\" r=\"4\"/><circle cx=\"250\" cy=\"72\" r=\"4\"/><circle cx=\"254\" cy=\"72\" r=\"4\"/></g><g font-size=\"7.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"126\" y=\"52\">1848</text><text x=\"126\" y=\"42\">Grondwet</text><text x=\"250\" y=\"30\">1917/1919</text><text x=\"250\" y=\"20\">kiesrecht</text></g><g font-size=\"6.5\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"126\" y=\"108\">Thorbecke:</text><text x=\"126\" y=\"117\">min. verantw.</text><text x=\"250\" y=\"108\">evenredig +</text><text x=\"250\" y=\"117\">vrouwenkiesrecht</text></g></svg><div class=\"sam-figcap\"><strong>Democratisering:</strong> in 1848 legde Thorbecke de basis (grondwet, ministeriële verantwoordelijkheid). In 1917 kwam de evenredige vertegenwoordiging en algemeen mannenkiesrecht, in 1919 het vrouwenkiesrecht.</div></div><div class=\"sam-head\">Parlementaire democratie</div><p>In een <strong>parlementaire democratie</strong> controleert het gekozen parlement de regering. Dankzij de <strong>ministeriële verantwoordelijkheid</strong> (1848) moeten ministers zich verantwoorden tegenover de Staten-Generaal, niet de koning.</p><div class=\"sam-tip\">1848 is het scharnierjaar: Thorbecke's grondwet maakte ministers verantwoordelijk aan het parlement en beperkte de macht van de koning — het begin van de parlementaire democratie.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom is de invoering van het algemeen kiesrecht (1917/1919) een belangrijke stap in de democratisering?</div><ol class=\"sam-worked-steps\"><li>Vóór 1917 mocht alleen een beperkte, welgestelde groep mannen stemmen (censuskiesrecht).</li><li>Met algemeen kiesrecht kregen alle volwassen mannen (1917) en vrouwen (1919) stemrecht.</li><li>Daardoor werd het parlement een afspiegeling van de hele bevolking.</li></ol><div class=\"sam-worked-ans\">✅ Het kiesrecht werd van een klein deel uitgebreid naar iedereen — de kern van democratisering.</div></div></div>","vwo_bi_D":"<div class=\"sam-intro\"><strong>Interactie</strong> gaat over beïnvloeding: hoe een biologische eenheid haar omgeving beïnvloedt én erdoor wordt beïnvloed, en hoe ze daarop reageert. Je bekijkt dat op oplopende schaal — van <strong>moleculen</strong> en <strong>cellen</strong> via het <strong>gedrag</strong> van een organisme tot hele <strong>ecosystemen</strong>.</div><div class=\"sam-head\">Wat je voor het examen moet kennen (syllabus)</div><p>Domein D bestaat uit de subdomeinen hieronder. <strong>D4 (Seksualiteit)</strong> is vooral schoolexamenstof en valt buiten deze samenvatting.</p><table class=\"sam-table\"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>D1</td><td>Moleculaire interactie</td><td>signaalmolecuul + receptor (sleutel–slot)</td></tr><tr><td>D2</td><td>Cellulaire interactie</td><td>cellen communiceren: synaps, hormonen, afweer</td></tr><tr><td>D3</td><td>Gedrag en interactie</td><td>prikkel → verwerking → reactie; gedrag</td></tr><tr><td>D5</td><td>Interactie in ecosystemen</td><td>symbiose, concurrentie, predator–prooi</td></tr></tbody></table><div class=\"sam-head\">D1 · Moleculaire interactie</div><p>Communicatie in en tussen cellen begint bij <strong>moleculen die op elkaar passen</strong>. Een <strong>signaalmolecuul</strong> (ligand, bv. een hormoon of neurotransmitter) bindt aan een <strong>receptor</strong> met een precies passende vorm — het <strong>sleutel–slot-principe</strong>. Alleen de juiste combinatie geeft een reactie.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 130\" role=\"img\" aria-label=\"Een signaalmolecuul past als een sleutel in een receptor en zet in de cel een respons in gang\"><defs><marker id=\"giD1\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><rect x=\"150\" y=\"20\" width=\"170\" height=\"94\" fill=\"var(--mu)\" opacity=\".08\"/><line x1=\"150\" y1=\"20\" x2=\"150\" y2=\"114\" stroke=\"var(--mu)\" stroke-width=\"2\"/><text x=\"238\" y=\"107\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">binnenkant cel</text><circle cx=\"60\" cy=\"52\" r=\"16\" fill=\"var(--or)\" opacity=\".8\"/><text x=\"60\" y=\"34\" font-size=\"7.5\" fill=\"var(--dk)\" text-anchor=\"middle\">signaalmolecuul</text><path d=\"M150,44 h-18 a10,10 0 0 0 0,20 h18\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><text x=\"150\" y=\"80\" font-size=\"7.5\" fill=\"var(--dk)\" text-anchor=\"middle\">receptor</text><line x1=\"80\" y1=\"52\" x2=\"126\" y2=\"53\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giD1)\"/><line x1=\"168\" y1=\"54\" x2=\"250\" y2=\"54\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giD1)\"/><text x=\"210\" y=\"47\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">respons in de cel</text></svg><div class=\"sam-figcap\"><strong>Sleutel–slot:</strong> alleen een signaalmolecuul met de juiste vorm bindt aan de receptor. Die binding zet ín de cel een reactie in gang (bijvoorbeeld een enzym activeren of een gen aanzetten).</div></div><p>Dezelfde specifieke binding zie je bij <strong>enzym en substraat</strong>, bij <strong>antigeen en antilichaam</strong> en bij <strong>hormoon en receptor</strong>. Een molecuul dat de receptor bezet maar géén respons geeft, werkt als <strong>remmer</strong>.</p><div class=\"sam-head\">D2 · Cellulaire interactie</div><p>Cellen stemmen hun activiteit op elkaar af via signalen. De twee hoofdsystemen ken je uit domein B, maar hier draait het om de <strong>communicatie tussen de cellen</strong>:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Zenuwstelsel</div><ul><li>snel, kortdurend, gericht</li><li>signaal via de synaps</li><li>neurotransmitter → volgende cel</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Hormoonstelsel</div><ul><li>trager, langdurig, breed</li><li>hormoon via het bloed</li><li>werkt alleen op doelcellen met de juiste receptor</li></ul></div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 320 128\" role=\"img\" aria-label=\"In de synaps geeft de zendende cel neurotransmitter af die op receptoren van de ontvangende cel bindt\"><defs><marker id=\"giD2\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"8\" y=\"34\" width=\"120\" height=\"60\" rx=\"8\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"68\" y=\"30\" font-size=\"8\" fill=\"var(--dk)\" text-anchor=\"middle\">zendende cel</text><rect x=\"192\" y=\"34\" width=\"120\" height=\"60\" rx=\"8\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"252\" y=\"30\" font-size=\"8\" fill=\"var(--dk)\" text-anchor=\"middle\">ontvangende cel</text><text x=\"160\" y=\"112\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">synapsspleet</text><circle cx=\"150\" cy=\"52\" r=\"4\" fill=\"var(--or)\"/><circle cx=\"162\" cy=\"64\" r=\"4\" fill=\"var(--or)\"/><circle cx=\"150\" cy=\"76\" r=\"4\" fill=\"var(--or)\"/><line x1=\"128\" y1=\"64\" x2=\"140\" y2=\"64\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giD2)\"/><line x1=\"172\" y1=\"64\" x2=\"190\" y2=\"64\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giD2)\"/><text x=\"160\" y=\"46\" font-size=\"7\" fill=\"var(--or)\" text-anchor=\"middle\">neurotransmitter</text></svg><div class=\"sam-figcap\"><strong>Synaps:</strong> bij een impuls geeft de zendende cel neurotransmitter af in de synapsspleet; dat molecuul bindt aan receptoren van de ontvangende cel (weer sleutel–slot, D1) en geeft de prikkel door.</div></div><p>Ook het <strong>afweersysteem</strong> werkt via cel-cel-herkenning: cellen herkennen met receptoren lichaamsvreemde antigenen en waarschuwen elkaar met signaalstoffen.</p><div class=\"sam-head\">D3 · Gedrag en interactie</div><p><strong>Gedrag</strong> is alles wat een organisme waarneembaar doet als reactie op prikkels. De basisketen loopt van prikkel naar reactie:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 336 74\" role=\"img\" aria-label=\"Reactieketen: prikkel wordt door een zintuig opgevangen, door het zenuwstelsel verwerkt en door een effector omgezet in een reactie\"><defs><marker id=\"giD3\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><g font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><rect x=\"4\" y=\"26\" width=\"56\" height=\"30\" rx=\"5\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"32\" y=\"44\">prikkel</text><rect x=\"80\" y=\"26\" width=\"56\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"108\" y=\"44\">zintuig</text><rect x=\"156\" y=\"22\" width=\"70\" height=\"38\" rx=\"5\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"191\" y=\"38\">zenuw-</text><text x=\"191\" y=\"49\">stelsel</text><rect x=\"246\" y=\"26\" width=\"56\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"274\" y=\"44\">effector</text></g><text x=\"322\" y=\"45\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"start\">→ reactie</text><line x1=\"60\" y1=\"41\" x2=\"78\" y2=\"41\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giD3)\"/><line x1=\"136\" y1=\"41\" x2=\"154\" y2=\"41\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giD3)\"/><line x1=\"226\" y1=\"41\" x2=\"244\" y2=\"41\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giD3)\"/></svg><div class=\"sam-figcap\"><strong>Reactieketen:</strong> een <strong>zintuig</strong> vangt de prikkel op, het <strong>zenuwstelsel</strong> verwerkt de informatie en een <strong>effector</strong> (spier of klier) voert de reactie uit.</div></div><table class=\"sam-table\"><thead><tr><th>Type gedrag</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Aangeboren</td><td>vastgelegd in het DNA, meteen aanwezig (bv. reflex, instinct)</td></tr><tr><td>Aangeleerd</td><td>ontstaat door ervaring (bv. conditionering, inprenting)</td></tr></tbody></table><p>Gedrag heeft altijd een <strong>functie</strong>: het vergroot de overlevings- of voortplantingskans. Denk aan <strong>communicatie</strong> tussen organismen (geur, geluid, houding) en aan reageren op <strong>abiotische</strong> factoren (licht, temperatuur).</p><div class=\"sam-tip\">Bij een examenvraag over gedrag: benoem eerst de <strong>prikkel</strong>, dan de <strong>reactie</strong>, en verklaar de reactie via het <strong>voordeel</strong> voor overleving of voortplanting.</div><div class=\"sam-head\">D5 · Interactie in ecosystemen</div><p>Tussen soorten in een ecosysteem bestaan vaste relaties. Ze verklaren waarom populaties groeien, krimpen of samen in evenwicht blijven.</p><table class=\"sam-table\"><thead><tr><th>Relatie</th><th>Soort 1 / Soort 2</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Mutualisme</td><td>voordeel / voordeel</td><td>bij en bloem</td></tr><tr><td>Commensalisme</td><td>voordeel / geen effect</td><td>zeepok op walvis</td></tr><tr><td>Parasitisme</td><td>voordeel / nadeel</td><td>teek op gastheer</td></tr><tr><td>Predatie</td><td>eet / wordt gegeten</td><td>vos en konijn</td></tr><tr><td>Competitie</td><td>nadeel / nadeel</td><td>strijd om voedsel/ruimte</td></tr></tbody></table><p><strong>Concurrentie</strong> kan <strong>intraspecifiek</strong> zijn (binnen één soort — meestal het hevigst, want gelijke behoeften) of <strong>interspecifiek</strong> (tussen soorten). Predator en prooi houden elkaar in een <strong>schommelend evenwicht</strong>:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 330 168\" role=\"img\" aria-label=\"Predator-prooi grafiek: de prooipopulatie piekt en daarna volgt met vertraging de predatorpopulatie\"><defs><marker id=\"giD5\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"40\" y1=\"150\" x2=\"322\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#giD5)\"/><line x1=\"40\" y1=\"150\" x2=\"40\" y2=\"18\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#giD5)\"/><text x=\"326\" y=\"164\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"end\">tijd</text><text x=\"8\" y=\"24\" font-size=\"8\" fill=\"var(--mu)\">aantal</text><path d=\"M40,120 C70,60 100,52 130,96 C160,138 190,138 220,96 C250,56 280,58 310,110\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><path d=\"M40,140 C75,128 104,86 134,80 C168,74 196,104 226,120 C256,134 286,112 312,86\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-dasharray=\"5 4\"/><text x=\"96\" y=\"44\" font-size=\"8\" fill=\"var(--or)\">prooi</text><text x=\"150\" y=\"70\" font-size=\"8\" fill=\"var(--mu)\">predator</text></svg><div class=\"sam-figcap\"><strong>Predator–prooi-cyclus:</strong> veel prooi → predatoren nemen toe → prooi wordt opgegeten en daalt → predatoren krijgen voedseltekort en dalen → prooi herstelt. De predatorpiek volgt steeds ná die van de prooi.</div></div><div class=\"sam-warn\"><strong>Veelgemaakte fout:</strong> de predatorpopulatie loopt <strong>achter</strong> op de prooipopulatie, niet gelijk op. Eerst stijgt de prooi, dán pas (met vertraging) de predator. Zet in een grafiek de pieken dus niet op dezelfde plek.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 1 — receptorspecificiteit</div><div class=\"sam-worked-q\">Een medicijn bezet de receptor voor een hormoon, maar geeft zelf geen respons. Wat is het effect op de cel, en hoe heet zo'n stof?</div><ol class=\"sam-worked-steps\"><li>Het hormoon kan niet meer aan de receptor binden — de plaats is bezet (sleutel–slot, D1).</li><li>Zonder binding van het hormoon komt de respons in de cel niet op gang.</li><li>Een stof die de receptor blokkeert zonder respons heet een <strong>remmer</strong> (antagonist).</li></ol><div class=\"sam-worked-ans\">✅ Het hormoonsignaal wordt geblokkeerd; de stof werkt als remmer/antagonist.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 2 — predator en prooi</div><div class=\"sam-worked-q\">In een gebied neemt eerst het aantal hazen sterk toe, en pas daarna het aantal vossen. Verklaar deze volgorde.</div><ol class=\"sam-worked-steps\"><li>Meer hazen betekent meer voedsel voor de vossen.</li><li>Door het ruime voedsel overleven meer jonge vossen en groeit de vossenpopulatie — maar dat kost tijd (draagtijd, opgroeien).</li><li>Daardoor stijgt het aantal vossen pas ná de piek van de hazen.</li></ol><div class=\"sam-worked-ans\">✅ De predator (vos) reageert met vertraging op de toename van de prooi (haas).</div></div>","vwo_bi_C":"<div class=\"sam-intro\"><strong>Zelforganisatie</strong> is het vermogen van een biologisch systeem om vanuit de delen zélf nieuwe, geordende structuren te vormen. Daarbij ontstaan op elk hoger niveau <strong>emergente eigenschappen</strong>: eigenschappen die de losse onderdelen niet hebben. Je bekijkt dit op drie schalen — de <strong>cel</strong>, het <strong>organisme</strong> en het <strong>ecosysteem</strong>.</div><div class=\"sam-head\">Wat je voor het examen moet kennen (syllabus)</div><p>Domein C bestaat uit drie subdomeinen. Deze samenvatting dekt ze alle drie:</p><table class=\"sam-table\"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>C1</td><td>Zelforganisatie van cellen</td><td>genexpressie, genregulatie, celdifferentiatie</td></tr><tr><td>C2</td><td>Zelforganisatie van het organisme</td><td>organisatieniveaus, weefsels, ontwikkeling</td></tr><tr><td>C3</td><td>Zelforganisatie van ecosystemen</td><td>voedselrelaties, kringlopen, successie</td></tr></tbody></table><div class=\"sam-head\">C1 · Zelforganisatie van cellen</div><p>Alle cellen van een organisme bevatten hetzelfde <strong>DNA</strong>, en tóch is een spiercel iets heel anders dan een zenuwcel. Dat komt doordat in elke cel <strong>andere genen aan- of uitstaan</strong>. Twee begrippen staan centraal: <strong>genexpressie</strong> en <strong>celdifferentiatie</strong>.</p><ul><li><strong>Genexpressie</strong>: het tot uiting komen van een gen doordat het wordt afgelezen tot eiwit (DNA → mRNA → eiwit; zie domein B1). Alleen een <em>afgelezen</em> gen bepaalt wat de cel doet.</li><li><strong>Genregulatie</strong>: mechanismen die bepalen wélke genen in een cel worden afgelezen. Regeleiwitten (transcriptiefactoren) kunnen een gen aan- of uitzetten; ook stoffen van buiten de cel sturen dit.</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 330 132\" role=\"img\" aria-label=\"Dezelfde stamcel vormt door verschillende genregulatie verschillende gespecialiseerde cellen\"><defs><marker id=\"giC1\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"10\" y=\"50\" width=\"80\" height=\"34\" rx=\"17\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"50\" y=\"65\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">stamcel</text><text x=\"50\" y=\"77\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">alle genen mogelijk</text><rect x=\"230\" y=\"10\" width=\"92\" height=\"30\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"276\" y=\"29\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">spiercel</text><rect x=\"230\" y=\"52\" width=\"92\" height=\"30\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"276\" y=\"71\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">zenuwcel</text><rect x=\"230\" y=\"94\" width=\"92\" height=\"30\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"276\" y=\"113\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">kliercel</text><path d=\"M90,63 C150,50 170,30 228,25\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC1)\"/><path d=\"M90,67 C150,67 170,67 228,67\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC1)\"/><path d=\"M90,71 C150,84 170,104 228,109\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC1)\"/><text x=\"158\" y=\"94\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">celdifferentiatie</text></svg><div class=\"sam-figcap\"><strong>Celdifferentiatie:</strong> een ongespecialiseerde <strong>stamcel</strong> vormt door verschillende genregulatie gespecialiseerde cellen. Elke cel heeft hetzelfde DNA, maar leest andere genen af.</div></div><ul><li><strong>Stamcellen</strong> zijn cellen die zich nog kunnen delen én differentiëren. <strong>Embryonale</strong> stamcellen kunnen elk celtype worden; <strong>adulte</strong> stamcellen (bv. in beenmerg) zijn beperkter.</li><li><strong>Emergente eigenschap</strong> op celniveau: uit de ordening van moleculen ontstaat een levende cel met eigenschappen (stofwisseling, deling) die losse moleculen niet hebben.</li></ul><div class=\"sam-tip\">Onthoud het onderscheid: <strong>differentiatie</strong> = specialiseren (welke genen aan/uit), <strong>deling</strong> = vermeerderen (mitose). Een cel doet vaak eerst het een, dan het ander.</div><div class=\"sam-head\">C2 · Zelforganisatie van het organisme</div><p>Cellen organiseren zich tot steeds grotere gehelen. Op elk niveau ontstaan nieuwe, <strong>emergente</strong> eigenschappen:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 92\" role=\"img\" aria-label=\"Organisatieniveaus van cel naar weefsel naar orgaan naar orgaanstelsel naar organisme\"><defs><marker id=\"giC2\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><g font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><rect x=\"6\" y=\"34\" width=\"52\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".12\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"32\" y=\"52\">cel</text><rect x=\"76\" y=\"34\" width=\"56\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"104\" y=\"52\">weefsel</text><rect x=\"150\" y=\"34\" width=\"56\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"178\" y=\"52\">orgaan</text><rect x=\"224\" y=\"30\" width=\"60\" height=\"38\" rx=\"5\" fill=\"var(--or)\" opacity=\".18\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"254\" y=\"46\">orgaan-</text><text x=\"254\" y=\"57\">stelsel</text><rect x=\"302\" y=\"34\" width=\"34\" height=\"30\" rx=\"5\" fill=\"var(--or)\" opacity=\".22\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"319\" y=\"49\">orga-</text><text x=\"319\" y=\"59\">nisme</text></g><line x1=\"58\" y1=\"49\" x2=\"74\" y2=\"49\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giC2)\"/><line x1=\"132\" y1=\"49\" x2=\"148\" y2=\"49\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giC2)\"/><line x1=\"206\" y1=\"49\" x2=\"222\" y2=\"49\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giC2)\"/><line x1=\"284\" y1=\"49\" x2=\"300\" y2=\"49\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giC2)\"/></svg><div class=\"sam-figcap\"><strong>Organisatieniveaus:</strong> gespecialiseerde cellen van dezelfde soort vormen samen een <strong>weefsel</strong>, weefsels een <strong>orgaan</strong>, organen een <strong>orgaanstelsel</strong> en die samen het <strong>organisme</strong>. Elk niveau heeft nieuwe eigenschappen.</div></div><table class=\"sam-table\"><thead><tr><th>Weefsels (voorbeelden)</th><th>Functie</th></tr></thead><tbody><tr><td>Dekweefsel (epitheel)</td><td>bedekt en beschermt oppervlakken, opname/afgifte</td></tr><tr><td>Bind- en steunweefsel</td><td>verbindt en ondersteunt (bv. bot, kraakbeen)</td></tr><tr><td>Spierweefsel</td><td>samentrekken → beweging</td></tr><tr><td>Zenuwweefsel</td><td>impulsen geleiden en verwerken</td></tr></tbody></table><p>Een organisme ontstaat door <strong>embryonale ontwikkeling</strong> uit één bevruchte eicel. Daarbij spelen samen:</p><ul><li><strong>Celdeling</strong> (mitose): meer cellen, met identiek DNA.</li><li><strong>Celdifferentiatie</strong>: cellen specialiseren (C1).</li><li><strong>Morfogenese</strong>: vormgeving — cellen komen op de juiste plaats en vormen de bouw van het lichaam.</li><li><strong>Inductie</strong>: cellen sturen elkaars ontwikkeling met signaalstoffen. <strong>Apoptose</strong> (geprogrammeerde celdood) verwijdert overtollige cellen (bv. tussen vingers).</li></ul><div class=\"sam-warn\"><strong>Let op het verschil:</strong> <strong>groei</strong> is toename van het aantal cellen of celgrootte; <strong>ontwikkeling</strong> is het ontstaan van vorm en specialisatie. Een organisme kan zich ontwikkelen zonder te groeien en omgekeerd.</div><div class=\"sam-head\">C3 · Zelforganisatie van ecosystemen</div><p>Ook boven het organisme gaat de ordening door. Een <strong>ecosysteem</strong> is een begrensd gebied met alle <strong>biotische</strong> factoren (het levende: planten, dieren, micro-organismen) en <strong>abiotische</strong> factoren (het niet-levende: licht, temperatuur, water, bodem) samen.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 96\" role=\"img\" aria-label=\"Organisatieniveaus in de ecologie van individu naar populatie naar levensgemeenschap naar ecosysteem\"><defs><marker id=\"giC3a\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><g font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><rect x=\"6\" y=\"34\" width=\"58\" height=\"30\" rx=\"5\" fill=\"var(--mu)\" opacity=\".1\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"35\" y=\"52\">individu</text><rect x=\"82\" y=\"34\" width=\"62\" height=\"30\" rx=\"5\" fill=\"var(--mu)\" opacity=\".13\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"113\" y=\"52\">populatie</text><rect x=\"162\" y=\"30\" width=\"70\" height=\"38\" rx=\"5\" fill=\"var(--mu)\" opacity=\".16\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"197\" y=\"46\">levens-</text><text x=\"197\" y=\"57\">gemeenschap</text><rect x=\"250\" y=\"30\" width=\"66\" height=\"38\" rx=\"5\" fill=\"var(--or)\" opacity=\".18\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"283\" y=\"46\">eco-</text><text x=\"283\" y=\"57\">systeem</text></g><line x1=\"64\" y1=\"49\" x2=\"80\" y2=\"49\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC3a)\"/><line x1=\"144\" y1=\"49\" x2=\"160\" y2=\"49\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC3a)\"/><line x1=\"232\" y1=\"49\" x2=\"248\" y2=\"49\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giC3a)\"/></svg><div class=\"sam-figcap\"><strong>Ecologische niveaus:</strong> individuen van één soort vormen een <strong>populatie</strong>, alle populaties samen de <strong>levensgemeenschap</strong>, en die met de abiotische omgeving het <strong>ecosysteem</strong>.</div></div><p>In een ecosysteem hangen soorten samen via <strong>voedselrelaties</strong>. De rollen:</p><ul><li><strong>Producenten</strong> (planten): leggen met fotosynthese energie vast — het begin van elke keten.</li><li><strong>Consumenten</strong> (dieren): eten andere organismen (herbivoor, carnivoor, omnivoor).</li><li><strong>Reducenten</strong> (bacteriën, schimmels): breken dood materiaal af tot mineralen die planten weer opnemen.</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 300 150\" role=\"img\" aria-label=\"Energiepiramide: van producenten naar toppredator neemt de beschikbare energie per niveau sterk af\"><g stroke=\"var(--or)\" stroke-width=\"1.2\"><polygon points=\"40,26 260,26 218,58 82,58\" fill=\"var(--or)\" opacity=\".28\"/><polygon points=\"82,62 218,62 190,94 110,94\" fill=\"var(--or)\" opacity=\".2\"/><polygon points=\"110,98 190,98 168,130 132,130\" fill=\"var(--or)\" opacity=\".13\"/></g><g font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"150\" y=\"46\">producenten</text><text x=\"150\" y=\"82\">herbivoren</text><text x=\"150\" y=\"118\">carnivoren</text></g><text x=\"286\" y=\"30\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"end\">veel energie</text><text x=\"286\" y=\"132\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"end\">weinig energie</text></svg><div class=\"sam-figcap\"><strong>Energiepiramide:</strong> per trofisch niveau gaat ± 90% van de energie verloren (vooral als warmte bij dissimilatie). Daardoor is er steeds minder energie en zijn er weinig toppredatoren.</div></div><p>Stoffen daarentegen gaan <strong>rond</strong> in <strong>kringlopen</strong> — ze raken niet op. Ken de <strong>koolstofkringloop</strong> (CO₂ ↔ organische stof via fotosynthese en verbranding/dissimilatie) en de <strong>stikstofkringloop</strong> (bacteriën zetten stikstof om in opneembare vorm en weer terug).</p><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Successie</td><td>geleidelijke verandering van levensgemeenschap: van <strong>pioniers</strong> naar een stabiel <strong>climaxstadium</strong></td></tr><tr><td>Draagkracht</td><td>maximale populatiegrootte die een gebied blijvend kan onderhouden</td></tr><tr><td>Dynamisch evenwicht</td><td>aantallen schommelen rond een gemiddelde; het systeem herstelt zich na een verstoring</td></tr><tr><td>Biodiversiteit</td><td>de soortenrijkdom; meer diversiteit → stabieler ecosysteem</td></tr></tbody></table><div class=\"sam-tip\">Rode draad door het hele domein: <strong>energie stroomt (eenrichting, gaat verloren als warmte), stoffen gaan rond (kringloop).</strong> Verwar deze twee nooit in een examenvraag.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 1 — genregulatie</div><div class=\"sam-worked-q\">Een spiercel en een zenuwcel uit hetzelfde lichaam bevatten precies hetzelfde DNA. Leg uit hoe ze tóch verschillende eiwitten kunnen bevatten.</div><ol class=\"sam-worked-steps\"><li>Alle lichaamscellen ontstaan door mitose uit één cel en hebben dus identiek DNA.</li><li>Door <strong>genregulatie</strong> staan in elke cel andere genen aan of uit.</li><li>Alleen de afgelezen (tot expressie gebrachte) genen leveren eiwit; daardoor verschilt de eiwitinhoud.</li></ol><div class=\"sam-worked-ans\">✅ Niet het DNA verschilt, maar wélke genen tot expressie komen (genregulatie → celdifferentiatie).</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 2 — energie in een keten</div><div class=\"sam-worked-q\">In een keten gras → konijn → vos is er per niveau steeds minder biomassa en energie. Geef de biologische verklaring.</div><ol class=\"sam-worked-steps\"><li>Elk organisme gebruikt het grootste deel van de opgenomen energie zelf voor stofwisseling (dissimilatie); die energie verdwijnt als warmte.</li><li>Slechts ± 10% wordt vastgelegd in nieuwe biomassa en is beschikbaar voor het volgende niveau.</li><li>Daardoor daalt de energie (en biomassa) sterk per trofisch niveau — de energiepiramide.</li></ol><div class=\"sam-worked-ans\">✅ Energieverlies als warmte bij elke stap; energie stroomt in één richting en gaat niet rond.</div></div>","vwo_ec_H":"<div class=\"sam-intro\">Hoe rijk is een land, en hoe eerlijk is die rijkdom verdeeld? Dit domein gaat over <strong>welvaart</strong> en het <strong>bbp</strong>, over <strong>economische groei</strong>, over de <strong>inkomensverdeling</strong> en over de winst van <strong>internationale handel</strong>.</div><div class=\"sam-head\">Welvaart en het bbp</div><p>Het <strong>bruto binnenlands product</strong> (bbp) is de totale waarde van alle in een land geproduceerde goederen en diensten. Het is een maat voor welvaart <em>in enge zin</em>, maar zegt niets over milieu, vrije tijd of geluk (welvaart in ruime zin).</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Reële economische groei</div><div class=\"sam-formula-eq\">reële groei ≈ nominale bbp-groei − inflatie</div><div class=\"sam-formula-note\">Reële groei corrigeert voor prijsstijging en meet dus of er écht meer geproduceerd wordt, niet alleen duurder.</div></div><div class=\"sam-head\">Inkomensverdeling: de Lorenzcurve</div><p>De <strong>Lorenzcurve</strong> toont hoe scheef de inkomens verdeeld zijn. Hij zet het cumulatieve inkomensaandeel uit tegen het cumulatieve bevolkingsaandeel. Hoe verder de curve van de diagonaal (volledige gelijkheid) af buigt, hoe schever de verdeling.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 172\" role=\"img\" aria-label=\"Lorenzcurve die de scheefheid van de inkomensverdeling toont ten opzichte van de lijn van volledige gelijkheid\"><defs><marker id=\"ecHa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"312\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecHa)\"/><line x1=\"44\" y1=\"158\" x2=\"44\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecHa)\"/><line x1=\"44\" y1=\"150\" x2=\"294\" y2=\"40\" stroke=\"var(--mu)\" stroke-width=\"1.4\" stroke-dasharray=\"4 3\"/><path d=\"M44.0,150.0 L100.3,146.4 L144.0,136.6 L181.5,122.2 L212.8,105.5 L244.0,84.2 L269.0,63.7 L294.0,40.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><text x=\"150\" y=\"90\" font-size=\"9\" font-weight=\"700\" fill=\"var(--mu)\" transform=\"rotate(-24,150,90)\">volledige gelijkheid</text><text x=\"210\" y=\"132\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">Lorenzcurve</text><text x=\"150\" y=\"167\" font-size=\"8\" fill=\"var(--mu)\">% bevolking</text><text x=\"10\" y=\"36\" font-size=\"8\" fill=\"var(--mu)\">% inkomen</text></svg><div class=\"sam-figcap\"><strong>Lorenzcurve:</strong> bij volledige gelijkheid valt de curve samen met de diagonaal. Hoe boller de curve, hoe ongelijker: de armste 60% krijgt hier maar een klein deel van het inkomen.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Gini-coëfficiënt</div><div class=\"sam-formula-eq\">0 = volledige gelijkheid  ·  1 = volledige ongelijkheid</div><div class=\"sam-formula-note\">De gini-coëfficiënt vat de scheefheid samen in één getal (het oppervlak tussen de diagonaal en de Lorenzcurve). Hoger = ongelijker.</div></div><div class=\"sam-head\">Internationale handel</div><p>Landen handelen op basis van <strong>comparatieve voordelen</strong>: specialiseren en ruilen vergroot de totale welvaart. <strong>Protectie</strong> (invoerheffingen, quota) beschermt eigen bedrijven, maar maakt producten duurder en remt de wereldwelvaart.</p><div class=\"sam-tip\">Het bbp per hoofd van de bevolking maakt landen vergelijkbaar, maar verbergt de <strong>verdeling</strong>: twee landen met hetzelfde gemiddelde kunnen een heel verschillende Lorenzcurve hebben.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Het nominale bbp groeit met 4%, de inflatie is 1,5%. Hoe groot is de reële groei bij benadering?</div><ol class=\"sam-worked-steps\"><li>Reële groei ≈ nominale groei − inflatie.</li><li>≈ 4% − 1,5%.</li><li>≈ 2,5%.</li></ol><div class=\"sam-worked-ans\">✅ De reële economische groei is ongeveer 2,5% — er wordt écht meer geproduceerd.</div></div></div>","vwo_na_E":"<div class=\"sam-intro\">Instabiele atoomkernen zenden <strong>ioniserende straling</strong> uit. Je onderscheidt <strong>α-, β- en γ-straling</strong>, rekent met de <strong>halveringstijd</strong> van het verval, en beoordeelt de <strong>dosis</strong> en de bescherming tegen straling.</div><div class=\"sam-head\">Soorten ioniserende straling</div><p><strong>Ioniserende straling</strong> heeft genoeg energie om elektronen los te maken. De drie hoofdsoorten verschillen sterk in doordringend vermogen.</p><table class=\"sam-table\"><thead><tr><th>Type</th><th>Wat</th><th>Doordringend vermogen</th></tr></thead><tbody><tr><td>α (alfa)</td><td>heliumkern (2p + 2n)</td><td>klein — papier stopt het</td></tr><tr><td>β (bèta)</td><td>elektron</td><td>gemiddeld — aluminium</td></tr><tr><td>γ (gamma)</td><td>elektromagnetische straling</td><td>groot — dik lood/beton</td></tr></tbody></table><div class=\"sam-head\">Radioactief verval en halveringstijd</div><p>Bij <strong>radioactief verval</strong> vervalt een instabiele kern tot een stabielere. Hoe lang dat duurt, druk je uit in de <strong>halveringstijd</strong>: de tijd waarin de helft van de kernen vervalt.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Vervalkromme: het aantal kernen halveert elke halveringstijd\"><defs><marker id=\"naEa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#naEa)\"/><line x1=\"44\" y1=\"158\" x2=\"44\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#naEa)\"/><path d=\"M44.0,40.0 L61.3,57.5 L78.5,72.2 L95.8,84.6 L113.0,95.0 L130.3,103.8 L147.5,111.1 L164.8,117.3 L182.0,122.5 L199.3,126.9 L216.5,130.6 L233.8,133.6 L251.0,136.3 L268.3,138.4 L285.5,140.3 L302.8,141.8 L320.0,143.1\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><line x1=\"44\" y1=\"95\" x2=\"113\" y2=\"95\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"113\" y1=\"95\" x2=\"113\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"182\" y1=\"122.5\" x2=\"182\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><text x=\"30\" y=\"98\" font-size=\"8\" fill=\"var(--mu)\">½N₀</text><text x=\"30\" y=\"44\" font-size=\"8\" fill=\"var(--mu)\">N₀</text><text x=\"106\" y=\"164\" font-size=\"8\" fill=\"var(--mu)\">t½</text><text x=\"172\" y=\"164\" font-size=\"8\" fill=\"var(--mu)\">2·t½</text></svg><div class=\"sam-figcap\"><strong>Vervalkromme:</strong> na één halveringstijd (t½) is de helft over, na twee halveringstijden een kwart, enzovoort. De curve is exponentieel en bereikt nooit precies nul.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Aantal kernen na verval</div><div class=\"sam-formula-eq\">N = N₀ · (½)<sup>t / t½</sup></div><div class=\"sam-formula-note\">N₀ het beginaantal, t½ de halveringstijd. De activiteit (verval per seconde, in becquerel) daalt op precies dezelfde manier.</div></div><div class=\"sam-head\">Kernreacties</div><p>Bij verval en kernreacties gelden <strong>behoudswetten</strong>: het totale aantal nucleonen (massagetal) en de totale lading (atoomnummer) blijven behouden. Zo bepaal je welke kern ontstaat.</p><div class=\"sam-head\">Dosis en bescherming</div><p>De schadelijkheid hangt af van de opgenomen <strong>dosis</strong> (in gray/sievert). Bescherming rust op drie pijlers:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Beschermingsmaatregelen</div><ul><li>afstand houden (intensiteit daalt kwadratisch)</li><li>afscherming (lood, beton)</li><li>blootstellingstijd beperken</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Toepassingen</div><ul><li>medische beeldvorming en bestraling</li><li>ouderdomsbepaling (C-14)</li><li>energie (kernsplitsing)</li></ul></div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een bron heeft een halveringstijd van 8 dagen. Welk deel is na 24 dagen nog over?</div><ol class=\"sam-worked-steps\"><li>24 dagen = 24/8 = 3 halveringstijden.</li><li>N = N₀·(½)³ = N₀·⅛.</li></ol><div class=\"sam-worked-ans\">✅ Na 24 dagen is nog ⅛ (12,5%) van de kernen over.</div></div></div>","vwo_ec_C":"<div class=\"sam-intro\">Waarom ruilen mensen en landen? Omdat <strong>ruil</strong> iedereen beter af kan maken. Door je te specialiseren in wat je <em>relatief</em> het beste kunt (je <strong>comparatieve voordeel</strong>) en de rest te ruilen, stijgt de totale welvaart. <strong>Geld</strong> maakt die ruil soepel.</div><div class=\"sam-head\">Arbeidsverdeling en specialisatie</div><p>Als iedereen alles zelf zou maken, is de productie laag. Door <strong>arbeidsverdeling</strong> — ieder doet waar hij goed in is — stijgt de productiviteit enorm. De keerzijde is <strong>afhankelijkheid</strong>: je hebt anderen nodig voor de rest.</p><div class=\"sam-head\">Comparatief voordeel</div><p>Je hebt een <strong>comparatief voordeel</strong> in het goed dat je met de <em>laagste opofferingskosten</em> maakt — ook als iemand anders in álles absoluut beter is. Beide partijen winnen door zich te specialiseren in hun comparatieve voordeel en te ruilen.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 150\" role=\"img\" aria-label=\"Twee landen specialiseren zich en ruilen: land 1 levert graan, land 2 levert wijn\"><rect x=\"14\" y=\"45\" width=\"80\" height=\"46\" rx=\"8\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"54\" y=\"66\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Land 1</text><text x=\"54\" y=\"80\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">graan</text><rect x=\"206\" y=\"45\" width=\"80\" height=\"46\" rx=\"8\" fill=\"var(--or)\" opacity=\".13\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"246\" y=\"66\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Land 2</text><text x=\"246\" y=\"80\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">wijn</text><defs><marker id=\"ecCa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><path d=\"M96,58 C140,40 160,40 204,58\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\" marker-end=\"url(#ecCa)\"/><text x=\"150\" y=\"36\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">graan →</text><path d=\"M204,80 C160,98 140,98 96,80\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\" marker-end=\"url(#ecCa)\"/><text x=\"150\" y=\"108\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">← wijn</text></svg><div class=\"sam-figcap\"><strong>Specialiseren en ruilen:</strong> elk land maakt waar het een comparatief voordeel heeft en ruilt het overschot. Samen produceren en consumeren ze méér dan zonder ruil.</div></div><div class=\"sam-head\">De rol van geld</div><p>Zonder geld heb je <strong>ruil in natura</strong> nodig, wat een 'dubbele samenloop van behoeften' vereist (jij wilt wat de ander heeft én andersom). <strong>Geld</strong> lost dat op en heeft drie functies:</p><table class=\"sam-table\"><thead><tr><th>Functie van geld</th><th>Betekenis</th></tr></thead><tbody><tr><td>Ruilmiddel</td><td>algemeen geaccepteerd bij transacties</td></tr><tr><td>Rekenmiddel</td><td>maakt prijzen vergelijkbaar</td></tr><tr><td>Oppotmiddel</td><td>waarde bewaren voor later</td></tr></tbody></table><div class=\"sam-warn\"><strong>Absoluut ≠ comparatief voordeel:</strong> ook een land dat álles efficiënter maakt (absoluut voordeel) wint bij ruil, zolang het zich richt op het goed met de laagste opofferingskosten.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Anna maakt in een uur 10 broden óf 5 taarten; Ben 4 broden óf 4 taarten. Wie heeft het comparatieve voordeel in taarten?</div><ol class=\"sam-worked-steps\"><li>Anna's opofferingskost per taart = 10/5 = 2 broden.</li><li>Ben's opofferingskost per taart = 4/4 = 1 brood.</li><li>Ben geeft minder broden op per taart.</li></ol><div class=\"sam-worked-ans\">✅ Ben heeft het comparatieve voordeel in taarten (laagste opofferingskosten), Anna in brood.</div></div></div>","vwo_ec_B":"<div class=\"sam-intro\">Economie begint bij één onvermijdelijke waarheid: <strong>schaarste</strong>. Behoeften zijn onbeperkt, maar middelen niet. Daardoor moet je <strong>keuzes</strong> maken, en elke keuze kost je het beste alternatief: de <strong>opofferingskosten</strong>.</div><div class=\"sam-head\">Behoeften, middelen en keuzes</div><p><strong>Schaarste</strong> betekent dat er niet genoeg middelen zijn om alle behoeften te vervullen. Je moet dus kiezen. De waarde van het <strong>beste alternatief</strong> dat je opgeeft, heet de <strong>opofferingskosten</strong> (alternatieve kosten).</p><div class=\"sam-head\">De productiemogelijkhedencurve</div><p>De <strong>productiemogelijkhedencurve</strong> (PMC) toont alle combinaties van twee goederen die je met je middelen <em>maximaal</em> kunt maken. Meer van het ene goed betekent minder van het andere — dat is de opofferingskost, zichtbaar als de helling.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 172\" role=\"img\" aria-label=\"Productiemogelijkhedencurve met een punt binnen, op en buiten de grens\"><defs><marker id=\"ecBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"312\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecBa)\"/><line x1=\"44\" y1=\"158\" x2=\"44\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecBa)\"/><path d=\"M44,45 L84.0,46.3 L123.1,50.1 L160.2,56.4 L194.5,65.1 L225.0,75.8 L251.1,88.3 L272.1,102.3 L287.5,117.6 L296.8,133.6 L300.0,150.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><circle cx=\"120\" cy=\"120\" r=\"4\" fill=\"var(--mu)\"/><text x=\"98\" y=\"118\" font-size=\"9\" fill=\"var(--mu)\">C</text><text x=\"90\" y=\"132\" font-size=\"7\" fill=\"var(--mu)\">onbenut</text><circle cx=\"194.5\" cy=\"65.1\" r=\"4\" fill=\"var(--dk)\"/><text x=\"200\" y=\"62\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\">A</text><text x=\"200\" y=\"72\" font-size=\"7\" fill=\"var(--mu)\">efficiënt</text><circle cx=\"255\" cy=\"55\" r=\"4\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.5\" stroke-dasharray=\"2 2\"/><text x=\"260\" y=\"52\" font-size=\"9\" fill=\"var(--mu)\">B</text><text x=\"258\" y=\"62\" font-size=\"7\" fill=\"var(--mu)\">onhaalbaar</text><text x=\"150\" y=\"167\" font-size=\"8.5\" fill=\"var(--mu)\">goed X</text><text x=\"8\" y=\"34\" font-size=\"8.5\" fill=\"var(--mu)\">goed Y</text></svg><div class=\"sam-figcap\"><strong>Productiemogelijkhedencurve:</strong> punt A ligt op de grens (efficiënt), C erbinnen (middelen onbenut), B erbuiten (onhaalbaar met de huidige middelen). Verschuiven langs de curve kost altijd wat van het andere goed.</div></div><div class=\"sam-head\">Productiefactoren</div><p>Om te produceren zijn <strong>productiefactoren</strong> nodig. Elke factor levert een eigen inkomen op:</p><table class=\"sam-table\"><thead><tr><th>Productiefactor</th><th>Beloning</th></tr></thead><tbody><tr><td>Arbeid</td><td>loon</td></tr><tr><td>Kapitaal</td><td>rente/winst</td></tr><tr><td>Natuur (grond)</td><td>pacht/huur</td></tr><tr><td>Ondernemerschap</td><td>winst</td></tr></tbody></table><div class=\"sam-tip\">De PMC wijst naar buiten (economische groei) als er méér of betere productiefactoren komen, bijvoorbeeld door technologische vooruitgang of een groeiende beroepsbevolking.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een land besteedt meer middelen aan wapens en minder aan voedsel. Wat zijn de opofferingskosten?</div><ol class=\"sam-worked-steps\"><li>Middelen zijn schaars, dus meer wapens kan alleen ten koste van iets anders.</li><li>Het opgeofferde alternatief is de misgelopen voedselproductie.</li></ol><div class=\"sam-worked-ans\">✅ De opofferingskosten van de extra wapens zijn de hoeveelheid voedsel die niet meer geproduceerd wordt.</div></div></div>","vwo_ec_G":"<div class=\"sam-intro\">Niet iedereen weet evenveel, en de toekomst is onzeker. Dit domein gaat over <strong>risico</strong> (verzekeren en risico delen) en <strong>asymmetrische informatie</strong>: wat er misgaat als de ene partij meer weet dan de andere.</div><div class=\"sam-head\">Risico delen: verzekeren</div><p>Bij een <strong>verzekering</strong> betalen veel mensen een kleine <strong>premie</strong> in een gezamenlijke pot. De ongelukkige enkeling die schade lijdt, krijgt een <strong>uitkering</strong>. Zo wordt een groot, onzeker risico omgezet in een kleine, zekere kostenpost.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 180\" role=\"img\" aria-label=\"Verzekering: veel mensen betalen premie in een pot, een enkeling krijgt een uitkering\"><defs><marker id=\"ecGa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><g fill=\"var(--mu)\"><circle cx=\"30\" cy=\"30\" r=\"8\"/><circle cx=\"30\" cy=\"60\" r=\"8\"/><circle cx=\"30\" cy=\"90\" r=\"8\"/><circle cx=\"30\" cy=\"120\" r=\"8\"/><circle cx=\"30\" cy=\"150\" r=\"8\"/></g><text x=\"30\" y=\"172\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">premies</text><g stroke=\"var(--or)\" stroke-width=\"1.5\" fill=\"none\"><line x1=\"42\" y1=\"34\" x2=\"118\" y2=\"80\" marker-end=\"url(#ecGa)\"/><line x1=\"42\" y1=\"60\" x2=\"118\" y2=\"84\" marker-end=\"url(#ecGa)\"/><line x1=\"42\" y1=\"90\" x2=\"118\" y2=\"90\" marker-end=\"url(#ecGa)\"/><line x1=\"42\" y1=\"120\" x2=\"118\" y2=\"96\" marker-end=\"url(#ecGa)\"/><line x1=\"42\" y1=\"146\" x2=\"118\" y2=\"100\" marker-end=\"url(#ecGa)\"/></g><circle cx=\"150\" cy=\"90\" r=\"34\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.5\"/><text x=\"150\" y=\"88\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">pot</text><text x=\"150\" y=\"100\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">verzekeraar</text><line x1=\"184\" y1=\"90\" x2=\"248\" y2=\"90\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#ecGa)\"/><circle cx=\"270\" cy=\"90\" r=\"11\" fill=\"var(--dk)\"/><text x=\"270\" y=\"93\" font-size=\"8\" fill=\"#fff\" text-anchor=\"middle\">💥</text><text x=\"270\" y=\"118\" font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\">uitkering</text></svg><div class=\"sam-figcap\"><strong>Risicopooling:</strong> velen betalen een kleine premie; de enkeling met schade krijgt een grote uitkering. Het risico wordt over de hele groep gespreid.</div></div><div class=\"sam-head\">Asymmetrische informatie</div><p>Er is <strong>asymmetrische informatie</strong> als de ene partij meer weet dan de andere. Dat leidt tot twee klassieke problemen:</p><table class=\"sam-table\"><thead><tr><th>Probleem</th><th>Wanneer</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Averechtse selectie</td><td>vóór de transactie</td><td>vooral zieke mensen sluiten een zorgverzekering</td></tr><tr><td>Moreel wangedrag</td><td>ná de transactie</td><td>wie verzekerd is, gaat roekelozer om met risico</td></tr></tbody></table><div class=\"sam-head\">Oplossingen</div><p>Partijen proberen de informatiekloof te dichten met <strong>signalen</strong> (diploma, keurmerk), <strong>screening</strong> (medische keuring), <strong>eigen risico</strong> en <strong>verplichte deelname</strong> (zodat niet alleen de slechte risico's meedoen).</p><div class=\"sam-warn\"><strong>Averechtse selectie ≠ moreel wangedrag:</strong> averechtse selectie speelt vóór het contract (wie doet mee?), moreel wangedrag erna (hoe gedraag je je met een verzekering?).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom stellen zorgverzekeraars een verplichte basisverzekering en een eigen risico in?</div><ol class=\"sam-worked-steps\"><li>Verplichte deelname voorkomt <strong>averechtse selectie</strong>: ook gezonde mensen betalen mee, dus de pot blijft betaalbaar.</li><li>Een eigen risico remt <strong>moreel wangedrag</strong>: je betaalt de eerste kosten zelf en gaat bewuster met zorg om.</li></ol><div class=\"sam-worked-ans\">✅ Beide maatregelen bestrijden een probleem van asymmetrische informatie.</div></div></div>","vwo_ec_F":"<div class=\"sam-intro\">Mensen en bedrijven zijn vaak beter af als ze <strong>samenwerken</strong>, maar individueel eigenbelang staat dat in de weg. Met <strong>speltheorie</strong> analyseer je die spanning; <strong>collectieve actie</strong> en <strong>cao's</strong> laten zien hoe partijen hun onderhandelingsmacht bundelen.</div><div class=\"sam-head\">Speltheorie: het gevangenendilemma</div><p>In een <strong>gevangenendilemma</strong> kiezen twee spelers los van elkaar. Wat individueel het slimst lijkt (verraden), pakt samen slechter uit dan wederzijds samenwerken. De <strong>dominante strategie</strong> leidt tot een slechter <strong>evenwicht</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Uitbetalingsmatrix van het gevangenendilemma met de straffen voor twee spelers\"><text x=\"150\" y=\"16\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Speler B</text><text x=\"118\" y=\"42\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">zwijgt</text><text x=\"188\" y=\"42\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">verraadt</text><text x=\"18\" y=\"88\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\" transform=\"rotate(-90,18,88)\">zwijgt</text><text x=\"18\" y=\"152\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\" transform=\"rotate(-90,18,152)\">verraadt</text><text x=\"8\" y=\"120\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" transform=\"rotate(-90,8,120)\">Speler A</text><g stroke=\"var(--mu)\" stroke-width=\"1.5\" fill=\"none\"><rect x=\"90\" y=\"50\" width=\"180\" height=\"120\"/><line x1=\"180\" y1=\"50\" x2=\"180\" y2=\"170\"/><line x1=\"90\" y1=\"110\" x2=\"270\" y2=\"110\"/></g><text x=\"135\" y=\"85\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">−1 / −1</text><text x=\"135\" y=\"98\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">beiden kort</text><text x=\"225\" y=\"85\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">−10 / 0</text><text x=\"225\" y=\"98\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">A de dupe</text><text x=\"135\" y=\"145\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">0 / −10</text><text x=\"135\" y=\"158\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">B de dupe</text><text x=\"225\" y=\"145\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">−5 / −5</text><text x=\"225\" y=\"158\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">evenwicht</text></svg><div class=\"sam-figcap\"><strong>Gevangenendilemma:</strong> de getallen zijn de straffen (A / B) in jaren. Verraden is voor beiden de dominante strategie, dus ze belanden in −5/−5 — terwijl samen zwijgen (−1/−1) beter was.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Dominante strategie en evenwicht</div><div class=\"sam-formula-eq\">dominant = beste keuze, wat de ander ook doet</div><div class=\"sam-formula-note\">Een <strong>Nash-evenwicht</strong> is een situatie waarin geen speler er alleen op vooruitgaat door van strategie te wisselen. In het dilemma is dat het slechtere 'verraden/verraden'.</div></div><div class=\"sam-head\">Collectieve actie</div><p>Bij een <strong>collectief goed</strong> (zoals schone lucht of een staking) profiteert iedereen, ook wie niet meebetaalt: het <strong>meelifterprobleem</strong> (free-riding). Daardoor komt vrijwillige samenwerking moeilijk tot stand en is soms dwang of coördinatie nodig.</p><div class=\"sam-head\">Onderhandelen: vakbonden en cao</div><p>Werknemers vergroten hun <strong>onderhandelingsmacht</strong> door zich te verenigen in een <strong>vakbond</strong>. Samen met werkgevers sluiten ze een <strong>cao</strong> (collectieve arbeidsovereenkomst) over loon en arbeidsvoorwaarden.</p><div class=\"sam-tip\">Hoe geloofwaardiger je dreigement (bijv. een staking die je écht kunt volhouden), hoe sterker je onderhandelingspositie.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom leidt het gevangenendilemma tot een slechter resultaat dan mogelijk was?</div><ol class=\"sam-worked-steps\"><li>Verraden is voor elke speler individueel de beste keuze (dominante strategie).</li><li>Omdat beiden zo redeneren, verraden ze allebei.</li><li>Het resultaat (−5/−5) is slechter dan wederzijds zwijgen (−1/−1).</li></ol><div class=\"sam-worked-ans\">✅ Rationeel eigenbelang leidt hier tot een collectief slechtere uitkomst — vandaar het belang van afspraken.</div></div></div>","vwo_ec_E":"<div class=\"sam-intro\">Geld nu is meer waard dan geld later. Het concept <strong>ruilen over de tijd</strong> gaat over <strong>sparen</strong>, <strong>lenen</strong> en <strong>rente</strong>: hoe je consumptie verschuift tussen heden en toekomst, en hoe <strong>inflatie</strong> de koopkracht van geld uitholt.</div><div class=\"sam-head\">Sparen, lenen en rente</div><p>Wie <strong>spaart</strong> stelt consumptie uit en krijgt daarvoor <strong>rente</strong> als beloning. Wie <strong>leent</strong> haalt consumptie naar voren en betaalt rente als prijs. De rente is dus de prijs van geld over tijd.</p><div class=\"sam-head\">Samengestelde rente</div><p>Bij <strong>samengestelde rente</strong> krijg je rente over je rente: het bedrag groeit <strong>exponentieel</strong>, veel sneller dan bij enkelvoudige (lineaire) rente.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Groei van een spaarbedrag: samengestelde rente stijgt exponentieel, enkelvoudige rente lineair\"><defs><marker id=\"ecEa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecEa)\"/><line x1=\"44\" y1=\"158\" x2=\"44\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecEa)\"/><path d=\"M44.0,150.0 L55.0,148.1 L88.2,142.3 L143.4,132.8 L198.6,123.2 L253.8,113.6 L320.0,102.2\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"2\" stroke-dasharray=\"5 3\"/><path d=\"M44.0,150.0 L66.1,146.1 L110.2,136.7 L154.4,124.8 L198.6,109.8 L242.7,90.9 L286.9,67.0 L320.0,45.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><text x=\"250\" y=\"60\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">samengesteld</text><text x=\"250\" y=\"112\" font-size=\"9\" font-weight=\"700\" fill=\"var(--mu)\">enkelvoudig</text><text x=\"180\" y=\"166\" font-size=\"8.5\" fill=\"var(--mu)\">tijd (jaren)</text><text x=\"10\" y=\"30\" font-size=\"8.5\" fill=\"var(--mu)\">waarde</text></svg><div class=\"sam-figcap\"><strong>Rente op rente:</strong> bij samengestelde rente (oranje) groeit het spaarbedrag exponentieel; bij enkelvoudige rente (stippellijn) alleen lineair. Op lange termijn is het verschil enorm.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Eindwaarde bij samengestelde rente</div><div class=\"sam-formula-eq\">E = B · (1 + r)<sup>n</sup></div><div class=\"sam-formula-note\">E de eindwaarde, B het beginbedrag, r de rente (als decimaal), n het aantal jaren. Andersom bereken je de <strong>contante waarde</strong>: B = E / (1 + r)ⁿ.</div></div><div class=\"sam-head\">Contante waarde</div><p>De <strong>contante waarde</strong> is wat een toekomstig bedrag <em>nu</em> waard is. Hiermee vergelijk je bedragen op verschillende momenten eerlijk — onmisbaar bij investeringsbeslissingen.</p><div class=\"sam-head\">Inflatie en koopkracht</div><p><strong>Inflatie</strong> is een stijging van het algemene prijspeil: voor hetzelfde geld koop je minder. De <strong>reële</strong> rente corrigeert de nominale rente voor inflatie.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Reële rente</div><div class=\"sam-formula-eq\">reële rente ≈ nominale rente − inflatie</div><div class=\"sam-formula-note\">Is de inflatie hoger dan je spaarrente, dan daalt je koopkracht ondanks de rente: je reële rente is negatief.</div></div><div class=\"sam-warn\"><strong>Let op:</strong> sparen bij 2% rente terwijl de inflatie 3% is, betekent dat je geld reëel <em>minder</em> waard wordt. Nominale groei ≠ koopkrachtgroei.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Je zet €1.000 vast tegen 5% samengestelde rente. Hoeveel staat er na 2 jaar?</div><ol class=\"sam-worked-steps\"><li>E = B·(1+r)ⁿ = 1000 · (1,05)².</li><li>= 1000 · 1,1025.</li><li>= €1.102,50.</li></ol><div class=\"sam-worked-ans\">✅ €1.102,50 — de €2,50 boven €1.100 is de rente-over-rente.</div></div></div>","vwo_in_B":"<div class=\"sam-intro\">Onder elke app zit hardware en software: computers werken met <strong>binaire</strong> getallen en <strong>Booleaanse logica</strong>, een <strong>besturingssysteem</strong> beheert de bronnen, en <strong>netwerken</strong> koppelen alles via afgesproken protocollen. Data bescherm je met <strong>encryptie</strong>.</div><div class=\"sam-head\">Digitale representatie</div><p>Een computer kent maar twee toestanden: 0 en 1 (een <strong>bit</strong>). Alle data — getallen, tekst, beeld — wordt <strong>binair</strong> opgeslagen. Acht bits vormen een <strong>byte</strong>.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Binair naar decimaal</div><div class=\"sam-formula-eq\">1011₂ = 1·8 + 0·4 + 1·2 + 1·1 = 11</div><div class=\"sam-formula-note\">Elke positie is een macht van 2 (…, 8, 4, 2, 1). Hexadecimaal (grondtal 16) kort binair af: 4 bits = 1 hex-cijfer.</div></div><div class=\"sam-head\">Booleaanse logica</div><p>Digitale schakelingen rekenen met <strong>logische poorten</strong> die 0/1 (onwaar/waar) combineren.</p><table class=\"sam-table\"><thead><tr><th>Poort</th><th>Waar als…</th></tr></thead><tbody><tr><td>AND</td><td>beide ingangen 1 zijn</td></tr><tr><td>OR</td><td>minstens één ingang 1 is</td></tr><tr><td>NOT</td><td>de ingang 0 is (keert om)</td></tr></tbody></table><div class=\"sam-head\">Computernetwerken</div><p>Apparaten communiceren via het internet volgens het <strong>TCP/IP</strong>-protocol. <strong>DNS</strong> vertaalt een domeinnaam (slagio.nl) naar een IP-adres; een <strong>server</strong> stuurt de gevraagde gegevens terug naar de <strong>client</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 130\" role=\"img\" aria-label=\"Netwerkschema waarin een client via een router en het internet een server bereikt\"><defs><marker id=\"inBa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"12\" y=\"48\" width=\"52\" height=\"34\" rx=\"4\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"38\" y=\"62\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">client</text><text x=\"38\" y=\"74\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">browser</text><ellipse cx=\"150\" cy=\"65\" rx=\"42\" ry=\"26\" fill=\"var(--or)\" opacity=\".12\" stroke=\"var(--or)\" stroke-width=\"1.3\" stroke-dasharray=\"4 3\"/><text x=\"150\" y=\"62\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">internet</text><text x=\"150\" y=\"74\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">TCP/IP · DNS</text><rect x=\"236\" y=\"48\" width=\"52\" height=\"34\" rx=\"4\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"262\" y=\"62\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">server</text><text x=\"262\" y=\"74\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">website</text><line x1=\"65\" y1=\"60\" x2=\"106\" y2=\"60\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#inBa)\"/><line x1=\"194\" y1=\"70\" x2=\"235\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#inBa)\"/><text x=\"80\" y=\"53\" font-size=\"7\" fill=\"var(--or)\">verzoek</text><text x=\"205\" y=\"63\" font-size=\"7\" fill=\"var(--or)\">data</text></svg><div class=\"sam-figcap\"><strong>Client-server:</strong> de client stuurt een verzoek via het internet (waar DNS de naam naar een IP-adres vertaalt); de server stuurt de gevraagde data terug.</div></div><div class=\"sam-head\">Beveiliging en databases</div><p>Gevoelige data wordt <strong>versleuteld</strong> (encryptie): alleen met de juiste sleutel lees je het bericht. <strong>Hashing</strong> maakt een onomkeerbare 'vingerafdruk' (bijv. van wachtwoorden). Gestructureerde gegevens sla je op in een <strong>database</strong>, die je bevraagt met <strong>SQL</strong>.</p><div class=\"sam-tip\"><strong>Hashing ≠ encryptie:</strong> encryptie is met de sleutel terug te draaien, hashing niet. Daarom bewaar je wachtwoorden gehasht, niet versleuteld.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Zet het binaire getal 1101 om naar decimaal.</div><ol class=\"sam-worked-steps\"><li>Posities (macht van 2): 8, 4, 2, 1.</li><li>1·8 + 1·4 + 0·2 + 1·1.</li><li>= 8 + 4 + 0 + 1 = 13.</li></ol><div class=\"sam-worked-ans\">✅ 1101₂ = 13.</div></div></div>","vwo_in_A":"<div class=\"sam-intro\">Algoritmisch denken is de kern van informatica: een probleem oplossen met een <strong>algoritme</strong> — een eindige, ondubbelzinnige reeks stappen. Je legt het vast in een <strong>flowchart</strong> of <strong>pseudocode</strong>, met <strong>selectie</strong>, <strong>iteratie</strong> en soms <strong>recursie</strong>.</div><div class=\"sam-head\">Algoritme en flowchart</div><p>Een <strong>flowchart</strong> tekent de stappen als blokken: een ovaal voor start/eind, een rechthoek voor een bewerking en een <strong>ruit</strong> voor een beslissing (voorwaarde). Hieronder een lus die de getallen 1 t/m 10 afdrukt:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 260 240\" role=\"img\" aria-label=\"Flowchart van een lus die telt van 1 tot en met 10 en elk getal afdrukt\"><defs><marker id=\"inAa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><ellipse cx=\"130\" cy=\"18\" rx=\"32\" ry=\"12\" fill=\"var(--or)\" opacity=\".18\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"130\" y=\"22\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Start</text><rect x=\"95\" y=\"38\" width=\"70\" height=\"22\" rx=\"3\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"130\" y=\"53\" font-size=\"9\" fill=\"var(--dk)\" text-anchor=\"middle\">i = 1</text><polygon points=\"130,70 172,92 130,114 88,92\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"130\" y=\"95\" font-size=\"8.5\" fill=\"var(--dk)\" text-anchor=\"middle\">i ≤ 10 ?</text><rect x=\"92\" y=\"128\" width=\"76\" height=\"22\" rx=\"3\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"130\" y=\"143\" font-size=\"8.5\" fill=\"var(--dk)\" text-anchor=\"middle\">druk i af</text><rect x=\"92\" y=\"158\" width=\"76\" height=\"22\" rx=\"3\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"130\" y=\"173\" font-size=\"8.5\" fill=\"var(--dk)\" text-anchor=\"middle\">i = i + 1</text><ellipse cx=\"34\" cy=\"92\" rx=\"30\" ry=\"12\" fill=\"var(--dk)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"34\" y=\"96\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Einde</text><g stroke=\"var(--mu)\" stroke-width=\"1.3\" fill=\"none\"><line x1=\"130\" y1=\"30\" x2=\"130\" y2=\"37\" marker-end=\"url(#inAa)\"/><line x1=\"130\" y1=\"60\" x2=\"130\" y2=\"69\" marker-end=\"url(#inAa)\"/><line x1=\"130\" y1=\"114\" x2=\"130\" y2=\"127\" marker-end=\"url(#inAa)\"/><path d=\"M168,171 L210,171 L210,92 L173,92\" marker-end=\"url(#inAa)\"/><line x1=\"88\" y1=\"92\" x2=\"65\" y2=\"92\" marker-end=\"url(#inAa)\"/></g><text x=\"136\" y=\"124\" font-size=\"8\" font-weight=\"700\" fill=\"var(--or)\">ja</text><text x=\"72\" y=\"86\" font-size=\"8\" font-weight=\"700\" fill=\"var(--or)\">nee</text></svg><div class=\"sam-figcap\"><strong>Iteratie (lus):</strong> zolang de voorwaarde 'i ≤ 10' waar is, wordt i afgedrukt en met 1 verhoogd. Is de voorwaarde onwaar, dan stopt de lus.</div></div><div class=\"sam-head\">Bouwstenen van een algoritme</div><table class=\"sam-table\"><thead><tr><th>Structuur</th><th>Betekenis</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Sequentie</td><td>stappen na elkaar</td><td>regel 1, dan 2</td></tr><tr><td>Selectie</td><td>keuze op voorwaarde</td><td>if … else</td></tr><tr><td>Iteratie</td><td>herhaling (lus)</td><td>for / while</td></tr></tbody></table><div class=\"sam-head\">Variabelen en recursie</div><p>Een <strong>variabele</strong> bewaart een waarde van een bepaald <strong>datatype</strong> (int, string, boolean). Bij <strong>recursie</strong> roept een functie zichzelf aan met een kleiner probleem, tot een <strong>basisgeval</strong> de herhaling stopt.</p><div class=\"sam-warn\"><strong>Let op bij recursie:</strong> zonder een goed <strong>basisgeval</strong> (stopvoorwaarde) blijft de functie zichzelf aanroepen — een oneindige lus die crasht (stack overflow).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Wat drukt deze pseudocode af?  <em>i = 1; zolang i ≤ 3: druk i af; i = i + 2</em></div><ol class=\"sam-worked-steps\"><li>i = 1 → 1 ≤ 3, druk 1 af, i wordt 3.</li><li>i = 3 → 3 ≤ 3, druk 3 af, i wordt 5.</li><li>i = 5 → 5 ≤ 3 is onwaar, stop.</li></ol><div class=\"sam-worked-ans\">✅ De uitvoer is: 1 3.</div></div></div>","havo_na_A":"<div class=\"sam-intro\">Natuurkunde begint bij <strong>meten en verbanden</strong>: grootheden, eenheden en hoe grootheden samenhangen. Herken je de grafiekvorm, dan ken je meteen het soort verband — en andersom.</div><div class=\"sam-head\">Grootheden, eenheden en het SI-stelsel</div><p>Een <strong>grootheid</strong> is een meetbare eigenschap (afstand, massa, tijd); een <strong>eenheid</strong> is de afgesproken maat waarin je die uitdrukt. Om metingen wereldwijd vergelijkbaar te houden gebruikt men het SI-stelsel met zeven basiseenheden.</p><table class=\"sam-table\"><thead><tr><th>Grootheid</th><th>Basiseenheid</th><th>Symbool</th></tr></thead><tbody><tr><td>Lengte</td><td>meter</td><td>m</td></tr><tr><td>Massa</td><td>kilogram</td><td>kg</td></tr><tr><td>Tijd</td><td>seconde</td><td>s</td></tr><tr><td>Stroomsterkte</td><td>ampère</td><td>A</td></tr><tr><td>Temperatuur</td><td>kelvin</td><td>K</td></tr><tr><td>Hoeveelheid stof</td><td>mol</td><td>mol</td></tr><tr><td>Lichtsterkte</td><td>candela</td><td>cd</td></tr></tbody></table><div class=\"sam-head\">Voorvoegsels en wetenschappelijke notatie</div><p>Voorvoegsels staan voor machten van tien, zodat je grote en kleine getallen kort opschrijft.</p><table class=\"sam-table\"><thead><tr><th>Voorvoegsel</th><th>Symbool</th><th>Factor</th></tr></thead><tbody><tr><td>giga</td><td>G</td><td>10⁹</td></tr><tr><td>mega</td><td>M</td><td>10⁶</td></tr><tr><td>kilo</td><td>k</td><td>10³</td></tr><tr><td>milli</td><td>m</td><td>10⁻³</td></tr><tr><td>micro</td><td>µ</td><td>10⁻⁶</td></tr><tr><td>nano</td><td>n</td><td>10⁻⁹</td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Wetenschappelijke notatie</div><div class=\"sam-formula-eq\">5 430 000 m = 5,43·10⁶ m &nbsp;|&nbsp; 0,00000341 s = 3,41·10⁻⁶ s</div><div class=\"sam-formula-note\">Eén cijfer vóór de komma, vermenigvuldigd met een macht van tien. Bij kleine getallen is de macht negatief.</div></div><div class=\"sam-head\">Significante cijfers</div><p>Het aantal significante cijfers geeft aan hoe nauwkeurig een meting is. Voorloopnullen tellen niet mee: 0,0047 heeft er twee.</p><table class=\"sam-table\"><thead><tr><th>Bewerking</th><th>Regel voor de uitkomst</th></tr></thead><tbody><tr><td>Vermenigvuldigen / delen</td><td>evenveel significante cijfers als de minst nauwkeurige waarde</td></tr><tr><td>Optellen / aftrekken</td><td>evenveel decimalen als de waarde met de minste decimalen</td></tr><tr><td>Logaritme</td><td>aantal decimalen = aantal significante cijfers van het origineel</td></tr></tbody></table><div class=\"sam-tip\">Voorbeeld (optellen): 2,45 (twee decimalen) + 3,1 (één decimaal) = 5,55 → afronden op één decimaal geeft <strong>5,6</strong>. Op het examen telt significantie alleen mee als er expliciet om gevraagd wordt.</div><div class=\"sam-head\">Grafieken: helling en oppervlakte</div><p>In een (A,B)-diagram staat A op de verticale as en B op de horizontale as. De helling en de oppervlakte onder de grafiek hebben elk een natuurkundige betekenis.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Helling van een (x,t)-diagram</div><div class=\"sam-formula-eq\">v = Δx / Δt</div><div class=\"sam-formula-note\">De helling van een plaats-tijddiagram is de snelheid. Bij een kromme bepaal je de helling met een raaklijn.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Oppervlakte onder een (v,t)-diagram</div><div class=\"sam-formula-eq\">x = v · t</div><div class=\"sam-formula-note\">De oppervlakte onder een snelheid-tijddiagram is de afgelegde afstand. Algemeen: bij y = b·c is de oppervlakte onder de (b,c)-grafiek gelijk aan grootheid y.</div></div><div class=\"sam-head\">Soorten verbanden</div><table class=\"sam-table\"><thead><tr><th>Verband</th><th>Formule</th><th>Grafiekvorm</th></tr></thead><tbody><tr><td>Recht evenredig</td><td>y = a·x</td><td>rechte lijn door de oorsprong</td></tr><tr><td>Lineair</td><td>y = a·x + b</td><td>rechte lijn, niet door de oorsprong</td></tr><tr><td>Omgekeerd evenredig</td><td>y = a / x</td><td>hyperbool</td></tr><tr><td>Kwadratisch</td><td>y = a·x²</td><td>parabool</td></tr><tr><td>Omgekeerd kwadratisch</td><td>y = a / x²</td><td>steilere hyperbool</td></tr><tr><td>Wortelverband</td><td>y = a·√x</td><td>afvlakkende kromme</td></tr></tbody></table><div class=\"sam-figure\"><svg viewBox=\"0 0 414 222\" role=\"img\" aria-label=\"Soorten verbanden en hun grafiekvorm\"><line x1=\"34\" y1=\"96\" x2=\"34\" y2=\"28\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"34\" y1=\"96\" x2=\"194\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M34.0,96.0 L38.4,94.1 L42.8,92.2 L47.2,90.4 L51.6,88.5 L56.1,86.6 L60.5,84.7 L64.9,82.8 L69.3,80.9 L73.7,79.1 L78.1,77.2 L82.5,75.3 L86.9,73.4 L91.4,71.5 L95.8,69.6 L100.2,67.8 L104.6,65.9 L109.0,64.0 L113.4,62.1 L117.8,60.2 L122.2,58.4 L126.6,56.5 L131.1,54.6 L135.5,52.7 L139.9,50.8 L144.3,48.9 L148.7,47.1 L153.1,45.2 L157.5,43.3 L161.9,41.4 L166.4,39.5 L170.8,37.6 L175.2,35.8 L179.6,33.9 L184.0,32.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"109\" y=\"114\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Recht evenredig (y = a·x)</text><line x1=\"244\" y1=\"96\" x2=\"244\" y2=\"14\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"244\" y1=\"96\" x2=\"404\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M263.5,17.2 L267.3,30.2 L271.2,39.5 L275.0,46.5 L278.9,51.9 L282.7,56.3 L286.5,59.9 L290.4,62.9 L294.2,65.4 L298.0,67.6 L301.9,69.5 L305.7,71.1 L309.6,72.6 L313.4,73.9 L317.2,75.0 L321.1,76.1 L324.9,77.0 L328.8,77.9 L332.6,78.7 L336.4,79.4 L340.3,80.0 L344.1,80.7 L347.9,81.2 L351.8,81.7 L355.6,82.2 L359.5,82.7 L363.3,83.1 L367.1,83.5 L371.0,83.9 L374.8,84.3 L378.6,84.6 L382.5,84.9 L386.3,85.2 L390.2,85.5 L394.0,85.8\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"323\" y=\"114\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Omgekeerd evenredig (y = a/x)</text><line x1=\"34\" y1=\"196\" x2=\"34\" y2=\"128\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"34\" y1=\"196\" x2=\"194\" y2=\"196\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M34.0,196.0 L38.4,195.9 L42.8,195.8 L47.2,195.5 L51.6,195.1 L56.1,194.6 L60.5,194.0 L64.9,193.3 L69.3,192.5 L73.7,191.5 L78.1,190.5 L82.5,189.3 L86.9,188.0 L91.4,186.6 L95.8,185.1 L100.2,183.5 L104.6,181.8 L109.0,180.0 L113.4,178.1 L117.8,176.0 L122.2,173.9 L126.6,171.6 L131.1,169.2 L135.5,166.7 L139.9,164.1 L144.3,161.4 L148.7,158.6 L153.1,155.6 L157.5,152.6 L161.9,149.4 L166.4,146.2 L170.8,142.8 L175.2,139.3 L179.6,135.7 L184.0,132.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"109\" y=\"214\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Kwadratisch (y = a·x²)</text><line x1=\"244\" y1=\"196\" x2=\"244\" y2=\"128\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"244\" y1=\"196\" x2=\"404\" y2=\"196\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M244.0,196.0 L248.4,185.0 L252.8,180.5 L257.2,177.0 L261.6,174.0 L266.1,171.5 L270.5,169.1 L274.9,167.0 L279.3,165.0 L283.7,163.1 L288.1,161.3 L292.5,159.6 L296.9,158.0 L301.4,156.4 L305.8,154.9 L310.2,153.5 L314.6,152.1 L319.0,150.7 L323.4,149.4 L327.8,148.2 L332.2,146.9 L336.6,145.7 L341.1,144.5 L345.5,143.4 L349.9,142.2 L354.3,141.1 L358.7,140.0 L363.1,139.0 L367.5,137.9 L371.9,136.9 L376.4,135.9 L380.8,134.9 L385.2,133.9 L389.6,132.9 L394.0,132.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"323\" y=\"214\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Wortelverband (y = a·√x)</text></svg><div class=\"sam-figcap\"><strong>Herken het verband aan de vorm:</strong> rechte lijn, hyperbool, parabool of afvlakkende wortelkromme.</div></div><div class=\"sam-tip\"><strong>Coördinatentransformatie</strong>: zet je bijvoorbeeld √x of 1/x op een as, dan wordt een krom verband een rechte lijn. Ontstaat na de transformatie een rechte lijn, dan is het vermoeden over het verband bevestigd.</div><div class=\"sam-head\">Goniometrie (rechthoekige driehoek)</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">SOS · CAS · TOA</div><div class=\"sam-formula-eq\">sin α = overstaand / schuin &nbsp;|&nbsp; cos α = aanliggend / schuin &nbsp;|&nbsp; tan α = overstaand / aanliggend</div><div class=\"sam-formula-note\">Handig bij het ontbinden van krachten en het rekenen met hoeken. Schuine zijde = langste zijde, tegenover de rechte hoek.</div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 320 198\" role=\"img\" aria-label=\"Rechthoekige driehoek met SOS CAS TOA\"><polygon points=\"50,160 250,160 250,50\" fill=\"rgba(var(--or-rgb),.08)\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linejoin=\"round\"/><path d=\"M236,160 L236,146 L250,146\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.3\"/><path d=\"M80,160 A30,30 0 0,0 76.3,146.5\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><text x=\"89\" y=\"153\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">α</text><text x=\"150\" y=\"177\" font-size=\"9.5\" fill=\"var(--mu)\" text-anchor=\"middle\">aanliggend</text><text x=\"267\" y=\"108\" font-size=\"9.5\" fill=\"var(--mu)\" text-anchor=\"middle\" transform=\"rotate(90 267 108)\">overstaand</text><text x=\"138\" y=\"96\" font-size=\"9.5\" fill=\"var(--mu)\" text-anchor=\"middle\" transform=\"rotate(-28 138 96)\">schuine zijde</text></svg><div class=\"sam-figcap\"><strong>SOS · CAS · TOA:</strong> sin α = overstaand/schuin, cos α = aanliggend/schuin, tan α = overstaand/aanliggend. Onmisbaar bij het ontbinden van krachten.</div></div><div class=\"sam-head\">Onderzoeken en ontwerpen</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Onderzoekscyclus</div><ul><li>Onderzoeksvraag + hypothese</li><li>Werkplan opstellen</li><li>Experiment uitvoeren</li><li>Resultaten verwerken</li><li>Conclusie: hypothese kloppend?</li><li>Moet reproduceerbaar zijn</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Ontwerpcyclus</div><ul><li>Ontwerpvraag</li><li>Programma van eisen</li><li>Ontwerp + prototype maken</li><li>Testen aan de eisen</li><li>Evalueren en verbeteren</li><li>Eventueel opnieuw doorlopen</li></ul></div></div><div class=\"sam-warn\">Houd de <strong>onafhankelijke variabele</strong> (die je zelf instelt) en de <strong>afhankelijke variabele</strong> (die je meet) uit elkaar, en houd alle storende variabelen constant. Anders kun je het effect niet aan de OV toeschrijven.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een auto rijdt 1,80 km in 75 s. Bereken de gemiddelde snelheid in m/s met het juiste aantal significante cijfers.</div><ol class=\"sam-worked-steps\"><li>Zet om naar SI-eenheden: 1,80 km = 1,80 × 10³ = 1800 m.</li><li>v = Δx / Δt = 1800 / 75 = 24 m/s.</li><li>Significantie: 75 heeft 2 significante cijfers → rond af op 2: 24 m/s.</li></ol><div class=\"sam-worked-ans\">✅ v = 24 m/s.</div></div>","havo_na_B":"<div class=\"sam-intro\">Een <strong>trilling herhaalt zich in de tijd</strong>; plant die zich voort door een medium, dan is het een <strong>golf</strong>. Amplitude, periode en frequentie keren overal terug, en v = f·λ geldt voor élke golf.</div><div class=\"sam-head\">Trillingen</div><p>Een <strong>trilling</strong> is een beweging die zich periodiek herhaalt. In een (u,t)-diagram zet je de uitwijking u uit tegen de tijd t.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 360 172\" role=\"img\" aria-label=\"Harmonische trilling in een uitwijking-tijddiagram\"><defs><marker id=\"naT\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"40\" y1=\"95\" x2=\"350\" y2=\"95\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#naT)\"/><line x1=\"44\" y1=\"152\" x2=\"44\" y2=\"34\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#naT)\"/><path d=\"M44.0,95.0 L47.0,89.3 L50.0,83.7 L53.0,78.2 L56.0,73.1 L59.0,68.2 L62.0,63.9 L65.0,60.0 L68.0,56.7 L71.0,54.0 L74.0,52.0 L77.0,50.6 L80.0,50.0 L83.0,50.2 L86.0,51.0 L89.0,52.6 L92.0,54.8 L95.0,57.7 L98.0,61.2 L101.0,65.3 L104.0,69.8 L107.0,74.7 L110.0,80.0 L113.0,85.5 L116.0,91.2 L119.0,96.9 L122.0,102.6 L125.0,108.2 L128.0,113.5 L131.0,118.6 L134.0,123.3 L137.0,127.5 L140.0,131.2 L143.0,134.3 L146.0,136.8 L149.0,138.5 L152.0,139.6 L155.0,140.0 L158.0,139.6 L161.0,138.5 L164.0,136.8 L167.0,134.3 L170.0,131.2 L173.0,127.5 L176.0,123.3 L179.0,118.6 L182.0,113.5 L185.0,108.2 L188.0,102.6 L191.0,96.9 L194.0,91.2 L197.0,85.5 L200.0,80.0 L203.0,74.7 L206.0,69.8 L209.0,65.3 L212.0,61.2 L215.0,57.7 L218.0,54.8 L221.0,52.6 L224.0,51.0 L227.0,50.2 L230.0,50.0 L233.0,50.6 L236.0,52.0 L239.0,54.0 L242.0,56.7 L245.0,60.0 L248.0,63.9 L251.0,68.2 L254.0,73.1 L257.0,78.2 L260.0,83.7 L263.0,89.3 L266.0,95.0 L269.0,100.7 L272.0,106.3 L275.0,111.8 L278.0,116.9 L281.0,121.8 L284.0,126.1 L287.0,130.0 L290.0,133.3 L293.0,136.0 L296.0,138.0 L299.0,139.4 L302.0,140.0 L305.0,139.8 L308.0,139.0 L311.0,137.4 L314.0,135.2 L317.0,132.3 L320.0,128.8 L323.0,124.7 L326.0,120.2 L329.0,115.3 L332.0,110.0 L335.0,104.5 L338.0,98.8\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/><line x1=\"80\" y1=\"95\" x2=\"80\" y2=\"50\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><text x=\"86\" y=\"74\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">A</text><line x1=\"80\" y1=\"44\" x2=\"228\" y2=\"44\" stroke=\"var(--mu)\" stroke-width=\"1\" marker-start=\"url(#naT)\" marker-end=\"url(#naT)\"/><line x1=\"80\" y1=\"50\" x2=\"80\" y2=\"44\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"228\" y1=\"50\" x2=\"228\" y2=\"44\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><text x=\"150\" y=\"40\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">T</text><text x=\"34\" y=\"42\" font-size=\"9.5\" fill=\"var(--mu)\">u</text><text x=\"344\" y=\"108\" font-size=\"9.5\" fill=\"var(--mu)\">t</text></svg><div class=\"sam-figcap\"><strong>Harmonische trilling:</strong> de uitwijking u volgt een sinus. <strong>A</strong> = amplitude (maximale uitwijking), <strong>T</strong> = trillingstijd (één hele trilling).</div></div><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Evenwichtsstand</td><td>de rustpositie van het systeem</td></tr><tr><td>Uitwijking (u)</td><td>de afstand tot de evenwichtsstand</td></tr><tr><td>Amplitude</td><td>de maximale uitwijking</td></tr><tr><td>Trillingstijd / periode (T)</td><td>de tijd van één volledige trilling</td></tr><tr><td>Frequentie (f)</td><td>aantal trillingen per seconde (Hz)</td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Frequentie en periode</div><div class=\"sam-formula-eq\">f = 1 / T</div><div class=\"sam-formula-note\">f de frequentie (Hz), T de trillingstijd (s). Frequentie en periode zijn omgekeerd evenredig.</div></div><div class=\"sam-tip\">Bij een <strong>harmonische trilling</strong> is de uitwijking recht evenredig met de terugwerkende kracht; het (u,t)-diagram heeft de vorm van een sinus.</div><div class=\"sam-head\">Massa-veersysteem en resonantie</div><p>Hang je een massa aan een veer en laat je die los, dan ontstaat een trilling met een vaste eigenfrequentie (de eigentrilling) die afhangt van de massa en de veerconstante.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Periode massa-veersysteem</div><div class=\"sam-formula-eq\">T = 2π · √(m / C)</div><div class=\"sam-formula-note\">T de periode (s), m de massa (kg), C de veerconstante (N/m). Een zwaardere massa of een slappere veer geeft een langere periode.</div></div><div class=\"sam-warn\"><strong>Resonantie</strong> treedt op als een gedwongen trilling dezelfde frequentie heeft als de eigenfrequentie van het systeem: de amplitude loopt dan sterk op. Voorbeeld: de Tacoma Narrows Bridge bezweek in 1940 doordat de wind de brug op haar eigenfrequentie aandreef.</div><div class=\"sam-head\">Lopende golven</div><p>Een <strong>golf</strong> is een trilling die zich voortplant door een medium (lucht, water, vaste stof) of door de ruimte. Een golf transporteert energie, maar verplaatst de deeltjes van het medium niet.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Golfsnelheid</div><div class=\"sam-formula-eq\">v = f · λ</div><div class=\"sam-formula-note\">v de voortplantingssnelheid (m/s), f de frequentie (Hz), λ de golflengte (m). Deze formule geldt voor álle golven (BiNaS).</div></div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Transversale golf</div><ul><li>Trilling loodrecht op de voortplantingsrichting</li><li>Voorbeeld: golf in een touw</li><li>Licht is transversaal (elektrisch + magnetisch veld)</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Longitudinale golf</div><ul><li>Trilling in dezelfde richting als de voortplanting</li><li>Voorbeeld: geluid</li><li>Bestaat uit verdichtingen en verdunningen</li></ul></div></div><p><strong>Geluid</strong> is een longitudinale golf; de geluidssnelheid hangt af van het medium en de temperatuur (op te zoeken in BiNaS). Terugkaatsing tegen een oppervlak geeft een echo. <strong>Licht</strong> is een transversale golf met een vaste snelheid.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Lichtsnelheid in vacuüm</div><div class=\"sam-formula-eq\">c = 2,99792458·10⁸ m/s</div><div class=\"sam-formula-note\">De snelheid waarmee elektromagnetische straling (licht) zich door vacuüm voortplant. In BiNaS afgerond beschikbaar.</div></div><div class=\"sam-head\">Staande golven</div><p>Een <strong>staande golf</strong> heeft geen voortplantingsrichting. Hij ontstaat door terugkaatsing en heeft <strong>knopen</strong> (punten die stilstaan) en <strong>buiken</strong> (punten met maximale uitwijking).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 400 176\" role=\"img\" aria-label=\"Staande golven: grondtoon en eerste boventoon\"><line x1=\"44\" y1=\"44\" x2=\"44\" y2=\"60\" stroke=\"var(--mu)\" stroke-width=\"2\"/><line x1=\"356\" y1=\"44\" x2=\"356\" y2=\"60\" stroke=\"var(--mu)\" stroke-width=\"2\"/><path d=\"M44.0,52.0 L47.0,51.3 L50.0,50.6 L53.0,49.8 L56.0,49.1 L59.0,48.4 L62.0,47.7 L65.0,47.0 L68.0,46.3 L71.0,45.6 L74.0,44.9 L77.0,44.2 L80.0,43.5 L83.0,42.8 L86.0,42.2 L89.0,41.5 L92.0,40.8 L95.0,40.2 L98.0,39.6 L101.0,39.0 L104.0,38.4 L107.0,37.8 L110.0,37.2 L113.0,36.6 L116.0,36.1 L119.0,35.5 L122.0,35.0 L125.0,34.5 L128.0,34.0 L131.0,33.6 L134.0,33.1 L137.0,32.7 L140.0,32.2 L143.0,31.8 L146.0,31.5 L149.0,31.1 L152.0,30.7 L155.0,30.4 L158.0,30.1 L161.0,29.8 L164.0,29.6 L167.0,29.3 L170.0,29.1 L173.0,28.9 L176.0,28.7 L179.0,28.5 L182.0,28.4 L185.0,28.3 L188.0,28.2 L191.0,28.1 L194.0,28.0 L197.0,28.0 L200.0,28.0 L203.0,28.0 L206.0,28.0 L209.0,28.1 L212.0,28.2 L215.0,28.3 L218.0,28.4 L221.0,28.5 L224.0,28.7 L227.0,28.9 L230.0,29.1 L233.0,29.3 L236.0,29.6 L239.0,29.8 L242.0,30.1 L245.0,30.4 L248.0,30.7 L251.0,31.1 L254.0,31.5 L257.0,31.8 L260.0,32.2 L263.0,32.7 L266.0,33.1 L269.0,33.6 L272.0,34.0 L275.0,34.5 L278.0,35.0 L281.0,35.5 L284.0,36.1 L287.0,36.6 L290.0,37.2 L293.0,37.8 L296.0,38.4 L299.0,39.0 L302.0,39.6 L305.0,40.2 L308.0,40.8 L311.0,41.5 L314.0,42.2 L317.0,42.8 L320.0,43.5 L323.0,44.2 L326.0,44.9 L329.0,45.6 L332.0,46.3 L335.0,47.0 L338.0,47.7 L341.0,48.4 L344.0,49.1 L347.0,49.8 L350.0,50.6 L353.0,51.3 L356.0,52.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><path d=\"M44.0,52.0 L47.0,52.7 L50.0,53.4 L53.0,54.2 L56.0,54.9 L59.0,55.6 L62.0,56.3 L65.0,57.0 L68.0,57.7 L71.0,58.4 L74.0,59.1 L77.0,59.8 L80.0,60.5 L83.0,61.2 L86.0,61.8 L89.0,62.5 L92.0,63.2 L95.0,63.8 L98.0,64.4 L101.0,65.0 L104.0,65.6 L107.0,66.2 L110.0,66.8 L113.0,67.4 L116.0,67.9 L119.0,68.5 L122.0,69.0 L125.0,69.5 L128.0,70.0 L131.0,70.4 L134.0,70.9 L137.0,71.3 L140.0,71.8 L143.0,72.2 L146.0,72.5 L149.0,72.9 L152.0,73.3 L155.0,73.6 L158.0,73.9 L161.0,74.2 L164.0,74.4 L167.0,74.7 L170.0,74.9 L173.0,75.1 L176.0,75.3 L179.0,75.5 L182.0,75.6 L185.0,75.7 L188.0,75.8 L191.0,75.9 L194.0,76.0 L197.0,76.0 L200.0,76.0 L203.0,76.0 L206.0,76.0 L209.0,75.9 L212.0,75.8 L215.0,75.7 L218.0,75.6 L221.0,75.5 L224.0,75.3 L227.0,75.1 L230.0,74.9 L233.0,74.7 L236.0,74.4 L239.0,74.2 L242.0,73.9 L245.0,73.6 L248.0,73.3 L251.0,72.9 L254.0,72.5 L257.0,72.2 L260.0,71.8 L263.0,71.3 L266.0,70.9 L269.0,70.4 L272.0,70.0 L275.0,69.5 L278.0,69.0 L281.0,68.5 L284.0,67.9 L287.0,67.4 L290.0,66.8 L293.0,66.2 L296.0,65.6 L299.0,65.0 L302.0,64.4 L305.0,63.8 L308.0,63.2 L311.0,62.5 L314.0,61.8 L317.0,61.2 L320.0,60.5 L323.0,59.8 L326.0,59.1 L329.0,58.4 L332.0,57.7 L335.0,57.0 L338.0,56.3 L341.0,55.6 L344.0,54.9 L347.0,54.2 L350.0,53.4 L353.0,52.7 L356.0,52.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" stroke-dasharray=\"4 3\" opacity=\".55\"/><circle cx=\"44\" cy=\"52\" r=\"3\" fill=\"var(--dk)\"/><circle cx=\"356\" cy=\"52\" r=\"3\" fill=\"var(--dk)\"/><text x=\"200\" y=\"20\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--mu)\" text-anchor=\"middle\">Grondtoon — 1 buik, 2 knopen</text><line x1=\"44\" y1=\"124\" x2=\"44\" y2=\"140\" stroke=\"var(--mu)\" stroke-width=\"2\"/><line x1=\"356\" y1=\"124\" x2=\"356\" y2=\"140\" stroke=\"var(--mu)\" stroke-width=\"2\"/><path d=\"M44.0,132.0 L47.0,130.6 L50.0,129.1 L53.0,127.7 L56.0,126.3 L59.0,124.9 L62.0,123.5 L65.0,122.2 L68.0,120.8 L71.0,119.6 L74.0,118.4 L77.0,117.2 L80.0,116.1 L83.0,115.0 L86.0,114.0 L89.0,113.1 L92.0,112.2 L95.0,111.5 L98.0,110.7 L101.0,110.1 L104.0,109.6 L107.0,109.1 L110.0,108.7 L113.0,108.4 L116.0,108.2 L119.0,108.0 L122.0,108.0 L125.0,108.0 L128.0,108.2 L131.0,108.4 L134.0,108.7 L137.0,109.1 L140.0,109.6 L143.0,110.1 L146.0,110.7 L149.0,111.5 L152.0,112.2 L155.0,113.1 L158.0,114.0 L161.0,115.0 L164.0,116.1 L167.0,117.2 L170.0,118.4 L173.0,119.6 L176.0,120.8 L179.0,122.2 L182.0,123.5 L185.0,124.9 L188.0,126.3 L191.0,127.7 L194.0,129.1 L197.0,130.6 L200.0,132.0 L203.0,133.4 L206.0,134.9 L209.0,136.3 L212.0,137.7 L215.0,139.1 L218.0,140.5 L221.0,141.8 L224.0,143.2 L227.0,144.4 L230.0,145.6 L233.0,146.8 L236.0,147.9 L239.0,149.0 L242.0,150.0 L245.0,150.9 L248.0,151.8 L251.0,152.5 L254.0,153.3 L257.0,153.9 L260.0,154.4 L263.0,154.9 L266.0,155.3 L269.0,155.6 L272.0,155.8 L275.0,156.0 L278.0,156.0 L281.0,156.0 L284.0,155.8 L287.0,155.6 L290.0,155.3 L293.0,154.9 L296.0,154.4 L299.0,153.9 L302.0,153.3 L305.0,152.5 L308.0,151.8 L311.0,150.9 L314.0,150.0 L317.0,149.0 L320.0,147.9 L323.0,146.8 L326.0,145.6 L329.0,144.4 L332.0,143.2 L335.0,141.8 L338.0,140.5 L341.0,139.1 L344.0,137.7 L347.0,136.3 L350.0,134.9 L353.0,133.4 L356.0,132.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><path d=\"M44.0,132.0 L47.0,133.4 L50.0,134.9 L53.0,136.3 L56.0,137.7 L59.0,139.1 L62.0,140.5 L65.0,141.8 L68.0,143.2 L71.0,144.4 L74.0,145.6 L77.0,146.8 L80.0,147.9 L83.0,149.0 L86.0,150.0 L89.0,150.9 L92.0,151.8 L95.0,152.5 L98.0,153.3 L101.0,153.9 L104.0,154.4 L107.0,154.9 L110.0,155.3 L113.0,155.6 L116.0,155.8 L119.0,156.0 L122.0,156.0 L125.0,156.0 L128.0,155.8 L131.0,155.6 L134.0,155.3 L137.0,154.9 L140.0,154.4 L143.0,153.9 L146.0,153.3 L149.0,152.5 L152.0,151.8 L155.0,150.9 L158.0,150.0 L161.0,149.0 L164.0,147.9 L167.0,146.8 L170.0,145.6 L173.0,144.4 L176.0,143.2 L179.0,141.8 L182.0,140.5 L185.0,139.1 L188.0,137.7 L191.0,136.3 L194.0,134.9 L197.0,133.4 L200.0,132.0 L203.0,130.6 L206.0,129.1 L209.0,127.7 L212.0,126.3 L215.0,124.9 L218.0,123.5 L221.0,122.2 L224.0,120.8 L227.0,119.6 L230.0,118.4 L233.0,117.2 L236.0,116.1 L239.0,115.0 L242.0,114.0 L245.0,113.1 L248.0,112.2 L251.0,111.5 L254.0,110.7 L257.0,110.1 L260.0,109.6 L263.0,109.1 L266.0,108.7 L269.0,108.4 L272.0,108.2 L275.0,108.0 L278.0,108.0 L281.0,108.0 L284.0,108.2 L287.0,108.4 L290.0,108.7 L293.0,109.1 L296.0,109.6 L299.0,110.1 L302.0,110.7 L305.0,111.5 L308.0,112.2 L311.0,113.1 L314.0,114.0 L317.0,115.0 L320.0,116.1 L323.0,117.2 L326.0,118.4 L329.0,119.6 L332.0,120.8 L335.0,122.2 L338.0,123.5 L341.0,124.9 L344.0,126.3 L347.0,127.7 L350.0,129.1 L353.0,130.6 L356.0,132.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" stroke-dasharray=\"4 3\" opacity=\".55\"/><circle cx=\"44\" cy=\"132\" r=\"3\" fill=\"var(--dk)\"/><circle cx=\"200\" cy=\"132\" r=\"3\" fill=\"var(--dk)\"/><circle cx=\"356\" cy=\"132\" r=\"3\" fill=\"var(--dk)\"/><text x=\"200\" y=\"100\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--mu)\" text-anchor=\"middle\">1e boventoon — 2 buiken, 3 knopen</text></svg><div class=\"sam-figcap\"><strong>Staande golf:</strong> <strong>knopen</strong> staan stil (stippen), <strong>buiken</strong> hebben maximale uitwijking. Meer buiken = kortere golflengte = hogere toon.</div></div><ul><li>Een snaar die aan beide kanten vastzit kan op meerdere manieren trillen.</li><li><strong>Grondtoon</strong>: de eenvoudigste trilling — één buik en twee knopen, de grootste golflengte.</li><li><strong>Boventonen</strong>: meer knopen en buiken en een kleinere golflengte (hogere frequentie).</li></ul><div class=\"sam-tip\">v = f · λ geldt ook hier: bij een kortere golflengte (boventoon) hoort een hogere frequentie en dus een hogere toon.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een toon heeft een frequentie van 440 Hz. De geluidssnelheid is 343 m/s. Bereken de golflengte.</div><ol class=\"sam-worked-steps\"><li>Gebruik v = f · λ, dus λ = v / f.</li><li>λ = 343 / 440 = 0,7795… m.</li><li>Afronden op 2 significante cijfers: λ ≈ 0,78 m.</li></ol><div class=\"sam-worked-ans\">✅ λ ≈ 0,78 m.</div></div>","havo_na_C":"<div class=\"sam-intro\">De rode draad: <strong>krachten veranderen beweging</strong>. Een resulterende kracht geeft een versnelling (F = m·a), en energie gaat daarbij nooit verloren — ze verandert alleen van vorm.</div><div class=\"sam-head\">Beweging beschrijven</div><p><strong>Verplaatsing</strong> is het verschil tussen de eind- en beginpositie. Bij een <strong>eenparige rechtlijnige beweging</strong> is de snelheid constant en de versnelling nul.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Verplaatsing</div><div class=\"sam-formula-eq\">Δx = x<sub>eind</sub> − x<sub>start</sub></div><div class=\"sam-formula-note\">Een vector: richting telt mee. Eenheid meter (m).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Eenparige beweging</div><div class=\"sam-formula-eq\">s = v · t</div><div class=\"sam-formula-note\">s de afgelegde afstand (m), v de constante snelheid (m/s), t de tijd (s).</div></div><ul><li>In een <strong>(x,t)-diagram</strong> is de helling de snelheid; een rechte lijn betekent constante snelheid.</li><li>In een <strong>(v,t)-diagram</strong> is de oppervlakte onder de grafiek de verplaatsing.</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 320 198\" role=\"img\" aria-label=\"Snelheid-tijddiagram van een eenparig versnelde beweging\"><defs><marker id=\"naV\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><polygon points=\"46,170 270,170 270,52\" fill=\"rgba(var(--or-rgb),.15)\"/><line x1=\"46\" y1=\"172\" x2=\"46\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#naV)\"/><line x1=\"44\" y1=\"170\" x2=\"302\" y2=\"170\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#naV)\"/><line x1=\"46\" y1=\"170\" x2=\"270\" y2=\"52\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><line x1=\"270\" y1=\"52\" x2=\"270\" y2=\"170\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><text x=\"22\" y=\"106\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 106)\">snelheid v</text><text x=\"248\" y=\"186\" font-size=\"9.5\" fill=\"var(--mu)\">tijd t</text><text x=\"150\" y=\"150\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">oppervlakte = afstand s</text><text x=\"92\" y=\"96\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\" transform=\"rotate(-28 92 96)\">helling = versnelling a</text></svg><div class=\"sam-figcap\"><strong>(v,t)-diagram, eenparig versneld:</strong> de <strong>helling</strong> is de versnelling a, de <strong>oppervlakte</strong> onder de lijn is de afgelegde afstand s.</div></div><div class=\"sam-head\">Snelheid en versnelling</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Gemiddelde snelheid</div><div class=\"sam-formula-eq\">v<sub>gem</sub> = Δx / Δt</div><div class=\"sam-formula-note\">Totale verplaatsing gedeeld door de totale tijd. De momentane snelheid lees je af met een raaklijn in een (x,t)-diagram (of via de afgeleide).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Versnelling</div><div class=\"sam-formula-eq\">a = Δv / Δt</div><div class=\"sam-formula-note\">De snelheidsverandering per seconde (m/s²). Bij vertraging is a negatief.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Eenparig versneld vanuit stilstand</div><div class=\"sam-formula-eq\">s = ½ · a · t²</div><div class=\"sam-formula-note\">Af te leiden uit de oppervlakte onder het (v,t)-diagram (een driehoek).</div></div><div class=\"sam-head\">Krachten</div><p>Een <strong>kracht</strong> (F, in newton) kan vorm of snelheid van een voorwerp veranderen. Je tekent krachten als vectoren met grootte, richting en aangrijpingspunt.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Zwaartekracht</div><div class=\"sam-formula-eq\">F<sub>z</sub> = m · g</div><div class=\"sam-formula-note\">m de massa (kg), g de valversnelling (op aarde 9,81 m/s²). Werkt loodrecht naar beneden, aangrijpend in het zwaartepunt.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Veerkracht</div><div class=\"sam-formula-eq\">F<sub>v</sub> = C · u</div><div class=\"sam-formula-note\">C de veerconstante (N/m), u de uitwijking (m).</div></div><ul><li><strong>Normaalkracht</strong>: steunkracht loodrecht op een oppervlak.</li><li><strong>Wrijvingskracht</strong>: werkt tegen de beweging in (schuif-, rol- en luchtwrijving).</li><li><strong>Spankracht</strong>: in een gespannen touw of kabel.</li><li><strong>Vrije val</strong>: eenparig versnelde beweging door de zwaartekracht (luchtweerstand verwaarloosd); alle massa's versnellen met g.</li></ul><div class=\"sam-head\">Krachten samenstellen en ontbinden</div><ul><li><strong>Op één lijn</strong>: zelfde richting optellen, tegengestelde richting aftrekken.</li><li><strong>Loodrecht</strong>: gebruik de stelling van Pythagoras voor de resultante.</li><li><strong>Willekeurige hoek</strong>: parallellogrammethode; de diagonaal is de resultante F<sub>res</sub>.</li><li><strong>Ontbinden</strong>: omgekeerde van de parallellogrammethode; gebruik sin/cos (zie domein A) om de componenten te berekenen.</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 340 200\" role=\"img\" aria-label=\"Krachten ontbinden op een helling\"><defs><marker id=\"naFd\" markerWidth=\"9\" markerHeight=\"9\" refX=\"6\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--dk)\"/></marker><marker id=\"naFo\" markerWidth=\"9\" markerHeight=\"9\" refX=\"6\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><polygon points=\"40,170 300,170 300,80\" fill=\"rgba(100,116,139,.12)\" stroke=\"var(--mu)\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/><polygon points=\"162.8,134.9 158.3,121.7 177.2,115.1 181.7,128.4\" fill=\"var(--or)\" opacity=\".85\"/><line x1=\"170\" y1=\"125\" x2=\"154.5\" y2=\"130.4\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naFo)\"/><line x1=\"170\" y1=\"125\" x2=\"185.5\" y2=\"169.7\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naFo)\"/><line x1=\"170\" y1=\"125\" x2=\"170\" y2=\"174\" stroke=\"var(--dk)\" stroke-width=\"2.2\" marker-end=\"url(#naFd)\"/><line x1=\"154.5\" y1=\"130.4\" x2=\"170\" y2=\"174\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"185.5\" y1=\"169.7\" x2=\"170\" y2=\"174\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><path d=\"M66,170 A26,26 0 0,0 62.5,160\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.3\"/><text x=\"71\" y=\"166\" font-size=\"9\" fill=\"var(--mu)\">θ</text><text x=\"174\" y=\"158\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">Fz</text><text x=\"126\" y=\"126\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">F∥</text><text x=\"190\" y=\"158\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">F⊥</text></svg><div class=\"sam-figcap\"><strong>Kracht ontbinden op een helling:</strong> de zwaartekracht F<sub>z</sub> splitst in een component lángs de helling (F∥, laat glijden) en een component loodrecht erop (F⊥).</div></div><div class=\"sam-head\">Wetten van Newton</div><ul><li><strong>Eerste wet (traagheid)</strong>: zonder resulterende kracht blijft een voorwerp in rust of in eenparige beweging.</li><li><strong>Tweede wet</strong>: een resulterende kracht geeft een versnelling.</li><li><strong>Derde wet (actie = reactie)</strong>: oefent A een kracht uit op B, dan oefent B een even grote, tegengestelde kracht uit op A.</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Tweede wet van Newton</div><div class=\"sam-formula-eq\">F<sub>res</sub> = m · a</div><div class=\"sam-formula-note\">F<sub>res</sub> de resulterende kracht (N), m de massa (kg), a de versnelling (m/s²).</div></div><div class=\"sam-head\">Hefboomwet (momenten)</div><p>Een <strong>moment</strong> is de draaikracht om een draaipunt: kracht maal arm (de loodrechte afstand van het draaipunt tot de werklijn). Een hefboom is in evenwicht als de momenten links en rechts gelijk zijn.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Hefboomwet</div><div class=\"sam-formula-eq\">F<sub>1</sub> · r<sub>1</sub> = F<sub>2</sub> · r<sub>2</sub></div><div class=\"sam-formula-note\">F de kracht (N), r de bijbehorende arm (m). In evenwicht zijn beide momenten gelijk.</div></div><div class=\"sam-head\">Arbeid, energie en vermogen</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Arbeid</div><div class=\"sam-formula-eq\">W = F · s</div><div class=\"sam-formula-note\">W de arbeid (J), F de kracht in de bewegingsrichting (N), s de verplaatsing (m). Een tegenwerkende kracht (wrijving) levert negatieve arbeid. In een (F,s)-diagram is de oppervlakte de arbeid.</div></div><table class=\"sam-table\"><thead><tr><th>Energievorm</th><th>Formule</th></tr></thead><tbody><tr><td>Kinetische energie</td><td>E<sub>k</sub> = ½ · m · v²</td></tr><tr><td>Zwaarte-energie</td><td>E<sub>z</sub> = m · g · h</td></tr><tr><td>Veerenergie</td><td>E<sub>v</sub> = ½ · C · u²</td></tr><tr><td>Chemische energie (vast)</td><td>E<sub>chem</sub> = r<sub>m</sub> · m</td></tr><tr><td>Chemische energie (vloeistof/gas)</td><td>E<sub>chem</sub> = r<sub>v</sub> · V</td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Vermogen</div><div class=\"sam-formula-eq\">P = W / t = F · v</div><div class=\"sam-formula-note\">P het vermogen (W = J/s), W de arbeid (J), t de tijd (s).</div></div><div class=\"sam-head\">Energiebehoud en rendement</div><p>Energie gaat nooit verloren, maar zet zich om van de ene vorm in de andere: de som van de toegevoerde energie is gelijk aan de som van de afgevoerde energie.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Wet van energiebehoud</div><div class=\"sam-formula-eq\">ΣE<sub>in</sub> = ΣE<sub>uit</sub></div><div class=\"sam-formula-note\">Voorbeeld vrije val: m·g·h = ½·m·v² &nbsp;→&nbsp; v = √(2·g·h).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Arbeid en kinetische energie</div><div class=\"sam-formula-eq\">W<sub>tot</sub> = ΔE<sub>k</sub></div><div class=\"sam-formula-note\">Positieve totale arbeid laat de kinetische energie (en snelheid) toenemen; negatieve arbeid laat die afnemen.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Rendement</div><div class=\"sam-formula-eq\">η = (E<sub>nuttig</sub> / E<sub>in</sub>) · 100%</div><div class=\"sam-formula-note\">Ook met vermogen: η = (P<sub>nuttig</sub> / P<sub>in</sub>) · 100%. Ligt altijd tussen 0% en 100%.</div></div><div class=\"sam-head\">Warmte en materie</div><p>Volgens het <strong>molecuulmodel</strong> bestaat alle materie uit bewegende moleculen met ruimte ertussen; hun rangschikking bepaalt de fase (vast, vloeibaar, gas). Smelten, verdampen en sublimeren kosten energie; stollen, condenseren en rijpen geven energie af.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Temperatuur in kelvin</div><div class=\"sam-formula-eq\">T(K) = T(°C) + 273,15</div><div class=\"sam-formula-note\">Het absolute nulpunt is 0 K = −273,15 °C; daar bewegen moleculen niet meer.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Soortelijke warmte</div><div class=\"sam-formula-eq\">Q = c · m · ΔT</div><div class=\"sam-formula-note\">Q de warmte (J), c de soortelijke warmte (J·kg⁻¹·K⁻¹, BiNaS), m de massa (kg), ΔT het temperatuurverschil.</div></div><div class=\"sam-head\">Warmtetransport</div><ul><li><strong>Geleiding</strong>: warmte door een vaste stof; metalen geleiden goed, isolatoren slecht.</li><li><strong>Stroming</strong>: warmte verplaatst met een bewegend gas of vloeistof; een vacuüm (dubbel glas) voorkomt dit.</li><li><strong>Straling</strong>: warmte zonder tussenstof, zoals zonnestraling; reflecterende oppervlakken kaatsen die terug.</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Warmtestroom</div><div class=\"sam-formula-eq\">P = λ · A · (ΔT / L)</div><div class=\"sam-formula-note\">P de warmtestroom (W), λ de warmtegeleidingscoëfficiënt (W·m⁻¹·K⁻¹), A de oppervlakte (m²), L de dikte (m).</div></div><div class=\"sam-tip\">Een <strong>warmtepomp</strong> verplaatst warmte in plaats van die op te wekken; daardoor kan de COP (= E<sub>nuttig</sub> / E<sub>in</sub>) groter dan 1 zijn — anders dan een gewoon rendement.</div><div class=\"sam-head\">Cirkelbeweging en gravitatie</div><p>Bij een <strong>eenparige cirkelbeweging</strong> beweegt een voorwerp met constante snelheid langs een cirkel. Een naar het middelpunt gerichte kracht (de middelpuntzoekende kracht) houdt het in de baan.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Omloopsnelheid</div><div class=\"sam-formula-eq\">v<sub>cirkel</sub> = (2π · r) / T</div><div class=\"sam-formula-note\">r de straal (m), T de omlooptijd (s). In één omloop wordt de omtrek 2πr afgelegd.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Middelpuntzoekende kracht</div><div class=\"sam-formula-eq\">F<sub>mpz</sub> = (m · v²) / r</div><div class=\"sam-formula-note\">m de massa (kg), v de baansnelheid (m/s), r de straal (m).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Gravitatiekracht</div><div class=\"sam-formula-eq\">F<sub>G</sub> = G · (m<sub>1</sub> · m<sub>2</sub>) / r²</div><div class=\"sam-formula-note\">G de gravitatieconstante (6,67·10⁻¹¹ m³·kg⁻¹·s⁻²), m₁ en m₂ de massa's (kg), r de afstand tussen de zwaartepunten (m). De zwaartekracht F<sub>z</sub> = m·g is hiervan een speciaal geval aan het aardoppervlak.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een bal van 0,50 kg valt van 20 m hoogte (luchtweerstand verwaarloosd, g = 9,81 m/s²). Bereken de snelheid vlak boven de grond.</div><ol class=\"sam-worked-steps\"><li>Energiebehoud: zwaarte-energie → kinetische energie: m·g·h = ½·m·v².</li><li>De massa valt weg: v = √(2 · g · h) = √(2 × 9,81 × 20) = √392,4.</li><li>v ≈ 19,8 m/s.</li></ol><div class=\"sam-worked-ans\">✅ v ≈ 20 m/s — de massa maakt bij vrije val niet uit.</div></div>","havo_na_D":"<div class=\"sam-intro\">Stroom is <strong>ladingstransport door een gesloten kring</strong>. Drie grootheden sturen alles aan — spanning U, stroom I en weerstand R — verbonden door de wet van Ohm (U = I·R).</div><div class=\"sam-head\">Lading en atoombouw</div><p>Een atoom heeft een positieve kern met daaromheen negatieve elektronen. In een metaal bewegen sommige elektronen vrij door het rooster van positieve ionen — die <strong>vrije elektronen</strong> dragen de elektrische stroom.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Elementaire lading</div><div class=\"sam-formula-eq\">e = 1,602·10⁻¹⁹ C</div><div class=\"sam-formula-note\">De lading van één proton (+) of elektron (−). Gelijksoortige ladingen stoten elkaar af, tegengestelde trekken elkaar aan.</div></div><ul><li>Een <strong>geleider</strong> (metaal) laat stroom goed door; een <strong>isolator</strong> (hout, kunststof) niet.</li><li>Meer protonen dan elektronen → positief ion; meer elektronen → negatief ion.</li></ul><div class=\"sam-head\">Stroomsterkte</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Stroomsterkte</div><div class=\"sam-formula-eq\">I = Q / t</div><div class=\"sam-formula-note\">I de stroomsterkte (ampère, A), Q de lading (coulomb, C), t de tijd (s).</div></div><div class=\"sam-tip\">De (afgesproken) stroomrichting loopt van plus naar min; de elektronen zelf bewegen van min naar plus. Een <strong>ampèremeter</strong> meet de stroom en staat in serie.</div><div class=\"sam-head\">Spanning en stroomkring</div><p><strong>Spanning</strong> (U, in volt) is het energieverschil per lading tussen twee punten. Een spanningsbron levert de energie om de elektronen te laten bewegen. Een <strong>voltmeter</strong> meet de spanning en staat parallel.</p><p>Een <strong>stroomkring</strong> is een gesloten pad: verbind je de plus- en minpool via een geleider, dan stromen de elektronen van min naar plus.</p><div class=\"sam-head\">Weerstand en de wet van Ohm</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Wet van Ohm</div><div class=\"sam-formula-eq\">R = U / I</div><div class=\"sam-formula-note\">R de weerstand (ohm, Ω), U de spanning (V), I de stroomsterkte (A).</div></div><ul><li><strong>Ohmse weerstand</strong>: R is constant; U en I zijn recht evenredig.</li><li><strong>Niet-ohmse weerstand</strong>: R verandert met spanning of temperatuur.</li></ul><div class=\"sam-head\">Serie- en parallelschakeling</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Serie</div><ul><li>Componenten achter elkaar</li><li>Stroom overal gelijk: I<sub>tot</sub> = I<sub>1</sub> = I<sub>2</sub></li><li>Spanning verdeeld: U<sub>tot</sub> = U<sub>1</sub> + U<sub>2</sub></li><li>R<sub>tot</sub> = R<sub>1</sub> + R<sub>2</sub> + …</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Parallel</div><ul><li>Componenten naast elkaar</li><li>Spanning overal gelijk: U<sub>tot</sub> = U<sub>1</sub> = U<sub>2</sub></li><li>Stroom splitst: I<sub>tot</sub> = I<sub>1</sub> + I<sub>2</sub></li><li>1/R<sub>tot</sub> = 1/R<sub>1</sub> + 1/R<sub>2</sub> + …</li></ul></div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 420 184\" role=\"img\" aria-label=\"Serie- en parallelschakeling\"><g stroke=\"var(--mu)\" stroke-width=\"1.8\" stroke-linecap=\"round\" fill=\"none\"><line x1=\"50\" y1=\"46\" x2=\"180\" y2=\"46\"/><line x1=\"180\" y1=\"46\" x2=\"180\" y2=\"140\"/><line x1=\"180\" y1=\"140\" x2=\"50\" y2=\"140\"/><line x1=\"50\" y1=\"46\" x2=\"50\" y2=\"88\"/><line x1=\"50\" y1=\"98\" x2=\"50\" y2=\"140\"/><line x1=\"240\" y1=\"46\" x2=\"390\" y2=\"46\"/><line x1=\"240\" y1=\"140\" x2=\"390\" y2=\"140\"/><line x1=\"390\" y1=\"46\" x2=\"390\" y2=\"140\"/><line x1=\"240\" y1=\"46\" x2=\"240\" y2=\"88\"/><line x1=\"240\" y1=\"98\" x2=\"240\" y2=\"140\"/><line x1=\"300\" y1=\"46\" x2=\"300\" y2=\"140\"/><line x1=\"350\" y1=\"46\" x2=\"350\" y2=\"140\"/></g><line x1=\"38\" y1=\"88\" x2=\"62\" y2=\"88\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"44\" y1=\"98\" x2=\"56\" y2=\"98\" stroke=\"var(--dk)\" stroke-width=\"3.5\"/><line x1=\"228\" y1=\"88\" x2=\"252\" y2=\"88\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"234\" y1=\"98\" x2=\"246\" y2=\"98\" stroke=\"var(--dk)\" stroke-width=\"3.5\"/><rect x=\"78\" y=\"39\" width=\"30\" height=\"14\" rx=\"2\" fill=\"var(--bg2)\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><rect x=\"122\" y=\"39\" width=\"30\" height=\"14\" rx=\"2\" fill=\"var(--bg2)\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><rect x=\"293\" y=\"79\" width=\"14\" height=\"30\" rx=\"2\" fill=\"var(--bg2)\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><rect x=\"343\" y=\"79\" width=\"14\" height=\"30\" rx=\"2\" fill=\"var(--bg2)\" stroke=\"var(--or)\" stroke-width=\"1.6\"/><text x=\"115\" y=\"26\" font-size=\"10.5\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">Serie</text><text x=\"315\" y=\"26\" font-size=\"10.5\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">Parallel</text><text x=\"93\" y=\"68\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">R₁</text><text x=\"137\" y=\"68\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">R₂</text><text x=\"284\" y=\"97\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">R₁</text><text x=\"366\" y=\"97\" font-size=\"9\" fill=\"var(--mu)\">R₂</text></svg><div class=\"sam-figcap\"><strong>Serie:</strong> één pad, de stroom is overal gelijk (R<sub>tot</sub> = R₁ + R₂). <strong>Parallel:</strong> aparte takken, de spanning is overal gelijk (1/R<sub>tot</sub> = 1/R₁ + 1/R₂).</div></div><div class=\"sam-head\">Vermogen en elektrische energie</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Elektrisch vermogen</div><div class=\"sam-formula-eq\">P = U · I</div><div class=\"sam-formula-note\">P het vermogen (watt, W), U de spanning (V), I de stroomsterkte (A). Ook P = E / t.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Elektrische energie</div><div class=\"sam-formula-eq\">E = P · t</div><div class=\"sam-formula-note\">E de energie (J), P het vermogen (W), t de tijd (s). 1 kWh = 1 kW gedurende 1 uur — een veelgebruikte eenheid voor verbruik.</div></div><div class=\"sam-head\">Opwekking en rendement</div><p>In een <strong>generator</strong> beweegt een spoel door een magneetveld en wordt elektrische energie opgewekt. Water-, verbrandings-, kern- en windcentrales drijven zo een turbine met spoel aan; een <strong>zonnecel</strong> zet zonlicht direct om in elektriciteit zonder bewegende delen.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Rendement</div><div class=\"sam-formula-eq\">η = (E<sub>nuttig</sub> / E<sub>in</sub>) · 100%</div><div class=\"sam-formula-note\">Of met vermogen: η = (P<sub>nuttig</sub> / P<sub>in</sub>) · 100%. Een ledlamp heeft een veel hoger rendement dan een gloeilamp.</div></div><div class=\"sam-head\">Elektriciteit in huis (veiligheid)</div><ul><li><strong>Zekering</strong>: smelt bij te hoge stroom (bijv. kortsluiting) en onderbreekt de kring.</li><li><strong>Aardlekschakelaar</strong>: onderbreekt de stroom bij een lekstroom (verschil tussen in- en uitgaande stroom) en beschermt tegen schokken.</li><li><strong>Isolatie</strong> van draden voorkomt lekstroom en schokken; een <strong>kWh-meter</strong> meet het verbruik.</li></ul><div class=\"sam-head\">Soortelijke en speciale weerstanden</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Soortelijke weerstand</div><div class=\"sam-formula-eq\">ρ = (R · A) / l</div><div class=\"sam-formula-note\">ρ de soortelijke weerstand (Ω·m), R de weerstand (Ω), A de doorsnede (m²), l de lengte (m). Een langere of dunnere draad heeft een hogere weerstand.</div></div><table class=\"sam-table\"><thead><tr><th>Component</th><th>Gedrag</th></tr></thead><tbody><tr><td>PTC</td><td>weerstand stijgt bij hogere temperatuur</td></tr><tr><td>NTC</td><td>weerstand daalt bij hogere temperatuur (thermometer)</td></tr><tr><td>LDR</td><td>weerstand daalt bij meer licht</td></tr><tr><td>Diode / LED</td><td>laat stroom maar in één richting door; een led geeft daarbij licht</td></tr></tbody></table><div class=\"sam-tip\"><strong>Transport</strong>: hoogspanning beperkt het energieverlies door weerstand over lange afstand; transformatoren verhogen de spanning voor transport en verlagen die weer voor veilig gebruik thuis.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Door een lampje loopt 0,50 A bij een spanning van 6,0 V. Bereken de weerstand en het vermogen.</div><ol class=\"sam-worked-steps\"><li>Wet van Ohm: R = U / I = 6,0 / 0,50 = 12 Ω.</li><li>Vermogen: P = U · I = 6,0 × 0,50 = 3,0 W.</li></ol><div class=\"sam-worked-ans\">✅ R = 12 Ω en P = 3,0 W.</div></div>","havo_na_E":"<div class=\"sam-intro\">Licht is zowel <strong>golf als deeltje (foton)</strong>, en instabiele kernen zenden <strong>ioniserende straling</strong> uit. Hogere frequentie = energierijker; meer afscherming en afstand = minder dosis.</div><div class=\"sam-head\">Elektromagnetisch spectrum</div><p>Elektromagnetische straling plant zich voort als golven van veranderende elektrische en magnetische velden — ook door vacuüm. Op golflengte gerangschikt vormt zij het EM-spectrum (van hoge naar lage energie):</p><div class=\"sam-figure\"><svg viewBox=\"0 0 420 150\" role=\"img\" aria-label=\"Het elektromagnetisch spectrum\"><defs><linearGradient id=\"emg\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\"><stop offset=\"0\" stop-color=\"#7c3aed\"/><stop offset=\"0.18\" stop-color=\"#2563eb\"/><stop offset=\"0.4\" stop-color=\"#22c55e\"/><stop offset=\"0.56\" stop-color=\"#eab308\"/><stop offset=\"0.76\" stop-color=\"#f97316\"/><stop offset=\"1\" stop-color=\"#ef4444\"/></linearGradient></defs><text x=\"20\" y=\"34\" font-size=\"8.5\" fill=\"var(--mu)\">◄ hoge energie · korte golflengte</text><text x=\"400\" y=\"34\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"end\">lage energie · lange golflengte ►</text><rect x=\"20\" y=\"46\" width=\"380\" height=\"26\" rx=\"4\" fill=\"url(#emg)\"/><g stroke=\"rgba(255,255,255,.55)\" stroke-width=\"1\"><line x1=\"74\" y1=\"46\" x2=\"74\" y2=\"72\"/><line x1=\"128\" y1=\"46\" x2=\"128\" y2=\"72\"/><line x1=\"182\" y1=\"46\" x2=\"182\" y2=\"72\"/><line x1=\"236\" y1=\"46\" x2=\"236\" y2=\"72\"/><line x1=\"290\" y1=\"46\" x2=\"290\" y2=\"72\"/><line x1=\"344\" y1=\"46\" x2=\"344\" y2=\"72\"/></g><g font-size=\"8\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"47\" y=\"88\">γ-straling</text><text x=\"101\" y=\"88\">Röntgen</text><text x=\"155\" y=\"88\">UV</text><text x=\"209\" y=\"88\">Zichtbaar</text><text x=\"263\" y=\"88\">Infrarood</text><text x=\"317\" y=\"88\">Microgolf</text><text x=\"371\" y=\"88\">Radio</text></g></svg><div class=\"sam-figcap\"><strong>EM-spectrum:</strong> alle straling is hetzelfde verschijnsel, gerangschikt op golflengte — van energierijke gammastraling tot energiearme radiogolven.</div></div><table class=\"sam-table\"><thead><tr><th>Soort</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Gammastraling</td><td>kernreacties (hoogste energie, kortste golflengte)</td></tr><tr><td>Röntgenstraling</td><td>medische scans</td></tr><tr><td>Ultraviolet</td><td>zonnestraling</td></tr><tr><td>Zichtbaar licht</td><td>daglicht</td></tr><tr><td>Infrarood</td><td>warmtestraling / warmtecamera</td></tr><tr><td>Microgolven</td><td>magnetron</td></tr><tr><td>Radiogolven</td><td>zenders (laagste energie, langste golflengte)</td></tr></tbody></table><div class=\"sam-head\">Fotonen</div><p>EM-straling gedraagt zich ook als deeltjes: <strong>fotonen</strong>. De energie van een foton hangt af van de frequentie.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Fotonenergie</div><div class=\"sam-formula-eq\">E = h · f = (h · c) / λ</div><div class=\"sam-formula-note\">E de fotonenergie (J), h de constante van Planck (6,626·10⁻³⁴ J·s), f de frequentie (Hz), c de lichtsnelheid, λ de golflengte (m).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Elektronvolt</div><div class=\"sam-formula-eq\">1 eV = 1,602·10⁻¹⁹ J</div><div class=\"sam-formula-note\">Een handige energie-eenheid op atoomschaal. Hogere frequentie (kortere golflengte) betekent een energierijker foton.</div></div><div class=\"sam-head\">Ioniserende straling</div><p><strong>Ioniserende straling</strong> kan elektronen uit atomen losmaken. Er zijn drie soorten, met verschillend doordringend en ioniserend vermogen.</p><table class=\"sam-table\"><thead><tr><th>Soort</th><th>Bestaat uit</th><th>Doordringend vermogen</th></tr></thead><tbody><tr><td>Alfa (α)</td><td>heliumkern (2 p + 2 n)</td><td>gering (sterk ioniserend)</td></tr><tr><td>Bèta (β)</td><td>elektron</td><td>middelmatig</td></tr><tr><td>Gamma (γ)</td><td>foton (EM-straling)</td><td>groot (zwak ioniserend)</td></tr></tbody></table><div class=\"sam-figure\"><svg viewBox=\"0 0 420 176\" role=\"img\" aria-label=\"Doordringend vermogen van alfa-, bèta- en gammastraling\"><defs><marker id=\"naR\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><rect x=\"22\" y=\"74\" width=\"20\" height=\"40\" rx=\"3\" fill=\"var(--or)\"/><text x=\"32\" y=\"128\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">bron</text><rect x=\"128\" y=\"40\" width=\"5\" height=\"100\" fill=\"rgba(120,130,150,.4)\"/><rect x=\"236\" y=\"40\" width=\"10\" height=\"100\" fill=\"rgba(120,130,150,.6)\"/><rect x=\"346\" y=\"40\" width=\"17\" height=\"100\" fill=\"rgba(70,80,100,.85)\"/><text x=\"130\" y=\"156\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">papier</text><text x=\"241\" y=\"156\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">aluminium</text><text x=\"354\" y=\"156\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">lood</text><line x1=\"44\" y1=\"58\" x2=\"126\" y2=\"58\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naR)\"/><text x=\"50\" y=\"51\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">α</text><line x1=\"44\" y1=\"94\" x2=\"234\" y2=\"94\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naR)\"/><text x=\"50\" y=\"87\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">β</text><line x1=\"44\" y1=\"130\" x2=\"408\" y2=\"130\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naR)\"/><text x=\"50\" y=\"123\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">γ</text></svg><div class=\"sam-figcap\"><strong>Doordringend vermogen:</strong> α-straling wordt al door een vel papier tegengehouden, β door een laagje aluminium, en γ pas (deels) door dik lood.</div></div><p>De <strong>dracht</strong> is de dikte waarbinnen alle alfa- of bètadeeltjes worden geabsorbeerd. Opname van straling heet <strong>absorptie</strong>, uitzending <strong>emissie</strong>. Natuurlijke bronnen zijn achtergrondstraling (uit de aarde) en kosmische straling (uit het heelal).</p><div class=\"sam-head\">Atoombouw en radioactief verval</div><p>Het atoomnummer Z is het aantal protonen, N het aantal neutronen. Atomen met gelijk Z maar verschillend massagetal zijn <strong>isotopen</strong>.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Massagetal</div><div class=\"sam-formula-eq\">A = Z + N</div><div class=\"sam-formula-note\">A het massagetal (protonen + neutronen), Z het atoomnummer (protonen), N het aantal neutronen. Notatie van een kern: <sub>Z</sub><sup>A</sup>X.</div></div><ul><li><strong>Alfaverval</strong>: de kern stoot een heliumkern uit; Z daalt met 2, A met 4 → ander element.</li><li><strong>Bètaverval</strong>: een neutron wordt een proton plus een elektron (dat wordt uitgezonden); Z stijgt met 1, A blijft gelijk → ander element.</li></ul><div class=\"sam-head\">Vervalreacties</div><p>Bij een vervalreactie blijven <strong>lading</strong> (onder) en <strong>massa</strong> (boven) behouden: de som links is gelijk aan de som rechts.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Voorbeeld: bètaverval van C-14</div><div class=\"sam-formula-eq\"><sub>6</sub><sup>14</sup>C → <sub>7</sub><sup>14</sup>N + <sub>−1</sub><sup>&nbsp;0</sup>e</div><div class=\"sam-formula-note\">Massagetal 14 = 14 + 0, lading 6 = 7 + (−1). Koolstof wordt stikstof.</div></div><div class=\"sam-head\">Activiteit en halveringstijd</div><p>De <strong>activiteit</strong> A (in s⁻¹, becquerel) is het aantal kernen dat per seconde vervalt. De <strong>halveringstijd</strong> t<sub>½</sub> is de tijd waarin de helft vervalt. In een (N,t)-diagram is de helling de activiteit: A = −ΔN/Δt.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 198\" role=\"img\" aria-label=\"Radioactief verval: aantal kernen tegen de tijd met halveringstijd\"><defs><marker id=\"naD\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><g stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"><line x1=\"46\" y1=\"104\" x2=\"115\" y2=\"104\"/><line x1=\"115\" y1=\"104\" x2=\"115\" y2=\"168\"/><line x1=\"46\" y1=\"136\" x2=\"184\" y2=\"136\"/><line x1=\"184\" y1=\"136\" x2=\"184\" y2=\"168\"/></g><line x1=\"46\" y1=\"170\" x2=\"46\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#naD)\"/><line x1=\"44\" y1=\"168\" x2=\"322\" y2=\"168\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#naD)\"/><path d=\"M46.0,40.0 L48.3,42.9 L50.6,45.8 L52.9,48.6 L55.2,51.3 L57.5,54.0 L59.8,56.6 L62.1,59.1 L64.4,61.6 L66.7,64.0 L69.0,66.4 L71.3,68.7 L73.6,71.0 L75.9,73.2 L78.2,75.4 L80.5,77.5 L82.8,79.6 L85.1,81.6 L87.4,83.6 L89.7,85.5 L92.0,87.4 L94.3,89.2 L96.6,91.0 L98.9,92.8 L101.2,94.5 L103.5,96.2 L105.8,97.8 L108.1,99.4 L110.4,101.0 L112.7,102.5 L115.0,104.0 L117.3,105.5 L119.6,106.9 L121.9,108.3 L124.2,109.6 L126.5,111.0 L128.8,112.3 L131.1,113.6 L133.4,114.8 L135.7,116.0 L138.0,117.2 L140.3,118.4 L142.6,119.5 L144.9,120.6 L147.2,121.7 L149.5,122.7 L151.8,123.8 L154.1,124.8 L156.4,125.8 L158.7,126.7 L161.0,127.7 L163.3,128.6 L165.6,129.5 L167.9,130.4 L170.2,131.2 L172.5,132.1 L174.8,132.9 L177.1,133.7 L179.4,134.5 L181.7,135.3 L184.0,136.0 L186.3,136.7 L188.6,137.4 L190.9,138.1 L193.2,138.8 L195.5,139.5 L197.8,140.1 L200.1,140.8 L202.4,141.4 L204.7,142.0 L207.0,142.6 L209.3,143.2 L211.6,143.7 L213.9,144.3 L216.2,144.8 L218.5,145.4 L220.8,145.9 L223.1,146.4 L225.4,146.9 L227.7,147.4 L230.0,147.8 L232.3,148.3 L234.6,148.8 L236.9,149.2 L239.2,149.6 L241.5,150.0 L243.8,150.5 L246.1,150.9 L248.4,151.2 L250.7,151.6 L253.0,152.0 L255.3,152.4 L257.6,152.7 L259.9,153.1 L262.2,153.4 L264.5,153.7 L266.8,154.1 L269.1,154.4 L271.4,154.7 L273.7,155.0 L276.0,155.3 L278.3,155.6 L280.6,155.9 L282.9,156.2 L285.2,156.4 L287.5,156.7 L289.8,156.9 L292.1,157.2 L294.4,157.4 L296.7,157.7 L299.0,157.9 L301.3,158.2 L303.6,158.4 L305.9,158.6 L308.2,158.8 L310.5,159.0 L312.8,159.2 L315.1,159.4 L317.4,159.6 L319.7,159.8 L322.0,160.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><text x=\"40\" y=\"44\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">N₀</text><text x=\"40\" y=\"107\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">N₀/2</text><text x=\"40\" y=\"139\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">N₀/4</text><text x=\"115\" y=\"182\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">t½</text><text x=\"184\" y=\"182\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">2·t½</text><text x=\"20\" y=\"100\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 20 100)\">kernen N</text><text x=\"300\" y=\"184\" font-size=\"9.5\" fill=\"var(--mu)\">tijd t</text></svg><div class=\"sam-figcap\"><strong>Halveringstijd t½:</strong> elke t½ halveert het aantal kernen (N₀ → N₀/2 → N₀/4 …). De kromme daalt exponentieel, nooit helemaal tot nul.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Aantal overgebleven kernen</div><div class=\"sam-formula-eq\">N = N<sub>0</sub> · (½)^(t / t<sub>½</sub>)</div><div class=\"sam-formula-note\">N de overgebleven kernen, N₀ het aantal op t = 0, t de tijd, t<sub>½</sub> de halveringstijd (zelfde tijdseenheid als t).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Activiteit in de tijd</div><div class=\"sam-formula-eq\">A = A<sub>0</sub> · (½)^(t / t<sub>½</sub>)</div><div class=\"sam-formula-note\">A₀ de activiteit op t = 0. Dezelfde halveringswet als voor het aantal kernen.</div></div><div class=\"sam-head\">Absorptie en halveringsdikte</div><p>Een <strong>doorlaatkromme</strong> toont hoeveel straling overblijft na een bepaalde dikte materiaal. De <strong>halveringsdikte</strong> d<sub>½</sub> is de dikte waarna nog de helft over is (hangt af van energie en dichtheid).</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Stralingsintensiteit</div><div class=\"sam-formula-eq\">I = I<sub>0</sub> · (½)^(d / d<sub>½</sub>)</div><div class=\"sam-formula-note\">I de intensiteit na dikte d, I₀ de intensiteit van de bron, d<sub>½</sub> de halveringsdikte (m).</div></div><div class=\"sam-head\">Stralingsrisico: dosis en dosisequivalent</div><p><strong>Besmetting</strong>: radioactieve stof komt in of op het lichaam (straalt door). <strong>Bestraling</strong>: straling van buitenaf, stopt zodra de bron weg is. Ioniserende straling kan cellen en DNA beschadigen.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Stralingsdosis</div><div class=\"sam-formula-eq\">D = E / m</div><div class=\"sam-formula-note\">D de dosis (gray, Gy = J/kg), E de geabsorbeerde stralingsenergie (J), m de massa (kg).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Dosisequivalent</div><div class=\"sam-formula-eq\">H = w<sub>R</sub> · D</div><div class=\"sam-formula-note\">H het dosisequivalent (sievert, Sv), w<sub>R</sub> de weegfactor (20 voor alfa, 1 voor bèta en gamma), D de dosis (Gy).</div></div><div class=\"sam-head\">Bescherming en medische beeldvorming</div><p>Bescherm je tegen straling door <strong>afstand</strong> te vergroten, <strong>blootstellingstijd</strong> te verkorten en bronnen af te <strong>schermen</strong> (bijv. loodschort). Een dosimeter meet de ontvangen dosis.</p><table class=\"sam-table\"><thead><tr><th>Techniek</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Röntgenfoto</td><td>snel, vooral botten en longen; stralingsrisico</td></tr><tr><td>CT-scan</td><td>gedetailleerd 3D-beeld; hogere stralingsdosis</td></tr><tr><td>Echografie</td><td>geluidsgolven; veilig (geen ioniserende straling), lagere beeldkwaliteit</td></tr><tr><td>Nucleair (PET)</td><td>radioactieve tracer; tijdelijke besmetting van het lichaam</td></tr></tbody></table><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een bron heeft een activiteit van 800 Bq en een halveringstijd van 8 dagen. Bereken de activiteit na 24 dagen.</div><ol class=\"sam-worked-steps\"><li>Aantal halveringstijden: n = t / t<sub>½</sub> = 24 / 8 = 3.</li><li>A = A<sub>0</sub> · (½)ⁿ = 800 × (½)³ = 800 × ⅛.</li><li>A = 100 Bq.</li></ol><div class=\"sam-worked-ans\">✅ Na 24 dagen is de activiteit 100 Bq.</div></div>","havo_nl_A":"<div class=\"sam-head\">Signaalwoorden</div><table class=\"sam-table\"><thead><tr><th>Type verband</th><th>Signaalwoorden</th></tr></thead><tbody><tr><td><strong>Oorzaak–gevolg</strong></td><td>daardoor, dus, zodat, waardoor, als gevolg hiervan, vandaar, wat leidt tot</td></tr><tr><td><strong>Tegenstelling</strong></td><td>maar, echter, toch, terwijl, integendeel, daarentegen, in tegenstelling tot</td></tr><tr><td><strong>Toevoeging</strong></td><td>bovendien, daarnaast, ook, tevens, zelfs, niet alleen … maar ook</td></tr><tr><td><strong>Concessie</strong></td><td>weliswaar, hoewel, ondanks, ook al, zij het dat, toegegeven</td></tr><tr><td><strong>Volgorde</strong></td><td>ten eerste, vervolgens, ten slotte, enerzijds … anderzijds</td></tr><tr><td><strong>Conclusie</strong></td><td>kortom, dus, al met al, met andere woorden, samenvattend</td></tr></tbody></table><div class=\"sam-head\">Tekstsoorten</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Betoog</div><ul><li>Doel: één standpunt verdedigen</li><li>Eenzijdig — kiest positie</li><li>Stelling → argumenten → conclusie</li><li>Toon: stellig, overtuigend</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Beschouwing</div><ul><li>Doel: vraagstuk van meerdere kanten belichten</li><li>Meerzijdig — geen hard standpunt</li><li>Probleemstelling → perspectieven → nuance</li><li>Toon: genuanceerd, analytisch</li></ul></div></div><div class=\"sam-head\">Argumentatiestructuren</div><ul><li><strong>Enkelvoudig</strong>: één argument ondersteunt het standpunt direct.</li><li><strong>Meervoudig</strong>: meerdere onafhankelijke argumenten; elk staat op zichzelf. Wegvallen van één laat de andere geldig.</li><li><strong>Onderschikkend (ketting)</strong>: argument A wordt onderbouwd door sub-argument B. Breek je één schakel, valt het standpunt.</li><li><strong>Concessie + weerlegging</strong>: auteur erkent tegenargument (\"weliswaar X\") maar handhaaft standpunt (\"toch Y\"). Verhoogt geloofwaardigheid.</li></ul><div class=\"sam-tip\">Bepaal bij een examentekst altijd eerst het communicatieve doel: wil de auteur overtuigen of informeren? Dit bepaalt de tekstsoort en hoe je de hoofdgedachte formuleert.</div><div class=\"sam-warn\">Hoofdgedachte ≠ onderwerp. \"Sociale media\" is het onderwerp. \"Sociale media vergroot eenzaamheid bij jongeren\" is de hoofdgedachte — een standpunt of bewering over het onderwerp.</div>","havo_nl_E":"<div class=\"sam-head\">Argumentatieschema's</div><table class=\"sam-table\"><thead><tr><th>Schema</th><th>Definitie</th><th>Drogreden (valkuil)</th></tr></thead><tbody><tr><td><strong>Oorzaak–gevolg</strong></td><td>A veroorzaakt B</td><td>Andere oorzaken worden genegeerd</td></tr><tr><td><strong>Kenmerk</strong></td><td>X heeft eigenschap Y, hoort dus in categorie Z</td><td>De eigenschap klopt niet of is niet relevant</td></tr><tr><td><strong>Vergelijking</strong></td><td>A is vergelijkbaar met B, dus geldt voor A wat voor B geldt</td><td>Situaties wijken op relevante punten af</td></tr><tr><td><strong>Voorbeeld (inductie)</strong></td><td>X is een goed voorbeeld van Y, dus geldt Y algemeen</td><td>Overhaaste generalisatie: te weinig gevallen</td></tr><tr><td><strong>Autoriteit</strong></td><td>Deskundige Z zegt X, dus klopt X</td><td>Bron is niet deskundig of heeft een belang</td></tr></tbody></table><div class=\"sam-head\">Drogredenen</div><table class=\"sam-table\"><thead><tr><th>Drogreden</th><th>Wat is het?</th><th>Voorbeeld</th></tr></thead><tbody><tr><td><strong>Overhaaste generalisatie</strong></td><td>Van te weinig gevallen een algemene conclusie trekken</td><td>\"Mijn neef rijdt gevaarlijk, dus jongeren rijden slecht\"</td></tr><tr><td><strong>Cirkelredenering</strong></td><td>Standpunt wordt als bewijs voor zichzelf gebruikt</td><td>\"Cannabis moet legaal zijn want het verbod is onzinnig — en het verbod is onzinnig want het moet legaal zijn\"</td></tr><tr><td><strong>Ad hominem</strong></td><td>Persoon aanvallen in plaats van het argument</td><td>\"Jij kunt niets over eerlijkheid zeggen, want jij hebt zelf ook gelogen\"</td></tr><tr><td><strong>Vals dilemma</strong></td><td>Slechts twee opties presenteren, terwijl er meer zijn</td><td>\"Je bent voor ons of tegen ons — er is niets tussenin\"</td></tr><tr><td><strong>Gezagsdrogreden</strong></td><td>Beroep op autoriteit die niet deskundig is op dit terrein</td><td>\"Een voetballer beveelt dit supplement aan\"</td></tr><tr><td><strong>Stroman</strong></td><td>Standpunt van tegenstander overdrijven of vervormen</td><td>\"Wie minder vlees wil eten, wil dat we allemaal verhongeren\"</td></tr></tbody></table><div class=\"sam-tip\">Noem bij een drogreden altijd: (1) de naam, (2) waarom de redenering schijnbaar geldig lijkt, (3) waarom het toch niet klopt. Alleen de naam noemen levert weinig punten op.</div><div class=\"sam-warn\">Een drogreden is een logische fout in de redenering, niet per se een feitelijk onjuiste bewering. Een argument kan feitelijk correct zijn maar toch als drogreden functioneren.</div>","havo_wa_B":"<div class=\"sam-intro\">Domein B is je <strong>gereedschapskist</strong>: rekenregels, machten, wortels en haakjes om elke formule te herleiden &#8212; plus de telregels (permutaties en combinaties) om mogelijkheden te tellen.</div><div class=\"sam-head\">Rekenen met breuken</div><ul><li><strong>Optellen/aftrekken</strong>: maak eerst gelijknamig, dan tellers optellen: a/b + c/d = (a&#183;d + c&#183;b)/(b&#183;d).</li><li><strong>Vermenigvuldigen</strong>: teller &#215; teller, noemer &#215; noemer.</li><li><strong>Delen</strong>: delen door een breuk = vermenigvuldigen met het omgekeerde.</li><li><strong>Vereenvoudigen</strong>: deel teller en noemer door hun grootste gemene deler.</li></ul><div class=\"sam-head\">Rekenregels voor machten</div><table class=\"sam-table\"><thead><tr><th>Regel</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>x&#8304; = 1</td><td>6&#8304; = 1</td></tr><tr><td>x&#7491; &#183; x&#7495; = x&#7491;&#8314;&#7495;</td><td>5&#179; &#183; 5&#8310; = 5&#8313;</td></tr><tr><td>x&#7491; / x&#7495; = x&#7491;&#8315;&#7495;</td><td>x&#8309;/x&#179; = x&#178;</td></tr><tr><td>(x&#7491;)&#7495; = x&#7491;&#183;&#7495;</td><td>(x&#178;)&#8308; = x&#8312;</td></tr><tr><td>x&#8315;&#8319; = 1/x&#8319;</td><td>2&#8315;&#179; = 1/8</td></tr><tr><td>&#7495;&#8730;(x&#7491;) = x&#7491;&#7341;&#7495;</td><td>&#8730;x = x&#185;&#7339;&#178;</td></tr></tbody></table><div class=\"sam-head\">Wortels en haakjes</div><ul><li>&#8730;(x&#183;y) = &#8730;x &#183; &#8730;y &nbsp;|&nbsp; &#8730;(x/y) = &#8730;x / &#8730;y.</li><li>Enkele haakjes: a(b + c) = ab + ac.</li><li>Dubbele haakjes: (a + b)(c + d) = ac + ad + bc + bd.</li><li>Merkwaardig: (x + a)(x + b) = x&#178; + (a + b)x + ab.</li></ul><div class=\"sam-head\">Procenten</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Percentage</div><div class=\"sam-formula-eq\">percentage = (deel / geheel) &#215; 100%</div><div class=\"sam-formula-note\">Het woord <strong>van</strong> of <strong>dan</strong> staat altijd v&#243;&#243;r het geheel (= 100%).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Procentuele verandering</div><div class=\"sam-formula-eq\">((nieuw &#8722; oud) / oud) &#215; 100%</div><div class=\"sam-formula-note\">Een toename met p% hoort bij groeifactor 1 + p/100; een afname bij 1 &#8722; p/100.</div></div><div class=\"sam-head\">Telproblemen</div><p>De <strong>vermenigvuldigingsregel</strong>: het totale aantal mogelijkheden is het product van het aantal keuzes per stap. Kies daarna de juiste telregel:</p><table class=\"sam-table\"><thead><tr><th>Volgorde belangrijk?</th><th>Herhaling toegestaan?</th><th>Aantal manieren (k uit n)</th></tr></thead><tbody><tr><td>Ja</td><td>Ja</td><td>n&#7495;</td></tr><tr><td>Ja</td><td>Nee (permutatie)</td><td>n! / (n &#8722; k)!</td></tr><tr><td>Nee (combinatie)</td><td>Nee</td><td>n! / (k! &#183; (n &#8722; k)!) = nCr</td></tr></tbody></table><div class=\"sam-tip\">Faculteit: n! = 1 &#215; 2 &#215; 3 &#215; &#8230; &#215; n. Op de grafische rekenmachine bereken je een combinatie met de <strong>nCr</strong>-knop en een permutatie met <strong>nPr</strong>.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">&#9999;&#65039; Voorbeeldopgave</div><div class=\"sam-worked-q\">Uit een groep van 17 mensen worden 4 gekozen voor een commissie. De volgorde maakt niet uit. Hoeveel verschillende viertallen zijn mogelijk?</div><ol class=\"sam-worked-steps\"><li>Volgorde maakt niet uit en geen herhaling &#8594; combinatie.</li><li>Aantal = n! / (k!&#183;(n&#8722;k)!) met n = 17 en k = 4.</li><li>Op de GR: 17 nCr 4.</li></ol><div class=\"sam-worked-ans\">&#9989; Er zijn 2380 verschillende viertallen.</div></div><div class=\"sam-warn\">Let bij telproblemen altijd eerst op de twee vragen: doet de <strong>volgorde</strong> ertoe, en mag je een object <strong>opnieuw</strong> gebruiken? Daarmee kies je de juiste formule.</div>","havo_wa_C":"<div class=\"sam-intro\">In domein C herken je <strong>welk verband</strong> achter een tabel, grafiek of formule zit &#8212; recht/omgekeerd evenredig, lineair of exponentieel &#8212; en stel je de bijbehorende formule op.</div><div class=\"sam-head\">Soorten verbanden</div><div class=\"sam-figure\"><svg viewBox=\"0 0 414 222\" role=\"img\" aria-label=\"Soorten verbanden\"><line x1=\"34\" y1=\"96\" x2=\"34\" y2=\"28\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"34\" y1=\"96\" x2=\"194\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M34.0,96.0 L38.4,94.1 L42.8,92.2 L47.2,90.4 L51.6,88.5 L56.1,86.6 L60.5,84.7 L64.9,82.8 L69.3,80.9 L73.7,79.1 L78.1,77.2 L82.5,75.3 L86.9,73.4 L91.4,71.5 L95.8,69.6 L100.2,67.8 L104.6,65.9 L109.0,64.0 L113.4,62.1 L117.8,60.2 L122.2,58.4 L126.6,56.5 L131.1,54.6 L135.5,52.7 L139.9,50.8 L144.3,48.9 L148.7,47.1 L153.1,45.2 L157.5,43.3 L161.9,41.4 L166.4,39.5 L170.8,37.6 L175.2,35.8 L179.6,33.9 L184.0,32.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"109\" y=\"114\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Recht evenredig (y = a&#183;x)</text><line x1=\"244\" y1=\"96\" x2=\"244\" y2=\"14\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"244\" y1=\"96\" x2=\"404\" y2=\"96\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M263.5,20.5 L267.3,30.2 L271.2,39.5 L275.0,46.5 L278.9,51.9 L282.7,56.3 L286.5,59.9 L290.4,62.9 L294.2,65.4 L298.0,67.6 L301.9,69.5 L305.7,71.1 L309.6,72.6 L313.4,73.9 L317.2,75.0 L321.1,76.1 L324.9,77.0 L328.8,77.9 L332.6,78.7 L336.4,79.4 L340.3,80.0 L344.1,80.7 L347.9,81.2 L351.8,81.7 L355.6,82.2 L359.5,82.7 L363.3,83.1 L367.1,83.5 L371.0,83.9 L374.8,84.3 L378.6,84.6 L382.5,84.9 L386.3,85.2 L390.2,85.5 L394.0,85.8\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"323\" y=\"114\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Omgekeerd (y = a/x)</text><line x1=\"34\" y1=\"196\" x2=\"34\" y2=\"128\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"34\" y1=\"196\" x2=\"194\" y2=\"196\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M34.0,181.9 L38.4,180.8 L42.8,179.6 L47.2,178.4 L51.6,177.3 L56.1,176.1 L60.5,174.9 L64.9,173.8 L69.3,172.6 L73.7,171.4 L78.1,170.2 L82.5,169.1 L86.9,167.9 L91.4,166.7 L95.8,165.6 L100.2,164.4 L104.6,163.2 L109.0,162.1 L113.4,160.9 L117.8,159.7 L122.2,158.6 L126.6,157.4 L131.1,156.2 L135.5,155.1 L139.9,153.9 L144.3,152.7 L148.7,151.6 L153.1,150.4 L157.5,149.2 L161.9,148.1 L166.4,146.9 L170.8,145.7 L175.2,144.6 L179.6,143.4 L184.0,142.2\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"109\" y=\"214\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Lineair (y = a&#183;x + b)</text><line x1=\"244\" y1=\"196\" x2=\"244\" y2=\"128\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><line x1=\"244\" y1=\"196\" x2=\"404\" y2=\"196\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><path d=\"M244.0,191.4 L248.4,191.0 L252.8,190.6 L257.2,190.2 L261.6,189.7 L266.1,189.2 L270.5,188.7 L274.9,188.1 L279.3,187.5 L283.7,186.8 L288.1,186.0 L292.5,185.2 L296.9,184.4 L301.4,183.4 L305.8,182.4 L310.2,181.3 L314.6,180.1 L319.0,178.9 L323.4,177.5 L327.8,176.0 L332.2,174.4 L336.6,172.6 L341.1,170.7 L345.5,168.7 L349.9,166.5 L354.3,164.1 L358.7,161.6 L363.1,158.8 L367.5,155.8 L371.9,152.6 L376.4,149.1 L380.8,145.3 L385.2,141.2 L389.6,136.8 L394.0,132.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.2\" stroke-linecap=\"round\"/><text x=\"323\" y=\"214\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Exponentieel (y = b&#183;g&#8339;)</text></svg><div class=\"sam-figcap\"><strong>Herken het verband aan de vorm:</strong> rechte lijn door (0,0), hyperbool, schuine rechte lijn of een steeds sneller stijgende kromme.</div></div><div class=\"sam-head\">Recht en omgekeerd evenredig</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Recht evenredig</div><ul><li>y = a&#183;x</li><li>rechte lijn door (0,0)</li><li>x wordt k&#215; zo groot &#8594; y ook k&#215;</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Omgekeerd evenredig</div><ul><li>y = a/x</li><li>dalende hyperbool</li><li>x wordt k&#215; zo groot &#8594; y k&#215; zo klein</li></ul></div></div><div class=\"sam-head\">Lineair verband</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Lineaire formule</div><div class=\"sam-formula-eq\">y = a&#183;x + b</div><div class=\"sam-formula-note\">a = hellingsgetal/richtingsco&#235;ffici&#235;nt, b = startwaarde (snijpunt met de y-as). Gelijke toename per stap in de tabel.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Richtingsco&#235;ffici&#235;nt</div><div class=\"sam-formula-eq\">a = &#916;y / &#916;x</div><div class=\"sam-formula-note\">Neem twee punten en deel het verschil in y door het verschil in x.</div></div><p><strong>Formule opstellen</strong>: (1) bereken a, (2) vul een bekend punt in, (3) bereken b, (4) maak de formule compleet.</p><div class=\"sam-head\">Exponentieel verband</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Exponenti&#235;le groei</div><div class=\"sam-formula-eq\">N = b &#183; g&#7511;</div><div class=\"sam-formula-note\">b = startwaarde, g = groeifactor, t = tijd. g &gt; 1: groei &nbsp;|&nbsp; g &lt; 1: krimp.</div></div><ul><li><strong>Groeifactor</strong> per stap = nieuw / oud (steeds hetzelfde bij exponentieel).</li><li><strong>Verdubbelingstijd</strong>: los g&#7511; = 2 op. &nbsp; <strong>Halveringstijd</strong>: los g&#7511; = 0,5 op (met de GR via intersect).</li><li><strong>Verzadiging</strong>: bij heel grote t nadert g&#7511; naar 0; de hoeveelheid loopt dan tegen een maximum aan.</li></ul><div class=\"sam-head\">Vergelijkingen en snijpunten</div><ul><li><strong>Balansmethode</strong>: doe aan beide kanten dezelfde bewerking.</li><li>A &#183; B = 0 &#8594; A = 0 of B = 0.</li><li><strong>Snijpunt</strong> van twee grafieken: stel de formules aan elkaar gelijk (of gebruik intersect op de GR).</li><li>Snijpunt met de x-as: stel f(x) = 0. Snijpunt met de y-as: vul x = 0 in.</li></ul><div class=\"sam-tip\"><strong>Interpoleren</strong> = schatten binnen de gemeten waarden; <strong>extrapoleren</strong> = schatten buiten de gemeten waarden (onzekerder).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">&#9999;&#65039; Voorbeeldopgave</div><div class=\"sam-worked-q\">Bij een ticketprijs van &#8364;40 worden 130 kaartjes verkocht, bij &#8364;50 nog maar 50. Het verband is lineair. Stel de formule q = a&#183;p + b op (q = aantal, p = prijs).</div><ol class=\"sam-worked-steps\"><li>Richtingsco&#235;ffici&#235;nt: a = (130 &#8722; 50)/(40 &#8722; 50) = 80 / &#8722;10 = &#8722;8.</li><li>Vul een punt in, bijv. p = 40, q = 130: 130 = &#8722;8&#183;40 + b.</li><li>130 = &#8722;320 + b, dus b = 450.</li></ol><div class=\"sam-worked-ans\">&#9989; De formule is q = &#8722;8&#183;p + 450.</div></div><div class=\"sam-warn\">Koppel je modeluitkomst altijd terug naar de context: een negatieve hoeveelheid of een prijs buiten het bereik is meestal onrealistisch.</div>","havo_wa_D":"<div class=\"sam-intro\">Domein D draait om <strong>hoe snel iets verandert</strong>: van de gemiddelde helling (differentiequoti&#235;nt) naar de helling in &#233;&#233;n punt (raaklijn), en de hellinggrafiek die laat zien waar een functie stijgt of daalt. <em>(Domein D telt alleen mee voor het SE.)</em></div><div class=\"sam-head\">Stijgen en dalen</div><table class=\"sam-table\"><thead><tr><th>Type</th><th>Betekenis</th></tr></thead><tbody><tr><td>Toenemende stijging</td><td>stijgt steeds sneller</td></tr><tr><td>Afnemende stijging</td><td>stijgt, maar steeds langzamer</td></tr><tr><td>Toenemende daling</td><td>daalt steeds sneller</td></tr><tr><td>Afnemende daling</td><td>daalt, maar steeds langzamer</td></tr></tbody></table><div class=\"sam-head\">Differentie en differentiequoti&#235;nt</div><ul><li><strong>Differentie</strong>: een verschil op een interval. &#916;x = verschil op de x-as, &#916;y = verschil op de y-as.</li><li>Een <strong>toenamediagram</strong> zet de differenties van opeenvolgende intervallen in een staafdiagram.</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Differentiequoti&#235;nt</div><div class=\"sam-formula-eq\">a = &#916;y / &#916;x = (y_b &#8722; y_a)/(x_b &#8722; x_a)</div><div class=\"sam-formula-note\">De gemiddelde helling van een functie over een interval &#8212; oftewel hoogteverschil gedeeld door breedteverschil.</div></div><div class=\"sam-head\">Raaklijn en hellinggrafiek</div><p>Een <strong>raaklijn</strong> raakt de grafiek in &#233;&#233;n punt; haar helling is de helling van de grafiek in dat punt. Kies twee punten op de raaklijn en bereken het differentiequoti&#235;nt.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 400 238\" role=\"img\" aria-label=\"Functie en bijbehorende hellinggrafiek\"><defs><marker id=\"hl\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"36\" y1=\"70\" x2=\"378\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#hl)\"/><path d=\"M40.0,72.5 L48.0,78.4 L56.0,83.4 L64.0,87.6 L72.0,90.9 L80.0,93.4 L88.0,95.1 L96.0,96.2 L104.0,96.7 L112.0,96.5 L120.0,95.8 L128.0,94.6 L136.0,93.0 L144.0,91.0 L152.0,88.6 L160.0,86.0 L168.0,83.1 L176.0,80.0 L184.0,76.7 L192.0,73.4 L200.0,70.0 L208.0,66.6 L216.0,63.3 L224.0,60.0 L232.0,56.9 L240.0,54.0 L248.0,51.4 L256.0,49.0 L264.0,47.0 L272.0,45.4 L280.0,44.2 L288.0,43.5 L296.0,43.3 L304.0,43.8 L311.9,44.9 L319.9,46.6 L327.9,49.1 L335.9,52.4 L343.9,56.6 L351.9,61.6 L359.9,67.5\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"36\" y1=\"175\" x2=\"378\" y2=\"175\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#hl)\"/><path d=\"M40.0,216.6 L48.0,210.4 L56.0,204.5 L64.0,198.9 L72.0,193.7 L80.0,188.8 L88.0,184.2 L96.0,179.9 L104.0,175.9 L112.0,172.2 L120.0,168.9 L128.0,165.9 L136.0,163.2 L144.0,160.8 L152.0,158.7 L160.0,157.0 L168.0,155.5 L176.0,154.4 L184.0,153.6 L192.0,153.2 L200.0,153.0 L208.0,153.2 L216.0,153.6 L224.0,154.4 L232.0,155.5 L240.0,157.0 L248.0,158.7 L256.0,160.8 L264.0,163.2 L272.0,165.9 L280.0,168.9 L288.0,172.2 L296.0,175.9 L304.0,179.9 L311.9,184.2 L319.9,188.8 L327.9,193.7 L335.9,198.9 L343.9,204.5 L351.9,210.4 L359.9,216.6\" fill=\"none\" stroke=\"#2563eb\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"105.9\" y1=\"20\" x2=\"105.9\" y2=\"220\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"294.1\" y1=\"20\" x2=\"294.1\" y2=\"220\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><circle cx=\"105.9\" cy=\"96.7\" r=\"3\" fill=\"var(--or)\"/><circle cx=\"294.1\" cy=\"43.3\" r=\"3\" fill=\"var(--or)\"/><circle cx=\"105.9\" cy=\"175\" r=\"3\" fill=\"#2563eb\"/><circle cx=\"294.1\" cy=\"175\" r=\"3\" fill=\"#2563eb\"/><text x=\"44\" y=\"34\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">f(x)</text><text x=\"44\" y=\"206\" font-size=\"10\" font-weight=\"700\" fill=\"#2563eb\">helling van f</text><text x=\"92\" y=\"116\" font-size=\"8.5\" fill=\"var(--mu)\">dal</text><text x=\"284\" y=\"40\" font-size=\"8.5\" fill=\"var(--mu)\">top</text></svg><div class=\"sam-figcap\"><strong>Hellinggrafiek:</strong> waar f een <strong>top of dal</strong> heeft, snijdt de hellinggrafiek de x-as (helling = 0). Stijgt f, dan ligt de helling bov&#233;n de x-as; daalt f, dan eronder.</div></div><div class=\"sam-tip\">Onthoud de drie regels: top of dal van f &#8594; hellinggrafiek snijdt de x-as; f stijgt &#8594; helling positief (bov&#233;n de x-as); f daalt &#8594; helling negatief (onder de x-as).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">&#9999;&#65039; Voorbeeldopgave</div><div class=\"sam-worked-q\">Op de raaklijn aan de grafiek van f in het punt x = 2 liggen de punten (1, 0) en (3, 8). Bepaal de helling van f in x = 2.</div><ol class=\"sam-worked-steps\"><li>De helling in x = 2 is de helling van de raaklijn.</li><li>Differentiequoti&#235;nt: a = &#916;y/&#916;x = (8 &#8722; 0)/(3 &#8722; 1).</li><li>= 8 / 2.</li></ol><div class=\"sam-worked-ans\">&#9989; De helling in x = 2 is 4.</div></div>","havo_wa_E":"<div class=\"sam-intro\">Statistiek (domein E) is de <strong>kern van het CE</strong>: van een steekproef naar uitspraken over de hele populatie &#8212; met centrum- en spreidingsmaten, de normale verdeling en betrouwbaarheidsintervallen.</div><div class=\"sam-head\">Populatie en steekproef</div><ul><li><strong>Populatie</strong>: alle objecten van je onderzoek; <strong>steekproef</strong>: een selectie eruit.</li><li><strong>Proportie</strong> = deel dat aan een kenmerk voldoet (populatieproportie p of steekproefproportie).</li><li>Een goede steekproef is <strong>aselect</strong> (iedereen evenveel kans), <strong>groot genoeg</strong> en <strong>representatief</strong>.</li></ul><div class=\"sam-head\">Centrum- en spreidingsmaten</div><table class=\"sam-table\"><thead><tr><th>Maat</th><th>Betekenis</th></tr></thead><tbody><tr><td>Gemiddelde</td><td>som van waarden / aantal</td></tr><tr><td>Mediaan</td><td>middelste waarde (positie &#189;(n + 1))</td></tr><tr><td>Modus</td><td>meest voorkomende waarde</td></tr><tr><td>Spreidingsbreedte</td><td>hoogste &#8722; laagste waarde</td></tr><tr><td>Kwartielafstand</td><td>Q&#8323; &#8722; Q&#8321;</td></tr></tbody></table><p><strong>Standaardafwijking</strong> in stappen: (1) bereken het gemiddelde, (2) neem per waarde de afstand tot het gemiddelde, (3) kwadrateer die, (4) neem het gemiddelde van die kwadraten, (5) neem de wortel.</p><div class=\"sam-head\">Diagrammen</div><div class=\"sam-figure\"><svg viewBox=\"0 0 360 116\" role=\"img\" aria-label=\"Boxplot\"><defs><marker id=\"bx\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"24\" y1=\"82\" x2=\"346\" y2=\"82\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#bx)\"/><line x1=\"60\" y1=\"42\" x2=\"60\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"1.6\"/><line x1=\"60\" y1=\"56\" x2=\"120\" y2=\"56\" stroke=\"var(--mu)\" stroke-width=\"1.4\"/><line x1=\"240\" y1=\"56\" x2=\"300\" y2=\"56\" stroke=\"var(--mu)\" stroke-width=\"1.4\"/><line x1=\"300\" y1=\"42\" x2=\"300\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"1.6\"/><rect x=\"120\" y=\"40\" width=\"120\" height=\"32\" rx=\"3\" fill=\"rgba(var(--or-rgb),.14)\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><line x1=\"180\" y1=\"40\" x2=\"180\" y2=\"72\" stroke=\"var(--or)\" stroke-width=\"2.2\"/><text x=\"60\" y=\"100\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">min</text><text x=\"120\" y=\"100\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">Q&#8321;</text><text x=\"180\" y=\"100\" font-size=\"8.5\" fill=\"var(--or)\" text-anchor=\"middle\" font-weight=\"700\">mediaan</text><text x=\"240\" y=\"100\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">Q&#8323;</text><text x=\"300\" y=\"100\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">max</text></svg><div class=\"sam-figcap\"><strong>Boxplot:</strong> de box loopt van Q&#8321; tot Q&#8323; (de middelste 50%), met de mediaan als streep. De snorharen reiken tot de laagste en hoogste waarde.</div></div><p>Andere veelgebruikte diagrammen: staafdiagram (discrete waarden), steel-en-bladdiagram, cirkeldiagram (verhoudingen), frequentiepolygoon (ook cumulatief/relatief) en de puntenwolk (relatie tussen twee variabelen).</p><div class=\"sam-head\">Normale verdeling</div><p>Een <strong>normale verdeling</strong> is een symmetrische, klokvormige verdeling rond het gemiddelde &#956;. De standaardafwijking &#963; bepaalt de breedte: kleine &#963; = steile klok, grote &#963; = platte klok.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 400 184\" role=\"img\" aria-label=\"Normale verdeling met vuistregels\"><defs><marker id=\"nb\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"30\" y1=\"150\" x2=\"384\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#nb)\"/><path d=\"M40.0,150.0 L42.0,150.0 L44.0,149.9 L46.0,149.9 L48.0,149.9 L50.0,149.9 L52.0,149.9 L54.0,149.9 L56.0,149.8 L58.0,149.8 L60.0,149.8 L62.0,149.7 L64.0,149.7 L66.0,149.6 L68.0,149.5 L70.0,149.4 L72.0,149.3 L74.0,149.2 L76.0,149.1 L78.0,148.9 L80.0,148.8 L82.0,148.6 L84.0,148.4 L86.0,148.1 L88.0,147.8 L90.0,147.5 L92.0,147.1 L94.0,146.7 L96.0,146.3 L98.0,145.7 L100.0,145.2 L102.0,144.5 L104.0,143.8 L106.0,143.0 L108.0,142.2 L110.0,141.2 L112.0,140.2 L114.0,139.1 L116.0,137.9 L118.0,136.5 L120.0,135.1 L122.0,133.6 L124.0,131.9 L126.0,130.1 L128.0,128.2 L130.0,126.2 L132.0,124.1 L134.0,121.8 L136.0,119.4 L138.0,116.9 L140.0,114.3 L142.0,111.6 L144.0,108.7 L146.0,105.8 L148.0,102.7 L150.0,99.6 L152.0,96.5 L154.0,93.2 L156.0,89.9 L158.0,86.6 L160.0,83.3 L162.0,79.9 L164.0,76.6 L166.0,73.4 L168.0,70.1 L170.0,67.0 L172.0,63.9 L174.0,60.9 L176.0,58.1 L178.0,55.4 L180.0,52.9 L182.0,50.6 L184.0,48.5 L186.0,46.5 L188.0,44.8 L190.0,43.4 L192.0,42.2 L194.0,41.2 L196.0,40.5 L198.0,40.1 L200.0,40.0 L202.0,40.1 L204.0,40.5 L206.0,41.2 L208.0,42.2 L210.0,43.4 L212.0,44.8 L214.0,46.5 L216.0,48.5 L218.0,50.6 L220.0,52.9 L222.0,55.4 L224.0,58.1 L226.0,60.9 L228.0,63.9 L230.0,67.0 L232.0,70.1 L234.0,73.4 L236.0,76.6 L238.0,79.9 L240.0,83.3 L242.0,86.6 L244.0,89.9 L246.0,93.2 L248.0,96.5 L250.0,99.6 L252.0,102.7 L254.0,105.8 L256.0,108.7 L258.0,111.6 L260.0,114.3 L262.0,116.9 L264.0,119.4 L266.0,121.8 L268.0,124.1 L270.0,126.2 L272.0,128.2 L274.0,130.1 L276.0,131.9 L278.0,133.6 L280.0,135.1 L282.0,136.5 L284.0,137.9 L286.0,139.1 L288.0,140.2 L290.0,141.2 L292.0,142.2 L294.0,143.0 L296.0,143.8 L298.0,144.5 L300.0,145.2 L302.0,145.7 L304.0,146.3 L306.0,146.7 L308.0,147.1 L310.0,147.5 L312.0,147.8 L314.0,148.1 L316.0,148.4 L318.0,148.6 L320.0,148.8 L322.0,148.9 L324.0,149.1 L326.0,149.2 L328.0,149.3 L330.0,149.4 L332.0,149.5 L334.0,149.6 L336.0,149.7 L338.0,149.7 L340.0,149.8 L342.0,149.8 L344.0,149.8 L346.0,149.9 L348.0,149.9 L350.0,149.9 L352.0,149.9 L354.0,149.9 L356.0,149.9 L358.0,150.0 L360.0,150.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.5\" stroke-linecap=\"round\"/><line x1=\"200\" y1=\"150\" x2=\"200\" y2=\"40\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"160\" y1=\"150\" x2=\"160\" y2=\"141\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"240\" y1=\"150\" x2=\"240\" y2=\"141\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"120\" y1=\"150\" x2=\"120\" y2=\"135\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"280\" y1=\"150\" x2=\"280\" y2=\"135\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><text x=\"200\" y=\"166\" font-size=\"9\" fill=\"var(--dk)\" text-anchor=\"middle\" font-weight=\"700\">&#956;</text><text x=\"160\" y=\"166\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">&#956;-&#963;</text><text x=\"240\" y=\"166\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">&#956;+&#963;</text><text x=\"120\" y=\"166\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">&#956;-2&#963;</text><text x=\"280\" y=\"166\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">&#956;+2&#963;</text><text x=\"200\" y=\"120\" font-size=\"9.5\" fill=\"var(--or)\" text-anchor=\"middle\" font-weight=\"700\">68%</text><text x=\"200\" y=\"92\" font-size=\"9.5\" fill=\"#2563eb\" text-anchor=\"middle\" font-weight=\"700\">95%</text></svg><div class=\"sam-figcap\"><strong>Vuistregels:</strong> 68% van de waarnemingen ligt tussen &#956;&#177;&#963;, 95% tussen &#956;&#177;2&#963; en bijna 100% tussen &#956;&#177;3&#963;.</div></div><div class=\"sam-tip\">Op normaal-waarschijnlijkheidspapier vormt een normale verdeling een <strong>rechte lijn</strong>. Het gemiddelde lees je af bij 50%; de standaardafwijking is het verschil tussen de waarde bij 84% en die bij 50%.</div><div class=\"sam-head\">Betrouwbaarheidsinterval</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Standaardafwijking van de proportie</div><div class=\"sam-formula-eq\">&#963; = &#8730;( p(1 &#8722; p) / n )</div><div class=\"sam-formula-note\">p = (steekproef)proportie, n = steekproefgrootte.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">95%-betrouwbaarheidsinterval</div><div class=\"sam-formula-eq\">p &#8722; 2&#963; &nbsp;tot&nbsp; p + 2&#963;</div><div class=\"sam-formula-note\">Hiermee ligt de populatieproportie met 95% zekerheid in dat interval. Voor 68% gebruik je &#177;1&#963;.</div></div><div class=\"sam-head\">Groepen vergelijken</div><table class=\"sam-table\"><thead><tr><th>Maat</th><th>Groot verschil</th></tr></thead><tbody><tr><td>Percentageverschil (PV)</td><td>PV &gt; 30%</td></tr><tr><td>Odds-ratio (OR = ad/bc)</td><td>OR &gt; 3 (of &lt; &#8531;)</td></tr><tr><td>Effectgrootte (E)</td><td>E &gt; 0,8</td></tr></tbody></table><div class=\"sam-worked\"><div class=\"sam-worked-h\">&#9999;&#65039; Voorbeeldopgave</div><div class=\"sam-worked-q\">IQ-scores zijn normaal verdeeld met gemiddelde 100 en standaardafwijking 15. Welk percentage heeft een IQ hoger dan 130?</div><ol class=\"sam-worked-steps\"><li>130 ligt op 100 + 2&#963; (want 2 &#215; 15 = 30).</li><li>Vuistregel: 95% ligt tussen &#956; &#8722; 2&#963; en &#956; + 2&#963;, dus 5% ligt erbuiten.</li><li>Door symmetrie zit de helft daarvan boven +2&#963;: 5% / 2.</li></ol><div class=\"sam-worked-ans\">&#9989; Ongeveer 2,5% heeft een IQ hoger dan 130.</div></div><div class=\"sam-warn\">Verwar de spreidingsbreedte (hoogste &#8722; laagste) niet met de standaardafwijking. En let bij de mediaan op: zet de waarden eerst op volgorde.</div>","havo_ec_B":"<div class=\"sam-intro\">Economie draait om één onvermijdelijke waarheid: <strong>je middelen zijn schaars, dus elke keuze kost je het beste alternatief</strong>. Daarop bouwt dit domein voort — van keuzes en productiefactoren tot het meten van welvaart met het bbp.</div><div class=\"sam-head\">Schaarste en keuze</div><p>Schaarste dwingt tot kiezen, en elke keuze kost het beste alternatief dat je opgeeft.</p><ul><li><strong>Absolute schaarste</strong>: er is daadwerkelijk te weinig van iets</li><li><strong>Relatieve schaarste</strong>: je moet een middel opofferen om iets te kunnen maken (schaarste in economische zin)</li><li><strong>Vrije goederen</strong>: goederen waarvoor je niets hoeft op te offeren (bijv. lucht)</li><li><strong>Alternatief aanwendbaar</strong>: productiefactoren kun je voor verschillende doelen inzetten</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Keuzes afwegen</div><div class=\"sam-formula-eq\">nettobaten = baten − kosten</div><div class=\"sam-formula-note\">Opofferingskosten = de nettobaten van het beste alternatief. Gecorrigeerde nettobaten = nettobaten − opofferingskosten.</div></div><div class=\"sam-head\">Productiefactoren en hun beloning</div><table class=\"sam-table\"><thead><tr><th>Productiefactor</th><th>Beloning</th></tr></thead><tbody><tr><td>Natuur</td><td>pacht</td></tr><tr><td>Arbeid</td><td>loon</td></tr><tr><td>Kapitaal</td><td>rente en huur</td></tr><tr><td>Ondernemerschap</td><td>winst</td></tr></tbody></table><ul><li><strong>Primair inkomen</strong>: de beloning voor een productiefactor (loon, winst, rente, pacht)</li><li><strong>Overdrachtsinkomen</strong>: inkomen van de overheid zonder tegenprestatie, zoals een uitkering</li><li><strong>Secundair inkomen</strong>: primair inkomen − belasting en premies + overdrachtsinkomen</li></ul><div class=\"sam-head\">Budget en budgetlijn</div><ul><li><strong>Budget</strong>: het totaal aan middelen dat iemand heeft</li><li><strong>Begroting</strong>: een overzicht van de verwachte inkomsten en uitgaven (dagelijks, vast, incidenteel)</li><li><strong>Budgettair probleem</strong>: de uitgaven zijn hoger dan de inkomsten</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Budgetlijn</div><div class=\"sam-formula-eq\">M = P<sub>x</sub>·X + P<sub>y</sub>·Y</div><div class=\"sam-formula-note\">M het budget, P<sub>x</sub>/P<sub>y</sub> de prijzen, X/Y de aantallen. De lijn toont alle combinaties die met het budget mogelijk zijn (de budgetset); hij schuift bij een ander budget of andere prijzen.</div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 320 212\" role=\"img\" aria-label=\"Budgetlijn met het haalbare gebied\"><defs><marker id=\"ahB\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><polygon points=\"54,52 54,178 252,178\" fill=\"rgba(var(--or-rgb),.14)\"/><line x1=\"54\" y1=\"180\" x2=\"54\" y2=\"28\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahB)\"/><line x1=\"52\" y1=\"178\" x2=\"300\" y2=\"178\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahB)\"/><line x1=\"54\" y1=\"52\" x2=\"252\" y2=\"178\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><circle cx=\"54\" cy=\"52\" r=\"4\" fill=\"var(--or)\"/><circle cx=\"252\" cy=\"178\" r=\"4\" fill=\"var(--or)\"/><text x=\"24\" y=\"56\" font-size=\"9.5\" fill=\"var(--mu)\">max Y</text><text x=\"226\" y=\"194\" font-size=\"9.5\" fill=\"var(--mu)\">max X</text><text x=\"138\" y=\"96\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">budgetlijn</text><text x=\"92\" y=\"160\" font-size=\"9.5\" fill=\"var(--mu)\">haalbaar</text><text x=\"22\" y=\"116\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 116)\">goed Y</text><text x=\"150\" y=\"206\" font-size=\"9.5\" fill=\"var(--mu)\">goed X</text></svg><div class=\"sam-figcap\"><strong>Budgetlijn:</strong> alle combinaties van goed X en Y die je met budget M precies kunt betalen. Het gekleurde vlak is <strong>haalbaar</strong>; de lijn schuift bij een ander budget of andere prijs.</div></div><div class=\"sam-head\">Ruil en kostenvoordeel</div><p>Door schaarste ruilen mensen en landen middelen; dat gebeurt alleen bij <strong>wederzijds voordeel</strong>. Een volledig zelfvoorzienende economie heet een autarkie.</p><ul><li><strong>Transactiekosten</strong>: de kosten om een ruil tot stand te brengen (zoek-, informatie- en evaluatiekosten); moeten lager zijn dan het voordeel</li><li><strong>Arbeidsproductiviteit</strong>: de gemiddelde productie per werknemer per tijdseenheid; te verhogen via scholing, specialisatie en kapitaalgoederen</li><li><strong>Absoluut kostenvoordeel</strong>: een land kan een product goedkoper (met minder uren) maken dan een ander land</li><li><strong>Comparatief kostenvoordeel</strong>: een land kan een product relatief goedkoper maken; bepaald door de opofferingskosten</li></ul><div class=\"sam-tip\">Wie de láágste opofferingskosten voor een product heeft, kan zich daarin het beste specialiseren — ook als een ander land bij álles een absoluut voordeel heeft.</div><div class=\"sam-head\">Productie, toegevoegde waarde en het bbp</div><ul><li><strong>Formele productie</strong>: geregistreerde (witte) productie; informeel = zwart (verzwegen) of grijs (zonder geld)</li><li><strong>Bruto toegevoegde waarde</strong>: omzet − de kosten van ingekochte goederen en diensten</li><li><strong>Netto toegevoegde waarde</strong>: bruto toegevoegde waarde − afschrijvingen; gelijk aan het totale primaire inkomen</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Bbp — inkomensmethode</div><div class=\"sam-formula-eq\">Y = C + B + S</div><div class=\"sam-formula-note\">Het nationaal inkomen vanuit de besteding door huishoudens: consumptie + belasting + besparingen.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Bbp — bestedingsmethode</div><div class=\"sam-formula-eq\">Y = C + I + O + (E − M)</div><div class=\"sam-formula-note\">Het nationaal inkomen vanuit de totale uitgaven: consumptie + investeringen + overheidsbestedingen + export − import.</div></div><p>Daarnaast kun je het bbp berekenen via de <strong>objectieve methode</strong> (toegevoegde waarde van alle bedrijven en de overheid optellen) of de <strong>subjectieve methode</strong> (alle primaire inkomens optellen). Voor een eerlijke vergelijking corrigeer je voor inflatie (reëel vs nominaal bbp) en bevolkingsomvang (bbp per capita).</p><div class=\"sam-head\">De economische kringloop</div><p>De kringloop verbindt bestedingen, productie en inkomen via een <strong>reële stroom</strong> (goederen) en een <strong>monetaire stroom</strong> (geld). Lekken zijn belastingen (B) en besparingen (S).</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Kringloop-identiteit</div><div class=\"sam-formula-eq\">(S − I) + (B − O) = (E − M)</div><div class=\"sam-formula-note\">Het nationale spaarsaldo is gelijk aan het saldo op de lopende rekening: (B−O) saldo overheid, (S−I) saldo financiële sector, (E−M) saldo buitenland.</div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 360 180\" role=\"img\" aria-label=\"De economische kringloop\"><defs><marker id=\"ecKo\" markerWidth=\"9\" markerHeight=\"9\" refX=\"6\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker><marker id=\"ecKm\" markerWidth=\"9\" markerHeight=\"9\" refX=\"6\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"26\" y=\"62\" width=\"96\" height=\"50\" rx=\"8\" fill=\"rgba(var(--or-rgb),.10)\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><text x=\"74\" y=\"91\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">Gezinnen</text><rect x=\"238\" y=\"62\" width=\"96\" height=\"50\" rx=\"8\" fill=\"rgba(var(--or-rgb),.10)\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><text x=\"286\" y=\"91\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">Bedrijven</text><path d=\"M238,74 C198,32 162,32 122,74\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2\" marker-end=\"url(#ecKo)\"/><text x=\"180\" y=\"26\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">goederen &amp; diensten (reële stroom)</text><path d=\"M122,100 C162,142 198,142 238,100\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"2\" stroke-dasharray=\"5 3\" marker-end=\"url(#ecKm)\"/><text x=\"180\" y=\"156\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">geld · bestedingen (monetaire stroom)</text></svg><div class=\"sam-figcap\"><strong>Economische kringloop:</strong> goederen en arbeid vormen de <strong>reële stroom</strong>; het geld dat ertegenover staat is de <strong>monetaire stroom</strong> — die loopt precies de andere kant op.</div></div><div class=\"sam-head\">Welvaart</div><ul><li><strong>Welvaart in enge zin</strong>: alleen het materiële, gemeten met het bbp</li><li><strong>Welvaart in brede zin</strong>: ook immateriële zaken: gezondheid, onderwijs, milieu, geluk</li><li><strong>Human Development Index (HDI)</strong>: meet ontwikkeling via inkomen per hoofd, levensverwachting en onderwijsniveau</li><li><strong>Groen bbp</strong>: het bbp gecorrigeerd voor milieuschade en milieuverbetering</li></ul><div class=\"sam-warn\">Het bbp telt geen informeel werk (zwart, vrijwilligers, doe-het-zelf) en geen externe effecten mee, en zegt niets over de inkomensverdeling — daarom is het een beperkte welvaartsmaatstaf.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Land A maakt per uur 4 auto’s óf 8 tablets; land B per uur 1 auto óf 4 tablets. Waarin kan land B zich het beste specialiseren?</div><ol class=\"sam-worked-steps\"><li>Opofferingskosten = wat je opgeeft. Voor 1 tablet offert land A op: 4/8 = 0,5 auto.</li><li>Voor 1 tablet offert land B op: 1/4 = 0,25 auto.</li><li>Land B offert minder op (0,25 &lt; 0,5) → laagste opofferingskosten voor tablets.</li></ol><div class=\"sam-worked-ans\">✅ Land B specialiseert zich in tablets (comparatief voordeel), ook al heeft A bij beide een absoluut voordeel.</div></div>","havo_bi_A":"<div class=\"sam-head\">Variabelen in onderzoek</div><table class=\"sam-table\"><thead><tr><th>Variabele</th><th>Definitie</th><th>Voorbeeld</th></tr></thead><tbody><tr><td><strong>Onafhankelijk (OV)</strong></td><td>De variabele die de onderzoeker zelf verandert of manipuleert</td><td>Temperatuur, lichtintensiteit, concentratie</td></tr><tr><td><strong>Afhankelijk (AV)</strong></td><td>Wat je meet als gevolg van de OV</td><td>Groeisnelheid, O₂-productie, hartslag</td></tr><tr><td><strong>Constant (CV)</strong></td><td>Alles wat je gelijk houdt voor een eerlijke vergelijking</td><td>pH, volume, tijdsduur, soort organisme</td></tr></tbody></table><div class=\"sam-head\">Stappen wetenschappelijk onderzoek</div><ol class=\"sam-steps\"><li><strong>Waarneming / vraag</strong>: observeer iets opvallends of formuleer een heldere onderzoeksvraag.</li><li><strong>Hypothese</strong>: testbare voorspelling. Format: \"Als [OV verandert], dan [verwacht effect op AV], omdat [biologische redenering].\"</li><li><strong>Experiment</strong>: verander alleen de OV, houd alles overig constant. Gebruik een controlegroep (OV op nulwaarde).</li><li><strong>Resultaten verwerken</strong>: data in tabel en grafiek. Bereken gemiddelden bij herhaalde metingen voor betrouwbaarheid.</li><li><strong>Conclusie en evaluatie</strong>: wordt de hypothese bevestigd of verworpen? Benoem foutenbronnen en beperkingen.</li></ol><div class=\"sam-tip\">De controlegroep staat identiek aan de experimentele groep, behalve dat de OV op nulwaarde staat. Zonder controlegroep kun je geen eerlijke vergelijking maken en is de conclusie onbetrouwbaar.</div><div class=\"sam-warn\">Correlatie is geen causaliteit. Als twee variabelen samen veranderen, is de ene niet automatisch de oorzaak van de andere. Er kan een verstorende (confounding) variabele zijn die beide beïnvloedt.</div>","havo_ec_C":"<div class=\"sam-intro\">Bijna alles in dit domein komt samen in één grafiek: <strong>vraag en aanbod bepalen samen de prijs</strong>. Snap je het marktevenwicht, dan snap je ook elasticiteit, surplus, overheidsingrijpen én de marktvormen.</div><div class=\"sam-head\">De vraagzijde</div><p>Een <strong>markt</strong> is de plek waar vraag en aanbod samenkomen (consumenten, producenten, overheid en in een open economie het buitenland). De <strong>vraaglijn</strong> heeft een dalend verloop: hoe lager de prijs, hoe meer er gevraagd wordt.</p><ul><li><strong>Betalingsbereidheid</strong>: het maximale bedrag dat een consument voor een goed wil betalen</li><li><strong>Verschuiving lángs de vraaglijn</strong>: de gevraagde hoeveelheid verandert door een prijsverandering</li><li><strong>Verschuiving ván de vraaglijn</strong>: de hele lijn schuift door iets anders dan de prijs: budget, behoeften, aantal consumenten, prijs van een substituut of complement</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Prijselasticiteit van de vraag</div><div class=\"sam-formula-eq\">E<sub>v</sub> = %ΔQ<sub>v</sub> / %ΔP</div><div class=\"sam-formula-note\">|E<sub>v</sub>| &gt; 1 = elastisch (sterke reactie); tussen −1 en 1 = inelastisch. Uitzonderingen: Veblen-goederen (status) en Giffen-goederen, waarbij de vraag juist stijgt als de prijs stijgt.</div></div><table class=\"sam-table\"><thead><tr><th>Soort elasticiteit</th><th>Wat zegt het?</th></tr></thead><tbody><tr><td>Inkomenselasticiteit &gt; 1</td><td>luxe goed</td></tr><tr><td>Inkomenselasticiteit 0 tot 1</td><td>noodzakelijk goed</td></tr><tr><td>Inkomenselasticiteit &lt; 0</td><td>inferieur goed</td></tr><tr><td>Kruislingse elasticiteit positief</td><td>substituten (bijv. cola en Pepsi)</td></tr><tr><td>Kruislingse elasticiteit negatief</td><td>complementen (bijv. koffie en suiker)</td></tr></tbody></table><div class=\"sam-head\">De aanbodzijde en kosten</div><p>De <strong>aanbodlijn</strong> stijgt: hoe hoger de prijs, hoe meer producenten aanbieden. De lijn schuift lángs (door de prijs) of ván (door productiekosten, technologie, aantal aanbieders of overheidsbeleid).</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Totale kosten</div><div class=\"sam-formula-eq\">TK = TCK + TVK</div><div class=\"sam-formula-note\">TCK = totale constante kosten (onafhankelijk van de productie), TVK = totale variabele kosten (lopen mee met de productie; proportioneel, degressief of progressief).</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Gemiddelde en marginale kosten</div><div class=\"sam-formula-eq\">GTK = TK/q &nbsp;·&nbsp; GVK = TVK/q &nbsp;·&nbsp; GCK = TCK/q</div><div class=\"sam-formula-note\">GCK daalt bij meer productie. De marginale kosten (MK) zijn de extra kosten van één product méér.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Opbrengst, winst en break-even</div><div class=\"sam-formula-eq\">TO = P · q &nbsp;·&nbsp; TW = TO − TK &nbsp;·&nbsp; break-even: TO = TK</div><div class=\"sam-formula-note\">Bij het break-evenpunt is er geen winst en geen verlies. De break-evenafzet (BEA) is het aantal producten daar; BEO = BEA × prijs.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Prijselasticiteit van het aanbod</div><div class=\"sam-formula-eq\">E<sub>a</sub> = %ΔQ<sub>a</sub> / %ΔP</div><div class=\"sam-formula-note\">E<sub>a</sub> &lt; 1 = inelastisch aanbod, E<sub>a</sub> &gt; 1 = elastisch aanbod.</div></div><div class=\"sam-head\">Marktevenwicht en surplus</div><p>Waar de vraag- en aanbodlijn elkaar kruisen ontstaat het <strong>marktevenwicht</strong>: de evenwichtsprijs (waarbij vraag = aanbod) en de evenwichtshoeveelheid. Bij het <strong>ceteris paribus</strong>-principe kijk je alleen naar de prijs en houd je al het andere gelijk.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 238\" role=\"img\" aria-label=\"Vraag en aanbod met marktevenwicht, consumenten- en producentensurplus\"><defs><marker id=\"ahC\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><polygon points=\"50,37 50,115 180,115\" fill=\"rgba(37,99,235,.14)\"/><polygon points=\"50,193 50,115 180,115\" fill=\"rgba(var(--or-rgb),.17)\"/><line x1=\"50\" y1=\"115\" x2=\"180\" y2=\"115\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"180\" y1=\"115\" x2=\"180\" y2=\"200\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><line x1=\"50\" y1=\"202\" x2=\"50\" y2=\"26\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahC)\"/><line x1=\"48\" y1=\"200\" x2=\"316\" y2=\"200\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahC)\"/><line x1=\"50\" y1=\"37\" x2=\"305\" y2=\"190\" stroke=\"#2563eb\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><line x1=\"50\" y1=\"193\" x2=\"305\" y2=\"40\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><circle cx=\"180\" cy=\"115\" r=\"5.5\" fill=\"var(--bg2)\"/><circle cx=\"180\" cy=\"115\" r=\"3.3\" fill=\"var(--dk)\"/><text x=\"309\" y=\"194\" font-size=\"13\" font-weight=\"800\" fill=\"#2563eb\">V</text><text x=\"309\" y=\"44\" font-size=\"13\" font-weight=\"800\" fill=\"var(--or)\">A</text><text x=\"95\" y=\"90\" font-size=\"10.5\" font-weight=\"700\" fill=\"#2563eb\">CS</text><text x=\"88\" y=\"150\" font-size=\"10.5\" font-weight=\"700\" fill=\"var(--or)\">PS</text><text x=\"34\" y=\"119\" font-size=\"10\" fill=\"var(--mu)\">P*</text><text x=\"174\" y=\"216\" font-size=\"10\" fill=\"var(--mu)\">Q*</text><text x=\"22\" y=\"120\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 120)\">prijs (P)</text><text x=\"198\" y=\"232\" font-size=\"9.5\" fill=\"var(--mu)\">hoeveelheid (Q)</text></svg><div class=\"sam-figcap\"><strong>Marktevenwicht:</strong> waar vraag (V) en aanbod (A) kruisen liggen de evenwichtsprijs P* en hoeveelheid Q*. Daarboven het <strong>consumentensurplus</strong> (CS), eronder het <strong>producentensurplus</strong> (PS).</div></div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Consumentensurplus</div><ul><li>het voordeel voor kopers</li><li>betalingsbereidheid − evenwichtsprijs</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Producentensurplus</div><ul><li>het voordeel voor verkopers</li><li>evenwichtsprijs − leveringsbereidheid</li></ul></div></div><ul><li><strong>Totaal surplus</strong>: consumentensurplus + producentensurplus</li><li><strong>Pareto-efficiënt</strong>: het totale surplus is maximaal; dat is precies in het marktevenwicht. Niemand kan erop vooruit zonder dat een ander erop achteruit gaat</li><li><strong>Harberger-driehoek</strong>: het welvaartsverlies dat ontstaat door een prijsmaatregel van de overheid</li></ul><div class=\"sam-head\">De overheid grijpt in op de markt</div><ul><li><strong>Maximumprijs</strong>: een prijsplafond om een goed betaalbaar te houden; ligt onder het evenwicht en geeft een tekort</li><li><strong>Minimumprijs</strong>: een prijsbodem om aankoop te ontmoedigen; ligt boven het evenwicht en geeft een overschot</li><li><strong>Accijns (heffing)</strong>: een indirecte belasting; verhoogt de productiekosten, de aanbodlijn schuift naar links → hogere prijs, lagere hoeveelheid</li><li><strong>Subsidie</strong>: een bijdrage aan producenten; verlaagt de productiekosten, de aanbodlijn schuift naar rechts → lagere prijs, hogere hoeveelheid</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 340 232\" role=\"img\" aria-label=\"Maximumprijs leidt tot een tekort\"><defs><marker id=\"ecMu\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker><marker id=\"ecMo\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"50\" y1=\"202\" x2=\"50\" y2=\"26\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ecMu)\"/><line x1=\"48\" y1=\"200\" x2=\"316\" y2=\"200\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ecMu)\"/><line x1=\"50\" y1=\"37\" x2=\"305\" y2=\"190\" stroke=\"#2563eb\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"50\" y1=\"193\" x2=\"305\" y2=\"40\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><circle cx=\"180\" cy=\"115\" r=\"3\" fill=\"var(--mu)\"/><line x1=\"50\" y1=\"150\" x2=\"240\" y2=\"150\" stroke=\"#dc2626\" stroke-width=\"1.8\" stroke-dasharray=\"5 3\"/><text x=\"54\" y=\"144\" font-size=\"9\" font-weight=\"700\" fill=\"#dc2626\">max.prijs</text><line x1=\"122\" y1=\"150\" x2=\"122\" y2=\"200\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"238\" y1=\"150\" x2=\"238\" y2=\"200\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"124\" y1=\"166\" x2=\"236\" y2=\"166\" stroke=\"var(--or)\" stroke-width=\"1.6\" marker-start=\"url(#ecMo)\" marker-end=\"url(#ecMo)\"/><text x=\"180\" y=\"180\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">tekort</text><text x=\"308\" y=\"194\" font-size=\"12.5\" font-weight=\"800\" fill=\"#2563eb\">V</text><text x=\"308\" y=\"44\" font-size=\"12.5\" font-weight=\"800\" fill=\"var(--or)\">A</text><text x=\"118\" y=\"213\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Qa</text><text x=\"240\" y=\"213\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Qv</text><text x=\"22\" y=\"118\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 118)\">prijs</text><text x=\"270\" y=\"224\" font-size=\"9.5\" fill=\"var(--mu)\">hoeveelheid</text></svg><div class=\"sam-figcap\"><strong>Maximumprijs (prijsplafond):</strong> ligt onder de evenwichtsprijs. Bij die lage prijs is de gevraagde hoeveelheid (Q<sub>v</sub>) groter dan de aangeboden (Q<sub>a</sub>) → er ontstaat een <strong>tekort</strong>.</div></div><div class=\"sam-head\">Marktvormen</div><p>Marktvormen verschillen in het aantal aanbieders (veel = prijsnemers, weinig = prijszetters), het soort product (homogeen of heterogeen), het aantal vragers en de toetredingsbarrières.</p><table class=\"sam-table\"><thead><tr><th>Marktvorm</th><th>Aanbieders</th><th>Product</th><th>Toetreding</th></tr></thead><tbody><tr><td>Volkomen concurrentie</td><td>veel</td><td>homogeen</td><td>makkelijk</td></tr><tr><td>Monopolistische concurrentie</td><td>veel</td><td>heterogeen</td><td>makkelijk</td></tr><tr><td>Heterogeen oligopolie</td><td>weinig</td><td>heterogeen</td><td>moeilijk</td></tr><tr><td>Homogeen oligopolie</td><td>weinig</td><td>homogeen</td><td>moeilijk</td></tr><tr><td>Monopolie</td><td>één</td><td>homogeen</td><td>moeilijk</td></tr></tbody></table><ul><li><strong>Volkomen concurrentie</strong>: de prijs is een gegeven; producenten zijn hoeveelheidsaanpassers en GO = MO = P</li><li><strong>Oligopolie</strong>: enkele grote aanbieders; verleiding tot kartelvorming (prijsafspraken), wat bij wet verboden is</li><li><strong>Monopolie</strong>: één aanbieder (wettelijk of natuurlijk); maximaliseert winst waar MO = MK en kan via prijsdiscriminatie meer winst halen</li><li><strong>Toetredingsbarrières</strong>: schaalvoordelen, hoge investeringen of wettelijke beperkingen die nieuwkomers tegenhouden en zo de marktmacht beschermen</li></ul><div class=\"sam-head\">Marktfalen: collectieve goederen en externe effecten</div><p>Twee begrippen bepalen het soort goed: <strong>rivaliserend</strong> (gebruik door de één gaat ten koste van de ander) en <strong>uitsluitbaar</strong> (je kunt iemand van gebruik uitsluiten).</p><ul><li><strong>Collectief goed</strong>: niet-uitsluitbaar én niet-rivaliserend (bijv. dijken); de markt levert dit niet</li><li><strong>Quasi-collectief goed</strong>: in theorie individueel leverbaar, maar toch door de overheid geleverd (bijv. onderwijs)</li><li><strong>Free-rider (meelifter)</strong>: iemand die van een goed profiteert zonder eraan mee te betalen</li><li><strong>Negatief extern effect</strong>: onbedoeld nadeel voor derden (vervuiling); leidt tot overproductie. Overheid corrigeert met belasting of regels (internaliseren)</li><li><strong>Positief extern effect</strong>: onbedoeld voordeel voor derden (onderwijs); leidt tot te weinig productie. Overheid stimuleert met subsidie</li></ul><div class=\"sam-head\">Marktmacht, toezicht en de arbeidsmarkt</div><ul><li><strong>ACM</strong>: de Autoriteit Consument en Markt; verbiedt kartels en grijpt in bij misbruik van marktmacht</li><li><strong>AFM</strong>: de Autoriteit Financiële Markten; houdt toezicht op banken, verzekeraars, pensioenfondsen en beleggen</li><li><strong>Evenwichtsloon</strong>: het loon waar de vraag naar arbeid (vacatures) en het aanbod (wie kan en wil werken) elkaar snijden</li><li><strong>Contractvormen</strong>: vast (zekerheid), flexibel (wendbaarheid voor de werkgever) en zzp (vrijheid maar meer risico)</li><li><strong>Arbeidsmarktinstituties</strong>: vakbonden, cao’s, ondernemingsraden en het minimumloon; beschermen werknemers maar kunnen de markt ook beperken</li></ul><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">De prijs van een product stijgt met 10%. De gevraagde hoeveelheid daalt van 500 naar 460 stuks. Bereken de prijselasticiteit en beoordeel of de vraag elastisch is.</div><ol class=\"sam-worked-steps\"><li>%ΔQ = (460 − 500) / 500 × 100% = −8%.</li><li>E<sub>v</sub> = %ΔQ / %ΔP = −8% / +10% = −0,8.</li><li>|E<sub>v</sub>| = 0,8, en 0,8 &lt; 1 → de vraag is inelastisch.</li></ol><div class=\"sam-worked-ans\">✅ E<sub>v</sub> = −0,8; de vraag is inelastisch — ze reageert zwak op de prijs.</div></div>","havo_ec_D":"<div class=\"sam-intro\">Geld verschuift in de tijd: <strong>sparen stelt consumptie uit, lenen haalt die naar voren</strong>. Dit domein gaat over die ruil tussen nu en later — rente, belasting, inkomensverdeling, pensioen en risico.</div><div class=\"sam-head\">Sparen, lenen en rente</div><p><strong>Sparen</strong> is consumptie uitstellen naar later; <strong>lenen</strong> is toekomstige consumptie naar nu halen. Beide zijn vormen van <strong>intertemporele ruil</strong> (koopkracht ruilen tussen nu en later). De prijs van lenen is rente.</p><ul><li><strong>Enkelvoudige rente</strong>: rente alleen over de hoofdsom</li><li><strong>Samengestelde rente</strong>: rente over de hoofdsom én over eerder ontvangen rente</li><li><strong>Factoren voor de rentehoogte</strong>: risico, inflatieverwachting en looptijd</li></ul><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Reële rente</div><div class=\"sam-formula-eq\">reële rente ≈ nominale rente − inflatie</div><div class=\"sam-formula-note\">De nominale rente is het percentage in euro’s; de reële rente geeft de echte verandering in koopkracht. RIC = NIC / PIC × 100 (reëel = nominaal gecorrigeerd voor prijzen).</div></div><div class=\"sam-head\">Begroting en staatsschuld</div><ul><li><strong>Begrotingssaldo</strong>: overheidsinkomsten − uitgaven; tekort = lenen, overschot = sparen</li><li><strong>Financieringssaldo</strong>: begrotingssaldo minus aflossingen; bepaalt de jaarlijkse verandering van de staatsschuld</li><li><strong>Staatsschuld</strong>: de totale schuld van de overheid op een moment; volgens het EU-stabiliteitspact maximaal 60% van het bbp</li><li><strong>Anticyclisch begrotingsbeleid</strong>: in laagconjunctuur lenen en uitgeven om de economie te stimuleren; een begrotingstekort is feitelijk uitgestelde belasting</li></ul><div class=\"sam-head\">Belastingen</div><ul><li><strong>Directe belasting</strong>: op naam, rechtstreeks aan de Belastingdienst (bijv. loon-/inkomstenbelasting)</li><li><strong>Indirecte belasting</strong>: niet op naam, over producten en diensten (bijv. btw en accijns)</li><li><strong>Brutoloon → nettoloon</strong>: de werkgever houdt loonheffing in; de totale loonkosten liggen hoger door het werkgeversdeel van de premies</li></ul><table class=\"sam-table\"><thead><tr><th>Belastingstelsel</th><th>Kenmerk</th><th>Effect</th></tr></thead><tbody><tr><td>Progressief</td><td>hoger inkomen = hoger %tarief (schijven)</td><td>nivelleert</td></tr><tr><td>Proportioneel (vlaktaks)</td><td>voor iedereen hetzelfde %</td><td>verandert verhoudingen niet</td></tr><tr><td>Degressief</td><td>hoger inkomen = lager %tarief</td><td>denivelleert</td></tr></tbody></table><div class=\"sam-tip\">De inkomstenbelasting in Nederland kent drie boxen: box 1 (werk en woning, progressief schijventarief), box 2 (aanmerkelijk belang, ≥5% aandelen) en box 3 (sparen en beleggen, belasting over een fictief rendement). Aftrekposten verlagen, bijtellingen verhogen het belastbaar inkomen.</div><div class=\"sam-head\">Inkomensverdeling en inkomensbeleid</div><div class=\"sam-figure\"><svg viewBox=\"0 0 250 214\" role=\"img\" aria-label=\"Lorenzcurve en de lijn van volledige gelijkheid\"><defs><marker id=\"ahD\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><path d=\"M52.0,190.0 C53.7,189.9 58.7,189.8 62.0,189.4 C65.3,189.0 68.7,188.3 72.0,187.5 C75.3,186.7 78.7,185.6 82.0,184.4 C85.3,183.1 88.7,181.7 92.0,180.0 C95.3,178.3 98.7,176.5 102.0,174.4 C105.3,172.3 108.7,170.0 112.0,167.5 C115.3,165.0 118.7,162.3 122.0,159.4 C125.3,156.5 128.7,153.3 132.0,150.0 C135.3,146.7 138.7,143.1 142.0,139.4 C145.3,135.6 148.7,131.7 152.0,127.5 C155.3,123.3 158.7,119.0 162.0,114.4 C165.3,109.8 168.7,105.0 172.0,100.0 C175.3,95.0 178.7,89.8 182.0,84.4 C185.3,79.0 188.7,73.3 192.0,67.5 C195.3,61.7 198.7,55.6 202.0,49.4 C205.3,43.1 210.3,33.2 212.0,30.0 L52,190 Z\" fill=\"rgba(var(--or-rgb),.16)\"/><line x1=\"52\" y1=\"192\" x2=\"52\" y2=\"26\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahD)\"/><line x1=\"50\" y1=\"190\" x2=\"226\" y2=\"190\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahD)\"/><line x1=\"52\" y1=\"190\" x2=\"212\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.4\" stroke-dasharray=\"4 3\"/><path d=\"M52.0,190.0 C53.7,189.9 58.7,189.8 62.0,189.4 C65.3,189.0 68.7,188.3 72.0,187.5 C75.3,186.7 78.7,185.6 82.0,184.4 C85.3,183.1 88.7,181.7 92.0,180.0 C95.3,178.3 98.7,176.5 102.0,174.4 C105.3,172.3 108.7,170.0 112.0,167.5 C115.3,165.0 118.7,162.3 122.0,159.4 C125.3,156.5 128.7,153.3 132.0,150.0 C135.3,146.7 138.7,143.1 142.0,139.4 C145.3,135.6 148.7,131.7 152.0,127.5 C155.3,123.3 158.7,119.0 162.0,114.4 C165.3,109.8 168.7,105.0 172.0,100.0 C175.3,95.0 178.7,89.8 182.0,84.4 C185.3,79.0 188.7,73.3 192.0,67.5 C195.3,61.7 198.7,55.6 202.0,49.4 C205.3,43.1 210.3,33.2 212.0,30.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\"/><text x=\"150\" y=\"106\" font-size=\"9.5\" fill=\"var(--mu)\">45°-lijn</text><text x=\"84\" y=\"166\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--or)\">Lorenz</text><text x=\"118\" y=\"208\" font-size=\"9.5\" fill=\"var(--mu)\">% huishoudens</text><text x=\"22\" y=\"122\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 122)\">% inkomen</text></svg><div class=\"sam-figcap\"><strong>Lorenzcurve:</strong> hoe verder de curve van de 45°-lijn (volledige gelijkheid) afbuigt, hoe <strong>groter de inkomensongelijkheid</strong> (het gekleurde vlak).</div></div><ul><li><strong>Lorenzcurve</strong>: toont de inkomensverdeling; hoe verder van de 45°-lijn van volledige gelijkheid, hoe groter de ongelijkheid</li><li><strong>Nivelleren / denivelleren</strong>: inkomensverschillen kleiner maken / groter maken</li><li><strong>Primaire inkomensverdeling</strong>: vóór belasting, premies, subsidies en uitkeringen</li><li><strong>Secundaire inkomensverdeling</strong>: ná belasting en uitkeringen; meer genivelleerd dan de primaire</li><li><strong>Toeslagen</strong>: inkomensafhankelijke bijdragen (zorg-, huur-, kinderopvangtoeslag, kindgebonden budget); nivellerend</li><li><strong>Sociale voorzieningen vs verzekeringen</strong>: voorzieningen (bijstand) uit belasting; verzekeringen (AOW, WW, WIA) uit premies</li></ul><div class=\"sam-head\">Pensioen, risico en verzekeren</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Omslagstelsel</div><ul><li>werkenden nu betalen de huidige gepensioneerden</li><li>voorbeeld: AOW</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Kapitaaldekkingsstelsel</div><ul><li>je spaart en belegt voor je eigen pensioen</li><li>voorbeeld: bedrijfspensioen</li></ul></div></div><ul><li><strong>Waardevast vs welvaartsvast</strong>: waardevast stijgt mee met de prijzen (koopkracht gelijk), welvaartsvast met de lonen</li><li><strong>Risico-avers</strong>: iemand die risico liever vermijdt en zekerheid verkiest (basis voor verzekeren)</li><li><strong>Asymmetrische informatie</strong>: de ene partij weet meer dan de andere; verhoogt het risico voor de minst geïnformeerde</li><li><strong>Averechtse selectie</strong>: vóór het contract: vooral hoge risico’s verzekeren zich / slechte agenten worden aangetrokken</li><li><strong>Moral hazard</strong>: ná het contract: roekelozer gedrag omdat de schade toch gedekt is</li><li><strong>Premiedifferentiatie, bonus-malus, eigen risico</strong>: manieren om moral hazard tegen te gaan</li></ul><div class=\"sam-head\">Strategisch gedrag: principaal-agent en speltheorie</div><ul><li><strong>Principaal-agenttheorie</strong>: opdrachtgever (principaal) en opdrachtnemer (agent) met conflicterende belangen en informatie-asymmetrie; oplossing via screening, monitoring en prestatieprikkels</li><li><strong>Verzonken kosten</strong>: al gemaakte, niet-terugvorderbare uitgaven; mogen geen rol spelen in toekomstige beslissingen</li><li><strong>Berovingsprobleem</strong>: een investering kan waardeloos worden door strategisch gedrag van een ander (contracten beperken dit)</li><li><strong>Opbrengstenmatrix</strong>: tabel met de opbrengsten voor elke combinatie van keuzes (simultaan spel)</li><li><strong>Dominante strategie</strong>: een keuze die het beste is, ongeacht wat de ander doet</li><li><strong>Nash-evenwicht</strong>: niemand wil nog van keuze veranderen, gegeven de keuze van de ander</li><li><strong>Gevangenendilemma</strong>: het Nash-evenwicht is voor beiden slechter dan samenwerken; zelfbinding of afspraken kunnen dit verbeteren</li></ul><div class=\"sam-figure\"><svg viewBox=\"0 0 340 224\" role=\"img\" aria-label=\"Gevangenendilemma opbrengstenmatrix\"><text x=\"216\" y=\"26\" font-size=\"10\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">Speler B</text><text x=\"166\" y=\"58\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Zwijgt</text><text x=\"266\" y=\"58\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"middle\">Bekent</text><text x=\"22\" y=\"134\" font-size=\"10\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\" transform=\"rotate(-90 22 134)\">Speler A</text><text x=\"108\" y=\"108\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">Zwijgt</text><text x=\"108\" y=\"168\" font-size=\"9\" fill=\"var(--mu)\" text-anchor=\"end\">Bekent</text><rect x=\"120\" y=\"70\" width=\"92\" height=\"60\" fill=\"none\" stroke=\"var(--bo2)\" stroke-width=\"1.5\"/><rect x=\"212\" y=\"70\" width=\"92\" height=\"60\" fill=\"none\" stroke=\"var(--bo2)\" stroke-width=\"1.5\"/><rect x=\"120\" y=\"130\" width=\"92\" height=\"60\" fill=\"none\" stroke=\"var(--bo2)\" stroke-width=\"1.5\"/><rect x=\"212\" y=\"130\" width=\"92\" height=\"60\" fill=\"rgba(var(--or-rgb),.16)\" stroke=\"var(--or)\" stroke-width=\"2\"/><text x=\"166\" y=\"105\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">−1 , −1</text><text x=\"258\" y=\"105\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">−10 , 0</text><text x=\"166\" y=\"165\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">0 , −10</text><text x=\"258\" y=\"163\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">−5 , −5</text><text x=\"258\" y=\"182\" font-size=\"8\" font-weight=\"700\" fill=\"var(--or)\" text-anchor=\"middle\">Nash</text><text x=\"170\" y=\"212\" font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\">(uitkomsten als A , B — jaren cel)</text></svg><div class=\"sam-figcap\"><strong>Gevangenendilemma:</strong> beide bekennen is het <strong>Nash-evenwicht</strong> (−5, −5), terwijl beide zwijgen (−1, −1) voor allebei beter was. Eigenbelang leidt tot een slechtere uitkomst.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Je zet €2000 weg tegen 3% rente per jaar (samengesteld). De inflatie is 2%. Hoeveel staat er na 2 jaar, en wat is de reële rente?</div><ol class=\"sam-worked-steps\"><li>Samengestelde rente: eindbedrag = 2000 × 1,03² = 2000 × 1,0609.</li><li>= €2121,80 na 2 jaar.</li><li>Reële rente ≈ nominale rente − inflatie = 3% − 2% = 1%.</li></ol><div class=\"sam-worked-ans\">✅ €2121,80 op de rekening; je koopkracht groeit maar met ≈ 1% per jaar.</div></div>","havo_ec_E":"<div class=\"sam-intro\">De economie beweegt in golven. <strong>Conjunctuur, geld en inflatie hangen samen</strong>, en de overheid (begroting) en de centrale bank (rente) proberen die golf te temmen.</div><div class=\"sam-head\">Geld en banken</div><p>Geld lost de problemen van ruilhandel op doordat het <strong>ruilmiddel, rekenmiddel en oppotmiddel</strong> is. <strong>Fiduciair geld</strong> ontleent zijn waarde aan vertrouwen.</p><ul><li><strong>Chartaal vs giraal geld</strong>: chartaal = bankbiljetten en munten; giraal = direct opeisbare tegoeden bij banken</li><li><strong>Maatschappelijke geldhoeveelheid</strong>: giraal geld + chartaal geld van het publiek</li><li><strong>Geldschepping</strong>: banken brengen geld in omloop door uit te lenen; gebonden aan een liquiditeitseis (DNB houdt toezicht)</li><li><strong>Interne vs externe waarde</strong>: interne waarde = koopkracht; externe waarde = de wisselkoers (waarde in een andere valuta)</li><li><strong>Wet van Gresham</strong>: slecht geld verdringt goed geld</li></ul><div class=\"sam-head\">Conjunctuur</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Reëel bbp (index)</div><div class=\"sam-formula-eq\">index reëel bbp = (index nominaal bbp / index prijspeil) × 100</div><div class=\"sam-formula-note\">Nominale groei is in euro’s; reële groei is gecorrigeerd voor inflatie en toont de echte productiegroei.</div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 330 196\" role=\"img\" aria-label=\"Conjunctuurgolf: het reële bbp schommelt rond de trendlijn\"><defs><marker id=\"ahE\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"48\" y1=\"170\" x2=\"48\" y2=\"24\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahE)\"/><line x1=\"46\" y1=\"168\" x2=\"314\" y2=\"168\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#ahE)\"/><line x1=\"48\" y1=\"158\" x2=\"300\" y2=\"42\" stroke=\"var(--mu)\" stroke-width=\"1.5\" stroke-dasharray=\"5 4\"/><path d=\"M48.0,158.0 C50.0,155.2 56.0,146.2 60.0,141.2 C64.0,136.3 68.0,131.5 72.0,128.3 C76.0,125.1 80.0,122.9 84.0,121.9 C88.0,120.9 92.0,121.4 96.0,122.3 C100.0,123.2 104.0,125.5 108.0,127.4 C112.0,129.3 116.0,132.0 120.0,133.5 C124.0,135.1 128.0,136.6 132.0,136.7 C136.0,136.7 140.0,135.9 144.0,133.8 C148.0,131.6 152.0,128.1 156.0,123.9 C160.0,119.7 164.0,114.1 168.0,108.7 C172.0,103.2 176.0,96.8 180.0,91.3 C184.0,85.9 188.0,80.3 192.0,76.1 C196.0,71.9 200.0,68.4 204.0,66.2 C208.0,64.1 212.0,63.3 216.0,63.3 C220.0,63.4 224.0,64.9 228.0,66.5 C232.0,68.0 236.0,70.7 240.0,72.6 C244.0,74.5 248.0,76.8 252.0,77.7 C256.0,78.6 260.0,79.1 264.0,78.1 C268.0,77.1 272.0,74.9 276.0,71.7 C280.0,68.5 284.0,63.7 288.0,58.8 C292.0,53.8 298.0,44.8 300.0,42.0\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.6\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/><text x=\"250\" y=\"52\" font-size=\"9.5\" fill=\"var(--mu)\">trend</text><text x=\"68\" y=\"110\" font-size=\"9.5\" font-weight=\"700\" fill=\"#16a34a\">hoog</text><text x=\"116\" y=\"152\" font-size=\"9.5\" font-weight=\"700\" fill=\"#dc2626\">laag</text><text x=\"270\" y=\"186\" font-size=\"9.5\" fill=\"var(--mu)\">tijd</text><text x=\"22\" y=\"104\" font-size=\"9.5\" fill=\"var(--mu)\" transform=\"rotate(-90 22 104)\">reëel bbp</text></svg><div class=\"sam-figcap\"><strong>Conjunctuurgolf:</strong> het reële bbp schommelt rond de stijgende trendlijn. Boven de trend = <strong>hoogconjunctuur</strong>, eronder = <strong>laagconjunctuur</strong>.</div></div><ul><li><strong>Productiecapaciteit</strong>: de maximale productie als alle productiefactoren volledig worden benut</li><li><strong>Hoog- vs laagconjunctuur</strong>: reële bbp-groei boven respectievelijk onder de trendlijn</li><li><strong>Recessie / depressie</strong>: twee kwartalen krimp / een ernstige, langdurige recessie met massale werkloosheid</li><li><strong>Onderbesteding (negatieve spiraal)</strong>: minder besteden → minder productie → meer werkloosheid → lager inkomen → nog minder besteden</li><li><strong>Conjunctuurklok</strong>: het CBS bundelt vertrouwens-, economische en arbeidsmarktindicatoren; 12 uur = hoog, 6 uur = laag</li></ul><div class=\"sam-head\">Inflatie</div><ul><li><strong>Inflatie / deflatie</strong>: algemene prijsstijging (koopkracht daalt) / prijsdaling (koopkracht stijgt)</li><li><strong>Bestedingsinflatie</strong>: de vraag is groter dan het aanbod (te veel geld jaagt te weinig goederen na)</li><li><strong>Kosteninflatie</strong>: hogere productiekosten (lonen, grondstoffen) worden doorberekend in de prijzen</li></ul><div class=\"sam-tip\">Inflatie maakt een schuldenlast lichter en spaargeld minder waard. Een vaste uitkering verliest koopkracht; een waardevaste uitkering stijgt mee met de prijzen.</div><div class=\"sam-head\">Anticyclisch beleid van de overheid</div><ul><li><strong>Automatische stabilisatoren</strong>: dempen de conjunctuur vanzelf: het progressieve belastingstelsel en de sociale zekerheid (zonder nieuw besluit)</li><li><strong>Actief anticyclisch beleid</strong>: de overheid grijpt bewust in: in laagconjunctuur meer uitgeven of belasting verlagen, in hoogconjunctuur het omgekeerde</li><li><strong>Inverdieneffect</strong>: hogere uitgaven leiden tot meer productie en extra belastinginkomsten</li><li><strong>Uitverdieneffect</strong>: belastingverhoging drukt consumptie en productie, waardoor de opbrengst tegenvalt</li></ul><div class=\"sam-head\">De centrale bank (ECB)</div><ul><li><strong>Monetair beleid</strong>: de ECB stuurt de inflatie richting ongeveer 2% via de rente en de geldhoeveelheid</li><li><strong>Refi-rente</strong>: de rente die de ECB aan commerciële banken rekent</li><li><strong>Rente bij conjunctuur</strong>: bij hoogconjunctuur verhoogt de ECB de rente (minder lenen/besteden); bij laagconjunctuur verlaagt ze die</li><li><strong>EMU</strong>: de Economische en Monetaire Unie: de eurolanden met de euro als gezamenlijke munt; de ECB voert onafhankelijk beleid voor de EU als geheel</li><li><strong>Stabiliteits- en groeipact</strong>: onder andere: begrotingstekort ≤ 3% van het bbp en staatsschuld ≤ 60% van het bbp</li></ul><div class=\"sam-head\">Internationale handel, groei en werkloosheid</div><ul><li><strong>Vrijhandel vs protectionisme</strong>: vrije handel geeft specialisatie en welvaart; protectionisme beschermt de eigen economie</li><li><strong>Protectionistische maatregelen</strong>: importtarieven (invoerrechten), importquota en strenge importvoorschriften</li><li><strong>Motieven protectionisme</strong>: het infant-industry-argument, het tegengaan van dumping en het beschermen van strategische sectoren</li><li><strong>Betalingsbalans</strong>: overzicht van alle transacties met het buitenland: lopende rekening (goederen, diensten, inkomens) en financiële rekening</li><li><strong>Structurele economische groei</strong>: blijvende groei van het reële bbp per capita door meer of betere productiefactoren (onderwijs, innovatie/R&D, infrastructuur)</li></ul><table class=\"sam-table\"><thead><tr><th>Vorm van werkloosheid</th><th>Oorzaak</th></tr></thead><tbody><tr><td>Frictiewerkloosheid</td><td>tijdelijk tussen twee banen of na de studie</td></tr><tr><td>Kwalitatief structureel</td><td>mismatch in vaardigheden, opleiding of regio</td></tr><tr><td>Kwantitatief structureel</td><td>te weinig banen door automatisering of verplaatsing</td></tr><tr><td>Seizoenswerkloosheid</td><td>werk dat alleen in bepaalde seizoenen bestaat</td></tr><tr><td>Conjuncturele werkloosheid</td><td>dalende bestedingen in een laagconjunctuur</td></tr></tbody></table><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Het nominale bbp stijgt met 5%, terwijl de prijzen met 3% stijgen. Groeit de economie reëel?</div><ol class=\"sam-worked-steps\"><li>Reële groei ≈ nominale groei − inflatie = 5% − 3% = 2%.</li><li>Exacter via index: (105 / 103) × 100 ≈ 101,9 → +1,9%.</li><li>Positief → er wordt echt méér geproduceerd, niet alleen tegen hogere prijzen.</li></ol><div class=\"sam-worked-ans\">✅ Ja, de economie groeit reëel met ≈ 2%.</div></div>","havo_gs_A":"<div class=\"sam-intro\">Geschiedenis is geordend in <strong>tien tijdvakken</strong>, elk met een paar kenmerkende aspecten. Heb je die volgorde als kapstok in je hoofd, dan plaats je elke gebeurtenis razendsnel — dat is de kern van het examen.</div><div class=\"sam-head\">Tien tijdvakken</div><div class=\"sam-figure\"><svg viewBox=\"0 0 420 78\" role=\"img\" aria-label=\"De tien tijdvakken op een tijdbalk\"><defs><marker id=\"tvA\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"14.0\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.22)\"/><text x=\"32.9\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">1</text><rect x=\"53.2\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.29)\"/><text x=\"72.1\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">2</text><rect x=\"92.4\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.36)\"/><text x=\"111.2\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">3</text><rect x=\"131.6\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.44)\"/><text x=\"150.5\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">4</text><rect x=\"170.8\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.51)\"/><text x=\"189.7\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">5</text><rect x=\"210.0\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.58)\"/><text x=\"228.8\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">6</text><rect x=\"249.2\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.65)\"/><text x=\"268.1\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">7</text><rect x=\"288.4\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.72)\"/><text x=\"307.3\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">8</text><rect x=\"327.6\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.80)\"/><text x=\"346.5\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">9</text><rect x=\"366.8\" y=\"26\" width=\"37.7\" height=\"30\" rx=\"3\" fill=\"rgba(var(--or-rgb),0.87)\"/><text x=\"385.7\" y=\"45\" font-size=\"13\" font-weight=\"800\" fill=\"var(--dk)\" text-anchor=\"middle\">10</text><text x=\"14\" y=\"20\" font-size=\"8.6\" fill=\"var(--mu)\">3000 v.C.</text><text x=\"406\" y=\"20\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"end\">heden</text><line x1=\"14\" y1=\"68\" x2=\"406\" y2=\"68\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#tvA)\"/><text x=\"14\" y=\"64\" font-size=\"8.4\" fill=\"var(--mu)\">verleden</text></svg><div class=\"sam-figcap\"><strong>De tien tijdvakken</strong> als kapstok: van de prehistorie (1) tot nu (10); de kleur loopt op met de tijd.</div></div><table class=\"sam-table\"><thead><tr><th>#</th><th>Tijdvak</th><th>Periode</th><th>Kenmerkend aspect</th></tr></thead><tbody><tr><td>1</td><td><strong>Jagers en boeren</strong></td><td>tot 3000 v.C.</td><td>Neolithische revolutie: overgang van nomaden naar landbouw en veehouderij</td></tr><tr><td>2</td><td><strong>Grieken en Romeinen</strong></td><td>3000 v.C.–500 n.C.</td><td>Democratie in Athene; Romeinse rechtsstaat en expansie</td></tr><tr><td>3</td><td><strong>Monniken en ridders</strong></td><td>500–1000</td><td>Verspreiding christendom; feodalisme; Karel de Grote</td></tr><tr><td>4</td><td><strong>Steden en staten</strong></td><td>1000–1500</td><td>Opkomst handel en steden; kruistochten; Hanze</td></tr><tr><td>5</td><td><strong>Ontdekkers en hervormers</strong></td><td>1500–1600</td><td>Reformatie; Europese expansie en kolonialisme; Copernicus</td></tr><tr><td>6</td><td><strong>Regenten en vorsten</strong></td><td>1600–1700</td><td>Gouden Eeuw; absolutisme (Lodewijk XIV); VOC en slavenhandel</td></tr><tr><td>7</td><td><strong>Pruiken en revoluties</strong></td><td>1700–1800</td><td>Verlichting; Amerikaanse en Franse Revolutie; democratiedrang</td></tr><tr><td>8</td><td><strong>Burgers en stoommachines</strong></td><td>1800–1900</td><td>Industrialisatie; nationalisme; socialisme; imperialisme</td></tr><tr><td>9</td><td><strong>Wereldoorlogen</strong></td><td>1900–1950</td><td>WO I en WO II; totalitarisme; Holocaust; begin dekolonisatie</td></tr><tr><td>10</td><td><strong>Televisie en computers</strong></td><td>1950–heden</td><td>Koude Oorlog; dekolonisatie; Europese integratie; globalisering</td></tr></tbody></table><div class=\"sam-head\">Historische denkvaardigheden</div><ul><li><strong>Chronologisch ordenen</strong>: plaatsen van gebeurtenissen in de juiste tijdsvolgorde. Gebruik tijdvakken als kapstok voor oriëntatie.</li><li><strong>Oorzaak en gevolg</strong>: onderscheid directe oorzaak (aanleiding) van structurele oorzaken (onderliggende factoren). Bijv. moord op Frans Ferdinand = aanleiding WO I; nationalisme + imperialisme + bondgenootschappen = structurele oorzaken.</li><li><strong>Perspectief</strong>: mensen in het verleden dachten anders dan wij. Beoordeel handelingen vanuit de context van hun tijd, niet met moderne normen (anachronisme vermijden).</li><li><strong>Verandering en continuïteit</strong>: wat veranderde? Wat bleef gelijk? Niet alles verandert tegelijk of even snel.</li><li><strong>Bronkritiek</strong>: wie schreef de bron, wanneer, met welk doel? Primaire bron (tijdgenoot) vs. secundaire bron (later historicus). Elke bron heeft een perspectief.</li></ul><div class=\"sam-tip\">Bij een historische vergelijkingsvraag: noem altijd zowel overeenkomsten als verschillen. Een antwoord dat er één kant belicht scoort maximaal de helft van de punten.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Examenvraag: leg uit dat de moord op Frans Ferdinand (1914) een aanleiding en geen structurele oorzaak van de Eerste Wereldoorlog was.</div><ol class=\"sam-worked-steps\"><li>Maak het onderscheid: een aanleiding is de directe vonk; structurele oorzaken spelen al langer.</li><li>Noem structurele oorzaken: nationalisme, imperialisme, het bondgenootschappenstelsel en de bewapeningswedloop.</li><li>Leg het verband: zonder die spanningen had de moord geen wereldoorlog ontketend — hij was de vonk in een al explosief geheel.</li></ol><div class=\"sam-worked-ans\">✅ Benoem de moord als aanleiding én minstens één structurele oorzaak, en leg het verband — dat levert de punten op.</div></div>","havo_gs_B":"<div class=\"sam-intro\">⭐ Veruit het belangrijkste domein voor het CE. <strong>Tien tijdvakken plus drie historische contexten</strong> — gebruik de tijdbalken hieronder om eerst de chronologie vast te zetten, en stamp daarna pas de begrippen erbij.</div><div class=\"sam-head\">🌾 Tijdvak 1 — Jagers en boeren (tot 3000 v.C.)</div> <p>Van rondtrekkende jagers-verzamelaars naar de eerste boeren en steden in het Midden-Oosten.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Landbouwrevolutie</span><span class=\"sam-chip\">Eerste steden</span><span class=\"sam-chip\">Sociale ongelijkheid</span></div> <ul> <li><strong>Prehistorie</strong>: de tijd vóór het schrift; onze kennis komt uit archeologie (bijv. de vondst van Ötzi).</li> <li><strong>Jager-verzamelaars</strong>: nomaden die leefden van jagen en het verzamelen van voedsel.</li> <li><strong>Landbouwrevolutie</strong>: de overgang rond 9000 v.C. naar zelf voedsel verbouwen; begon in het Midden-Oosten.</li> <li><strong>Domesticatie</strong>: het temmen en veredelen van planten en dieren.</li> <li><strong>Sedentair</strong>: op een vaste plek wonen, tegenover de nomadische leefwijze.</li> <li><strong>Autarkie</strong>: dorpen die zelfvoorzienend zijn en alles zelf produceren.</li> <li><strong>Sociale ongelijkheid</strong>: verschil in bezit, aanzien en macht; ontstond door vast bezit.</li> <li><strong>Natuurgodsdienst</strong>: geloof in goden die samenvallen met natuurverschijnselen of dieren.</li> <li><strong>Landbouwstedelijke samenleving</strong>: de eerste steden (Soemeriërs in Mesopotamië, ~3000 v.C.).</li> <li><strong>Spijkerschrift</strong>: het Soemerische schrift; in Egypte gebruikte men hiërogliefen.</li> <li><strong>Specialisatie</strong>: het ontstaan van aparte beroepen dankzij een landbouwoverschot.</li> </ul> <div class=\"sam-head\">🏛️ Tijdvak 2 — Grieken en Romeinen (3000 v.C.–500 n.C.)</div> <p>De klassieke oudheid: Griekse stadstaten en wetenschap, het Romeinse imperium en de opkomst van het christendom.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Griekse democratie</span><span class=\"sam-chip\">Romeins imperium</span><span class=\"sam-chip\">Opkomst christendom</span></div> <ul> <li><strong>Polis</strong>: een onafhankelijke Griekse stadstaat.</li> <li><strong>Directe democratie</strong>: in Athene (vanaf 507 v.C.) stemden burgers zelf over wetten en bestuurders.</li> <li><strong>Rationeel-wetenschappelijk wereldbeeld</strong>: de wereld verklaren vanuit verstand en onderzoek in plaats van goden.</li> <li><strong>Griekse filosofen</strong>: Socrates, Plato en Aristoteles.</li> <li><strong>Klassieke vormentaal</strong>: de Grieks-Romeinse stijl in kunst en bouwkunst.</li> <li><strong>Romanisering</strong>: de verspreiding van de Grieks-Romeinse cultuur over het rijk.</li> <li><strong>Pax Romana</strong>: ongeveer twee eeuwen van vrede en welvaart in het keizerrijk.</li> <li><strong>Limes</strong>: de bewaakte buitengrens van het Romeinse Rijk.</li> <li><strong>Monotheïsme</strong>: het geloof in één God (jodendom en christendom).</li> <li><strong>Diaspora</strong>: de verspreiding van de joden over de wereld.</li> <li><strong>Christendom als staatsgodsdienst</strong>: in 380 n.C. onder keizer Theodosius.</li> </ul> <table class=\"sam-table\"><thead><tr><th>Bestuursvorm</th><th>Wie heeft de macht?</th></tr></thead><tbody> <tr><td>Monarchie</td><td>één erfelijke koning</td></tr> <tr><td>Aristocratie</td><td>een groep met erfelijke voorrechten (adel)</td></tr> <tr><td>Oligarchie</td><td>enkele rijke families</td></tr> <tr><td>Tirannie</td><td>één autoritaire alleenheerser</td></tr> <tr><td>Democratie</td><td>(een deel van) de burgers</td></tr> </tbody></table> <div class=\"sam-head\">🛡️ Tijdvak 3 — Monniken en ridders (500–1000)</div> <p>De vroege middeleeuwen: hofstelsel en feodalisme, de verspreiding van christendom en islam.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Hofstelsel</span><span class=\"sam-chip\">Feodalisme</span><span class=\"sam-chip\">Opkomst islam</span></div><div class=\"sam-figure\"><svg viewBox=\"0 0 320 200\" role=\"img\" aria-label=\"Feodale piramide\"><polygon points=\"160,25 188,60 132,60\" fill=\"rgba(var(--or-rgb),.85)\"/><polygon points=\"132,60 188,60 220,100 100,100\" fill=\"rgba(var(--or-rgb),.58)\"/><polygon points=\"100,100 220,100 252,140 68,140\" fill=\"rgba(var(--or-rgb),.38)\"/><polygon points=\"68,140 252,140 280,175 40,175\" fill=\"rgba(var(--or-rgb),.20)\"/><polygon points=\"160,25 280,175 40,175\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/><text x=\"160\" y=\"51\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">Koning</text><text x=\"160\" y=\"86\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">Adel (leenheren)</text><text x=\"160\" y=\"125\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Ridders (vazallen)</text><text x=\"160\" y=\"162\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Horigen · boeren</text></svg><div class=\"sam-figcap\"><strong>Feodale piramide:</strong> de koning geeft land in leen aan de adel, die het doorgeeft aan ridders; onderaan bewerken de horigen het land (hofstelsel).</div></div> <ul> <li><strong>Hofstelsel</strong>: economisch stelsel waarin horigen werken op het domein van een landheer.</li> <li><strong>Horigen</strong>: onvrije boeren, gebonden aan het land, die herendiensten leveren.</li> <li><strong>Feodalisme</strong>: leenstelsel waarbij een leenheer land of een ambt in leen geeft aan leenmannen in ruil voor trouw.</li> <li><strong>Kerstening</strong>: het bekeren van volken tot het christendom (Clovis, Karel de Grote).</li> <li><strong>Syncretisme</strong>: de vermenging van christelijke en heidense gebruiken.</li> <li><strong>Islam</strong>: gesticht door Mohammed (vanaf 610); kernbegrippen zijn de Koran, de vijf zuilen en de jihad.</li> <li><strong>Kalifaat</strong>: de islamitische staat onder een kalief; groeide uit tot een groot Arabisch Rijk.</li> <li><strong>Soennieten en sjiieten</strong>: de twee hoofdstromingen binnen de islam.</li> <li><strong>Karel de Grote</strong>: in 800 tot keizer gekroond; verenigde een groot deel van Europa.</li> <li><strong>Tweezwaardenleer</strong>: de scheiding tussen wereldlijke en geestelijke macht.</li> </ul> <div class=\"sam-head\">🏰 Tijdvak 4 — Steden en staten (1000–1500)</div> <p>De late middeleeuwen: opbloei van steden en handel, kerk-staatconflicten en beginnende staatsvorming.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Steden &amp; handel</span><span class=\"sam-chip\">Kerk vs staat</span><span class=\"sam-chip\">Staatsvorming</span></div> <ul> <li><strong>Verstedelijking</strong>: de hernieuwde groei van steden vanaf ongeveer het jaar 1000.</li> <li><strong>Drieslagstelsel</strong>: efficiëntere akkerbouw die zorgde voor een landbouwoverschot.</li> <li><strong>Geldeconomie</strong>: handel met geld, wisselbrieven en banken in plaats van ruilhandel.</li> <li><strong>Hanze</strong>: een samenwerkingsverband van Noord-Europese handelssteden.</li> <li><strong>Stadsrechten</strong>: privileges (eigen wetten, stadsmuren) die een stad van een heer kreeg.</li> <li><strong>Gilden</strong>: stedelijke beroepsverenigingen waar je verplicht lid van moest zijn.</li> <li><strong>Investituurstrijd</strong>: het conflict (1076–1122) tussen paus en keizer over het benoemen van bisschoppen.</li> <li><strong>Inquisitie</strong>: een kerkelijke rechtbank die ketters veroordeelde.</li> <li><strong>Kruistochten</strong>: heilige oorlogen om het Heilige Land, vanaf 1095.</li> <li><strong>Reconquista</strong>: de christelijke herovering van het Iberisch schiereiland op de moslims.</li> <li><strong>Staatsvorming en centralisatie</strong>: vorsten maken hun rijk tot één geheel met centraal bestuur.</li> <li><strong>Magna Carta</strong>: document uit 1215 dat de macht van de Engelse koning inperkte.</li> </ul> <div class=\"sam-head\">🧭 Tijdvak 5 — Ontdekkers en hervormers (1500–1600)</div> <p>De vroegmoderne tijd: Europese expansie over zee, Renaissance, Reformatie en het begin van de Opstand.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Europese expansie</span><span class=\"sam-chip\">Renaissance</span><span class=\"sam-chip\">Reformatie</span></div> <ul> <li><strong>Overzeese expansie</strong>: Europese ontdekkingsreizen op zoek naar goud, handel en christelijk grondgebied.</li> <li><strong>Vasco da Gama</strong>: bereikte in 1498 via Kaap de Goede Hoop een zeeroute naar Indië.</li> <li><strong>Columbus</strong>: bereikte in 1492 (per ongeluk) Amerika.</li> <li><strong>Renaissance</strong>: letterlijk \"wedergeboorte\"; een heroriëntatie op de klassieke oudheid.</li> <li><strong>Humanisme</strong>: kritisch denken staat centraal, niet blind vertrouwen op de Bijbel (Erasmus).</li> <li><strong>Reformatie</strong>: kerkhervorming; Luther (95 stellingen, 1517) en Calvijn.</li> <li><strong>Antiklerikalisme</strong>: verzet tegen de macht en rijkdom van de geestelijkheid.</li> <li><strong>Beeldenstorm</strong>: protestantse vernieling van katholieke kerken in 1566.</li> <li><strong>Tachtigjarige Oorlog</strong>: de Opstand tegen Filips II (1568–1648).</li> <li><strong>Unie van Utrecht</strong>: het bondgenootschap van de noordelijke gewesten (1579).</li> <li><strong>Plakkaat van Verlatinghe</strong>: de onafhankelijkheidsverklaring van 1581.</li> </ul> <div class=\"sam-head\">⚓ Tijdvak 6 — Regenten en vorsten (1600–1700)</div> <p>De Gouden Eeuw van de Republiek, het handelskapitalisme van VOC en WIC en de wetenschappelijke revolutie.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Gouden Eeuw</span><span class=\"sam-chip\">Handelskapitalisme</span><span class=\"sam-chip\">Wetenschappelijke revolutie</span></div> <ul> <li><strong>Republiek der Zeven Verenigde Nederlanden</strong>: een staat zonder koning, bestuurd via de Staten-Generaal en regenten.</li> <li><strong>Stadhouder</strong>: de machtigste man, meestal een prins van Oranje.</li> <li><strong>Gouden Eeuw</strong>: de 17e-eeuwse bloei van handel, nijverheid en cultuur.</li> <li><strong>Stapelmarkt</strong>: de Republiek als centrale opslag- en doorvoerplaats van Europa.</li> <li><strong>Handelskapitalisme</strong>: investeren met aandelen om winst te maken met handel.</li> <li><strong>VOC</strong>: opgericht in 1602; het eerste bedrijf met verhandelbare aandelen en een monopolie op de handel met Azië.</li> <li><strong>WIC</strong>: opgericht in 1621; monopolie op de Atlantische handel en de driehoekshandel.</li> <li><strong>Driehoekshandel</strong>: handel tussen Europa, Afrika en Amerika, verbonden met slavernij.</li> <li><strong>Wetenschappelijke revolutie</strong>: de natuur als machine, met eigen methoden (Bacon, Descartes, Newton).</li> <li><strong>Heliocentrisme</strong>: het idee dat de aarde om de zon draait (Copernicus, Galilei).</li> <li><strong>Absolutisme</strong>: een vorst met alle macht, zoals elders in Europa.</li> </ul> <div class=\"sam-head\">⚖️ Tijdvak 7 — Pruiken en revoluties (1700–1800)</div> <p>De Verlichting en de democratische revoluties in Amerika, Frankrijk en de Nederlanden.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Verlichting</span><span class=\"sam-chip\">Democratische revoluties</span><span class=\"sam-chip\">Trias politica</span></div> <ul> <li><strong>Verlichting</strong>: nadruk op de rede (ratio) tegen onwetendheid en intolerantie.</li> <li><strong>Rationalisme</strong>: kennis en vooruitgang via het verstand.</li> <li><strong>Volkssoevereiniteit</strong>: de macht komt van het volk, niet van God (Locke, Rousseau).</li> <li><strong>Trias politica</strong>: scheiding van wetgevende, uitvoerende en rechterlijke macht (Montesquieu).</li> <li><strong>Verlicht absolutisme</strong>: een vorst voert verlichte hervormingen door maar houdt alle macht.</li> <li><strong>Ancien régime</strong>: de Franse standensamenleving vol ongelijkheid vóór de revolutie.</li> <li><strong>Abolitionisme</strong>: het streven naar afschaffing van de slavernij.</li> <li><strong>Amerikaanse Revolutie</strong>: onafhankelijkheid van de VS (1776); \"no taxation without representation\".</li> <li><strong>Franse Revolutie</strong>: begon in 1789 met de bestorming van de Bastille; Verklaring van de Rechten van de Mens.</li> <li><strong>Bataafse Revolutie</strong>: de patriotten kwamen in 1795 met Franse hulp aan de macht.</li> <li><strong>Napoleon</strong>: greep in 1799 de macht, kroonde zich keizer (1804) en werd in 1815 verslagen bij Waterloo.</li> </ul> <div class=\"sam-head\">🚂 Tijdvak 8 — Burgers en stoommachines (1800–1900)</div> <p>Industrialisatie, de sociale kwestie, modern imperialisme en de opkomst van politieke stromingen en emancipatie.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Industrialisatie</span><span class=\"sam-chip\">Sociale kwestie</span><span class=\"sam-chip\">Modern imperialisme</span></div> <ul> <li><strong>Industriële revolutie</strong>: productie met machines en stoomkracht vanaf ongeveer 1800.</li> <li><strong>Stoommachine</strong>: een betrouwbare energiebron, sterk verbeterd door James Watt (1764).</li> <li><strong>Urbanisatie</strong>: de trek van het platteland naar de stad.</li> <li><strong>Sociale kwestie</strong>: de slechte woon- en werkomstandigheden, kinderarbeid en lage lonen van arbeiders.</li> <li><strong>Bourgeoisie en proletariaat</strong>: de bezittende klasse tegenover de arbeidersklasse (Marx).</li> <li><strong>Modern imperialisme</strong>: het opbouwen van grote koloniale rijken (Conferentie van Berlijn, 1884).</li> <li><strong>Censuskiesrecht</strong>: stemrecht alleen voor mannen die genoeg belasting betaalden.</li> <li><strong>Grondwet van 1848</strong>: Thorbecke voerde ministeriële verantwoordelijkheid en een direct gekozen Tweede Kamer in.</li> <li><strong>Emancipatie</strong>: feminisme (Aletta Jacobs) en abolitionisme streden voor gelijke rechten.</li> <li><strong>Schoolstrijd</strong>: de strijd om overheidssubsidie voor bijzonder (religieus) onderwijs.</li> </ul> <table class=\"sam-table\"><thead><tr><th>Politieke stroming</th><th>Kernidee</th></tr></thead><tbody> <tr><td>Liberalisme</td><td>individuele vrijheid en een vrije markt met weinig overheid</td></tr> <tr><td>Socialisme</td><td>opkomen voor de arbeiders en tegen ongelijkheid in macht en rijkdom</td></tr> <tr><td>Confessionalisme</td><td>politiek gebaseerd op religieuze normen en waarden</td></tr> <tr><td>Nationalisme</td><td>sterke verbondenheid met het eigen land en volk</td></tr> </tbody></table> <div class=\"sam-head\">🪖 Tijdvak 9 — Wereldoorlogen (1900–1950)</div> <p>Twee totale oorlogen, de opkomst van totalitaire regimes, de economische wereldcrisis en de Holocaust.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Wereldoorlogen</span><span class=\"sam-chip\">Totalitarisme</span><span class=\"sam-chip\">Holocaust</span></div> <ul> <li><strong>Eerste Wereldoorlog</strong>: 1914–1918; directe aanleiding was de moord op Frans Ferdinand; loopgravenoorlog.</li> <li><strong>Totale oorlog</strong>: de hele maatschappij wordt in dienst gesteld van de oorlog.</li> <li><strong>Verdrag van Versailles</strong>: 1919; Duitsland werd schuldig verklaard en kreeg herstelbetalingen en gebiedsverlies.</li> <li><strong>Propaganda</strong>: communicatie om de mening van de massa te sturen.</li> <li><strong>Totalitarisme</strong>: één leider of partij met totale controle via censuur en onderdrukking.</li> <li><strong>Beurskrach en Grote Depressie</strong>: de wereldwijde economische crisis vanaf 1929; aanpak via de New Deal.</li> <li><strong>Tweede Wereldoorlog</strong>: 1939–1945; Blitzkrieg, het keerpunt bij Stalingrad en D-Day (1944).</li> <li><strong>Holocaust</strong>: de systematische genocide op de Joden (Wannsee-conferentie 1942, de Endlösung).</li> <li><strong>Bezetting van Nederland</strong>: 1940–1945; aanpassing, collaboratie en verzet; de hongerwinter.</li> </ul> <table class=\"sam-table\"><thead><tr><th>Totalitaire ideologie</th><th>Kenmerk</th></tr></thead><tbody> <tr><td>Communisme</td><td>staatsbezit en gelijkheid; Sovjet-Unie onder Stalin</td></tr> <tr><td>Fascisme</td><td>nationalisme, geweld en leidersverering; Mussolini in Italië</td></tr> <tr><td>Nationaalsocialisme</td><td>fascisme plus antisemitisme en Lebensraum; Hitler in Duitsland</td></tr> </tbody></table> <div class=\"sam-head\">📺 Tijdvak 10 — Televisie en computers (1950–heden)</div> <p>De Koude Oorlog, dekolonisatie, Europese eenwording en een welvarende, ontzuilende en multiculturele samenleving.</p><div class=\"sam-chips\"><span class=\"sam-chip sam-chip-lead\">Kenmerkend</span><span class=\"sam-chip\">Koude Oorlog</span><span class=\"sam-chip\">Dekolonisatie</span><span class=\"sam-chip\">Europese eenwording</span></div> <ul> <li><strong>Koude Oorlog</strong>: 1945–1989; spanning tussen de VS en de Sovjet-Unie, kapitalisme tegenover communisme.</li> <li><strong>IJzeren Gordijn</strong>: de scheiding tussen het westelijke en het communistische Oost-Europa.</li> <li><strong>Containment en Marshallplan</strong>: het indammen van het communisme en economische hulp aan West-Europa.</li> <li><strong>NAVO en Warschaupact</strong>: het westerse (1949) en communistische (1955) militaire bondgenootschap.</li> <li><strong>Cubacrisis</strong>: in 1962 het hoogtepunt van de nucleaire dreiging.</li> <li><strong>Dekolonisatie</strong>: koloniën worden onafhankelijk (Brits-Indië 1947, Indonesië 1949).</li> <li><strong>Politionele acties</strong>: het Nederlandse militaire optreden tegen de Indonesische onafhankelijkheid.</li> <li><strong>Europese eenwording</strong>: EGKS (1952), EEG (1957), de EU (1992) en de euro (2002).</li> <li><strong>Verzorgingsstaat</strong>: uitbouw van sociale zekerheid en een consumptiemaatschappij na de oorlog.</li> <li><strong>Ontzuiling</strong>: het verdwijnen van de zuilen door welvaart, individualisering en secularisatie.</li> <li><strong>Jeugdculturen</strong>: nozems, hippies en provo’s; daarnaast de tweede feministische golf.</li> <li><strong>Multiculturele samenleving</strong>: ontstaan door immigratiegolven (gastarbeiders, Suriname).</li> </ul><div class=\"sam-head\">Historische context — Het Britse Rijk (1585–1900)</div><p>Van eerste koloniën tot wereldmacht: kolonisatie, slavenhandel, India en de industriële revolutie.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 440 122\" role=\"img\" aria-label=\"Tijdbalk Brits Rijk\"><defs><marker id=\"tlA\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"20\" y1=\"72\" x2=\"420\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#tlA)\"/><line x1=\"26.0\" y1=\"72\" x2=\"26.0\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"26.0\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"26.0\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Eerste</text><text x=\"26.0\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">kolonies</text><text x=\"26.0\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1585</text><line x1=\"53.1\" y1=\"72\" x2=\"53.1\" y2=\"52.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"53.1\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"53.1\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Virginia</text><text x=\"53.1\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1607</text><line x1=\"261.3\" y1=\"72\" x2=\"261.3\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"261.3\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"261.3\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">VS</text><text x=\"261.3\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">onafhankelijk</text><text x=\"261.3\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1776</text><line x1=\"331.5\" y1=\"72\" x2=\"331.5\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"331.5\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"331.5\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Slavernij</text><text x=\"331.5\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">afgeschaft</text><text x=\"331.5\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1833</text><line x1=\"361.0\" y1=\"72\" x2=\"361.0\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"361.0\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"361.0\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Opstand</text><text x=\"361.0\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">India</text><text x=\"361.0\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1857</text><line x1=\"414.0\" y1=\"72\" x2=\"414.0\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"414.0\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"414.0\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Wereld-</text><text x=\"414.0\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">macht</text><text x=\"414.0\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1900</text></svg><div class=\"sam-figcap\"><strong>Het Britse Rijk in vogelvlucht</strong> — van de eerste koloniën tot grootste wereldmacht; de afschaffing van de slavernij en de greep op India zijn scharnierpunten.</div></div><ul><li><strong>Overzeese expansie</strong>: Engelse kolonisatie als reactie op de Spaanse dominantie (Roanoke 1585, Virginia 1607).</li><li><strong>Armada (1588)</strong>: de mislukte Spaanse invasievloot tegen Engeland.</li><li><strong>East India Company (EIC)</strong>: Britse handelscompagnie met eigen leger die India bestuurde via lokale vorsten.</li><li><strong>Thirteen colonies</strong>: de dertien Britse vestigingskoloniën in Noord-Amerika.</li><li><strong>Pilgrim Fathers</strong>: puriteinse migranten die met de Mayflower vertrokken; stamvaders van de VS.</li><li><strong>Plantagekoloniën</strong>: de zuidelijke koloniën, gericht op exportproducten met slavenarbeid.</li><li><strong>Transatlantische driehoekshandel</strong>: handel tussen Europa, Afrika en Amerika, met tot slaaf gemaakten als handelswaar.</li><li><strong>Abolitionisme</strong>: streven naar afschaffing van de slavernij; handel verboden in 1807, slavernij in 1833.</li><li><strong>Amerikaanse Revolutie</strong>: “no taxation without representation”; onafhankelijkheid in 1776, erkend in 1783.</li><li><strong>Opstand van 1857</strong>: Indiase muiterij; daarna nam de Britse kroon het bestuur over van de EIC en werd Victoria keizerin van India.</li><li><strong>Modern imperialisme</strong>: India als grondstoffenbron én afzetmarkt; de Indiase nijverheid ging ten onder.</li><li><strong>Indian National Congress</strong>: Indiase beweging voor gelijkheid en uiteindelijk onafhankelijkheid.</li><li><strong>White man’s burden</strong>: het idee dat Europeanen de plicht hadden “beschaving” te brengen.</li><li><strong>Industriële revolutie</strong>: begon rond 1750 in Groot-Brittannië; stoommachine, Spinning Jenny, urbanisatie.</li><li><strong>Reform Bill (1832)</strong>: kiesrechtuitbreiding die de industriële burgerij meer macht gaf.</li><li><strong>Industrieel kapitalisme</strong>: winst herinvesteren in een vrije markt; Londen werd het financiële centrum, “werkplaats van de wereld”.</li></ul><div class=\"sam-head\">Historische context — Duitsland 1918–1991</div><p>Van de Weimarrepubliek via het naziregime en de deling naar de hereniging.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 440 122\" role=\"img\" aria-label=\"Tijdbalk Duitsland\"><defs><marker id=\"tlA\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"20\" y1=\"72\" x2=\"420\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#tlA)\"/><line x1=\"31.3\" y1=\"72\" x2=\"31.3\" y2=\"32.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"31.3\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"31.3\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Versailles</text><text x=\"31.3\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1919</text><line x1=\"105.7\" y1=\"72\" x2=\"105.7\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"105.7\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"105.7\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Hitler aan</text><text x=\"105.7\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">de macht</text><text x=\"105.7\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1933</text><line x1=\"169.5\" y1=\"72\" x2=\"169.5\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"169.5\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"169.5\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Stunde</text><text x=\"169.5\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Null</text><text x=\"169.5\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1945</text><line x1=\"190.8\" y1=\"72\" x2=\"190.8\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"190.8\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"190.8\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">BRD &amp;</text><text x=\"190.8\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">DDR</text><text x=\"190.8\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1949</text><line x1=\"254.5\" y1=\"72\" x2=\"254.5\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"254.5\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"254.5\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Berlijnse</text><text x=\"254.5\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Muur</text><text x=\"254.5\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1961</text><line x1=\"403.4\" y1=\"72\" x2=\"403.4\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"403.4\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"403.4\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Val van</text><text x=\"403.4\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">de Muur</text><text x=\"403.4\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1989</text></svg><div class=\"sam-figcap\"><strong>Duitsland 1918–1991</strong> — van Versailles via Hitlers machtsovername en de deling in BRD &amp; DDR naar de val van de Muur.</div></div><ul><li><strong>Verdrag van Versailles (1919)</strong>: Duitsland schuldig verklaard: herstelbetalingen, gebiedsverlies en ontwapening.</li><li><strong>Weimarrepubliek</strong>: de Duitse parlementaire democratie na de Eerste Wereldoorlog.</li><li><strong>Dolkstootlegende</strong>: de leugen dat het leger niet militair was verslagen maar “verraden” door links.</li><li><strong>Hyperinflatie (1923)</strong>: extreme geldontwaarding na de Franse bezetting van het Ruhrgebied.</li><li><strong>Dawesplan (1924)</strong>: Amerikaanse leningen die de Weimarrepubliek economische bloei brachten.</li><li><strong>Beurskrach (1929)</strong>: de wereldcrisis trof Duitsland zwaar toen de VS hun leningen terugvorderden.</li><li><strong>NSDAP</strong>: Hitlers nationaalsocialistische partij; in 1932 de grootste.</li><li><strong>Rijksdagbrand (1933)</strong>: aanleiding om burgerrechten in te perken.</li><li><strong>Machtigingswet (1933)</strong>: gaf Hitler het recht zonder parlement wetten te maken: absolute macht.</li><li><strong>Nazificatie</strong>: Duitsland wordt een totalitaire staat met Gestapo, SS en concentratiekampen.</li><li><strong>Volksgemeinschaft</strong>: het nazi-ideaal van een “zuivere” Arische gemeenschap.</li><li><strong>Stunde Null</strong>: het “uur nul”: het volledig verwoeste Duitsland in 1945.</li><li><strong>Bezettingszones</strong>: Duitsland (en Berlijn) verdeeld onder GB, Frankrijk, de VS en de Sovjet-Unie.</li><li><strong>Berlijnse luchtbrug (1948)</strong>: westerse reactie op de Sovjet-blokkade van West-Berlijn.</li><li><strong>BRD en DDR (1949)</strong>: het kapitalistische West- en het communistische Oost-Duitsland.</li><li><strong>Wirtschaftswunder</strong>: het snelle economische herstel van de BRD (Marshallhulp, Adenauer).</li><li><strong>Berlijnse Muur (1961)</strong>: gebouwd om de leegloop uit de DDR te stoppen.</li><li><strong>Ostpolitik</strong>: Willy Brandts beleid van toenadering tussen BRD en DDR.</li><li><strong>Glasnost en perestrojka</strong>: Gorbatsjovs openheid en hervormingen in de Sovjet-Unie.</li><li><strong>Val van de Muur (1989)</strong>: leidde tot de Duitse hereniging in 1990 (Kohl) en EU-lidmaatschap.</li></ul><div class=\"sam-head\">Historische context — Nederland 1948–2008</div><p>Wederopbouw en verzorgingsstaat, ontzuiling en jeugdculturen, migratie en polarisatie.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 440 122\" role=\"img\" aria-label=\"Tijdbalk Nederland\"><defs><marker id=\"tlA\" markerWidth=\"10\" markerHeight=\"10\" refX=\"5.5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"20\" y1=\"72\" x2=\"420\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"1.6\" marker-end=\"url(#tlA)\"/><line x1=\"26.0\" y1=\"72\" x2=\"26.0\" y2=\"43.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"26.0\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"26.0\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Verzorgings-</text><text x=\"26.0\" y=\"39.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">staat</text><text x=\"26.0\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1948</text><line x1=\"32.5\" y1=\"72\" x2=\"32.5\" y2=\"52.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"32.5\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"32.5\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">NAVO-lid</text><text x=\"32.5\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1949</text><line x1=\"187.7\" y1=\"72\" x2=\"187.7\" y2=\"32.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"187.7\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"187.7\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Oliecrisis</text><text x=\"187.7\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1973</text><line x1=\"310.5\" y1=\"72\" x2=\"310.5\" y2=\"63.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"310.5\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"310.5\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Maastricht</text><text x=\"310.5\" y=\"59.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">(EU)</text><text x=\"310.5\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1992</text><line x1=\"329.9\" y1=\"72\" x2=\"329.9\" y2=\"32.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"329.9\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"329.9\" y=\"28.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Srebrenica</text><text x=\"329.9\" y=\"94\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">1995</text><line x1=\"375.2\" y1=\"72\" x2=\"375.2\" y2=\"52.0\" stroke=\"var(--bo2)\" stroke-width=\"1\"/><circle cx=\"375.2\" cy=\"72\" r=\"3.4\" fill=\"var(--or)\"/><text x=\"375.2\" y=\"48.0\" font-size=\"8.6\" fill=\"var(--mu)\" text-anchor=\"middle\">Fortuyn</text><text x=\"375.2\" y=\"106\" font-size=\"9\" font-weight=\"800\" fill=\"var(--or)\" text-anchor=\"middle\">2002</text></svg><div class=\"sam-figcap\"><strong>Nederland 1948–2008</strong> — van de opbouw van de verzorgingsstaat naar ontzuiling, Europese eenwording en polarisatie na 2000.</div></div><ul><li><strong>Verzorgingsstaat</strong>: brede sociale voorzieningen, opgebouwd onder Drees vanaf 1948.</li><li><strong>Marshallplan</strong>: Amerikaanse hulp voor de wederopbouw.</li><li><strong>Geleide loonpolitiek</strong>: bewust lage lonen om de export en werkgelegenheid te stimuleren.</li><li><strong>Maakbare samenleving</strong>: het geloof dat de overheid de samenleving kon herinrichten.</li><li><strong>Poldermodel</strong>: de overlegcultuur tussen overheid, werkgevers en vakbonden.</li><li><strong>Verzuiling</strong>: de samenleving verdeeld in katholieke, protestantse, socialistische en liberale zuilen.</li><li><strong>Einde neutraliteit</strong>: Nederland werd NAVO-lid (1949) en mede-oprichter van de EGKS (1952).</li><li><strong>Jeugdculturen</strong>: nozems, provo’s en hippies die zich tegen het gezag afzetten.</li><li><strong>Tweede feministische golf</strong>: de Dolle Mina’s streden voor gelijke rechten en anticonceptie.</li><li><strong>Consumptiemaatschappij</strong>: welvaartsgroei met autobezit en status-aankopen.</li><li><strong>Ontzuiling</strong>: de zuilen verdwijnen door ontkerkelijking, welvaart en televisie (D’66, CDA).</li><li><strong>Gastarbeiders</strong>: arbeidsmigranten uit Zuid-Europa, Marokko en Turkije; later gezinshereniging.</li><li><strong>Oliecrisis (1973)</strong>: leidde tot de autoloze zondag en het einde van de naoorlogse groei.</li><li><strong>Individualisering</strong>: nadruk op zelfredzaamheid; gedoogbeleid, homohuwelijk en euthanasie.</li><li><strong>Digitale revolutie</strong>: internet en mobiele telefoon vanaf de jaren ’90.</li><li><strong>Verdrag van Maastricht (1992)</strong>: de EEG wordt de Europese Unie; invoering van de euro.</li><li><strong>Srebrenica (1995)</strong>: de val van de safe area onder Nederlands toezicht; genocide op ruim 8000 mannen.</li><li><strong>Polarisatie</strong>: na 2000 groeit de kritiek op de multiculturele samenleving (Pim Fortuyn, 9/11).</li></ul><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Examenvraag (context Duitsland): leg uit hoe de economische crisis van 1929 bijdroeg aan de machtsovername van Hitler in 1933.</div><ol class=\"sam-worked-steps\"><li>Mechanisme: na de beurskrach (1929) vroegen de VS hun leningen (Dawesplan) terug → massawerkloosheid in Duitsland.</li><li>Gevolg: onvrede en wanhoop maakten kiezers ontvankelijk voor radicale partijen; de NSDAP beloofde werk en herstel en werd in 1932 de grootste.</li><li>Koppel de causale ketting: crisis → werkloosheid → steun NSDAP → benoeming van Hitler (1933) en de Machtigingswet.</li></ol><div class=\"sam-worked-ans\">✅ Leg de keten crisis → werkloosheid/onvrede → steun → machtsovername, met een concreet begrip (Dawesplan of Machtigingswet) als bewijs.</div></div>","vwo_wa_B":"<div class=\"sam-intro\">Domein B is je <strong>gereedschapskist</strong>: rekenen met <strong>machten en logaritmen</strong>, vergelijkingen oplossen, en de basis van de <strong>analyse</strong> — <strong>differentiëren</strong> (afgeleide) en <strong>integreren</strong> (primitieve).</div><div class=\"sam-head\">Machten en logaritmen</div><p>Een logaritme is de omgekeerde van een macht: <sup>g</sup>log(a) = x betekent gˣ = a. De rekenregels:</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Logaritmewetten</div><div class=\"sam-formula-eq\"><sup>g</sup>log(a·b) = <sup>g</sup>log a + <sup>g</sup>log b  ·  <sup>g</sup>log(aⁿ) = n·<sup>g</sup>log a</div><div class=\"sam-formula-note\">Grondtalwissel: <sup>g</sup>log a = (log a)/(log g). Een product wordt een som, een macht wordt een factor — handig om vergelijkingen met onbekende in de exponent op te lossen.</div></div><div class=\"sam-head\">Differentiëren</div><p>De <strong>afgeleide</strong> f′(x) geeft de <strong>helling</strong> van de grafiek in elk punt. Je gebruikt vaste regels:</p><table class=\"sam-table\"><thead><tr><th>Regel</th><th>Vorm</th></tr></thead><tbody><tr><td>Machtsregel</td><td>f(x)=xⁿ → f′(x)=n·xⁿ⁻¹</td></tr><tr><td>Kettingregel</td><td>(f(g(x)))′ = f′(g(x))·g′(x)</td></tr><tr><td>Productregel</td><td>(f·g)′ = f′·g + f·g′</td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Bijzondere afgeleiden (BiNaS/formulekaart)</div><div class=\"sam-formula-eq\">(eˣ)′ = eˣ  ·  (ln x)′ = 1/x  ·  (sin x)′ = cos x</div><div class=\"sam-formula-note\">De e-macht is zijn eigen afgeleide. Deze standaardafgeleiden moet je uit je hoofd kennen.</div></div><div class=\"sam-head\">Primitiveren (integreren)</div><p>De <strong>primitieve</strong> F(x) is het omgekeerde van differentiëren: F′(x) = f(x). Bij een onbepaalde integraal hoort altijd een constante + c.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Standaardprimitieven</div><div class=\"sam-formula-eq\">∫xⁿ dx = xⁿ⁺¹/(n+1) + c  ·  ∫eˣ dx = eˣ + c  ·  ∫(1/x) dx = ln|x| + c</div><div class=\"sam-formula-note\">Let op de uitzondering: voor n = −1 werkt de machtsregel niet; dan krijg je de natuurlijke logaritme.</div></div><div class=\"sam-warn\"><strong>Veelgemaakte fout:</strong> vergeet bij het primitiveren de integratieconstante <strong>+ c</strong> niet, en bij de machtsregel het delen door de nieuwe exponent (n+1).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Differentieer f(x) = (2x + 1)³ met de kettingregel.</div><ol class=\"sam-worked-steps\"><li>Buitenkant: (…)³ → 3(…)²; binnenkant g(x)=2x+1 → g′(x)=2.</li><li>f′(x) = 3(2x+1)² · 2.</li><li>f′(x) = 6(2x+1)².</li></ol><div class=\"sam-worked-ans\">✅ f′(x) = 6(2x+1)².</div></div></div>","vwo_wa_C":"<div class=\"sam-intro\">In domein C herken je welk <strong>verband</strong> achter een tabel of grafiek zit — <strong>lineair, kwadratisch, exponentieel, logaritmisch</strong> of <strong>periodiek</strong> — en bereken je met de <strong>bepaalde integraal</strong> oppervlaktes en afgelegde afstanden.</div><div class=\"sam-head\">Standaardverbanden</div><table class=\"sam-table\"><thead><tr><th>Verband</th><th>Vorm</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Lineair</td><td>y = ax + b</td><td>constante toename</td></tr><tr><td>Kwadratisch</td><td>y = ax² + bx + c</td><td>parabool, top</td></tr><tr><td>Exponentieel</td><td>y = b·gˣ</td><td>vaste groeifactor</td></tr><tr><td>Periodiek</td><td>y = a·sin(b(x−c)) + d</td><td>amplitude a, periode 2π/b</td></tr></tbody></table><div class=\"sam-head\">De bepaalde integraal als oppervlakte</div><p>De <strong>bepaalde integraal</strong> van a tot b is gelijk aan de <strong>oppervlakte</strong> tussen de grafiek en de x-as. Je berekent hem met de primitieve F: het verschil F(b) − F(a).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Oppervlakte onder een grafiek tussen x is a en x is b als bepaalde integraal\"><defs><marker id=\"waCa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><path d=\"M110,150 L110.0,131.7 L129.5,123.8 L149.0,114.6 L168.5,104.3 L188.0,92.8 L207.5,80.0 L227.0,66.0 L240,56.0 L240,150 Z\" fill=\"var(--or)\" opacity=\".18\"/><line x1=\"40\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#waCa)\"/><line x1=\"40\" y1=\"158\" x2=\"40\" y2=\"24\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#waCa)\"/><path d=\"M40.0,150.0 L73.4,143.2 L106.9,132.8 L140.3,118.9 L173.7,101.3 L207.1,80.2 L240.6,55.5 L270.3,30.6 L300,28\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"110\" y1=\"150\" x2=\"110\" y2=\"131\" stroke=\"var(--dk)\" stroke-width=\"1\" stroke-dasharray=\"2 2\"/><line x1=\"240\" y1=\"150\" x2=\"240\" y2=\"56\" stroke=\"var(--dk)\" stroke-width=\"1\" stroke-dasharray=\"2 2\"/><text x=\"106\" y=\"164\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">a</text><text x=\"236\" y=\"164\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">b</text><text x=\"150\" y=\"120\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">oppervlakte</text></svg><div class=\"sam-figcap\"><strong>Oppervlakte = integraal:</strong> het gekleurde gebied onder de grafiek tussen x = a en x = b is precies de waarde van de bepaalde integraal ∫<sub>a</sub><sup>b</sup> f(x) dx.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Hoofdstelling van de integraalrekening</div><div class=\"sam-formula-eq\">∫<sub>a</sub><sup>b</sup> f(x) dx = F(b) − F(a)</div><div class=\"sam-formula-note\">F is een primitieve van f. Integreren is dus het omgekeerde van differentiëren.</div></div><div class=\"sam-tip\"><strong>Snelheid en afstand:</strong> de afgelegde afstand is de integraal van de snelheid: s = ∫v(t) dt. Andersom is de snelheid de afgeleide van de plaats.</div><div class=\"sam-head\">Periodieke functies</div><p>Bij f(x) = a·sin(b(x−c)) + d is a de <strong>amplitude</strong>, d de <strong>evenwichtsstand</strong>, c de horizontale verschuiving en de <strong>periode</strong> gelijk aan 2π/b.</p><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bereken de oppervlakte onder f(x) = 2x tussen x = 1 en x = 3.</div><ol class=\"sam-worked-steps\"><li>Primitieve: F(x) = x².</li><li>∫₁³ 2x dx = F(3) − F(1) = 9 − 1.</li><li>= 8.</li></ol><div class=\"sam-worked-ans\">✅ De oppervlakte is 8.</div></div></div>","vwo_wa_E":"<div class=\"sam-intro\">Domein D is de kern van het CE wiskunde A: van <strong>kansregels</strong> en de <strong>binomiale verdeling</strong> tot de <strong>normale verdeling</strong> en het <strong>hypothesetoetsen</strong>. Je rekent veel met de grafische rekenmachine (GR).</div><div class=\"sam-head\">Kansregels</div><table class=\"sam-table\"><thead><tr><th>Regel</th><th>Formule</th><th>Wanneer</th></tr></thead><tbody><tr><td>Productregel</td><td>P(A én B) = P(A)·P(B)</td><td>onafhankelijk ('en')</td></tr><tr><td>Somregel</td><td>P(A of B) = P(A)+P(B)</td><td>elkaar uitsluitend</td></tr><tr><td>Complement</td><td>P(niet A) = 1 − P(A)</td><td>'minstens één'</td></tr></tbody></table><div class=\"sam-head\">Binomiale verdeling</div><p>Bij n onafhankelijke pogingen met succeskans p is het aantal successen <strong>binomiaal verdeeld</strong>: B(n, p). Op de GR: binompdf (precies k) en binomcdf (hoogstens k).</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Binomiale kans</div><div class=\"sam-formula-eq\">P(X = k) = C(n,k) · pᵏ · (1−p)ⁿ⁻ᵏ</div><div class=\"sam-formula-note\">n het aantal pogingen, p de succeskans, k het aantal successen. Verwachting: µ = n·p.</div></div><div class=\"sam-head\">Normale verdeling</div><p>Veel grootheden (lengte, gewicht) zijn <strong>normaal verdeeld</strong>: een symmetrische klokvorm rond het gemiddelde µ, met spreiding σ. De <strong>68-95-99,7-regel</strong> geeft snel de kansen.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Normaalverdeling met de 68-95-99,7 procent regel rond het gemiddelde\"><defs><marker id=\"waDa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><path d=\"M40.0,149.6 L74.2,145.4 L102.2,130.2 L120.9,109.1 L136.4,85.8 L152.0,61.9 L167.6,44.7 L180.0,40.0 L192.4,44.7 L208.0,61.9 L223.6,85.8 L239.1,109.1 L257.8,130.2 L285.8,145.4 L320.0,149.6\" fill=\"var(--or)\" opacity=\".15\"/><line x1=\"30\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#waDa)\"/><path d=\"M40.0,149.6 L74.2,145.4 L102.2,130.2 L120.9,109.1 L136.4,85.8 L152.0,61.9 L167.6,44.7 L180.0,40.0 L192.4,44.7 L208.0,61.9 L223.6,85.8 L239.1,109.1 L257.8,130.2 L285.8,145.4 L320.0,149.6\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\"/><g stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"><line x1=\"180\" y1=\"40\" x2=\"180\" y2=\"150\"/><line x1=\"138\" y1=\"72\" x2=\"138\" y2=\"150\"/><line x1=\"222\" y1=\"72\" x2=\"222\" y2=\"150\"/><line x1=\"96\" y1=\"126\" x2=\"96\" y2=\"150\"/><line x1=\"264\" y1=\"126\" x2=\"264\" y2=\"150\"/></g><g font-size=\"8.5\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"180\" y=\"164\">µ</text><text x=\"138\" y=\"164\">−σ</text><text x=\"222\" y=\"164\">+σ</text><text x=\"96\" y=\"164\">−2σ</text><text x=\"264\" y=\"164\">+2σ</text></g><text x=\"180\" y=\"120\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">68%</text></svg><div class=\"sam-figcap\"><strong>68-95-99,7-regel:</strong> 68% van de waarnemingen ligt binnen 1σ van het gemiddelde, 95% binnen 2σ en 99,7% binnen 3σ.</div></div><div class=\"sam-head\">Hypothesetoets</div><p>Je toetst een <strong>nulhypothese</strong> H₀ tegen een alternatief H₁. Is de <strong>p-waarde</strong> kleiner dan het significantieniveau α (vaak 5%), dan verwerp je H₀.</p><div class=\"sam-warn\"><strong>Let op:</strong> een niet-verworpen H₀ is niet 'bewezen'. Je concludeert alleen dat er <em>onvoldoende bewijs</em> is om H₀ te verwerpen.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Je gooit 10 keer met een eerlijke munt. Wat is de kans op precies 6 keer kop? (p = 0,5)</div><ol class=\"sam-worked-steps\"><li>X ~ B(10; 0,5), gevraagd P(X = 6).</li><li>P(X=6) = C(10,6)·0,5⁶·0,5⁴ = 210 · 0,5¹⁰.</li><li>= 210 / 1024 ≈ 0,205.</li></ol><div class=\"sam-worked-ans\">✅ De kans is ongeveer 0,21 (21%).</div></div></div>","vwo_wb_C":"<div class=\"sam-intro\">Analyse is het hart van wiskunde B: <strong>differentiëren</strong> en <strong>integreren</strong> met alle regels, <strong>limieten</strong> en <strong>asymptoten</strong>, en het volledig <strong>onderzoeken van functies</strong> (extremen, buigpunten, verloop).</div><div class=\"sam-head\">Differentieerregels</div><table class=\"sam-table\"><thead><tr><th>Regel</th><th>Formule</th></tr></thead><tbody><tr><td>Kettingregel</td><td>(f(g(x)))′ = f′(g(x))·g′(x)</td></tr><tr><td>Productregel</td><td>(f·g)′ = f′g + fg′</td></tr><tr><td>Quotiëntregel</td><td>(f/g)′ = (f′g − fg′)/g²</td></tr></tbody></table><div class=\"sam-head\">De afgeleide als helling</div><p>De afgeleide f′(x) is de <strong>richtingscoëfficiënt</strong> van de <strong>raaklijn</strong> in een punt. Waar f′(x) = 0 ligt een <strong>extreem</strong> (top of dal); waar f″(x) van teken wisselt, ligt een <strong>buigpunt</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Grafiek van een functie met de raaklijn in een punt, waarvan de helling de afgeleide is\"><defs><marker id=\"wbBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"30\" y1=\"156\" x2=\"332\" y2=\"156\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#wbBa)\"/><line x1=\"40\" y1=\"164\" x2=\"40\" y2=\"20\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#wbBa)\"/><path d=\"M40.0,141.4 L66.0,104.9 L92.0,76.5 L118.0,56.2 L144.0,44.1 L167.1,40.1 L190.2,42.5 L216.2,52.8 L242.2,71.3 L268.2,97.9 L294.2,132.6 L300,141\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><line x1=\"210\" y1=\"40\" x2=\"290\" y2=\"117\" stroke=\"var(--dk)\" stroke-width=\"2\" stroke-dasharray=\"5 3\"/><circle cx=\"250\" cy=\"78.4\" r=\"4\" fill=\"var(--dk)\"/><text x=\"256\" y=\"74\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\">raakpunt</text><text x=\"150\" y=\"36\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">y = f(x)</text><text x=\"230\" y=\"130\" font-size=\"9\" fill=\"var(--mu)\">helling = f′(x)</text></svg><div class=\"sam-figcap\"><strong>Raaklijn:</strong> de gestippelde lijn raakt de grafiek in één punt. De richtingscoëfficiënt van die raaklijn is de waarde van de afgeleide f′(x) in dat punt.</div></div><div class=\"sam-head\">Integreren</div><p>Naast standaardprimitieven gebruik je op VWO twee technieken:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Substitutie</div><ul><li>voor samengestelde functies</li><li>vervang de binnenkant door u</li><li>omgekeerde kettingregel</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Partieel integreren</div><ul><li>voor producten van functies</li><li>∫u dv = uv − ∫v du</li><li>omgekeerde productregel</li></ul></div></div><div class=\"sam-head\">Limieten en asymptoten</div><p>Een <strong>limiet</strong> beschrijft het gedrag van f(x) als x een waarde nadert (of naar ±∞ gaat). Daaruit volgen <strong>asymptoten</strong>: lijnen die de grafiek steeds dichter nadert.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Raaklijn in een punt</div><div class=\"sam-formula-eq\">y = f(a) + f′(a)·(x − a)</div><div class=\"sam-formula-note\">a de x-coördinaat van het raakpunt. f(a) geeft de hoogte, f′(a) de helling van de raaklijn.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bepaal de vergelijking van de raaklijn aan f(x) = x² in het punt x = 3.</div><ol class=\"sam-worked-steps\"><li>f(3) = 9 en f′(x) = 2x, dus f′(3) = 6.</li><li>y = f(3) + f′(3)(x − 3) = 9 + 6(x − 3).</li><li>y = 6x − 9.</li></ol><div class=\"sam-worked-ans\">✅ De raaklijn is y = 6x − 9.</div></div></div>","vwo_wb_D":"<div class=\"sam-intro\">Goniometrie beschrijft draaiingen en periodieke verschijnselen met <strong>sinus</strong>, <strong>cosinus</strong> en <strong>tangens</strong>. De <strong>eenheidscirkel</strong> is je kompas, en met de <strong>optellings-</strong> en <strong>dubbele-hoekformules</strong> herschrijf en bewijs je identiteiten.</div><div class=\"sam-head\">De eenheidscirkel</div><p>Op de <strong>eenheidscirkel</strong> (straal 1) hoort bij een hoek α een punt (cos α, sin α). De sinus is de <strong>hoogte</strong> (y), de cosinus de <strong>horizontale</strong> afstand (x).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 210\" role=\"img\" aria-label=\"Eenheidscirkel met een hoek alfa en de projecties cosinus en sinus\"><defs><marker id=\"wbCa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><circle cx=\"120\" cy=\"120\" r=\"75\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.5\"/><line x1=\"30\" y1=\"120\" x2=\"230\" y2=\"120\" stroke=\"var(--mu)\" stroke-width=\"1.2\" marker-end=\"url(#wbCa)\"/><line x1=\"120\" y1=\"205\" x2=\"120\" y2=\"30\" stroke=\"var(--mu)\" stroke-width=\"1.2\" marker-end=\"url(#wbCa)\"/><line x1=\"120\" y1=\"120\" x2=\"168\" y2=\"62\" stroke=\"var(--or)\" stroke-width=\"2.4\"/><circle cx=\"168\" cy=\"62\" r=\"4\" fill=\"var(--or)\"/><line x1=\"168\" y1=\"120\" x2=\"168\" y2=\"62\" stroke=\"var(--dk)\" stroke-width=\"2\" stroke-dasharray=\"4 2\"/><line x1=\"120\" y1=\"120\" x2=\"168\" y2=\"120\" stroke=\"var(--dk)\" stroke-width=\"2\"/><path d=\"M148,120 A28,28 0 0,0 138,101\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"1.2\"/><text x=\"143\" y=\"114\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">α</text><text x=\"138\" y=\"135\" font-size=\"9\" fill=\"var(--dk)\">cos α</text><text x=\"172\" y=\"95\" font-size=\"9\" fill=\"var(--dk)\">sin α</text><text x=\"228\" y=\"134\" font-size=\"9\" fill=\"var(--mu)\">x</text><text x=\"126\" y=\"36\" font-size=\"9\" fill=\"var(--mu)\">y</text></svg><div class=\"sam-figcap\"><strong>Eenheidscirkel:</strong> bij hoek α hoort het punt (cos α, sin α). De tangens is sin α / cos α — de helling van de straal.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Grondformule van de goniometrie</div><div class=\"sam-formula-eq\">sin²α + cos²α = 1  ·  tan α = sin α / cos α</div><div class=\"sam-formula-note\">Volgt direct uit de stelling van Pythagoras op de eenheidscirkel. Hiermee herschrijf je uitdrukkingen en bewijs je identiteiten.</div></div><div class=\"sam-head\">Optellings- en dubbele-hoekformules</div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Optellingsformules</div><div class=\"sam-formula-eq\">sin(α±β) = sin α cos β ± cos α sin β<br>cos(α±β) = cos α cos β ∓ sin α sin β</div><div class=\"sam-formula-note\">Hieruit volgen de dubbele-hoekformules: sin 2α = 2 sin α cos α en cos 2α = cos²α − sin²α = 1 − 2sin²α.</div></div><div class=\"sam-head\">Goniometrische vergelijkingen</div><p>Een vergelijking als sin x = c heeft <strong>oneindig veel</strong> oplossingen. Je geeft ze met een periode: bijvoorbeeld x = … + k·2π. Gebruik de eenheidscirkel om alle hoeken in één omwenteling te vinden.</p><div class=\"sam-tip\">Onthoud de standaardwaarden: sin 30° = ½, sin 45° = ½√2, sin 60° = ½√3 (en cos precies andersom).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Vereenvoudig sin 2α als sin α = 0,6 en cos α = 0,8.</div><ol class=\"sam-worked-steps\"><li>Dubbele hoek: sin 2α = 2 sin α cos α.</li><li>= 2 × 0,6 × 0,8.</li><li>= 0,96.</li></ol><div class=\"sam-worked-ans\">✅ sin 2α = 0,96.</div></div></div>","vwo_wb_E":"<div class=\"sam-intro\">In de <strong>ruimtemeetkunde</strong> reken je met <strong>vectoren</strong> in drie dimensies. Met het <strong>inproduct</strong> vind je hoeken en loodrechte stand, met het <strong>uitproduct</strong> een normaalvector, en zo stel je vergelijkingen van <strong>lijnen</strong> en <strong>vlakken</strong> op.</div><div class=\"sam-head\">Vectoren in 3D</div><p>Een <strong>vector</strong> heeft een lengte en een richting. Je telt vectoren componentsgewijs op en vermenigvuldigt met een getal (scalair).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Een driedimensionaal assenstelsel met een vector vanuit de oorsprong\"><defs><marker id=\"wbDx\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker><marker id=\"wbDv\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"110\" y1=\"140\" x2=\"260\" y2=\"140\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#wbDx)\"/><line x1=\"110\" y1=\"140\" x2=\"110\" y2=\"25\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#wbDx)\"/><line x1=\"110\" y1=\"140\" x2=\"45\" y2=\"185\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#wbDx)\"/><text x=\"252\" y=\"156\" font-size=\"10\" fill=\"var(--mu)\">x</text><text x=\"98\" y=\"30\" font-size=\"10\" fill=\"var(--mu)\">z</text><text x=\"36\" y=\"188\" font-size=\"10\" fill=\"var(--mu)\">y</text><line x1=\"110\" y1=\"140\" x2=\"205\" y2=\"70\" stroke=\"var(--or)\" stroke-width=\"2.6\" marker-end=\"url(#wbDv)\"/><text x=\"180\" y=\"92\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">a⃗</text><circle cx=\"110\" cy=\"140\" r=\"3\" fill=\"var(--dk)\"/><text x=\"88\" y=\"152\" font-size=\"9\" fill=\"var(--mu)\">O</text></svg><div class=\"sam-figcap\"><strong>Vector in de ruimte:</strong> a⃗ = (a₁, a₂, a₃) vanuit de oorsprong O. De lengte volgt uit Pythagoras in drie dimensies.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Lengte van een vector</div><div class=\"sam-formula-eq\">|a⃗| = √(a₁² + a₂² + a₃²)</div><div class=\"sam-formula-note\">De driedimensionale versie van de stelling van Pythagoras.</div></div><div class=\"sam-head\">Inproduct: hoek en loodrechte stand</div><p>Het <strong>inproduct</strong> (dot-product) koppelt twee vectoren aan de hoek ertussen. Is het inproduct 0, dan staan de vectoren <strong>loodrecht</strong> op elkaar.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Inproduct</div><div class=\"sam-formula-eq\">a⃗ · b⃗ = a₁b₁ + a₂b₂ + a₃b₃ = |a⃗||b⃗|·cos φ</div><div class=\"sam-formula-note\">φ de hoek tussen de vectoren. Uit de laatste gelijkheid bereken je die hoek. a⃗ · b⃗ = 0 ⇔ loodrecht.</div></div><div class=\"sam-head\">Uitproduct en normaalvector</div><p>Het <strong>uitproduct</strong> (kruisproduct) a⃗ × b⃗ geeft een vector die <strong>loodrecht</strong> op beide staat — precies de <strong>normaalvector</strong> die je nodig hebt voor een vlak.</p><div class=\"sam-head\">Lijnen en vlakken</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Lijn (vectorvorm)</div><ul><li>r⃗ = a⃗ + t·d⃗</li><li>a⃗ steunpunt, d⃗ richting</li><li>t is de parameter</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Vlak</div><ul><li>n⃗ · r⃗ = d</li><li>n⃗ de normaalvector</li><li>loodrecht op het vlak</li></ul></div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Staan a⃗ = (2, −1, 3) en b⃗ = (1, 2, 0) loodrecht op elkaar?</div><ol class=\"sam-worked-steps\"><li>a⃗ · b⃗ = 2·1 + (−1)·2 + 3·0.</li><li>= 2 − 2 + 0 = 0.</li></ol><div class=\"sam-worked-ans\">✅ Het inproduct is 0, dus ja: de vectoren staan loodrecht.</div></div></div>","vwo_bi_B":"<div class=\"sam-intro\"><strong>Zelfregulatie</strong> is hét vermogen van een biologisch systeem om zichzelf in stand te houden — van het <strong>molecuul</strong> (eiwitsynthese) via de <strong>cel</strong> en het <strong>orgaan</strong> tot het hele <strong>organisme</strong>. De rode draad: <strong>homeostase</strong> (een constant intern milieu) via <strong>negatieve terugkoppeling</strong>.</div><div class=\"sam-head\">Wat je voor het examen moet kennen (syllabus)</div><p>Dit domein bestaat uit vijf subdomeinen. Deze samenvatting dekt ze allemaal:</p><table class=\"sam-table\"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>B1</td><td>Eiwitsynthese</td><td>DNA → mRNA → eiwit</td></tr><tr><td>B2</td><td>Stofwisseling van de cel</td><td>assimilatie/dissimilatie, transport</td></tr><tr><td>B3</td><td>Stofwisseling van het organisme</td><td>organen, vertering, ademhaling, uitscheiding</td></tr><tr><td>B4</td><td>Zelfregulatie van het organisme</td><td>homeostase, hormonaal + neuraal</td></tr><tr><td>B5</td><td>Afweer van het organisme</td><td>aangeboren + verworven immuniteit</td></tr></tbody></table><div class=\"sam-head\">B1 · Eiwitsynthese</div><p>Eiwitten bepalen wat een cel doet. Het bouwvoorschrift staat als <strong>genen</strong> in het <strong>DNA</strong>. Van gen naar eiwit gaat in twee stappen:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 118\" role=\"img\" aria-label=\"Eiwitsynthese: DNA wordt via transcriptie mRNA en via translatie in het ribosoom een eiwit\"><defs><marker id=\"giB1\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"10\" y=\"40\" width=\"66\" height=\"36\" rx=\"6\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"43\" y=\"56\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">DNA</text><text x=\"43\" y=\"68\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">(celkern)</text><rect x=\"128\" y=\"40\" width=\"66\" height=\"36\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"161\" y=\"56\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">mRNA</text><text x=\"161\" y=\"68\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">kopie van gen</text><rect x=\"246\" y=\"40\" width=\"66\" height=\"36\" rx=\"6\" fill=\"var(--or)\" opacity=\".2\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"279\" y=\"56\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">eiwit</text><text x=\"279\" y=\"68\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">(ribosoom)</text><line x1=\"76\" y1=\"58\" x2=\"126\" y2=\"58\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giB1)\"/><text x=\"101\" y=\"51\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">transcriptie</text><line x1=\"194\" y1=\"58\" x2=\"244\" y2=\"58\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giB1)\"/><text x=\"219\" y=\"51\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">translatie</text></svg><div class=\"sam-figcap\"><strong>Van gen naar eiwit:</strong> bij de <strong>transcriptie</strong> (in de kern) maakt RNA-polymerase van een gen een mRNA-kopie; bij de <strong>translatie</strong> leest het ribosoom het mRNA en rijgt tRNA de aminozuren aaneen tot een eiwit.</div></div><ul><li><strong>Codon</strong>: een basentriplet op het mRNA dat codeert voor één aminozuur. Met 4 basen zijn er 4³ = 64 codons (incl. start- en stopcodon).</li><li><strong>tRNA</strong> heeft een anticodon en brengt het bijpassende aminozuur aan.</li><li>Bij eukaryoten wordt het pre-mRNA eerst bewerkt: <strong>introns</strong> eruit, <strong>exons</strong> aaneen (splicing).</li></ul><div class=\"sam-tip\">De volgorde van de basen bepaalt de volgorde van de aminozuren, en die bepaalt de vorm en functie van het eiwit. Een fout in het DNA (mutatie) kan zo het eiwit veranderen.</div><div class=\"sam-head\">B2 · Stofwisseling van de cel</div><p>De <strong>stofwisseling</strong> (het metabolisme) is het geheel van alle chemische omzettingen in de cel. Twee richtingen:</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 120\" role=\"img\" aria-label=\"Assimilatie bouwt macromoleculen op en kost energie, dissimilatie breekt ze af en levert ATP\"><defs><marker id=\"giB2\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><rect x=\"14\" y=\"42\" width=\"88\" height=\"36\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"58\" y=\"58\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">bouwstenen</text><text x=\"58\" y=\"70\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">klein</text><rect x=\"198\" y=\"42\" width=\"88\" height=\"36\" rx=\"6\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"242\" y=\"58\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">macromolecuul</text><text x=\"242\" y=\"70\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">groot</text><path d=\"M104,52 C140,40 160,40 196,52\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\" marker-end=\"url(#giB2)\"/><text x=\"150\" y=\"36\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">assimilatie — kost energie</text><path d=\"M196,68 C160,80 140,80 104,68\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\" marker-end=\"url(#giB2)\"/><text x=\"150\" y=\"98\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">dissimilatie — levert ATP</text></svg><div class=\"sam-figcap\"><strong>Assimilatie</strong> (opbouw) maakt van kleine bouwstenen grote moleculen en kost energie; <strong>dissimilatie</strong> (afbraak) breekt ze af en levert energie in de vorm van <strong>ATP</strong>.</div></div><table class=\"sam-table\"><thead><tr><th>Transport door membraan</th><th>Hoe</th></tr></thead><tbody><tr><td>Diffusie</td><td>van hoge naar lage concentratie, passief (geen energie)</td></tr><tr><td>Osmose</td><td>diffusie van wáter door een membraan</td></tr><tr><td>Actief transport</td><td>tegen de gradiënt in, kost ATP (bv. natrium-kaliumpomp)</td></tr></tbody></table><p>Enzymen versnellen deze reacties en zijn <strong>substraatspecifiek</strong>. Een <strong>prokaryote</strong> cel (bacterie) heeft geen kern; een <strong>eukaryote</strong> cel wel, met organellen.</p><div class=\"sam-head\">B3 · Stofwisseling van het organisme</div><p>Bij een veelcellig organisme werken <strong>organen</strong> samen om stoffen op te nemen, te verwerken en af te voeren:</p><table class=\"sam-table\"><thead><tr><th>Orgaan(stelsel)</th><th>Functie</th></tr></thead><tbody><tr><td>Verteringsstelsel</td><td>voedsel → kleine moleculen; opname in het bloed</td></tr><tr><td>Ademhalingsstelsel</td><td>O₂ opnemen, CO₂ afvoeren (longen)</td></tr><tr><td>Bloedsomloop (hart)</td><td>transport van stoffen door het lichaam</td></tr><tr><td>Nieren</td><td>uitscheiding van afvalstoffen (ureum) en waterregeling</td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Fotosynthese en celademhaling</div><div class=\"sam-formula-eq\">6 CO₂ + 6 H₂O + licht → C₆H₁₂O₆ + 6 O₂  (assimilatie)<br>C₆H₁₂O₆ + 6 O₂ → 6 CO₂ + 6 H₂O + energie  (dissimilatie)</div><div class=\"sam-formula-note\">Planten leggen in de bladgroenkorrels energie vast in glucose (fotosynthese); álle cellen halen die energie er via celademhaling weer uit als ATP.</div></div><div class=\"sam-head\">B4 · Zelfregulatie van het organisme</div><p><strong>Homeostase</strong> is het constant houden van het interne milieu (temperatuur, bloedglucose, pH, water). Dat gebeurt via <strong>negatieve terugkoppeling</strong>: een afwijking van het <strong>setpoint</strong> wordt gemeten en tegengewerkt.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 150\" role=\"img\" aria-label=\"Negatieve terugkoppeling: een afwijking wordt gemeten door een sensor, verwerkt en door een effector tegengewerkt\"><defs><marker id=\"giB4\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><rect x=\"110\" y=\"12\" width=\"100\" height=\"30\" rx=\"6\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"160\" y=\"31\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">afwijking setpoint</text><rect x=\"228\" y=\"60\" width=\"84\" height=\"30\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"270\" y=\"79\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">sensor meet</text><rect x=\"118\" y=\"108\" width=\"84\" height=\"30\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"160\" y=\"127\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">verwerker</text><rect x=\"8\" y=\"60\" width=\"84\" height=\"30\" rx=\"6\" fill=\"var(--or)\" opacity=\".16\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"50\" y=\"76\" font-size=\"8.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">effector</text><text x=\"50\" y=\"86\" font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\">werkt tegen</text><path d=\"M210,30 C250,35 268,45 270,58\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giB4)\"/><path d=\"M258,90 C230,104 210,110 204,116\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giB4)\"/><path d=\"M116,124 C86,116 66,104 58,92\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giB4)\"/><path d=\"M50,58 C52,42 78,32 108,29\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giB4)\"/></svg><div class=\"sam-figcap\"><strong>Negatieve terugkoppeling:</strong> de afwijking wordt gemeten (sensor), verwerkt en door de effector tegengewerkt, zodat de waarde terugkeert naar het setpoint. De lus herhaalt zich continu.</div></div><p>Er zijn twee regelsystemen, die elkaar aanvullen:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Zenuwstelsel (neuraal)</div><ul><li>zeer snel, kortdurend</li><li>elektrische impuls: actiepotentiaal</li><li>synaps: Ca²⁺ → neurotransmitter</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Hormoonstelsel</div><ul><li>trager, langdurig</li><li>via het bloed</li><li>bv. insuline, glucagon, adrenaline, ADH</li></ul></div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Verloop van een actiepotentiaal met rust, depolarisatie, repolarisatie en hyperpolarisatie\"><defs><marker id=\"giAP\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"160\" x2=\"332\" y2=\"160\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#giAP)\"/><line x1=\"44\" y1=\"168\" x2=\"44\" y2=\"28\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#giAP)\"/><line x1=\"44\" y1=\"140\" x2=\"320\" y2=\"140\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><text x=\"4\" y=\"143\" font-size=\"8.5\" fill=\"var(--mu)\">−70</text><text x=\"8\" y=\"44\" font-size=\"8.5\" fill=\"var(--mu)\">+30</text><text x=\"10\" y=\"24\" font-size=\"8.5\" fill=\"var(--mu)\">mV</text><path d=\"M44,140 L77,140 L88,125 L105,40 L127,90 L149,148 L165,156 L196,143 L251,140 L320,140\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/><text x=\"98\" y=\"36\" font-size=\"8\" fill=\"var(--or)\">depolarisatie (Na⁺ in)</text><text x=\"150\" y=\"172\" font-size=\"8\" fill=\"var(--mu)\">repolarisatie (K⁺ uit)</text></svg><div class=\"sam-figcap\"><strong>Actiepotentiaal:</strong> bij de drempel gaan Na⁺-kanalen open (depolarisatie, piek +30 mV); daarna stromen K⁺-ionen uit (repolarisatie) met een korte hyperpolarisatie voor de rust terugkeert.</div></div><table class=\"sam-table\"><thead><tr><th>Hormoon</th><th>Effect</th></tr></thead><tbody><tr><td>Insuline</td><td>verlaagt bloedglucose (opslag als glycogeen)</td></tr><tr><td>Glucagon</td><td>verhoogt bloedglucose (afbraak glycogeen)</td></tr><tr><td>Adrenaline</td><td>vecht-of-vlucht: hartslag en glucose omhoog</td></tr><tr><td>ADH</td><td>waterhuishouding: terugresorptie in de nier</td></tr></tbody></table><div class=\"sam-warn\"><strong>Verstoring — diabetes:</strong> bij <strong>type 1</strong> maakt het lichaam geen insuline (aangeboren, alvleesklier), bij <strong>type 2</strong> reageren de cellen er slecht op. In beide gevallen blijft het bloedglucose te hoog; behandeling: insuline spuiten of leefstijl/medicatie.</div><div class=\"sam-head\">B5 · Afweer van het organisme</div><p>Het afweersysteem beschermt tegen ziekteverwekkers in twee lagen:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Aangeboren (niet-specifiek)</div><ul><li>direct aanwezig</li><li>huid, slijmvliezen, fagocyten</li><li>koorts en ontstekingsreactie</li><li>geen geheugen</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Verworven (specifiek)</div><ul><li>ontwikkelt zich, gericht</li><li>B-cellen → antilichamen</li><li>T-cellen (cellulaire afweer)</li><li>vormt geheugencellen</li></ul></div></div><ul><li><strong>Antigeen</strong>: lichaamsvreemde stof die een afweerreactie oproept.</li><li><strong>Antilichaam</strong>: eiwit dat plasmacellen (uit B-cellen) maken en dat specifiek aan een antigeen bindt.</li><li><strong>Actieve immuniteit</strong> (vaccinatie): je maakt zélf antilichamen en geheugencellen. <strong>Passieve immuniteit</strong>: je krijgt kant-en-klare antilichamen (bv. via de moedermelk).</li></ul><div class=\"sam-tip\">Bij een tweede besmetting met dezelfde ziekteverwekker reageren de <strong>geheugencellen</strong> veel sneller en sterker — daarom word je van veel ziekten maar één keer echt ziek, en werkt vaccinatie.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 1 — eiwitsynthese</div><div class=\"sam-worked-q\">Een gen bevat de basenvolgorde (mRNA) AUG-GCC-UAA. Uit hoeveel aminozuren bestaat het eiwit?</div><ol class=\"sam-worked-steps\"><li>Elk codon (triplet) codeert voor één aminozuur.</li><li>AUG = start (methionine), GCC = één aminozuur, UAA = stopcodon (codeert niet voor een aminozuur).</li><li>Dus: 2 aminozuren worden ingebouwd, daarna stopt de translatie.</li></ol><div class=\"sam-worked-ans\">✅ Het eiwit(fragment) bestaat uit 2 aminozuren; het stopcodon beëindigt de synthese.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 2 — homeostase</div><div class=\"sam-worked-q\">Na een koolhydraatrijke maaltijd stijgt het bloedglucose. Beschrijf de negatieve terugkoppeling die volgt.</div><ol class=\"sam-worked-steps\"><li>De alvleesklier (sensor + verwerker) meet de hoge glucosewaarde en scheidt <strong>insuline</strong> af.</li><li>Insuline (effector-signaal) zet lever- en spiercellen aan glucose op te nemen en als glycogeen op te slaan.</li><li>Het bloedglucose daalt naar het setpoint; de insulineafgifte stopt.</li></ol><div class=\"sam-worked-ans\">✅ De afwijking wordt gemeten en tegengewerkt — klassieke negatieve terugkoppeling (B4).</div></div></div>","vwo_bi_E":"<div class=\"sam-intro\"><strong>Reproductie</strong> is het vermogen van biologische eenheden om zichzelf te vermenigvuldigen — van het kopiëren van <strong>DNA</strong> en de <strong>cel</strong> tot de voortplanting van het hele <strong>organisme</strong>. Belangrijk: reproductie is géén exact kopiëren. Door <strong>mutatie</strong> en <strong>recombinatie</strong> ontstaat <strong>variatie</strong>, de grondstof voor evolutie (domein F).</div><div class=\"sam-head\">Wat je voor het examen moet kennen (syllabus)</div><p>Domein E bestaat uit drie subdomeinen. Deze samenvatting dekt ze alle drie:</p><table class=\"sam-table\"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>E1</td><td>DNA-replicatie</td><td>semiconservatief verdubbelen van DNA</td></tr><tr><td>E2</td><td>Levenscyclus van de cel</td><td>celcyclus, mitose én meiose</td></tr><tr><td>E3</td><td>Reproductie van het organisme</td><td>voortplanting en erfelijkheid</td></tr></tbody></table><div class=\"sam-head\">E1 · DNA-replicatie</div><p>Vóór een cel deelt, moet al het DNA worden verdubbeld, zodat beide dochtercellen een complete kopie krijgen. Dat gebeurt <strong>semiconservatief</strong>: de dubbele helix gaat open en elke oude streng dient als <strong>mal (template)</strong> voor een nieuwe streng. Elke nieuwe DNA-molecuul bestaat dus uit één oude en één nieuwe streng.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 140\" role=\"img\" aria-label=\"Semiconservatieve replicatie: de dubbele helix splitst en elke oude streng krijgt een nieuwe complementaire streng\"><defs><marker id=\"giE1\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"40\" y1=\"16\" x2=\"40\" y2=\"124\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"52\" y1=\"16\" x2=\"52\" y2=\"124\" stroke=\"var(--dk)\" stroke-width=\"2\"/><text x=\"46\" y=\"136\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">origineel</text><path d=\"M60,70 C90,64 96,40 96,20\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giE1)\"/><path d=\"M60,70 C90,76 96,100 96,120\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#giE1)\"/><g><line x1=\"150\" y1=\"16\" x2=\"150\" y2=\"124\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"162\" y1=\"16\" x2=\"162\" y2=\"124\" stroke=\"var(--or)\" stroke-width=\"2\"/></g><g><line x1=\"220\" y1=\"16\" x2=\"220\" y2=\"124\" stroke=\"var(--or)\" stroke-width=\"2\"/><line x1=\"232\" y1=\"16\" x2=\"232\" y2=\"124\" stroke=\"var(--dk)\" stroke-width=\"2\"/></g><text x=\"226\" y=\"136\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">2 kopieën</text><rect x=\"270\" y=\"18\" width=\"10\" height=\"20\" fill=\"var(--dk)\"/><text x=\"288\" y=\"32\" font-size=\"7.5\" fill=\"var(--mu)\">oud</text><rect x=\"270\" y=\"44\" width=\"10\" height=\"20\" fill=\"var(--or)\"/><text x=\"288\" y=\"58\" font-size=\"7.5\" fill=\"var(--mu)\">nieuw</text></svg><div class=\"sam-figcap\"><strong>Semiconservatief:</strong> het enzym <strong>DNA-polymerase</strong> plaatst tegenover elke base de complementaire base (A–T, C–G). Beide kopieën bevatten één oude (zwarte) en één nieuwe (oranje) streng.</div></div><div class=\"sam-warn\"><strong>Let op:</strong> replicatie (DNA verdubbelen) is iets anders dan transcriptie (mRNA maken van een gen, domein B1). Replicatie kopieert álle DNA vóór een celdeling; transcriptie leest één gen af om een eiwit te maken.</div><div class=\"sam-head\">E2 · Levenscyclus van de cel</div><p>Een cel doorloopt de <strong>celcyclus</strong>: een lange <strong>interfase</strong> (groeien en DNA verdubbelen) gevolgd door de <strong>celdeling</strong>. Er zijn twee soorten kerndeling met een heel verschillend doel:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Mitose (gewone deling)</div><ul><li>voor groei en herstel</li><li>1 cel → <strong>2</strong> dochtercellen</li><li>dochtercellen <strong>identiek</strong> aan elkaar</li><li>diploïd (2n) → diploïd (2n)</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Meiose (reductiedeling)</div><ul><li>voor geslachtscellen (gameten)</li><li>1 cel → <strong>4</strong> dochtercellen</li><li>dochtercellen <strong>verschillend</strong></li><li>diploïd (2n) → haploïd (n)</li></ul></div></div><div class=\"sam-figure\"><svg viewBox=\"0 0 320 132\" role=\"img\" aria-label=\"Meiose: een diploïde cel deelt in twee stappen tot vier haploïde geslachtscellen\"><defs><marker id=\"giE2\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><circle cx=\"34\" cy=\"66\" r=\"20\" fill=\"var(--or)\" opacity=\".18\" stroke=\"var(--or)\" stroke-width=\"1.3\"/><text x=\"34\" y=\"69\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">2n</text><circle cx=\"150\" cy=\"36\" r=\"15\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"150\" y=\"40\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">n</text><circle cx=\"150\" cy=\"96\" r=\"15\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.1\"/><text x=\"150\" y=\"100\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">n</text><g fill=\"var(--or)\" opacity=\".12\" stroke=\"var(--or)\" stroke-width=\"1\"><circle cx=\"270\" cy=\"20\" r=\"13\"/><circle cx=\"270\" cy=\"52\" r=\"13\"/><circle cx=\"270\" cy=\"80\" r=\"13\"/><circle cx=\"270\" cy=\"112\" r=\"13\"/></g><g font-size=\"7.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"270\" y=\"23\">n</text><text x=\"270\" y=\"55\">n</text><text x=\"270\" y=\"83\">n</text><text x=\"270\" y=\"115\">n</text></g><path d=\"M54,58 C90,44 110,40 134,38\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giE2)\"/><path d=\"M54,74 C90,88 110,92 134,94\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.5\" marker-end=\"url(#giE2)\"/><path d=\"M165,32 C200,24 230,20 255,20\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giE2)\"/><path d=\"M165,40 C200,46 230,50 255,50\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giE2)\"/><path d=\"M165,92 C200,86 230,82 255,80\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giE2)\"/><path d=\"M165,100 C200,106 230,110 255,110\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.4\" marker-end=\"url(#giE2)\"/><text x=\"100\" y=\"20\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">meiose I</text><text x=\"215\" y=\"128\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">meiose II</text></svg><div class=\"sam-figcap\"><strong>Meiose:</strong> in twee delingen ontstaan uit één diploïde cel (2n) vier haploïde geslachtscellen (n). Door <strong>crossing-over</strong> en de toevallige verdeling van chromosomen is elke gameet uniek.</div></div><div class=\"sam-tip\">Variatie in gameten ontstaat op twee manieren tijdens de meiose: <strong>crossing-over</strong> (chromosomen wisselen stukken uit) en de <strong>onafhankelijke verdeling</strong> van de chromosomenparen. Bij de bevruchting komt daar de toevallige combinatie van twee gameten nog bovenop.</div><div class=\"sam-head\">E3 · Reproductie van het organisme</div><p>Organismen planten zich <strong>ongeslachtelijk</strong> voort (één ouder, identieke nakomelingen — klonen) of <strong>geslachtelijk</strong> (twee ouders, gameten versmelten bij de <strong>bevruchting</strong> tot een diploïde zygote — variatie). Hoe eigenschappen overerven, beschrijf je met de genetica:</p><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Genotype / fenotype</td><td>de genen die je hebt / hoe je eruitziet (genen + milieu)</td></tr><tr><td>Allel</td><td>een variant van een gen (bv. A of a)</td></tr><tr><td>Dominant / recessief</td><td>komt altijd tot uiting / alleen bij twee dezelfde allelen</td></tr><tr><td>Homozygoot / heterozygoot</td><td>twee gelijke allelen (AA, aa) / twee verschillende (Aa)</td></tr></tbody></table><p>Met een <strong>kruisingsschema</strong> voorspel je de verhoudingen bij de nakomelingen. Een kruising van twee dragers (Aa × Aa):</p><div class=\"sam-figure\"><svg viewBox=\"0 0 220 150\" role=\"img\" aria-label=\"Kruisingsschema Aa maal Aa geeft één AA, twee Aa en één aa\"><g stroke=\"var(--bo)\" stroke-width=\"1.2\" fill=\"none\"><rect x=\"60\" y=\"40\" width=\"70\" height=\"45\"/><rect x=\"130\" y=\"40\" width=\"70\" height=\"45\"/><rect x=\"60\" y=\"85\" width=\"70\" height=\"45\"/><rect x=\"130\" y=\"85\" width=\"70\" height=\"45\"/></g><g font-size=\"13\" font-weight=\"700\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"95\" y=\"30\">A</text><text x=\"165\" y=\"30\">a</text></g><g font-size=\"13\" font-weight=\"700\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"45\" y=\"67\">A</text><text x=\"45\" y=\"112\">a</text></g><g font-size=\"14\" font-weight=\"700\" text-anchor=\"middle\"><text x=\"95\" y=\"68\" fill=\"var(--or)\">AA</text><text x=\"165\" y=\"68\" fill=\"var(--dk)\">Aa</text><text x=\"95\" y=\"113\" fill=\"var(--dk)\">Aa</text><text x=\"165\" y=\"113\" fill=\"var(--mu)\">aa</text></g></svg><div class=\"sam-figcap\"><strong>Kruisingsschema (Punnett):</strong> Aa × Aa geeft een genotype-verhouding <strong>1 AA : 2 Aa : 1 aa</strong>. Is A dominant, dan is de fenotype-verhouding <strong>3 dominant : 1 recessief</strong>.</div></div><ul><li><strong>Autosomaal</strong>: het gen ligt op een gewoon chromosoom (niet het geslachtschromosoom).</li><li><strong>X-chromosomaal</strong>: het gen ligt op het X-chromosoom; mannen (XY) hebben er maar één van, dus een recessieve eigenschap komt bij hen vaker tot uiting (bv. kleurenblindheid).</li></ul><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 1 — mitose of meiose?</div><div class=\"sam-worked-q\">Een menselijke huidcel bevat 46 chromosomen. Hoeveel chromosomen hebben de cellen die ontstaan na (a) mitose en (b) meiose?</div><ol class=\"sam-worked-steps\"><li>Mitose houdt het aantal gelijk: elke dochtercel is diploïd (2n).</li><li>Meiose halveert het aantal (reductiedeling): elke gameet is haploïd (n).</li><li>2n = 46, dus n = 23.</li></ol><div class=\"sam-worked-ans\">✅ (a) na mitose: 46 chromosomen; (b) na meiose: 23 chromosomen.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 2 — kruising</div><div class=\"sam-worked-q\">Bruine ogen (B) zijn dominant over blauwe (b). Twee bruinogige ouders krijgen een blauwogig kind. Wat zijn de genotypen van de ouders?</div><ol class=\"sam-worked-steps\"><li>Het kind is blauwogig → genotype bb, dus het kreeg van elke ouder een b-allel.</li><li>Beide ouders zijn bruinogig maar dragen een b: ze zijn dus heterozygoot (Bb).</li><li>Controle: Bb × Bb geeft kans op bb (blauw) = 1/4. Dat klopt.</li></ol><div class=\"sam-worked-ans\">✅ Beide ouders zijn <strong>Bb</strong> (heterozygoot, drager van blauw).</div></div>","vwo_bi_F":"<div class=\"sam-intro\"><strong>Evolutie</strong> verklaart hoe soorten in de loop van vele generaties veranderen en hoe nieuwe soorten ontstaan. De motor is <strong>natuurlijke selectie</strong> die inwerkt op de <strong>variatie</strong> binnen een populatie — variatie die voortkomt uit mutatie en recombinatie (domein E).</div><div class=\"sam-head\">Wat je voor het examen moet kennen (syllabus)</div><p>Domein F bestaat uit twee subdomeinen. Deze samenvatting dekt ze allebei:</p><table class=\"sam-table\"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>F1</td><td>Selectie</td><td>variatie + selectiedruk → aanpassing</td></tr><tr><td>F2</td><td>Soortvorming</td><td>isolatie → nieuwe soorten; bewijs voor evolutie</td></tr></tbody></table><div class=\"sam-head\">F1 · Selectie</div><p>Binnen een populatie verschillen individuen erfelijk van elkaar (<strong>variatie</strong>). Er worden méér nakomelingen geboren dan er kunnen overleven, dus is er <strong>concurrentie</strong> om voedsel, ruimte en partners. Individuen wier eigenschappen het best bij het milieu passen, hebben de grootste kans om te overleven en zich voort te planten — ze geven hun allelen vaker door. Zo verschuift over generaties de <strong>allelfrequentie</strong> in de populatie.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 138\" role=\"img\" aria-label=\"Natuurlijke selectie: uit een gevarieerde populatie overleven de best aangepaste vormen, die de volgende generatie gaan overheersen\"><defs><marker id=\"giF1\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><text x=\"52\" y=\"16\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">variatie</text><g><circle cx=\"30\" cy=\"40\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"52\" cy=\"34\" r=\"7\" fill=\"var(--mu)\" opacity=\".5\"/><circle cx=\"74\" cy=\"42\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"40\" cy=\"60\" r=\"7\" fill=\"var(--mu)\" opacity=\".5\"/><circle cx=\"64\" cy=\"62\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"30\" cy=\"80\" r=\"7\" fill=\"var(--mu)\" opacity=\".5\"/><circle cx=\"60\" cy=\"84\" r=\"7\" fill=\"var(--dk)\"/></g><text x=\"160\" y=\"16\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">selectiedruk</text><text x=\"160\" y=\"66\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">lichte vorm valt op</text><text x=\"160\" y=\"79\" font-size=\"7.5\" fill=\"var(--or)\" text-anchor=\"middle\">→ opgegeten</text><line x1=\"90\" y1=\"60\" x2=\"230\" y2=\"60\" stroke=\"var(--or)\" stroke-width=\"1.6\" marker-end=\"url(#giF1)\"/><text x=\"286\" y=\"16\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">volgende generatie</text><g><circle cx=\"264\" cy=\"42\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"286\" cy=\"38\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"308\" cy=\"44\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"274\" cy=\"62\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"298\" cy=\"64\" r=\"7\" fill=\"var(--dk)\"/><circle cx=\"286\" cy=\"82\" r=\"7\" fill=\"var(--mu)\" opacity=\".5\"/></g></svg><div class=\"sam-figcap\"><strong>Natuurlijke selectie:</strong> in een donkere omgeving worden lichte vormen vaker gezien en opgegeten. De donkere vorm plant zich vaker voort, zodat die in de volgende generatie overheerst (bekend voorbeeld: de <strong>berkenspanner</strong>).</div></div><ul><li><strong>Selectiedruk</strong>: de mate waarin het milieu bepaalde eigenschappen bevoordeelt of benadeelt.</li><li><strong>Adaptatie</strong>: een erfelijke aanpassing die de overlevings- of voortplantingskans vergroot.</li><li><strong>Fitness</strong>: de mate waarin een individu bijdraagt aan de volgende generatie (aantal nakomelingen dat zelf overleeft).</li></ul><div class=\"sam-warn\"><strong>Veelgemaakte fout:</strong> een organisme past zich niet <em>doelgericht</em> aan. Mutaties ontstaan <strong>toevallig</strong>; het milieu <strong>selecteert</strong> achteraf welke toevallige varianten het best werken. Zeg dus nooit \"de spanner werd donker omdat hij dat nodig had\".</div><div class=\"sam-tip\">Voorwaarden voor natuurlijke selectie: (1) er is erfelijke variatie, (2) er worden meer nakomelingen geboren dan overleven, (3) de variatie beïnvloedt de overlevings-/voortplantingskans. Voldoe je aan alle drie, dan treedt selectie op.</div><div class=\"sam-head\">F2 · Soortvorming</div><p>Een <strong>soort</strong> is een groep organismen die zich onderling kan voortplanten en daarbij <strong>vruchtbare</strong> nakomelingen krijgt. Nieuwe soorten ontstaan wanneer delen van een populatie <strong>geïsoleerd</strong> raken en geen genen meer uitwisselen.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 140\" role=\"img\" aria-label=\"Soortvorming: een populatie wordt door een barrière gescheiden, de delen evolueren apart en worden twee soorten\"><defs><marker id=\"giF2\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><ellipse cx=\"42\" cy=\"70\" rx=\"30\" ry=\"24\" fill=\"var(--or)\" opacity=\".2\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"42\" y=\"73\" font-size=\"8\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">1 soort</text><line x1=\"128\" y1=\"34\" x2=\"128\" y2=\"106\" stroke=\"var(--mu)\" stroke-width=\"2\" stroke-dasharray=\"4 3\"/><text x=\"128\" y=\"122\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">barrière</text><path d=\"M72,60 C95,50 108,46 118,44\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#giF2)\"/><path d=\"M72,80 C95,90 108,94 118,96\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#giF2)\"/><ellipse cx=\"210\" cy=\"42\" rx=\"26\" ry=\"18\" fill=\"var(--mu)\" opacity=\".18\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><ellipse cx=\"210\" cy=\"100\" rx=\"26\" ry=\"18\" fill=\"var(--mu)\" opacity=\".18\" stroke=\"var(--mu)\" stroke-width=\"1.1\"/><text x=\"210\" y=\"45\" font-size=\"7.5\" fill=\"var(--dk)\" text-anchor=\"middle\">evolueert apart</text><text x=\"210\" y=\"103\" font-size=\"7.5\" fill=\"var(--dk)\" text-anchor=\"middle\">evolueert apart</text><line x1=\"238\" y1=\"42\" x2=\"268\" y2=\"42\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#giF2)\"/><line x1=\"238\" y1=\"100\" x2=\"268\" y2=\"100\" stroke=\"var(--mu)\" stroke-width=\"1.3\" marker-end=\"url(#giF2)\"/><ellipse cx=\"292\" cy=\"42\" rx=\"24\" ry=\"17\" fill=\"var(--or)\" opacity=\".22\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><ellipse cx=\"292\" cy=\"100\" rx=\"24\" ry=\"17\" fill=\"var(--or)\" opacity=\".22\" stroke=\"var(--or)\" stroke-width=\"1.2\"/><text x=\"292\" y=\"45\" font-size=\"7.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">soort A</text><text x=\"292\" y=\"103\" font-size=\"7.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">soort B</text></svg><div class=\"sam-figcap\"><strong>Soortvorming:</strong> een <strong>geografische barrière</strong> (rivier, gebergte) scheidt de populatie. Door verschillende selectiedruk en toeval evolueren de delen apart. Kunnen ze zich later niet meer onderling voortplanten, dan zijn het aparte soorten.</div></div><p><strong>Adaptieve radiatie</strong>: vanuit één soort ontstaan in korte tijd veel nieuwe soorten die elk een eigen leefwijze hebben (klassiek voorbeeld: de <strong>Darwinvinken</strong> met elk een eigen snavelvorm).</p><table class=\"sam-table\"><thead><tr><th>Bewijs voor evolutie</th><th>Wat het laat zien</th></tr></thead><tbody><tr><td>Fossielen</td><td>overgangsvormen en verandering door de tijd</td></tr><tr><td>Homologie</td><td>zelfde bouwplan (bv. voorpoot zoogdieren) → gemeenschappelijke voorouder</td></tr><tr><td>DNA-vergelijking</td><td>hoe meer DNA-overeenkomst, hoe nauwer verwant</td></tr><tr><td>Embryologie</td><td>vroege embryo's van gewervelden lijken sterk op elkaar</td></tr></tbody></table><div class=\"sam-tip\">In een <strong>evolutionaire stamboom</strong> (fylogenie) staat elk splitsingspunt voor een gemeenschappelijke voorouder. Soorten die pas laat splitsen, zijn nauwer verwant — dat zie je ook terug in hun DNA-overeenkomst.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 1 — antibioticaresistentie</div><div class=\"sam-worked-q\">In een bacteriepopulatie overleven na een antibioticakuur alleen resistente bacteriën. Verklaar dit met natuurlijke selectie — en waarom is \"de bacteriën werden resistent door het antibioticum\" fout?</div><ol class=\"sam-worked-steps\"><li>Door toevallige mutaties was er al vóór de kuur variatie: enkele bacteriën waren resistent.</li><li>Het antibioticum vormt de selectiedruk: gevoelige bacteriën sterven, resistente overleven.</li><li>De overlevers planten zich voort; hun resistentie-allel overheerst nu de populatie.</li></ol><div class=\"sam-worked-ans\">✅ Het antibioticum <strong>selecteert</strong> bestaande resistente varianten; het <strong>veroorzaakt</strong> de resistentie niet. De mutatie was er al, toevallig.</div></div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave 2 — één soort of twee?</div><div class=\"sam-worked-q\">Twee gescheiden vogelpopulaties worden herenigd. Ze paren wel, maar de eieren komen niet uit. Zijn het één of twee soorten? Leg uit.</div><ol class=\"sam-worked-steps\"><li>Het biologische soortbegrip vraagt om <strong>vruchtbare</strong> nakomelingen.</li><li>Er komen geen (levensvatbare) nakomelingen: er is reproductieve isolatie.</li><li>Dus de genenuitwisseling is definitief verbroken.</li></ol><div class=\"sam-worked-ans\">✅ Het zijn <strong>twee soorten</strong>: de soortvorming is voltooid doordat ze samen geen vruchtbare nakomelingen krijgen.</div></div>","vwo_sk_B":"<div class=\"sam-intro\">De <strong>bindingssoort</strong> bepaalt de eigenschappen van een stof. Je onderscheidt <strong>ion-</strong>, <strong>atoom-</strong> (covalente) en <strong>metaalbinding</strong>, voorspelt de <strong>molecuulvorm</strong> met VSEPR en verklaart smelt- en kookpunten uit de <strong>intermoleculaire krachten</strong>.</div><div class=\"sam-head\">Ionbinding en covalente binding</div><p>Bij een <strong>ionbinding</strong> worden elektronen overgedragen (metaal + niet-metaal) en trekken tegengestelde ionen elkaar aan in een <strong>ionrooster</strong>. Bij een <strong>covalente binding</strong> delen niet-metalen elektronenparen.</p><table class=\"sam-table\"><thead><tr><th>Binding</th><th>Deeltjes</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Ionbinding</td><td>metaal + niet-metaal</td><td>hoog smeltpunt, geleidt opgelost</td></tr><tr><td>Covalent (molecuul)</td><td>niet-metalen</td><td>lager smeltpunt, geleidt niet</td></tr><tr><td>Metaalbinding</td><td>metaalatomen + vrije e⁻</td><td>geleidt, buigzaam, glanzend</td></tr></tbody></table><div class=\"sam-head\">Molecuulvorm (VSEPR) en polariteit</div><p>Het <strong>VSEPR-model</strong> zegt dat elektronenparen elkaar zoveel mogelijk afstoten; daaruit volgt de <strong>molecuulgeometrie</strong>. Staat er een verschil in elektronegativiteit én is het molecuul niet-symmetrisch, dan is het <strong>polair</strong> (het heeft een dipool).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 170\" role=\"img\" aria-label=\"Watermolecuul met gebogen vorm, partiele ladingen en een netto dipoolvector\"><defs><marker id=\"skCd\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"150\" y1=\"60\" x2=\"108\" y2=\"118\" stroke=\"var(--mu)\" stroke-width=\"2.5\"/><line x1=\"150\" y1=\"60\" x2=\"192\" y2=\"118\" stroke=\"var(--mu)\" stroke-width=\"2.5\"/><circle cx=\"150\" cy=\"60\" r=\"17\" fill=\"var(--dk)\"/><text x=\"150\" y=\"65\" font-size=\"13\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">O</text><circle cx=\"108\" cy=\"118\" r=\"12\" fill=\"var(--mu)\"/><text x=\"108\" y=\"122\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">H</text><circle cx=\"192\" cy=\"118\" r=\"12\" fill=\"var(--mu)\"/><text x=\"192\" y=\"122\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">H</text><text x=\"175\" y=\"48\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">δ−</text><text x=\"80\" y=\"126\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">δ+</text><text x=\"204\" y=\"126\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">δ+</text><line x1=\"150\" y1=\"95\" x2=\"150\" y2=\"40\" stroke=\"var(--or)\" stroke-width=\"2\" stroke-dasharray=\"4 2\" marker-end=\"url(#skCd)\"/><text x=\"156\" y=\"90\" font-size=\"9.5\" fill=\"var(--or)\">dipool</text><text x=\"120\" y=\"90\" font-size=\"9\" fill=\"var(--mu)\">104,5°</text></svg><div class=\"sam-figcap\"><strong>Water is polair:</strong> de gebogen vorm (104,5°) zorgt dat de δ−-kant (O) en de δ+-kant (H's) niet samenvallen — er blijft een netto dipool over.</div></div><div class=\"sam-head\">Intermoleculaire krachten</div><p>Tussen moleculen werken zwakkere krachten die het smelt- en kookpunt bepalen. Van zwak naar sterk:</p><table class=\"sam-table\"><thead><tr><th>Kracht</th><th>Waar</th><th>Sterkte</th></tr></thead><tbody><tr><td>Vanderwaals</td><td>alle moleculen</td><td>zwak (sterker bij grotere massa)</td></tr><tr><td>Dipool-dipool</td><td>polaire moleculen</td><td>gemiddeld</td></tr><tr><td>Waterstofbrug</td><td>O–H, N–H, F–H</td><td>sterk</td></tr></tbody></table><div class=\"sam-tip\">Water heeft door zijn <strong>waterstofbruggen</strong> een opvallend hoog kookpunt (100 °C) voor zo'n klein molecuul.</div><div class=\"sam-warn\"><strong>Denkfout:</strong> bij smelten of koken verbreek je de <em>intermoleculaire</em> krachten, niet de sterke covalente bindingen bínnen het molecuul. Water dat kookt blijft H₂O.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom heeft CO₂ geen dipool, terwijl H₂O die wel heeft? Beide hebben polaire bindingen.</div><ol class=\"sam-worked-steps\"><li>CO₂ is lineair (O=C=O): de twee bindingsdipolen wijzen precies tegengesteld.</li><li>Ze heffen elkaar op → netto dipool nul → apolair.</li><li>H₂O is gebogen: de dipolen heffen elkaar niet op → netto dipool.</li></ol><div class=\"sam-worked-ans\">✅ De molecuulvorm bepaalt of de bindingsdipolen elkaar opheffen. CO₂ is apolair, H₂O polair.</div></div></div><div class=\"sam-intro\">De <strong>organische chemie</strong> gaat over koolstofverbindingen. Je herkent stofklassen aan hun <strong>functionele groep</strong>, voorspelt reacties (<strong>substitutie</strong>, <strong>additie</strong>, <strong>condensatie</strong>) en begrijpt hoe kleine bouwstenen tot <strong>polymeren</strong> aaneenrijgen.</div><div class=\"sam-head\">Koolwaterstoffen: alkanen, alkenen, alkynen</div><p>Koolwaterstoffen bevatten alleen C en H. Het aantal bindingen tussen de koolstofatomen bepaalt de klasse en de reactiviteit.</p><table class=\"sam-table\"><thead><tr><th>Klasse</th><th>Binding</th><th>Uitgang</th></tr></thead><tbody><tr><td>Alkaan</td><td>enkele C–C (verzadigd)</td><td>-aan</td></tr><tr><td>Alkeen</td><td>dubbele C=C (onverzadigd)</td><td>-een</td></tr><tr><td>Alkyn</td><td>drievoudige C≡C</td><td>-yn</td></tr></tbody></table><div class=\"sam-head\">Functionele groepen</div><p>De <strong>functionele groep</strong> bepaalt de eigenschappen en de naam. Deze moet je herkennen:</p><table class=\"sam-table\"><thead><tr><th>Groep</th><th>Kenmerk</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Alcohol</td><td>–OH</td><td>ethanol</td></tr><tr><td>Carbonzuur</td><td>–COOH</td><td>azijnzuur</td></tr><tr><td>Ester</td><td>–COO–</td><td>geur/aroma's</td></tr><tr><td>Amine</td><td>–NH₂</td><td>aminozuren</td></tr></tbody></table><div class=\"sam-head\">Substitutie en additie</div><p>Een <strong>verzadigd</strong> molecuul (alkaan) reageert via <strong>substitutie</strong>: een atoom wordt vervangen. Een <strong>onverzadigd</strong> molecuul (alkeen) reageert via <strong>additie</strong>: de dubbele band gaat open en er komen atomen bij.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 150\" role=\"img\" aria-label=\"Additiereactie waarbij een dubbele koolstofbinding opengaat en twee broomatomen worden toegevoegd\"><text x=\"20\" y=\"60\" font-size=\"13\" font-weight=\"700\" fill=\"var(--dk)\">C</text><text x=\"70\" y=\"60\" font-size=\"13\" font-weight=\"700\" fill=\"var(--dk)\">C</text><line x1=\"34\" y1=\"52\" x2=\"64\" y2=\"52\" stroke=\"var(--or)\" stroke-width=\"2\"/><line x1=\"34\" y1=\"58\" x2=\"64\" y2=\"58\" stroke=\"var(--or)\" stroke-width=\"2\"/><text x=\"24\" y=\"90\" font-size=\"9\" fill=\"var(--mu)\">alkeen (C=C)</text><text x=\"105\" y=\"58\" font-size=\"11\" fill=\"var(--mu)\">+ Br₂</text><defs><marker id=\"skBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"150\" y1=\"53\" x2=\"185\" y2=\"53\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#skBa)\"/><text x=\"210\" y=\"60\" font-size=\"13\" font-weight=\"700\" fill=\"var(--dk)\">C</text><text x=\"260\" y=\"60\" font-size=\"13\" font-weight=\"700\" fill=\"var(--dk)\">C</text><line x1=\"224\" y1=\"55\" x2=\"254\" y2=\"55\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"216\" y1=\"46\" x2=\"216\" y2=\"28\" stroke=\"var(--dk)\" stroke-width=\"1.5\"/><text x=\"211\" y=\"24\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">Br</text><line x1=\"266\" y1=\"46\" x2=\"266\" y2=\"28\" stroke=\"var(--dk)\" stroke-width=\"1.5\"/><text x=\"261\" y=\"24\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">Br</text><text x=\"214\" y=\"90\" font-size=\"9\" fill=\"var(--mu)\">verzadigd product</text></svg><div class=\"sam-figcap\"><strong>Additie:</strong> de dubbele binding gaat open en de twee broomatomen hechten aan de koolstofatomen. Het onverzadigde alkeen wordt een verzadigd product.</div></div><div class=\"sam-tip\">Toets voor onverzadigdheid: broomwater (bruin) <strong>ontkleurt</strong> bij een alkeen (additie), maar niet bij een alkaan.</div><div class=\"sam-head\">Polymerisatie</div><p>Kleine moleculen (<strong>monomeren</strong>) rijgen aaneen tot een <strong>polymeer</strong>. Twee typen:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Additiepolymerisatie</div><ul><li>alkenen koppelen via de dubbele band</li><li>geen bijproduct</li><li>bijv. polytheen (PE), PVC</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Condensatiepolymerisatie</div><ul><li>groepen reageren (–OH + –COOH)</li><li>klein bijproduct (vaak H₂O)</li><li>bijv. polyester, nylon</li></ul></div></div><div class=\"sam-head\">Isomerie en benzeen</div><p><strong>Isomeren</strong> hebben dezelfde molecuulformule maar een andere structuur (en dus andere eigenschappen). <strong>Benzeen</strong> (C₆H₆) is een ringvormige aromatische verbinding met bijzonder stabiele, gedelokaliseerde elektronen.</p><div class=\"sam-warn\"><strong>Let op:</strong> benzeen reageert ondanks zijn 'dubbele banden' niet via additie maar via <strong>substitutie</strong> — de aromatische ring is te stabiel om open te breken.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Etheen (C₂H₄) reageert met water tot ethanol. Welk reactietype is dit en waarom?</div><ol class=\"sam-worked-steps\"><li>Etheen is onverzadigd (C=C).</li><li>Het watermolecuul (H en OH) wordt aan de dubbele band toegevoegd; de band gaat open.</li><li>Er komt geen atoom vrij — het is dus geen substitutie.</li></ol><div class=\"sam-worked-ans\">✅ Een additiereactie: C₂H₄ + H₂O → C₂H₅OH.</div></div></div>","vwo_sk_C":"<div class=\"sam-intro\">Bij een <strong>omkeerbare reactie</strong> lopen de heen- en teruggaande reactie tegelijk. Zijn hun snelheden gelijk, dan is er een <strong>dynamisch evenwicht</strong>: de concentraties blijven constant, maar de reacties gaan door. De <strong>evenwichtsconstante K</strong> en het <strong>principe van Le Chatelier</strong> vertellen je waar dat evenwicht ligt en hoe het verschuift.</div><div class=\"sam-head\">Dynamisch evenwicht</div><p>In een gesloten systeem daalt de concentratie van de <strong>reactanten</strong> en stijgt die van de <strong>producten</strong>, tot beide snelheden gelijk zijn. Vanaf dat moment veranderen de concentraties niet meer, ook al blijven de reacties in beide richtingen doorgaan.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 360 172\" role=\"img\" aria-label=\"Concentratie-tijddiagram waarin reactanten dalen en producten stijgen tot een evenwicht\"><defs><marker id=\"skT\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"350\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#skT)\"/><line x1=\"44\" y1=\"150\" x2=\"44\" y2=\"24\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#skT)\"/><path d=\"M44.0,42.0 L47.7,46.0 L51.4,49.8 L55.1,53.3 L58.8,56.6 L62.5,59.7 L66.2,62.6 L69.9,65.4 L73.6,68.0 L77.3,70.4 L81.0,72.7 L84.7,74.8 L88.4,76.8 L92.1,78.7 L95.8,80.5 L99.5,82.2 L103.2,83.7 L106.9,85.2 L110.6,86.6 L114.3,87.9 L118.0,89.1 L121.7,90.2 L125.4,91.3 L129.1,92.3 L132.8,93.3 L136.5,94.2 L140.2,95.0 L143.9,95.8 L147.6,96.5 L151.3,97.2 L155.0,97.9 L158.7,98.5 L162.4,99.1 L166.1,99.6 L169.8,100.1 L173.5,100.6 L177.2,101.0 L180.9,101.5 L184.6,101.9 L188.3,102.2 L192.0,102.6 L195.7,102.9 L199.4,103.2 L203.1,103.5 L206.8,103.8 L210.5,104.0 L221.6,104.7 L240.1,105.6 L262.3,106.3 L291.9,107.0 L340.0,107.6\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/><path d=\"M44.0,150.0 L47.7,145.3 L51.4,140.8 L55.1,136.7 L58.8,132.7 L62.5,129.1 L66.2,125.6 L69.9,122.4 L73.6,119.3 L77.3,116.4 L81.0,113.8 L84.7,111.2 L88.4,108.8 L92.1,106.6 L95.8,104.5 L99.5,102.5 L103.2,100.7 L106.9,99.0 L110.6,97.3 L114.3,95.8 L118.0,94.3 L121.7,93.0 L125.4,91.7 L129.1,90.5 L132.8,89.4 L136.5,88.3 L140.2,87.4 L143.9,86.4 L147.6,85.6 L151.3,84.7 L155.0,84.0 L158.7,83.2 L162.4,82.6 L166.1,81.9 L169.8,81.3 L173.5,80.8 L177.2,80.2 L180.9,79.7 L184.6,79.3 L188.3,78.8 L199.4,77.7 L214.2,76.4 L232.7,75.2 L258.6,74.1 L291.9,73.2 L340.0,72.5\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/><line x1=\"210\" y1=\"24\" x2=\"210\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/><text x=\"216\" y=\"36\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--mu)\">evenwicht</text><text x=\"300\" y=\"103\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">reactant</text><text x=\"300\" y=\"69\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">product</text><text x=\"30\" y=\"30\" font-size=\"9.5\" fill=\"var(--mu)\">[ ]</text><text x=\"344\" y=\"164\" font-size=\"9.5\" fill=\"var(--mu)\">t</text></svg><div class=\"sam-figcap\"><strong>Instellen van het evenwicht:</strong> de concentraties veranderen eerst snel en daarna steeds trager, tot ze na de stippellijn constant blijven. Het evenwicht is <strong>dynamisch</strong>, niet stilstaand.</div></div><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Omkeerbare reactie</td><td>verloopt zowel heen (→) als terug (←), genoteerd met ⇌</td></tr><tr><td>Dynamisch evenwicht</td><td>heen- en teruggaande reactiesnelheid zijn gelijk</td></tr><tr><td>Ligging van het evenwicht</td><td>welke kant (reactanten/producten) overheerst</td></tr><tr><td>Aflopende reactie</td><td>gaat vrijwel volledig naar rechts (zeer grote K)</td></tr></tbody></table><div class=\"sam-head\">Evenwichtsconstante K</div><p>Voor een evenwicht <em>a</em>A + <em>b</em>B ⇌ <em>c</em>C + <em>d</em>D geldt een vaste verhouding tussen de concentraties, mits de temperatuur constant blijft.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Evenwichtsvoorwaarde</div><div class=\"sam-formula-eq\">K = ([C]<sup>c</sup> · [D]<sup>d</sup>) / ([A]<sup>a</sup> · [B]<sup>b</sup>)</div><div class=\"sam-formula-note\">De concentraties zijn die in de evenwichtstoestand (mol/L). Zuivere vaste stoffen en zuiver water reken je niet mee. K hangt alleen af van de temperatuur.</div></div><ul><li><strong>K ≫ 1</strong>: het evenwicht ligt rechts, veel product (bijna aflopend).</li><li><strong>K ≪ 1</strong>: het evenwicht ligt links, weinig product.</li><li>Een <strong>katalysator</strong> verandert K niet: het evenwicht wordt alleen sneller bereikt.</li></ul><div class=\"sam-head\">Principe van Le Chatelier</div><p>Verstoor je een evenwicht, dan verschuift het zó dat het de verstoring <strong>tegenwerkt</strong>. Drie soorten verstoring:</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Verschuift naar rechts als…</div><ul><li>je een reactant toevoegt</li><li>je een product afvoert</li><li>de druk stijgt en rechts staan minder mol gas</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Verschuift naar links als…</div><ul><li>je een product toevoegt</li><li>je een reactant afvoert</li><li>de druk stijgt en links staan minder mol gas</li></ul></div></div><div class=\"sam-warn\"><strong>Temperatuur is anders:</strong> alleen temperatuur verandert de waarde van <strong>K</strong>. Bij een <strong>exotherme</strong> reactie (warmte is een 'product') verschuift het evenwicht bij verwarming naar links en daalt K. Bij een <strong>endotherme</strong> reactie stijgt K bij verwarming.</div><div class=\"sam-head\">Zuur-base-evenwichten en pH</div><p>Zuren en basen stellen zich in water in op een evenwicht. Sterke zuren reageren vrijwel volledig; zwakke zuren maar gedeeltelijk.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">pH en de waterconstante</div><div class=\"sam-formula-eq\">pH = −log[H₃O⁺]  ·  pH + pOH = 14</div><div class=\"sam-formula-note\">Bij 25 °C geldt K<sub>w</sub> = [H₃O⁺]·[OH⁻] = 1,0·10⁻¹⁴. Een lagere pH betekent een hogere [H₃O⁺] en dus een zuurdere oplossing.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Zuurconstante van een zwak zuur</div><div class=\"sam-formula-eq\">K<sub>z</sub> = ([H₃O⁺] · [A⁻]) / [HA]</div><div class=\"sam-formula-note\">Hoe groter K<sub>z</sub>, hoe sterker het zuur. Voor een zwak zuur met beginconcentratie c geldt bij benadering [H₃O⁺] = √(K<sub>z</sub> · c).</div></div><div class=\"sam-head\">Buffers</div><p>Een <strong>buffer</strong> bevat een zwak zuur én zijn geconjugeerde base in vergelijkbare hoeveelheden. Toegevoegd H₃O⁺ wordt weggevangen door de base, toegevoegd OH⁻ door het zuur, zodat de pH nauwelijks verandert.</p><div class=\"sam-tip\">Een buffer werkt het best als [zuur] ≈ [base]; de pH ligt dan dicht bij de pK<sub>z</sub> van het zwakke zuur.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bereken de pH van een oplossing met 0,10 mol/L azijnzuur (K<sub>z</sub> = 1,8·10⁻⁵).</div><ol class=\"sam-worked-steps\"><li>Azijnzuur is een zwak zuur, gebruik [H₃O⁺] = √(K<sub>z</sub> · c).</li><li>[H₃O⁺] = √(1,8·10⁻⁵ × 0,10) = √(1,8·10⁻⁶) = 1,34·10⁻³ mol/L.</li><li>pH = −log(1,34·10⁻³) = 2,87.</li></ol><div class=\"sam-worked-ans\">✅ pH ≈ 2,9 — duidelijk zuur, maar minder dan bij een even sterk sterk zuur (dat pH 1,0 zou geven).</div></div></div><div class=\"sam-intro\">De <strong>elektrochemie</strong> koppelt redoxreacties aan elektrische stroom. In een <strong>galvanische cel</strong> levert een spontane reactie spanning; bij <strong>elektrolyse</strong> dwing je met stroom juist een reactie af. De <strong>reductiepotentiaal</strong> voorspelt wat er gebeurt.</div><div class=\"sam-head\">Redox: oxidatie en reductie</div><p>Bij een <strong>redoxreactie</strong> worden elektronen overgedragen. De ene stof staat elektronen af (oxidatie), de andere neemt ze op (reductie).</p><table class=\"sam-table\"><thead><tr><th>Halfreactie</th><th>Elektronen</th><th>Elektrode</th></tr></thead><tbody><tr><td>Oxidatie</td><td>staat e⁻ af</td><td>anode (−)</td></tr><tr><td>Reductie</td><td>neemt e⁻ op</td><td>kathode (+)</td></tr></tbody></table><div class=\"sam-head\">Galvanische cel (Daniell-cel)</div><p>Twee <strong>halfcellen</strong> zijn verbonden door een draad (voor de elektronen) en een <strong>zoutbrug</strong> (voor de ionbalans). De onedele metaal-elektrode wordt de anode; de edelere de kathode.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 190\" role=\"img\" aria-label=\"Daniell-cel met zink- en koperelektrode, zoutbrug en elektronenstroom door de draad\"><defs><marker id=\"skEe\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><path d=\"M30,80 L30,175 L120,175 L120,80\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.5\"/><path d=\"M180,80 L180,175 L270,175 L270,80\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.5\"/><rect x=\"30\" y=\"120\" width=\"90\" height=\"55\" fill=\"var(--mu)\" opacity=\".08\"/><rect x=\"180\" y=\"120\" width=\"90\" height=\"55\" fill=\"var(--or)\" opacity=\".10\"/><rect x=\"68\" y=\"70\" width=\"10\" height=\"80\" fill=\"var(--dk)\"/><rect x=\"222\" y=\"70\" width=\"10\" height=\"80\" fill=\"var(--dk)\"/><path d=\"M73,70 L73,45 L227,45 L227,70\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"2\"/><line x1=\"120\" y1=\"45\" x2=\"180\" y2=\"45\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#skEe)\"/><text x=\"135\" y=\"38\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">e⁻</text><path d=\"M120,95 Q150,72 180,95\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"6\" opacity=\".35\"/><text x=\"128\" y=\"80\" font-size=\"8\" fill=\"var(--mu)\">zoutbrug</text><text x=\"45\" y=\"60\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">Zn</text><text x=\"30\" y=\"190\" font-size=\"8.5\" fill=\"var(--mu)\">Zn / Zn²⁺  (anode −)</text><text x=\"215\" y=\"60\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">Cu</text><text x=\"182\" y=\"190\" font-size=\"8.5\" fill=\"var(--mu)\">Cu / Cu²⁺  (kathode +)</text></svg><div class=\"sam-figcap\"><strong>Daniell-cel:</strong> zink (onedel) lost op en staat elektronen af; die lopen door de draad naar de koperelektrode, waar Cu²⁺ neerslaat. De zoutbrug houdt beide oplossingen neutraal.</div></div><div class=\"sam-head\">Reductiepotentiaal en celspanning</div><p>De <strong>standaard reductiepotentiaal E°</strong> (BiNaS) geeft aan hoe graag een halfreactie elektronen opneemt. De celspanning is het verschil tussen de twee halfcellen.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Bronspanning van de cel</div><div class=\"sam-formula-eq\">E°<sub>cel</sub> = E°<sub>kathode</sub> − E°<sub>anode</sub></div><div class=\"sam-formula-note\">Een positieve E°<sub>cel</sub> betekent een spontane reactie. De <strong>Nernst-vergelijking</strong> corrigeert E voor afwijkende concentraties.</div></div><div class=\"sam-head\">Elektrolyse en Faraday</div><p>Bij <strong>elektrolyse</strong> dwingt een uitwendige spanning een niet-spontane reactie af. De hoeveelheid omgezette stof volgt uit de <strong>lading</strong>.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Wet van Faraday</div><div class=\"sam-formula-eq\">Q = I · t  ·  n(e⁻) = Q / F</div><div class=\"sam-formula-note\">Q de lading (C), I de stroom (A), t de tijd (s), F = 9,65·10⁴ C/mol (constante van Faraday). Zo bereken je hoeveel mol stof neerslaat of vrijkomt.</div></div><div class=\"sam-tip\"><strong>Corrosie</strong> (roesten) is een ongewenste redoxreactie. Bescherming: verven, verzinken (opofferingsanode) of kathodische bescherming met een onedeler metaal.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Door een elektrolyse-opstelling loopt 2,0 A gedurende 30 minuten. Hoeveel mol elektronen is er verplaatst? (F = 9,65·10⁴ C/mol)</div><ol class=\"sam-worked-steps\"><li>Q = I·t = 2,0 × (30 × 60) = 2,0 × 1800 = 3600 C.</li><li>n(e⁻) = Q / F = 3600 / 9,65·10⁴.</li><li>n(e⁻) = 3,7·10⁻² mol.</li></ol><div class=\"sam-worked-ans\">✅ Er is 0,037 mol elektronen verplaatst.</div></div></div>","vwo_na_B":"<div class=\"sam-intro\">Een <strong>trilling</strong> die zich voortplant is een <strong>golf</strong>. Op VWO reken je met de golfvergelijking v = f·λ, met <strong>staande golven</strong>, <strong>interferentie</strong> en <strong>diffractie</strong>, en met de <strong>brekingswet van Snellius</strong> en het <strong>Doppler-effect</strong>.</div><div class=\"sam-head\">Harmonische trilling</div><p>Een <strong>harmonische trilling</strong> heeft een sinusvormig (u,t)-diagram. Belangrijke grootheden: amplitude A, periode T en frequentie f.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Frequentie, periode en golfsnelheid</div><div class=\"sam-formula-eq\">f = 1/T  ·  v = f · λ</div><div class=\"sam-formula-note\">f de frequentie (Hz), T de periode (s), λ de golflengte (m), v de voortplantingssnelheid (m/s). v = f·λ geldt voor élke golf.</div></div><div class=\"sam-head\">Staande golven en resonantie</div><p>Kaatst een golf terug en interfereert hij met zichzelf, dan ontstaat een <strong>staande golf</strong> met <strong>knopen</strong> (stilstaand) en <strong>buiken</strong> (maximale uitwijking). Bij <strong>resonantie</strong> valt de aandrijffrequentie samen met een eigenfrequentie en loopt de amplitude sterk op.</p><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Knoop</td><td>punt dat niet trilt (destructieve interferentie)</td></tr><tr><td>Buik</td><td>punt met maximale amplitude (constructief)</td></tr><tr><td>Grondtoon</td><td>laagste eigenfrequentie, grootste golflengte</td></tr><tr><td>Boventoon</td><td>hogere eigenfrequentie, meer knopen</td></tr></tbody></table><div class=\"sam-head\">Interferentie en diffractie</div><p>Golven die elkaar ontmoeten <strong>superponeren</strong>: in fase → versterking (constructief), in tegenfase → uitdoving (destructief). Bij een <strong>tralie</strong> of spleet buigen golven af (diffractie) en ontstaan maxima onder bepaalde hoeken.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Maxima bij een tralie</div><div class=\"sam-formula-eq\">d · sin θ = n · λ</div><div class=\"sam-formula-note\">d de afstand tussen de spleten (m), θ de hoek van het n-de maximum, n = 0, 1, 2, … Een kleinere d geeft grotere hoeken tussen de maxima.</div></div><div class=\"sam-head\">Breking: de wet van Snellius</div><p>Gaat licht van het ene naar het andere medium, dan verandert de snelheid en <strong>breekt</strong> de straal. Naar een dichter medium (grotere n) buigt de straal <strong>naar de normaal</strong> toe.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Lichtstraal die aan een grensvlak breekt volgens de wet van Snellius\"><rect x=\"0\" y=\"100\" width=\"300\" height=\"100\" fill=\"var(--mu)\" opacity=\".08\"/><line x1=\"0\" y1=\"100\" x2=\"300\" y2=\"100\" stroke=\"var(--mu)\" stroke-width=\"1.5\"/><line x1=\"150\" y1=\"40\" x2=\"150\" y2=\"160\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"4 3\"/><text x=\"155\" y=\"50\" font-size=\"9\" fill=\"var(--mu)\">normaal</text><text x=\"10\" y=\"94\" font-size=\"9\" fill=\"var(--mu)\">medium 1 (n₁)</text><text x=\"10\" y=\"118\" font-size=\"9\" fill=\"var(--mu)\">medium 2 (n₂ &gt; n₁)</text><defs><marker id=\"naCr\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"97\" y1=\"47\" x2=\"150\" y2=\"100\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#naCr)\"/><line x1=\"150\" y1=\"100\" x2=\"180\" y2=\"163\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#naCr)\"/><path d=\"M150,70 A30,30 0 0,0 129,79\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"1.2\"/><text x=\"126\" y=\"74\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">θ₁</text><path d=\"M150,130 A30,30 0 0,0 164,127\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"1.2\"/><text x=\"158\" y=\"140\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">θ₂</text></svg><div class=\"sam-figcap\"><strong>Breking:</strong> in het dichtere medium (n₂ &gt; n₁) is θ₂ kleiner dan θ₁: de straal buigt naar de normaal toe.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Wet van Snellius</div><div class=\"sam-formula-eq\">n₁ · sin θ₁ = n₂ · sin θ₂</div><div class=\"sam-formula-note\">n de brekingsindex, θ de hoek met de normaal. Boven een grenshoek treedt <strong>totale terugkaatsing</strong> op (basis van glasvezel).</div></div><div class=\"sam-head\">Doppler-effect</div><p>Beweegt een geluidsbron naar je toe, dan worden de golven 'samengedrukt' en hoor je een <strong>hogere</strong> frequentie; beweegt de bron weg, dan een <strong>lagere</strong>. Bij licht heet dit roodverschuiving (bron weg) of blauwverschuiving (bron dichterbij).</p><div class=\"sam-tip\">Het Doppler-effect verklaart de veranderende toonhoogte van een voorbijrijdende sirene én de roodverschuiving waarmee astronomen zien dat het heelal uitdijt.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Licht valt vanuit lucht (n₁ = 1,00) onder θ₁ = 40° op glas (n₂ = 1,50). Bereken de brekingshoek θ₂.</div><ol class=\"sam-worked-steps\"><li>Snellius: sin θ₂ = (n₁/n₂) · sin θ₁.</li><li>sin θ₂ = (1,00/1,50) · sin 40° = 0,667 × 0,643 = 0,429.</li><li>θ₂ = sin⁻¹(0,429) = 25°.</li></ol><div class=\"sam-worked-ans\">✅ θ₂ ≈ 25° — de straal buigt naar de normaal toe, zoals verwacht bij een dichter medium.</div></div></div>","vwo_na_C":"<div class=\"sam-intro\">Mechanica draait om <strong>krachten en beweging</strong>. De <strong>wetten van Newton</strong> koppelen kracht aan versnelling, en twee behoudswetten — <strong>energie</strong> en <strong>impuls</strong> — laten je botsingen en bewegingen doorrekenen zonder elke kracht te kennen. Op VWO komt daar de <strong>cirkelbeweging</strong> en de <strong>gravitatiewet</strong> bij.</div><div class=\"sam-head\">De wetten van Newton</div><p>Newton beschrijft hoe krachten beweging veranderen. De resulterende (netto) kracht bepaalt de versnelling.</p><table class=\"sam-table\"><thead><tr><th>Wet</th><th>Inhoud</th></tr></thead><tbody><tr><td>1e (traagheid)</td><td>F<sub>res</sub> = 0 → snelheid blijft constant (of rust)</td></tr><tr><td>2e (bewegingswet)</td><td>F<sub>res</sub> = m·a: kracht geeft versnelling</td></tr><tr><td>3e (actie-reactie)</td><td>F<sub>A op B</sub> = −F<sub>B op A</sub></td></tr></tbody></table><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Tweede wet van Newton</div><div class=\"sam-formula-eq\">F<sub>res</sub> = m · a</div><div class=\"sam-formula-note\">F<sub>res</sub> de resulterende kracht (N), m de massa (kg), a de versnelling (m/s²). Ontbind schuine krachten altijd eerst in componenten (bijv. langs en loodrecht op een helling).</div></div><div class=\"sam-head\">Eenparige cirkelbeweging</div><p>Beweegt een voorwerp met constante snelheid langs een cirkel, dan verandert de <strong>richting</strong> van de snelheid voortdurend. Er is dus een versnelling, gericht naar het middelpunt: de <strong>middelpuntzoekende kracht</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Eenparige cirkelbeweging met snelheid rakend aan de cirkel en middelpuntzoekende kracht naar het centrum\"><defs><marker id=\"naBv\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker><marker id=\"naBf\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--dk)\"/></marker></defs><circle cx=\"150\" cy=\"105\" r=\"66\" fill=\"none\" stroke=\"var(--mu)\" stroke-width=\"1.5\" stroke-dasharray=\"4 3\"/><circle cx=\"150\" cy=\"105\" r=\"3\" fill=\"var(--mu)\"/><line x1=\"150\" y1=\"105\" x2=\"216\" y2=\"105\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><text x=\"178\" y=\"100\" font-size=\"10\" fill=\"var(--mu)\">r</text><circle cx=\"216\" cy=\"105\" r=\"6\" fill=\"var(--or)\"/><line x1=\"216\" y1=\"105\" x2=\"216\" y2=\"45\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#naBv)\"/><text x=\"222\" y=\"55\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">v</text><line x1=\"216\" y1=\"105\" x2=\"164\" y2=\"105\" stroke=\"var(--dk)\" stroke-width=\"2.4\" marker-end=\"url(#naBf)\"/><text x=\"168\" y=\"122\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\">F<tspan font-size=\"8\" dy=\"2\">mpz</tspan></text></svg><div class=\"sam-figcap\"><strong>Cirkelbeweging:</strong> de snelheid <strong>v</strong> staat rakend aan de baan (loodrecht op de straal), de middelpuntzoekende kracht <strong>F<sub>mpz</sub></strong> wijst naar het centrum. Zonder die kracht zou het voorwerp rechtdoor vliegen.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Middelpuntzoekende kracht en versnelling</div><div class=\"sam-formula-eq\">F<sub>mpz</sub> = m · v² / r  ·  a<sub>mpz</sub> = v² / r</div><div class=\"sam-formula-note\">v de baansnelheid (m/s), r de straal (m). De kracht wordt geleverd door bijv. zwaartekracht, spankracht of wrijving — F<sub>mpz</sub> is geen 'nieuwe' kracht maar de resultante ervan.</div></div><div class=\"sam-tip\">Snelheid bij een omloop: v = 2πr / T, met T de omlooptijd (s).</div><div class=\"sam-head\">Arbeid, energie en vermogen</div><p>Een kracht verricht <strong>arbeid</strong> als hij een voorwerp verplaatst. Arbeid verandert de energie van het voorwerp.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Arbeid en vermogen</div><div class=\"sam-formula-eq\">W = F · s · cos α  ·  P = W / t = F · v</div><div class=\"sam-formula-note\">W de arbeid (J), α de hoek tussen kracht en verplaatsing, P het vermogen (W). Staat de kracht loodrecht op de beweging (zoals F<sub>mpz</sub>), dan is cos 90° = 0 en verricht hij geen arbeid.</div></div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Kinetische energie</div><ul><li>E<sub>k</sub> = ½·m·v²</li><li>energie van de beweging</li><li>verviervoudigt bij dubbele v</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Zwaarte-energie</div><ul><li>E<sub>z</sub> = m·g·h</li><li>energie door de hoogte</li><li>g ≈ 9,81 m/s² (BiNaS)</li></ul></div></div><div class=\"sam-head\">Behoud van energie en impuls</div><p>In een systeem zonder wrijving blijft de <strong>totale mechanische energie</strong> behouden. Bij botsingen is bovendien altijd de <strong>impuls</strong> behouden.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Impuls en behoudswet</div><div class=\"sam-formula-eq\">p = m · v  ·  Σp<sub>vóór</sub> = Σp<sub>ná</sub></div><div class=\"sam-formula-note\">p de impuls (kg·m/s), een vectorgrootheid. Bij een <strong>elastische</strong> botsing blijft óók E<sub>k</sub> behouden; bij een <strong>inelastische</strong> botsing gaat E<sub>k</sub> deels over in warmte/vervorming.</div></div><div class=\"sam-head\">Gravitatie</div><p>Twee massa's trekken elkaar aan met de <strong>gravitatiekracht</strong>. Voor een satelliet levert die kracht precies de middelpuntzoekende kracht van de baan.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Gravitatiewet van Newton</div><div class=\"sam-formula-eq\">F<sub>g</sub> = G · m₁ · m₂ / r²</div><div class=\"sam-formula-note\">G = 6,67·10⁻¹¹ N·m²/kg² (BiNaS), r de afstand tussen de middelpunten (m). De kracht neemt kwadratisch af met de afstand.</div></div><div class=\"sam-warn\"><strong>Veelgemaakte fout:</strong> de middelpuntzoekende kracht is géén extra kracht in je krachtenschema. Teken de echte krachten (zwaartekracht, normaalkracht, spankracht…) en stel hun resultante naar het middelpunt gelijk aan m·v²/r.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een bal van 0,20 kg draait rond aan een touw met straal 0,50 m en snelheid 4,0 m/s. Bereken de middelpuntzoekende kracht.</div><ol class=\"sam-worked-steps\"><li>Gebruik F<sub>mpz</sub> = m·v²/r.</li><li>F<sub>mpz</sub> = 0,20 × (4,0)² / 0,50 = 0,20 × 16 / 0,50.</li><li>F<sub>mpz</sub> = 3,2 / 0,50 = 6,4 N.</li></ol><div class=\"sam-worked-ans\">✅ F<sub>mpz</sub> = 6,4 N — deze kracht levert het touw als spankracht.</div></div></div>","vwo_na_D":"<div class=\"sam-intro\">Een <strong>stroomkring</strong> beschrijf je met de wet van Ohm en de regels voor serie- en parallelschakelingen. Rondom een stroomdraad ontstaat een <strong>magnetisch veld</strong>, en een <strong>veranderend</strong> veld wekt weer spanning op (inductie) — de basis van generators en transformatoren.</div><div class=\"sam-head\">Wet van Ohm en vermogen</div><p>De stroomsterkte door een weerstand is recht evenredig met de spanning erover. Het <strong>vermogen</strong> is de energie die per seconde wordt omgezet.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Ohm en elektrisch vermogen</div><div class=\"sam-formula-eq\">U = I · R  ·  P = U · I = I² · R</div><div class=\"sam-formula-note\">U de spanning (V), I de stroomsterkte (A), R de weerstand (Ω), P het vermogen (W). Energie: E = P·t (J).</div></div><div class=\"sam-head\">Serie- en parallelschakeling</div><table class=\"sam-table\"><thead><tr><th></th><th>Serie</th><th>Parallel</th></tr></thead><tbody><tr><td>Stroom</td><td>overal gelijk</td><td>verdeelt zich</td></tr><tr><td>Spanning</td><td>verdeelt zich</td><td>overal gelijk</td></tr><tr><td>Vervangings-R</td><td>R = R₁ + R₂</td><td>1/R = 1/R₁ + 1/R₂</td></tr></tbody></table><div class=\"sam-tip\">Een parallelschakeling heeft altijd een <strong>kleinere</strong> vervangingsweerstand dan de kleinste deelweerstand.</div><div class=\"sam-head\">Condensator en RC-kring</div><p>Een <strong>condensator</strong> slaat lading op. De opgeslagen lading is evenredig met de spanning.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Lading op een condensator</div><div class=\"sam-formula-eq\">Q = C · U</div><div class=\"sam-formula-note\">Q de lading (C), C de capaciteit (F), U de spanning (V). In een <strong>RC-kring</strong> laadt/ontlaadt de condensator via een weerstand met een karakteristieke tijd τ = R·C.</div></div><div class=\"sam-head\">Magnetisch veld van een stroomdraad</div><p>Om een rechte stroomdraad lopen de veldlijnen als <strong>concentrische cirkels</strong>. De richting volgt uit de <strong>rechterhandregel</strong>: duim in de stroomrichting, vingers wijzen met het veld mee.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Magnetisch veld als concentrische cirkels rond een stroomdraad die uit het vlak komt\"><defs><marker id=\"naDb\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><circle cx=\"150\" cy=\"100\" r=\"26\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><circle cx=\"150\" cy=\"100\" r=\"46\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><circle cx=\"150\" cy=\"100\" r=\"66\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"1.8\"/><path d=\"M176,100 a26,26 0 0,1 -0.5,0\" stroke=\"var(--or)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#naDb)\"/><path d=\"M196,100 a46,46 0 0,1 -0.5,0\" stroke=\"var(--or)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#naDb)\"/><path d=\"M216,100 a66,66 0 0,1 -0.5,0\" stroke=\"var(--or)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#naDb)\"/><circle cx=\"150\" cy=\"100\" r=\"8\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"1.8\"/><circle cx=\"150\" cy=\"100\" r=\"2.5\" fill=\"var(--dk)\"/><text x=\"150\" y=\"88\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">I</text><text x=\"224\" y=\"104\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">B</text></svg><div class=\"sam-figcap\"><strong>Veld om een draad:</strong> de stroom I komt uit het vlak (⊙), het magnetisch veld B loopt in cirkels eromheen. Dichter bij de draad is het veld sterker.</div></div><div class=\"sam-head\">Inductie (Faraday)</div><p>Een <strong>veranderende</strong> magnetische flux door een spoel wekt een spanning op. Dat is het begin van domein E: generators, transformatoren en wisselstroom.</p><div class=\"sam-warn\"><strong>Let op het verschil:</strong> een <em>constante</em> stroom geeft een <em>constant</em> magnetisch veld, maar induceert géén spanning. Alleen een <strong>verandering</strong> van de flux (sterkte, oppervlak of hoek) wekt een inductiespanning op.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Twee weerstanden van 30 Ω en 60 Ω staan parallel op een bron van 12 V. Bereken de vervangingsweerstand en de totale stroom.</div><ol class=\"sam-worked-steps\"><li>1/R = 1/30 + 1/60 = 2/60 + 1/60 = 3/60, dus R = 20 Ω.</li><li>I = U/R = 12 / 20 = 0,60 A.</li></ol><div class=\"sam-worked-ans\">✅ R = 20 Ω en I<sub>totaal</sub> = 0,60 A.</div></div></div><div class=\"sam-intro\">Elektromagnetisme verbindt elektriciteit en magnetisme. Een lading in een magnetisch veld voelt de <strong>Lorentzkracht</strong>, een <strong>veranderende flux</strong> wekt spanning op (<strong>Faraday</strong>), en dat principe zit achter <strong>generators</strong>, <strong>transformatoren</strong> en <strong>wisselstroom</strong>.</div><div class=\"sam-head\">Elektrisch veld en potentiaal</div><p>Rondom een lading heerst een <strong>elektrisch veld</strong> E. Tussen twee platen (condensator) is dat veld homogeen.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Elektrisch veld tussen platen</div><div class=\"sam-formula-eq\">E = U / d  ·  F = q · E</div><div class=\"sam-formula-note\">E de veldsterkte (V/m of N/C), U de spanning (V), d de plaatafstand (m), q de lading (C). Een lading in het veld voelt kracht F = q·E.</div></div><div class=\"sam-head\">Lorentzkracht</div><p>Een lading die dwars door een magnetisch veld beweegt, voelt een kracht loodrecht op zowel de snelheid als het veld: de <strong>Lorentzkracht</strong>. De richting volgt uit de rechterhandregel (voor positieve lading).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Lorentzkracht op een positieve lading die door een magnetisch veld het vlak in beweegt\"><g stroke=\"var(--mu)\" stroke-width=\"1.2\" fill=\"none\"><circle cx=\"90\" cy=\"55\" r=\"6\"/><circle cx=\"150\" cy=\"55\" r=\"6\"/><circle cx=\"210\" cy=\"55\" r=\"6\"/><circle cx=\"90\" cy=\"150\" r=\"6\"/><circle cx=\"210\" cy=\"150\" r=\"6\"/></g><g stroke=\"var(--mu)\" stroke-width=\"1.2\"><path d=\"M85.8,50.8 L94.2,59.2 M94.2,50.8 L85.8,59.2\"/><path d=\"M145.8,50.8 L154.2,59.2 M154.2,50.8 L145.8,59.2\"/><path d=\"M205.8,50.8 L214.2,59.2 M214.2,50.8 L205.8,59.2\"/><path d=\"M85.8,145.8 L94.2,154.2 M94.2,145.8 L85.8,154.2\"/><path d=\"M205.8,145.8 L214.2,154.2 M214.2,145.8 L205.8,154.2\"/></g><text x=\"230\" y=\"45\" font-size=\"9\" fill=\"var(--mu)\">B (vlak in)</text><defs><marker id=\"naEv\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker><marker id=\"naEf\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--dk)\"/></marker></defs><circle cx=\"150\" cy=\"115\" r=\"9\" fill=\"var(--or)\"/><text x=\"150\" y=\"119\" font-size=\"11\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">+</text><line x1=\"159\" y1=\"115\" x2=\"225\" y2=\"115\" stroke=\"var(--or)\" stroke-width=\"2.4\" marker-end=\"url(#naEv)\"/><text x=\"205\" y=\"132\" font-size=\"11\" font-weight=\"700\" fill=\"var(--or)\">v</text><line x1=\"150\" y1=\"106\" x2=\"150\" y2=\"55\" stroke=\"var(--dk)\" stroke-width=\"2.4\" marker-end=\"url(#naEf)\"/><text x=\"156\" y=\"70\" font-size=\"11\" font-weight=\"700\" fill=\"var(--dk)\">F</text></svg><div class=\"sam-figcap\"><strong>Lorentzkracht:</strong> de lading + beweegt met snelheid v naar rechts, het veld B wijst het vlak in (⊗). De kracht F staat loodrecht op beide.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Lorentzkracht</div><div class=\"sam-formula-eq\">F = B · q · v  ·  (op een draad: F = B · I · ℓ)</div><div class=\"sam-formula-note\">B de magnetische veldsterkte (T), q de lading (C), v de snelheid (m/s), I de stroom (A), ℓ de draadlengte (m). Geldt maximaal als v (of I) loodrecht op B staat.</div></div><div class=\"sam-head\">Elektromagnetische inductie</div><p>Verandert de <strong>magnetische flux</strong> Φ door een spoel, dan ontstaat een inductiespanning. Dit is de <strong>wet van Faraday</strong>.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Inductiespanning (Faraday)</div><div class=\"sam-formula-eq\">U<sub>ind</sub> = −N · (ΔΦ / Δt)</div><div class=\"sam-formula-note\">N het aantal windingen, Φ de flux (Wb), Δt de tijd (s). Het minteken (wet van Lenz) geeft aan dat de inductiestroom de verandering tegenwerkt.</div></div><div class=\"sam-head\">Transformator en wisselstroom</div><p>Een <strong>transformator</strong> zet met twee spoelen om een gezamenlijke kern een wisselspanning om. De spanningen verhouden zich als de windingsaantallen.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Transformatorvergelijking</div><div class=\"sam-formula-eq\">U<sub>p</sub> / U<sub>s</sub> = N<sub>p</sub> / N<sub>s</sub></div><div class=\"sam-formula-note\">p = primair, s = secundair. Bij een ideale transformator geldt bovendien U<sub>p</sub>·I<sub>p</sub> = U<sub>s</sub>·I<sub>s</sub> (behoud van vermogen).</div></div><div class=\"sam-tip\">Hoogspanning transporteert energie met weinig verlies: bij hogere U hoort bij gelijk vermogen een lagere I, en de verliezen P = I²R dalen kwadratisch.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Een elektron (q = 1,6·10⁻¹⁹ C) beweegt met 2,0·10⁶ m/s loodrecht door een veld van 0,50 T. Bereken de Lorentzkracht.</div><ol class=\"sam-worked-steps\"><li>Gebruik F = B·q·v.</li><li>F = 0,50 × 1,6·10⁻¹⁹ × 2,0·10⁶.</li><li>F = 1,6·10⁻¹³ N.</li></ol><div class=\"sam-worked-ans\">✅ F = 1,6·10⁻¹³ N — klein, maar op de lichte elektronmassa geeft dat een enorme versnelling.</div></div></div>","vwo_na_F":"<div class=\"sam-intro\">De moderne fysica breekt met de klassieke natuurkunde. Licht gedraagt zich als <strong>deeltje</strong> (foton) én als golf, materie heeft een <strong>golflengte</strong> (de Broglie), atomen zenden licht uit in <strong>discrete lijnen</strong> (Bohr), en bij hoge snelheden gaat de <strong>relativiteitstheorie</strong> gelden.</div><div class=\"sam-head\">Foto-elektrisch effect</div><p>Licht kan elektronen uit een metaal losmaken, maar alleen als de <strong>frequentie</strong> hoog genoeg is — niet als de intensiteit hoog is. Einstein verklaarde dit met <strong>fotonen</strong>: lichtpakketjes met energie E = h·f.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Fotonenergie en foto-elektrisch effect</div><div class=\"sam-formula-eq\">E<sub>foton</sub> = h · f  ·  E<sub>k,max</sub> = h · f − W</div><div class=\"sam-formula-note\">h = 6,63·10⁻³⁴ J·s (constante van Planck), f de frequentie (Hz), W de uittree-energie van het metaal (J). Onder de grensfrequentie komt er geen enkel elektron vrij.</div></div><div class=\"sam-head\">Golf-deeltje-dualisme</div><p>Niet alleen licht, ook <strong>materie</strong> heeft een golfkarakter. De Broglie kende elk deeltje een golflengte toe die afhangt van zijn impuls.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">De Broglie-golflengte</div><div class=\"sam-formula-eq\">λ = h / p = h / (m · v)</div><div class=\"sam-formula-note\">λ de golflengte (m), p de impuls (kg·m/s). Voor grote voorwerpen is λ verwaarloosbaar klein; voor elektronen is hij meetbaar (elektronenmicroscoop).</div></div><div class=\"sam-head\">Spectraallijnen: het Bohr-model</div><p>Elektronen in een atoom mogen alleen bepaalde <strong>energieniveaus</strong> bezetten. Springt een elektron terug naar een lager niveau, dan zendt het een foton uit met precies het energieverschil — vandaar de scherpe <strong>spectraallijnen</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 200\" role=\"img\" aria-label=\"Energieniveaudiagram van waterstof met sprongen die fotonen uitzenden\"><g stroke=\"var(--dk)\" stroke-width=\"2\"><line x1=\"70\" y1=\"165\" x2=\"230\" y2=\"165\"/><line x1=\"70\" y1=\"110\" x2=\"230\" y2=\"110\"/><line x1=\"70\" y1=\"78\" x2=\"230\" y2=\"78\"/><line x1=\"70\" y1=\"60\" x2=\"230\" y2=\"60\"/></g><g font-size=\"9\" fill=\"var(--mu)\"><text x=\"236\" y=\"168\">n=1</text><text x=\"236\" y=\"113\">n=2</text><text x=\"236\" y=\"81\">n=3</text><text x=\"236\" y=\"63\">n=4</text><text x=\"24\" y=\"168\">−13,6</text><text x=\"30\" y=\"113\">−3,4</text><text x=\"30\" y=\"81\">−1,5</text><text x=\"30\" y=\"63\">−0,85</text><text x=\"14\" y=\"40\">E (eV)</text></g><defs><marker id=\"naFp\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--or)\"/></marker></defs><line x1=\"120\" y1=\"78\" x2=\"120\" y2=\"108\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naFp)\"/><line x1=\"170\" y1=\"60\" x2=\"170\" y2=\"108\" stroke=\"var(--or)\" stroke-width=\"2.2\" marker-end=\"url(#naFp)\"/><text x=\"126\" y=\"96\" font-size=\"8.5\" fill=\"var(--or)\">foton</text></svg><div class=\"sam-figcap\"><strong>Energieniveaus (waterstof):</strong> een elektron dat van n=3 of n=4 terugvalt naar n=2 zendt een foton uit. Het energieverschil bepaalt de kleur (frequentie) van de lijn.</div></div><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Energie van de uitgezonden lijn</div><div class=\"sam-formula-eq\">E<sub>foton</sub> = E<sub>hoog</sub> − E<sub>laag</sub> = h · f</div><div class=\"sam-formula-note\">Het foton krijgt precies het verschil tussen de twee energieniveaus. Daarom is elk element te herkennen aan zijn eigen lijnenspectrum.</div></div><div class=\"sam-head\">Radioactiviteit en relativiteit</div><p>Instabiele kernen vervallen onder uitzending van <strong>α-, β- of γ-straling</strong>. Bij <strong>kernsplitsing</strong> en -fusie komt energie vrij volgens E = mc². Bij snelheden dicht bij de lichtsnelheid treedt <strong>tijddilatatie</strong> op: bewegende klokken lopen langzamer.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Massa-energie-equivalentie</div><div class=\"sam-formula-eq\">E = m · c²</div><div class=\"sam-formula-note\">c = 3,00·10⁸ m/s. Een klein massaverlies (bij splitsing/fusie) levert een enorme energie op — de bron van kerncentrales en de zon.</div></div><div class=\"sam-warn\"><strong>Denkfout:</strong> bij het foto-elektrisch effect maakt méér licht (hogere intensiteit) niet dat er elektronen vrijkomen als de frequentie te laag is. Eén foton moet in zijn eentje genoeg energie hebben (h·f ≥ W).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bereken de energie van een foton met frequentie 5,0·10¹⁴ Hz (h = 6,63·10⁻³⁴ J·s).</div><ol class=\"sam-worked-steps\"><li>E = h·f = 6,63·10⁻³⁴ × 5,0·10¹⁴.</li><li>E = 3,3·10⁻¹⁹ J.</li><li>Omgerekend: 3,3·10⁻¹⁹ / 1,6·10⁻¹⁹ ≈ 2,1 eV.</li></ol><div class=\"sam-worked-ans\">✅ E ≈ 3,3·10⁻¹⁹ J ≈ 2,1 eV — typisch voor zichtbaar licht.</div></div></div>","vwo_ec_D":"<div class=\"sam-intro\">De <strong>micro-economie</strong> kijkt naar afzonderlijke markten: hoe <strong>vraag en aanbod</strong> samen de prijs bepalen, hoe gevoelig die is (<strong>elasticiteit</strong>), en hoe <strong>marktvormen</strong> en <strong>marktfalen</strong> de uitkomst beïnvloeden.</div><div class=\"sam-head\">Vraag, aanbod en evenwicht</div><p>De <strong>vraaglijn</strong> daalt (hogere prijs → minder vraag), de <strong>aanbodlijn</strong> stijgt. Waar ze elkaar snijden ligt het <strong>marktevenwicht</strong>: de evenwichtsprijs en -hoeveelheid.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 190\" role=\"img\" aria-label=\"Vraag- en aanbodlijnen die elkaar snijden in het marktevenwicht\"><defs><marker id=\"ecAa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"50\" y1=\"160\" x2=\"285\" y2=\"160\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecAa)\"/><line x1=\"50\" y1=\"170\" x2=\"50\" y2=\"25\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecAa)\"/><line x1=\"60\" y1=\"40\" x2=\"260\" y2=\"150\" stroke=\"var(--or)\" stroke-width=\"2.4\"/><line x1=\"60\" y1=\"150\" x2=\"260\" y2=\"40\" stroke=\"var(--dk)\" stroke-width=\"2.4\"/><line x1=\"50\" y1=\"95\" x2=\"160\" y2=\"95\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><line x1=\"160\" y1=\"95\" x2=\"160\" y2=\"160\" stroke=\"var(--mu)\" stroke-width=\"1\" stroke-dasharray=\"3 2\"/><circle cx=\"160\" cy=\"95\" r=\"4\" fill=\"var(--mu)\"/><text x=\"264\" y=\"150\" font-size=\"10\" font-weight=\"700\" fill=\"var(--or)\">vraag</text><text x=\"230\" y=\"38\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\">aanbod</text><text x=\"30\" y=\"99\" font-size=\"9\" fill=\"var(--mu)\">Pₑ</text><text x=\"156\" y=\"174\" font-size=\"9\" fill=\"var(--mu)\">Qₑ</text><text x=\"276\" y=\"174\" font-size=\"9\" fill=\"var(--mu)\">Q</text><text x=\"34\" y=\"34\" font-size=\"9\" fill=\"var(--mu)\">P</text></svg><div class=\"sam-figcap\"><strong>Marktevenwicht:</strong> in het snijpunt zijn de gevraagde en aangeboden hoeveelheid gelijk. Een prijs boven Pₑ geeft een overschot, eronder een tekort.</div></div><div class=\"sam-head\">Prijselasticiteit</div><p>De <strong>prijselasticiteit</strong> meet hoe sterk de gevraagde hoeveelheid reageert op een prijsverandering.</p><div class=\"sam-formula-box\"><div class=\"sam-formula-label\">Prijselasticiteit van de vraag</div><div class=\"sam-formula-eq\">E<sub>v</sub> = %ΔQ / %ΔP</div><div class=\"sam-formula-note\">|E<sub>v</sub>| &gt; 1: elastisch (gevoelig, vaak luxegoederen). |E<sub>v</sub>| &lt; 1: inelastisch (ongevoelig, vaak eerste levensbehoeften).</div></div><div class=\"sam-head\">Marktvormen</div><table class=\"sam-table\"><thead><tr><th>Marktvorm</th><th>Aanbieders</th><th>Prijsmacht</th></tr></thead><tbody><tr><td>Volledige mededinging</td><td>zeer veel</td><td>geen (prijsnemer)</td></tr><tr><td>Oligopolie</td><td>enkele</td><td>strategisch afhankelijk</td></tr><tr><td>Monopolie</td><td>één</td><td>groot (prijszetter)</td></tr></tbody></table><div class=\"sam-head\">Marktfalen</div><p>Soms leidt de markt niet tot een efficiënte uitkomst: <strong>marktfalen</strong>. Oorzaken zijn <strong>externe effecten</strong> (bijv. milieuschade), <strong>collectieve goederen</strong> en <strong>informatie-asymmetrie</strong>. De overheid kan dan ingrijpen (belasting, subsidie, regels).</p><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Bij een prijsstijging van 10% daalt de gevraagde hoeveelheid met 25%. Bereken de prijselasticiteit en beoordeel.</div><ol class=\"sam-worked-steps\"><li>E<sub>v</sub> = %ΔQ / %ΔP = −25% / +10%.</li><li>E<sub>v</sub> = −2,5.</li><li>|−2,5| &gt; 1.</li></ol><div class=\"sam-worked-ans\">✅ E<sub>v</sub> = −2,5: de vraag is elastisch (sterk prijsgevoelig).</div></div></div>","vwo_ec_I":"<div class=\"sam-intro\">De <strong>macro-economie</strong> bekijkt de economie als geheel: de <strong>conjunctuur</strong> (op- en neergang), <strong>werkloosheid</strong> en <strong>inflatie</strong>, en hoe de <strong>overheid</strong> en de <strong>centrale bank</strong> daarop sturen.</div><div class=\"sam-head\">Conjunctuur</div><p>De economie beweegt in golven rond een stijgende <strong>trend</strong> (structurele groei). Boven de trend is er <strong>hoogconjunctuur</strong>, eronder <strong>laagconjunctuur</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Conjunctuurgolf die op en neer beweegt rond een stijgende trendlijn\"><defs><marker id=\"ecBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"40\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecBa)\"/><line x1=\"40\" y1=\"158\" x2=\"40\" y2=\"20\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#ecBa)\"/><line x1=\"40\" y1=\"120\" x2=\"320\" y2=\"70\" stroke=\"var(--dk)\" stroke-width=\"1.6\" stroke-dasharray=\"6 4\"/><path d=\"M40.0,120.0 L64.9,130.2 L92.9,126.6 L120.9,106.0 L145.8,86.6 L170.7,79.4 L195.6,86.7 L223.6,99.6 L248.4,100.2 L273.3,85.8 L301.3,62.4 L320.0,52.1\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><text x=\"250\" y=\"66\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\">trend</text><text x=\"150\" y=\"78\" font-size=\"8.5\" fill=\"var(--or)\">hoogconjunctuur</text><text x=\"70\" y=\"145\" font-size=\"8.5\" fill=\"var(--mu)\">laagconjunctuur</text><text x=\"322\" y=\"164\" font-size=\"9\" fill=\"var(--mu)\">t</text></svg><div class=\"sam-figcap\"><strong>Conjunctuurgolf:</strong> de werkelijke productie (oranje) schommelt rond de trendmatige groei (gestippeld). Pieken = hoogconjunctuur, dalen = recessie.</div></div><div class=\"sam-head\">Werkloosheid en inflatie</div><p><strong>Inflatie</strong> is een aanhoudende stijging van het algemene prijspeil. De <strong>Phillipscurve</strong> suggereert een verband: bij lage werkloosheid stijgen de lonen en daarmee vaak de inflatie.</p><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Conjuncturele werkloosheid</td><td>door laagconjunctuur (te weinig vraag)</td></tr><tr><td>Structurele werkloosheid</td><td>door mismatch of technologie</td></tr><tr><td>Inflatie</td><td>stijging algemeen prijspeil (CPI)</td></tr></tbody></table><div class=\"sam-head\">Overheids- en monetair beleid</div><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Begrotingsbeleid (overheid)</div><ul><li>uitgaven en belastingen</li><li>stimuleren in een recessie</li><li>afremmen bij oververhitting</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Monetair beleid (ECB)</div><ul><li>sturen van de rente</li><li>lage rente = meer lenen/bestedingen</li><li>doel: prijsstabiliteit (~2%)</li></ul></div></div><div class=\"sam-head\">Internationaal en groei</div><p>De <strong>betalingsbalans</strong> registreert transacties met het buitenland; <strong>wisselkoersen</strong> bepalen de prijs van im- en export. Structurele <strong>economische groei</strong> meet je aan het reële <strong>bbp</strong>.</p><div class=\"sam-tip\">Reëel bbp corrigeert het nominale bbp voor inflatie, zodat je échte groei (meer goederen en diensten) meet, niet alleen prijsstijging.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Het nominale bbp groeit met 5%, de inflatie is 2%. Hoe groot is de reële groei bij benadering?</div><ol class=\"sam-worked-steps\"><li>Reële groei ≈ nominale groei − inflatie.</li><li>≈ 5% − 2%.</li><li>≈ 3%.</li></ol><div class=\"sam-worked-ans\">✅ De reële economische groei is ongeveer 3%.</div></div></div>","vwo_ak_B":"<div class=\"sam-intro\">Domein B gaat over de <strong>verweven wereld</strong>: <strong>globalisering</strong>, <strong>migratie</strong>, <strong>ongelijkheid</strong> tussen arm en rijk, en de <strong>demografische transitie</strong> die landen doorlopen naarmate ze zich ontwikkelen.</div><div class=\"sam-head\">Globalisering</div><p><strong>Globalisering</strong> is de toenemende wereldwijde verwevenheid — economisch, cultureel en politiek. Goederen, geld, mensen en informatie stromen steeds sneller over de wereld via lange <strong>handelsketens</strong>.</p><div class=\"sam-head\">Demografische transitie</div><p>Naarmate een land zich ontwikkelt, dalen eerst het <strong>sterftecijfer</strong> (betere zorg, voeding) en later het <strong>geboortecijfer</strong>. Het verschil ertussen bepaalt de bevolkingsgroei.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 340 172\" role=\"img\" aria-label=\"Demografisch transitiemodel met dalend sterftecijfer en later dalend geboortecijfer\"><defs><marker id=\"akBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><line x1=\"44\" y1=\"150\" x2=\"332\" y2=\"150\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#akBa)\"/><line x1=\"44\" y1=\"158\" x2=\"44\" y2=\"28\" stroke=\"var(--mu)\" stroke-width=\"1.5\" marker-end=\"url(#akBa)\"/><path d=\"M44,45 L140.6,45 L182,70 L246.4,108.9 L264.8,120 L320,120\" fill=\"none\" stroke=\"var(--or)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><path d=\"M44,48 L76.2,48 L122.2,79.8 L182,122 L320,122\" fill=\"none\" stroke=\"var(--dk)\" stroke-width=\"2.4\" stroke-linecap=\"round\"/><text x=\"150\" y=\"40\" font-size=\"9\" font-weight=\"700\" fill=\"var(--or)\">geboortecijfer</text><text x=\"60\" y=\"66\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\">sterftecijfer</text><g font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"90\" y=\"164\">fase 1</text><text x=\"150\" y=\"164\">2</text><text x=\"215\" y=\"164\">3</text><text x=\"290\" y=\"164\">4</text></g></svg><div class=\"sam-figcap\"><strong>Demografisch transitiemodel:</strong> in fase 2 daalt het sterftecijfer sterk (snelle groei); pas in fase 3 daalt ook het geboortecijfer. De kloof ertussen is de bevolkingsgroei.</div></div><div class=\"sam-head\">Migratie</div><p>Mensen migreren door <strong>pushfactoren</strong> (wat hen wegdrijft) en <strong>pullfactoren</strong> (wat hen aantrekt).</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Pushfactoren</div><ul><li>armoede, werkloosheid</li><li>oorlog en onveiligheid</li><li>klimaat/natuurrampen</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Pullfactoren</div><ul><li>werk en hoger loon</li><li>veiligheid en vrijheid</li><li>onderwijs, familie</li></ul></div></div><div class=\"sam-head\">Ontwikkeling en ongelijkheid</div><p>Verschillen in ontwikkeling meet je met de <strong>HDI</strong> (welvaart, levensverwachting én onderwijs). Landen in de <strong>periferie</strong> exporteren vaak goedkope grondstoffen en zijn economisch afhankelijk van het rijkere <strong>centrum</strong>.</p><div class=\"sam-tip\"><strong>Geopolitiek:</strong> de controle over grondstoffen, handelsroutes en invloedssferen leidt tot samenwerking én conflicten tussen landen.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">In fase 2 van de demografische transitie groeit de bevolking het snelst. Verklaar waarom.</div><ol class=\"sam-worked-steps\"><li>Het sterftecijfer daalt sterk door betere zorg en voeding.</li><li>Het geboortecijfer blijft in fase 2 nog hoog.</li><li>Het grote verschil tussen beide geeft een snelle natuurlijke aanwas.</li></ol><div class=\"sam-worked-ans\">✅ Hoge geboorten en sterk gedaalde sterfte samen geven de snelste groei.</div></div></div>","vwo_ak_C":"<div class=\"sam-intro\">Domein A gaat over het <strong>natuurlijke systeem Aarde</strong>: het <strong>klimaat</strong> en het <strong>broeikaseffect</strong>, de <strong>platentektoniek</strong>, de grote <strong>kringlopen</strong> en de menselijke invloed via <strong>klimaatverandering</strong>.</div><div class=\"sam-head\">Het broeikaseffect</div><p>De zon stuurt kortgolvige straling naar de aarde. Het aardoppervlak warmt op en zendt <strong>langgolvige</strong> (warmte)straling terug. <strong>Broeikasgassen</strong> (CO₂, CH₄, waterdamp) houden een deel daarvan vast — zonder dat effect zou de aarde ijskoud zijn; teveel ervan geeft <strong>opwarming</strong>.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 180\" role=\"img\" aria-label=\"Het broeikaseffect: inkomende zonnestraling en langgolvige straling die deels wordt vastgehouden door de atmosfeer\"><rect x=\"20\" y=\"150\" width=\"260\" height=\"20\" fill=\"var(--mu)\" opacity=\".18\"/><line x1=\"20\" y1=\"70\" x2=\"280\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"1.3\" stroke-dasharray=\"5 4\"/><text x=\"212\" y=\"64\" font-size=\"8.5\" fill=\"var(--mu)\">atmosfeer (broeikasgassen)</text><circle cx=\"45\" cy=\"30\" r=\"15\" fill=\"var(--or)\"/><text x=\"45\" y=\"34\" font-size=\"8\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">zon</text><defs><marker id=\"akAs\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--or)\"/></marker><marker id=\"akAw\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--dk)\"/></marker></defs><line x1=\"60\" y1=\"45\" x2=\"120\" y2=\"148\" stroke=\"var(--or)\" stroke-width=\"2\" marker-end=\"url(#akAs)\"/><line x1=\"80\" y1=\"42\" x2=\"150\" y2=\"148\" stroke=\"var(--or)\" stroke-width=\"2\" marker-end=\"url(#akAs)\"/><text x=\"58\" y=\"110\" font-size=\"8\" fill=\"var(--or)\">kortgolvig</text><line x1=\"180\" y1=\"148\" x2=\"205\" y2=\"74\" stroke=\"var(--dk)\" stroke-width=\"2\" marker-end=\"url(#akAw)\"/><line x1=\"210\" y1=\"72\" x2=\"235\" y2=\"148\" stroke=\"var(--dk)\" stroke-width=\"2\" marker-end=\"url(#akAw)\"/><text x=\"214\" y=\"120\" font-size=\"8\" fill=\"var(--dk)\">teruggekaatst</text><line x1=\"245\" y1=\"148\" x2=\"270\" y2=\"60\" stroke=\"var(--dk)\" stroke-width=\"2\" opacity=\".5\" marker-end=\"url(#akAw)\"/><text x=\"30\" y=\"166\" font-size=\"8\" fill=\"var(--mu)\">aardoppervlak</text></svg><div class=\"sam-figcap\"><strong>Broeikaseffect:</strong> kortgolvige zonnestraling warmt het oppervlak op; de langgolvige warmtestraling wordt deels door broeikasgassen teruggekaatst naar de aarde.</div></div><div class=\"sam-head\">Platentektoniek</div><p>De aardkorst bestaat uit <strong>platen</strong> die bewegen op de vloeibare mantel. Aan plaatgrenzen ontstaan <strong>vulkanen</strong>, <strong>aardbevingen</strong> en gebergten.</p><table class=\"sam-table\"><thead><tr><th>Plaatgrens</th><th>Beweging</th><th>Gevolg</th></tr></thead><tbody><tr><td>Divergent</td><td>platen uit elkaar</td><td>oceaanrug, nieuwe korst</td></tr><tr><td>Convergent</td><td>platen naar elkaar</td><td>gebergte, subductie, vulkanen</td></tr><tr><td>Transform</td><td>platen langs elkaar</td><td>aardbevingen (breuk)</td></tr></tbody></table><div class=\"sam-head\">Kringlopen</div><p>Stoffen circuleren in gesloten <strong>kringlopen</strong>. In de <strong>koolstofkringloop</strong> wordt CO₂ opgenomen door planten (fotosynthese) en vrijgemaakt door ademhaling en verbranding van fossiele brandstoffen — die extra uitstoot verstoort het evenwicht.</p><div class=\"sam-warn\"><strong>Klimaatverandering:</strong> het verbranden van fossiele brandstoffen verhoogt de CO₂-concentratie, versterkt het broeikaseffect en leidt tot opwarming, zeespiegelstijging en extremer weer. <strong>Adaptatie</strong> (aanpassen) en <strong>mitigatie</strong> (uitstoot beperken, duurzame energie) zijn de antwoorden.</p><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Leg uit waarom ontbossing het broeikaseffect versterkt (noem twee stappen).</div><ol class=\"sam-worked-steps\"><li>Bomen nemen via fotosynthese CO₂ op; minder bomen betekent minder opname.</li><li>Bij verbranding/rotting van het hout komt de opgeslagen CO₂ juist vrij.</li></ol><div class=\"sam-worked-ans\">✅ Minder opname én extra uitstoot verhogen de CO₂-concentratie, wat het broeikaseffect versterkt.</div></div></div>","vwo_gs_A":"<div class=\"sam-intro\">Domein A gaat niet over losse feiten, maar over <strong>historisch redeneren</strong>: gebeurtenissen in hun <strong>context</strong> plaatsen, <strong>oorzaken en gevolgen</strong> onderscheiden, <strong>bronnen</strong> beoordelen en <strong>continuïteit en verandering</strong> herkennen.</div><div class=\"sam-head\">Oorzaak en gevolg</div><p>Historici onderscheiden <strong>oorzaken</strong> (waarom iets gebeurde) van <strong>gevolgen</strong> (wat eruit voortkwam), en <strong>directe</strong> aanleidingen van dieperliggende <strong>structurele</strong> oorzaken.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 130\" role=\"img\" aria-label=\"Schema van oorzaken die leiden tot een gebeurtenis en daaruit voortvloeiende gevolgen\"><defs><marker id=\"gsAa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"6\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"14\" y=\"45\" width=\"80\" height=\"42\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"54\" y=\"63\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Oorzaken</text><text x=\"54\" y=\"77\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">structureel + direct</text><rect x=\"120\" y=\"45\" width=\"80\" height=\"42\" rx=\"6\" fill=\"var(--or)\" opacity=\".15\" stroke=\"var(--or)\" stroke-width=\"1.4\"/><text x=\"160\" y=\"63\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Gebeurtenis</text><text x=\"160\" y=\"77\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">in context</text><rect x=\"226\" y=\"45\" width=\"80\" height=\"42\" rx=\"6\" fill=\"var(--mu)\" opacity=\".12\" stroke=\"var(--mu)\" stroke-width=\"1.2\"/><text x=\"266\" y=\"63\" font-size=\"10\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Gevolgen</text><text x=\"266\" y=\"77\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">korte + lange termijn</text><line x1=\"96\" y1=\"66\" x2=\"118\" y2=\"66\" stroke=\"var(--mu)\" stroke-width=\"1.8\" marker-end=\"url(#gsAa)\"/><line x1=\"202\" y1=\"66\" x2=\"224\" y2=\"66\" stroke=\"var(--mu)\" stroke-width=\"1.8\" marker-end=\"url(#gsAa)\"/></svg><div class=\"sam-figcap\"><strong>Causaal redeneren:</strong> een gebeurtenis komt voort uit meerdere oorzaken (structureel én direct) en heeft gevolgen op korte en lange termijn. Alles staat in zijn historische context.</div></div><div class=\"sam-head\">Bronnen beoordelen</div><table class=\"sam-table\"><thead><tr><th>Bron</th><th>Wat</th><th>Let op</th></tr></thead><tbody><tr><td>Primair</td><td>uit de tijd zelf (brief, foto)</td><td>ooggetuige, maar gekleurd</td></tr><tr><td>Secundair</td><td>later geschreven (studie)</td><td>overzicht, maar interpretatie</td></tr></tbody></table><div class=\"sam-tip\">Beoordeel een bron altijd op <strong>representativiteit</strong> en <strong>betrouwbaarheid</strong>: wie maakte hem, wanneer, met welk doel en voor welk publiek?</div><div class=\"sam-head\">Continuïteit en verandering</div><p>Niet alles verandert tegelijk. <strong>Continuïteit</strong> (dingen die blijven) en <strong>verandering</strong> bestaan naast elkaar. Kernbegrippen om processen te duiden zijn <strong>revolutie</strong>, <strong>modernisering</strong> en <strong>emancipatie</strong>.</p><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom is een dagboek uit 1943 een primaire bron, en waarom moet je er toch kritisch mee omgaan?</div><ol class=\"sam-worked-steps\"><li>Het is uit de tijd zelf geschreven → primair, ooggetuige.</li><li>De schrijver ziet maar een deel en heeft een persoonlijk, gekleurd perspectief.</li></ol><div class=\"sam-worked-ans\">✅ Primair én waardevol, maar niet automatisch representatief of objectief.</div></div></div>","vwo_gs_B":"<div class=\"sam-intro\">De <strong>Moderne Tijd</strong> (1900–heden) is het belangrijkste examendomein: twee <strong>wereldoorlogen</strong>, de opkomst van <strong>totalitaire regimes</strong>, de <strong>Holocaust</strong>, <strong>dekolonisatie</strong>, de <strong>Koude Oorlog</strong> en de <strong>Europese integratie</strong>.</div><div class=\"sam-head\">De eeuw in één oogopslag</div><div class=\"sam-figure\"><svg viewBox=\"0 0 340 130\" role=\"img\" aria-label=\"Tijdbalk van 1900 tot 2000 met de belangrijkste gebeurtenissen van de twintigste eeuw\"><line x1=\"30\" y1=\"70\" x2=\"330\" y2=\"70\" stroke=\"var(--mu)\" stroke-width=\"2\"/><g font-size=\"8\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"30\" y=\"90\">1900</text><text x=\"115\" y=\"90\">1925</text><text x=\"200\" y=\"90\">1950</text><text x=\"285\" y=\"90\">1975</text><text x=\"325\" y=\"90\">2000</text></g><g stroke=\"var(--mu)\" stroke-width=\"1\"><line x1=\"30\" y1=\"65\" x2=\"30\" y2=\"75\"/><line x1=\"115\" y1=\"65\" x2=\"115\" y2=\"75\"/><line x1=\"200\" y1=\"65\" x2=\"200\" y2=\"75\"/><line x1=\"285\" y1=\"65\" x2=\"285\" y2=\"75\"/><line x1=\"325\" y1=\"65\" x2=\"325\" y2=\"75\"/></g><g fill=\"var(--or)\"><circle cx=\"78\" cy=\"70\" r=\"4\"/><circle cx=\"163\" cy=\"70\" r=\"4\"/><circle cx=\"197\" cy=\"70\" r=\"4\"/><circle cx=\"230\" cy=\"70\" r=\"4\"/></g><g font-size=\"7.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\"><text x=\"78\" y=\"52\">WO I</text><text x=\"78\" y=\"42\">1914</text><text x=\"163\" y=\"30\">WO II</text><text x=\"163\" y=\"20\">1939</text><text x=\"230\" y=\"52\">Koude</text><text x=\"230\" y=\"42\">Oorlog</text></g><g font-size=\"7\" fill=\"var(--mu)\" text-anchor=\"middle\"><text x=\"120\" y=\"110\">interbellum</text><text x=\"270\" y=\"110\">dekolonisatie / EU</text></g></svg><div class=\"sam-figcap\"><strong>Tijdbalk 20e eeuw:</strong> WO I (1914–18), het interbellum met de opkomst van dictaturen, WO II (1939–45), en daarna de Koude Oorlog, dekolonisatie en Europese eenwording.</div></div><div class=\"sam-head\">Wereldoorlogen en totalitarisme</div><p>Na WO I schoof het <strong>Verdrag van Versailles</strong> de schuld op Duitsland. De economische crisis (beurskrach 1929) voedde de opkomst van <strong>totalitaire</strong> regimes: fascisme (Italië), nazisme (Duitsland) en stalinisme (USSR). WO II leidde tot de <strong>Holocaust</strong>, de systematische massamoord op zes miljoen Joden.</p><table class=\"sam-table\"><thead><tr><th>Regime</th><th>Land</th><th>Kern</th></tr></thead><tbody><tr><td>Fascisme</td><td>Italië</td><td>nationalisme, leiderscultus</td></tr><tr><td>Nazisme</td><td>Duitsland</td><td>racisme, Lebensraum</td></tr><tr><td>Stalinisme</td><td>USSR</td><td>communisme, staatsterreur</td></tr></tbody></table><div class=\"sam-head\">Koude Oorlog en Europa</div><p>Na 1945 stonden de VS (kapitalisme) en de USSR (communisme) tegenover elkaar: de <strong>Koude Oorlog</strong> (1947–1991), met het <strong>IJzeren Gordijn</strong> en de Berlijnse Muur als symbolen. Tegelijk werden koloniën onafhankelijk (<strong>dekolonisatie</strong>) en groeide de <strong>Europese samenwerking</strong> uit tot de EU.</p><div class=\"sam-tip\">De Koude Oorlog bleef 'koud' door de <strong>afschrikking</strong> van kernwapens: een directe oorlog zou beide kanten vernietigen (MAD).</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Noem een structurele en een directe oorzaak van de opkomst van Hitler.</div><ol class=\"sam-worked-steps\"><li>Structureel: de vernedering en herstelbetalingen van het Verdrag van Versailles.</li><li>Direct: de economische crisis na de beurskrach van 1929 (massawerkloosheid).</li></ol><div class=\"sam-worked-ans\">✅ Structurele onvrede + acute crisis maakten de NSDAP aantrekkelijk.</div></div></div>","vwo_mw_B":"<div class=\"sam-intro\">Domein B gaat over de <strong>samenleving</strong>: hoe mensen via <strong>socialisatie</strong> normen en waarden leren, hoe de maatschappij in <strong>lagen</strong> is verdeeld (stratificatie), en hoe <strong>verzorgingsstaat</strong> en <strong>multiculturaliteit</strong> daarmee samenhangen.</div><div class=\"sam-head\">Socialisatie</div><p><strong>Socialisatie</strong> is het proces waarin je de cultuur (normen, waarden, rollen) van je samenleving leert. <strong>Primaire</strong> socialisatie gebeurt in het gezin; <strong>secundaire</strong> socialisatie op school, via vrienden, werk en media.</p><table class=\"sam-table\"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Norm</td><td>concrete gedragsregel</td></tr><tr><td>Waarde</td><td>nastrevenswaardig ideaal</td></tr><tr><td>Rol</td><td>verwacht gedrag bij een positie</td></tr><tr><td>Socialiserende instantie</td><td>gezin, school, media, peers</td></tr></tbody></table><div class=\"sam-head\">Sociale stratificatie</div><p>Een samenleving is verdeeld in <strong>lagen</strong> met verschillende hoeveelheden geld, macht en status. <strong>Sociale mobiliteit</strong> is de beweging tussen die lagen — omhoog of omlaag.</p><div class=\"sam-figure\"><svg viewBox=\"0 0 300 160\" role=\"img\" aria-label=\"Piramide van sociale stratificatie met een boven-, midden- en onderlaag en een pijl voor sociale mobiliteit\"><polygon points=\"150,20 210,70 90,70\" fill=\"var(--or)\" opacity=\".22\" stroke=\"var(--mu)\" stroke-width=\"1\"/><polygon points=\"90,72 210,72 245,118 55,118\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--mu)\" stroke-width=\"1\"/><polygon points=\"55,120 245,120 280,150 20,150\" fill=\"var(--or)\" opacity=\".07\" stroke=\"var(--mu)\" stroke-width=\"1\"/><text x=\"150\" y=\"55\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">bovenlaag</text><text x=\"150\" y=\"100\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">middenlaag</text><text x=\"150\" y=\"140\" font-size=\"9\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">onderlaag</text><defs><marker id=\"mwBa\" markerWidth=\"9\" markerHeight=\"9\" refX=\"5\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"var(--dk)\"/></marker></defs><line x1=\"265\" y1=\"145\" x2=\"265\" y2=\"45\" stroke=\"var(--dk)\" stroke-width=\"1.6\" stroke-dasharray=\"4 3\" marker-end=\"url(#mwBa)\"/><text x=\"272\" y=\"100\" font-size=\"7.5\" fill=\"var(--mu)\" transform=\"rotate(90,272,100)\">mobiliteit</text></svg><div class=\"sam-figcap\"><strong>Sociale stratificatie:</strong> de samenleving als piramide met een kleine bovenlaag en brede onderlaag. Via sociale mobiliteit kunnen mensen tussen de lagen bewegen.</div></div><div class=\"sam-head\">Verzorgingsstaat en samenleving</div><p>De <strong>verzorgingsstaat</strong> beschermt burgers tegen risico's (ziekte, werkloosheid, ouderdom) via collectieve voorzieningen.</p><div class=\"sam-compare\"><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Voordelen</div><ul><li>bestaanszekerheid</li><li>minder ongelijkheid</li><li>sociale samenhang</li></ul></div><div class=\"sam-compare-col\"><div class=\"sam-compare-head\">Nadelen</div><ul><li>hoge kosten/belastingen</li><li>risico op afhankelijkheid</li><li>vergrijzing zet druk</li></ul></div></div><div class=\"sam-head\">Deviantie</div><p><strong>Deviant</strong> gedrag wijkt af van de norm; als het strafbaar is, heet het <strong>criminaliteit</strong>. <strong>Stereotypering</strong> en <strong>discriminatie</strong> ontstaan wanneer groepen op basis van kenmerken ongelijk worden behandeld.</p><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Geef een voorbeeld van primaire en van secundaire socialisatie.</div><ol class=\"sam-worked-steps\"><li>Primair: je ouders leren je 'dank je wel' zeggen (in het gezin).</li><li>Secundair: op school leer je op je beurt wachten en samenwerken.</li></ol><div class=\"sam-worked-ans\">✅ Primair = gezin (eerste jaren), secundair = school/media/werk (later).</div></div></div>","vwo_mw_C":"<div class=\"sam-intro\">Domein A gaat over <strong>politiek en democratie</strong>: hoe <strong>macht</strong> wordt verdeeld en gelegitimeerd, hoe <strong>partijen</strong> en <strong>ideologieën</strong> verschillen, en hoe het Nederlandse <strong>kiesstelsel</strong> tot coalities leidt.</div><div class=\"sam-head\">Democratie en macht</div><p>In een <strong>democratie</strong> ligt de macht bij het volk. Bij een <strong>directe</strong> democratie stemt iedereen zelf; bij een <strong>representatieve</strong> democratie kiezen burgers vertegenwoordigers. Macht is pas stabiel als ze <strong>legitiem</strong> is: als burgers het gezag als rechtvaardig aanvaarden.</p><div class=\"sam-head\">Trias politica</div><p>Om machtsmisbruik te voorkomen wordt de macht gescheiden in drie onafhankelijke delen die elkaar <strong>controleren</strong> (checks and balances).</p><div class=\"sam-figure\"><svg viewBox=\"0 0 320 130\" role=\"img\" aria-label=\"De trias politica met de wetgevende, uitvoerende en rechterlijke macht die elkaar controleren\"><defs><marker id=\"mwAa\" markerWidth=\"8\" markerHeight=\"8\" refX=\"4\" refY=\"3\" orient=\"auto\" markerUnits=\"userSpaceOnUse\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"var(--mu)\"/></marker></defs><rect x=\"12\" y=\"40\" width=\"90\" height=\"50\" rx=\"6\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.4\"/><text x=\"57\" y=\"60\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Wetgevend</text><text x=\"57\" y=\"74\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">parlement</text><rect x=\"115\" y=\"40\" width=\"90\" height=\"50\" rx=\"6\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.4\"/><text x=\"160\" y=\"60\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Uitvoerend</text><text x=\"160\" y=\"74\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">regering</text><rect x=\"218\" y=\"40\" width=\"90\" height=\"50\" rx=\"6\" fill=\"var(--or)\" opacity=\".14\" stroke=\"var(--or)\" stroke-width=\"1.4\"/><text x=\"263\" y=\"60\" font-size=\"9.5\" font-weight=\"700\" fill=\"var(--dk)\" text-anchor=\"middle\">Rechterlijk</text><text x=\"263\" y=\"74\" font-size=\"7.5\" fill=\"var(--mu)\" text-anchor=\"middle\">rechters</text><line x1=\"104\" y1=\"58\" x2=\"113\" y2=\"58\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#mwAa)\"/><line x1=\"113\" y1=\"72\" x2=\"104\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#mwAa)\"/><line x1=\"207\" y1=\"58\" x2=\"216\" y2=\"58\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#mwAa)\"/><line x1=\"216\" y1=\"72\" x2=\"207\" y2=\"72\" stroke=\"var(--mu)\" stroke-width=\"1.4\" marker-end=\"url(#mwAa)\"/><text x=\"160\" y=\"24\" font-size=\"9\" font-weight=\"700\" fill=\"var(--mu)\" text-anchor=\"middle\">scheiding der machten</text></svg><div class=\"sam-figcap\"><strong>Trias politica:</strong> de wetgevende (parlement), uitvoerende (regering) en rechterlijke macht (rechters) zijn gescheiden en houden elkaar in evenwicht.</div></div><div class=\"sam-head\">Partijen en ideologieën</div><p>Politieke partijen verschillen langs een <strong>links–rechts</strong>-as (rol van de overheid in de economie) en een <strong>progressief–conservatief</strong>-as (omgang met tradities).</p><table class=\"sam-table\"><thead><tr><th>Stroming</th><th>Kernidee</th></tr></thead><tbody><tr><td>Socialisme (links)</td><td>gelijkheid, sterke overheid</td></tr><tr><td>Liberalisme (rechts)</td><td>vrijheid, vrije markt</td></tr><tr><td>Christendemocratie</td><td>gemeenschap, rentmeesterschap</td></tr></tbody></table><div class=\"sam-head\">Kiesstelsel en coalities</div><p>Nederland kent <strong>evenredige vertegenwoordiging</strong>: het aandeel stemmen bepaalt het aantal zetels. Omdat geen partij een meerderheid haalt, is een <strong>coalitie</strong> nodig.</p><div class=\"sam-tip\">Evenredige vertegenwoordiging geeft veel partijen een stem (representatief), maar maakt kabinetsvorming complex — een <strong>districtenstelsel</strong> geeft juist stabielere meerderheden maar minder evenredigheid.</div><div class=\"sam-worked\"><div class=\"sam-worked-h\">✍️ Voorbeeldopgave</div><div class=\"sam-worked-q\">Waarom is machtenscheiding belangrijk in een rechtsstaat?</div><ol class=\"sam-worked-steps\"><li>Als één orgaan alle macht heeft, kan het die misbruiken.</li><li>Door scheiding controleren de machten elkaar (checks and balances).</li></ol><div class=\"sam-worked-ans\">✅ De trias politica beschermt burgers tegen willekeur en machtsmisbruik.</div></div></div>"};

// ═══════ NIVEAU-DATA: lazy per-niveau laden (data-havo.js / data-vwo.js) ═══════
// Kern (dit bestand) bevat alleen LESMETHODES + SAM_RICH. De zware VAKKEN-arrays
// worden per niveau apart geladen zodat een bezoeker alleen zijn eigen niveau
// downloadt. ensureLevelData() injecteert het juiste bestand en verwerkt de data.
function _processLevelOe(arr){
  (arr||[]).forEach(function(vak){
    (vak.domeinen||[]).forEach(function(dom){
      (dom.oe||[]).forEach(function(q){
        if(!q.jaar){
          var m=q.bron&&q.bron.match(/(\d{4})\s+Tijdvak\s+(\d)/i);
          if(m){q.jaar=parseInt(m[1]);q.tijdvak=parseInt(m[2]);}
        }
      });
    });
  });
}
function _levelLoaded(level){return level==='vwo'?(typeof VAKKEN_VWO!=='undefined'):(typeof VAKKEN!=='undefined');}
var _levelDataCbs={havo:[],vwo:[]},_levelDataLoading={havo:false,vwo:false};
function ensureLevelData(level,cb){
  if(level!=='havo'&&level!=='vwo'){if(cb)cb();return;}
  if(_levelLoaded(level)){if(cb)cb();return;}
  if(cb)_levelDataCbs[level].push(cb);
  if(_levelDataLoading[level])return;
  _levelDataLoading[level]=true;
  var s=document.createElement('script');
  s.src='/data-'+level+'.js';
  var done=function(ok){
    _levelDataLoading[level]=false;
    if(ok){try{_processLevelOe(level==='vwo'?VAKKEN_VWO:VAKKEN);}catch(e){}}
    var cbs=_levelDataCbs[level];_levelDataCbs[level]=[];
    cbs.forEach(function(f){try{f();}catch(e){}});
    if(!ok){try{if(window.showToast)showToast('Kon lesdata niet laden - controleer je verbinding');}catch(e){}}
  };
  s.onload=function(){done(true);};
  s.onerror=function(){done(false);};
  document.head.appendChild(s);
}
